_COMPLETION_FOLLOWUP_PATTERN = re.compile(
    r"\b(?:did|have)\s+you\b|"
    r"\b(?:was|is)\b.{0,80}\b(?:opened|closed|done|completed|finished|on|off|"
    r"set|changed|sent|called|started|stopped|added|removed|replaced)\b|"
    r"\b(?:actually|really)\s+(?:opened|closed|done|completed|finished)\b|"
    r"\bstill\s+want\s+(?:to\s+)?(?:go\s+ahead|proceed)\b|"
    r"\b(?:already|previously)\s+(?:confirmed|said\s+yes)\b|"
    r"\bnot\s+sure\s+if\s+it\b",
    re.IGNORECASE,
)
_FAN_SPEED_FOLLOWUP_PATTERN = re.compile(
    r"\bfan\s+(?:speed|level)\b|"
    r"\b(?:increase|raise|bump|decrease|lower|reduce)\b.{0,40}\bfan\b",
    re.IGNORECASE,
)
