def _meeting_request_text(text: str, *, limit: int = 520) -> str | None:
    normalized = unicodedata.normalize("NFKC", text).strip()
    if (
        not normalized
        or len(normalized) > limit
        or any(character in normalized for character in "\r\n`")
        or re.search(
            r"\b(?:hypothetically|pretend|quoted|said|told|would\s+say|example\s+phrase)\b",
            normalized,
            re.IGNORECASE,
        )
        is not None
    ):
        return None
    return normalized


