@dataclass(slots=True)
class PreparedGoal:
    goal: Goal
    recipes: tuple[OperationRecipe, ...]
    bindings: tuple[LiveBinding, ...]
    closure: Any
    proof: FeasibilityProof
    read_need_ids: dict[str, tuple[str, ...]] = field(default_factory=dict)


@dataclass(slots=True)
class PreparedTurn:
    goals: tuple[PreparedGoal, ...]

    @property
    def by_goal_id(self) -> dict[str, PreparedGoal]:
        return {item.goal.goal_id: item for item in self.goals}

    @property
    def all_recipes(self) -> tuple[OperationRecipe, ...]:
        seen: set[str] = set()
        result: list[OperationRecipe] = []
        for item in self.goals:
            for recipe in item.recipes:
                if recipe.id not in seen:
                    seen.add(recipe.id)
                    result.append(recipe)
        return tuple(result)


@dataclass(slots=True)
class PlannedOutbound:
    envelope: OutboundEnvelope
    proposal: DecisionProposal | None = None
    decision: CommitDecision | None = None
    pending_need_ids: dict[str, tuple[str, ...]] = field(default_factory=dict)
    policy_operations: dict[str, str | None] = field(default_factory=dict)
    terminal_after_success: bool = False


