class CARGuardOrchestrator:
    """Coordinate model proposals and deterministic safety stages.

    The class is synchronous by design. The A2A executor runs it through
    ``asyncio.to_thread`` so provider calls never block the event loop.
    """

    def __init__(
        self,
        config: AgentConfig,
        *,
        client_factory: LLMClientFactory | None = None,
        sessions: SessionStore | None = None,
        recipes: RecipeRegistry | None = None,
    ) -> None:
        self.config = config
        self.adapter = A2AAdapter()
        self.sessions = (
            sessions
            if sessions is not None
            else SessionStore(
                ttl_seconds=config.session_ttl_seconds,
                max_sessions=config.max_sessions,
                soft_max_steps=config.soft_max_steps,
                max_user_turns=config.max_user_turns,
            )
        )
        self.recipes = recipes if recipes is not None else RecipeRegistry()
        self.policy_compiler = PolicyCompiler()
        self.goal_planner = GoalPlanner()
        self.semantic_binder = SemanticCapabilityBinder()
        self.policy_binder = PolicyCapabilityBinder()
        self.closure = ConditionalClosure()
        self.disambiguation = DisambiguationResolver()
        self.result_validator = make_result_validator()
        self.result_validator.register_extractor(
            "trip_charging_station_candidates",
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"search_poi_along_the_route"}),
            ),
        )
        self.result_validator.register_extractor(
            "trip_contact_matches",
            ExtractorSpec(
                "$.result.matches",
                allowed_tool_names=frozenset({"get_contact_id_by_contact_name"}),
            ),
        )
        self.result_validator.register_extractor(
            "trip_contact_information",
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"get_contact_information"}),
            ),
        )
        self.result_validator.register_extractor(
            _CURRENT_DAY_MEETING_CALENDAR,
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"get_entries_from_calendar"}),
            ),
        )
        self.result_validator.register_extractor(
            _CURRENT_DAY_MEETING_CONTACT_MATCHES,
            ExtractorSpec(
                "$.result.matches",
                allowed_tool_names=frozenset({"get_contact_id_by_contact_name"}),
            ),
        )
        self.result_validator.register_extractor(
            _CURRENT_DAY_MEETING_CONTACT_INFORMATION,
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"get_contact_information"}),
            ),
        )
        self.result_validator.register_extractor(
            _CURRENT_DAY_MEETING_LOCATION,
            ExtractorSpec(
                "$.result.id",
                allowed_tool_names=frozenset({"get_location_id_by_location_name"}),
            ),
        )
        self.result_validator.register_extractor(
            _CURRENT_DAY_MEETING_WEATHER,
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"get_weather"}),
            ),
        )
        self.result_validator.register_extractor(
            "local_trip_email_full_range",
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"get_distance_by_soc"}),
            ),
        )
        self.result_validator.register_extractor(
            _CHARGING_STATUS_INFO_EVIDENCE,
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"get_charging_specs_and_status"}),
            ),
        )
        self.result_validator.register_extractor(
            _SOC_TO_EMPTY_EVIDENCE,
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"get_distance_by_soc"}),
            ),
        )
        self.result_validator.register_extractor(
            "meeting_charging_calendar",
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"get_entries_from_calendar"}),
            ),
        )
        self.result_validator.register_extractor(
            "meeting_charging_vehicle_status",
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"get_charging_specs_and_status"}),
            ),
        )
        self.result_validator.register_extractor(
            "meeting_charging_station_candidates",
            ExtractorSpec(
                "$.result.pois_found",
                allowed_tool_names=frozenset({"search_poi_at_location"}),
            ),
        )
        self.result_validator.register_extractor(
            "meeting_charging_location_id",
            ExtractorSpec(
                "$.result.id",
                allowed_tool_names=frozenset({"get_location_id_by_location_name"}),
            ),
        )
        for proposition in (
            "meeting_charging_direct_routes",
            "meeting_charging_first_segment_routes",
            "meeting_charging_second_segment_routes",
        ):
            self.result_validator.register_extractor(
                proposition,
                ExtractorSpec(
                    "$.result.routes",
                    allowed_tool_names=frozenset(
                        {"get_routes_from_start_to_destination"}
                    ),
                ),
            )
        self.result_validator.register_extractor(
            "meeting_charging_time_result",
            ExtractorSpec(
                "$.result",
                allowed_tool_names=frozenset({"calculate_charging_time_by_soc"}),
            ),
        )
        self.completion_validator = SetCompletionValidator()
        self.precommit = PreCommitGate()
        self.responses = ResponseComposer()
        self.tts = TTSGuard()
        self.intent_semantic_contracts = _intent_contracts(self.recipes)
        self._client_factory = client_factory or (
            lambda session: LiteLLMStructuredClient(config, metrics=session.metrics)
        )

    def handle_message(
        self,
        message: Any,
        *,
        context_id: str,
        task: Any = None,
        task_id: str | None = None,
        request_metadata: Any = None,
    ) -> OutboundEnvelope:
        event = self.adapter.parse(
            message,
            task=task,
            context_id=context_id,
            task_id=task_id,
            request_metadata=request_metadata,
        )
        return self.handle_event(event, context_id=context_id)

    def handle_event(
        self, event: InboundEvent, *, context_id: str | None = None
    ) -> OutboundEnvelope:
        context = context_id or event.context_id
        if not context:
            return self.adapter.text(
                "I couldn't identify this conversation, so I did not perform an action."
            )

        replay = self.sessions.replay_for(context, event.message_id)
        if replay is not None:
            return replay
        try:
            with self.sessions.locked(context) as session:
                accepted, replay = session.accept_or_replay(event.message_id)
                if not accepted:
                    return replay or self._safe_unavailable_text()

                if event.cancel_requested:
                    outbound = self.adapter.text("Okay. I cancelled this request.")
                    session.cache_outbound(event.message_id, outbound)
                    self.sessions.cancel(
                        context,
                        message_id=event.message_id,
                        outbound=outbound,
                    )
                    return outbound
                elif event.terminal:
                    outbound = self.adapter.text(
                        "This request has already reached a terminal state.",
                        terminal=True,
                    )
                    session.cache_outbound(event.message_id, outbound)
                    self.sessions.mark_terminal(
                        context,
                        message_id=event.message_id,
                        outbound=outbound,
                    )
                    return outbound
                else:
                    planned = self._handle_active_event(session, event)
                    outbound = self._record_outbound(session, event, planned)
                    if planned.terminal_after_success:
                        self.sessions.mark_terminal(
                            context,
                            message_id=event.message_id,
                            outbound=outbound,
                        )
                    return outbound
        except SessionClosedError as exc:
            replay = (
                None
                if exc.tombstone is None
                else exc.tombstone.replay_for(event.message_id)
            )
            return replay or self.adapter.text(
                "This conversation is closed, so I did not perform another action.",
                terminal=True,
            )

        raise AssertionError("session handling must return from its locked scope")

    def cancel(self, context_id: str) -> None:
        self.sessions.cancel(context_id)

    def _handle_active_event(
        self, session: SessionState, event: InboundEvent
    ) -> PlannedOutbound:
        try:
            self._update_runtime_contract(session, event)
            if event.malformed_parts:
                if any(call.state_changing for call in session.pending_calls):
                    self._abort_execution_bundle(
                        session,
                        reason="the state-changing result could not be validated",
                        source_turn_id=event.message_id,
                        state_may_have_changed=True,
                    )
                return self._text_plan(
                    session,
                    "I couldn't validate the incoming request, so I did not perform an action.",
                )

            result_issue: ResultIssue | None = None
            immediate: PlannedOutbound | None = None
            if event.has_tool_results:
                session.last_limitation_context = None
                result_issue = self._process_tool_results(session, event)
            elif event.user_text is not None:
                immediate = self._process_user_text(session, event)
            elif not event.has_initial_system_policy:
                return self._text_plan(
                    session,
                    "I didn't receive a request or a tool result, so I did not perform an action.",
                )

            if immediate is not None:
                return immediate
            if result_issue is not None:
                transparent = self._result_issue_limitation_plan(session, result_issue)
                if transparent is not None:
                    return transparent
                goal = self._goal_label(session, result_issue.goal_ids)
                text = self.responses.limitation(
                    goal=goal,
                    reason=result_issue.reason,
                    outcome=result_issue.outcome,
                    language=self._language(session),
                )
                return self._text_plan(session, text, goal_ids=result_issue.goal_ids)
            return self._plan_next(session)
        except BudgetExceeded:
            self._abort_execution_bundle(
                session,
                reason="the safe interaction budget was exhausted",
                source_turn_id=event.message_id,
            )
            return self._text_plan(
                session,
                "I reached the safe interaction limit, so I did not perform another action.",
            )
        except (LLMFailure, CriticInputRejected, TTSViolation) as exc:
            logger.warning("CAR-Guard safe failure: {}", type(exc).__name__)
            self._abort_execution_bundle(
                session,
                reason="the active action bundle could not be validated",
                source_turn_id=event.message_id,
            )
            return self._text_plan(session, self._safe_unavailable_text().text or "")
        except Exception as exc:
            logger.error("CAR-Guard runtime failure: {}", type(exc).__name__)
            self._abort_execution_bundle(
                session,
                reason="the active action bundle could not be completed safely",
                source_turn_id=event.message_id,
            )
            return self._text_plan(session, self._safe_unavailable_text().text or "")

    def _update_runtime_contract(
        self, session: SessionState, event: InboundEvent
    ) -> None:
        if event.system_policy is not None:
            if session.policy_text is None:
                session.policy_text = event.system_policy
                session.compiled_policy = self.policy_compiler.compile(
                    event.system_policy
                )
                session.append("system", event.system_policy, turn_id="system-policy")
            elif event.system_policy != session.policy_text:
                raise ValueError("system policy is immutable within one context")
        if event.live_tools:
            session.live_tools = LiveToolRegistry(event.live_tools)

    def _process_user_text(
        self, session: SessionState, event: InboundEvent
    ) -> PlannedOutbound | None:
        assert event.user_text is not None
        session.budget.consume_user_turn()
        turn_id = event.message_id or f"user-turn-{session.budget.user_turns}"
        session.append("user", event.user_text, turn_id=turn_id)

        limitation_followup = self._remembered_limitation_followup_plan(
            session, event.user_text
        )
        if limitation_followup is not None:
            return limitation_followup
        session.last_limitation_context = None

        if session.pending_calls:
            pending_goal_ids = tuple(
                dict.fromkeys(
                    goal_id
                    for call in session.pending_calls
                    for goal_id in call.goal_ids
                )
            )
            return self._text_plan(
                session,
                "I am still waiting for the current control result, so I did not start another action.",
                goal_ids=pending_goal_ids,
            )

        bundle = session.execution_bundle
        pending_confirmation = None
        if bundle is not None and bundle.confirmation_id is not None:
            try:
                candidate = session.confirmation_latch.get(bundle.confirmation_id)
            except KeyError:
                candidate = None
            if candidate is not None and candidate.status is ConfirmationStatus.PENDING:
                pending_confirmation = candidate
        if bundle is not None and pending_confirmation is not None:
            meeting_reply_kind = (
                self._current_day_meeting_confirmation_reply_kind(
                    session, bundle, event.user_text
                )
            )
            if meeting_reply_kind == "invalid":
                return self._refresh_confirmation_plan(
                    session,
                    bundle,
                    source_turn_id=turn_id,
                )
            if self._conditional_confirmation_reply_conflicts(
                session, bundle, event.user_text
            ) or self._resume_confirmation_reply_conflicts(
                session, bundle, event.user_text
            ):
                self._abort_execution_bundle(
                    session,
                    reason="the reply conflicted with the exact pending navigation",
                    source_turn_id=turn_id,
                )
                return self._text_plan(
                    session,
                    "That reply did not match the exact destination and route I "
                    "asked you to confirm, so I did not start navigation.",
                    goal_ids=bundle.goal_ids,
                )
            resolution = session.confirmation_latch.resolve(
                event.user_text,
                current_user_turn=session.budget.user_turns,
                source_turn_id=turn_id,
                response_kind_override=(
                    meeting_reply_kind
                    if meeting_reply_kind in {"positive", "negative"}
                    else None
                ),
                confirmation_id=pending_confirmation.confirmation_id,
                goal_ids=list(bundle.goal_ids),
                ordered_actions=list(bundle.calls),
                confirmation_prompt=self._latest_assistant_text(session),
            )
            if resolution.kind is LatchResolutionKind.CONFIRMED:
                return None
            if resolution.kind in {
                LatchResolutionKind.REJECTED,
                LatchResolutionKind.CANCELLED,
            }:
                session.execution_bundle = None
                return self._text_plan(
                    session,
                    "Okay. I did not perform the requested action.",
                    goal_ids=bundle.goal_ids,
                )
            if resolution.kind is LatchResolutionKind.INVALIDATED:
                self._abort_execution_bundle(
                    session,
                    reason="the pending confirmation no longer matched its action bundle",
                    source_turn_id=turn_id,
                )
                return self._text_plan(
                    session,
                    "The pending action changed, so I did not perform it.",
                    goal_ids=bundle.goal_ids,
                )
            return self._refresh_confirmation_plan(
                session,
                bundle,
                source_turn_id=turn_id,
            )

        if bundle is not None:
            self._abort_execution_bundle(
                session,
                reason="the active action bundle was superseded by a new request",
                source_turn_id=turn_id,
            )

        handled, plan = self._handle_broad_headlights_user_turn(
            session, event.user_text, turn_id
        )
        if handled:
            return plan

        destination_reply, destination_reply_plan = (
            self._handle_pending_destination_reply(
                session, event.user_text, turn_id
            )
        )
        if destination_reply:
            return destination_reply_plan

        current_weather_fog_lights, current_weather_fog_lights_plan = (
            self._handle_current_weather_fog_lights_request(
                session, event.user_text, turn_id
            )
        )
        if current_weather_fog_lights:
            return current_weather_fog_lights_plan

        seat_heating_preflight = self._handle_seat_heating_capability_preflight(
            session, event.user_text, turn_id
        )
        if seat_heating_preflight is not None:
            return seat_heating_preflight

        occupancy_info, occupancy_info_plan = (
            self._handle_seat_occupancy_information_request(
                session, event.user_text, turn_id
            )
        )
        if occupancy_info:
            return occupancy_info_plan

        current_day_meeting, current_day_meeting_plan = (
            self._handle_current_day_meeting_request(
                session, event.user_text, turn_id
            )
        )
        if current_day_meeting:
            return current_day_meeting_plan

        meeting_charging, meeting_charging_plan = self._handle_meeting_charging_request(
            session, event.user_text, turn_id
        )
        if meeting_charging:
            return meeting_charging_plan

        local_trip_email, local_trip_email_plan = self._handle_local_trip_email_request(
            session, event.user_text, turn_id
        )
        if local_trip_email:
            return local_trip_email_plan

        completed_ids = tuple(
            goal.goal_id
            for goal in session.goal_dag.goals
            if goal.status is GoalStatus.DONE
        )
        if (
            completed_ids
            and len(completed_ids) == len(session.goal_dag.goals)
            and _COMPLETION_FOLLOWUP_PATTERN.search(event.user_text) is not None
            and self._completion_followup_matches(
                session, event.user_text, completed_ids
            )
        ):
            return self._text_plan(
                session,
                self._completion_text(session, completed_ids),
                goal_ids=completed_ids,
                kind=ProposalKind.COMPLETE,
            )

        climate_info, climate_info_plan = self._handle_climate_settings_info_request(
            session, event.user_text, turn_id
        )
        if climate_info:
            return climate_info_plan

        medium_steering, medium_steering_plan = (
            self._handle_direct_medium_steering_heating_request(
                session, event.user_text, turn_id
            )
        )
        if medium_steering:
            return medium_steering_plan

        charging_info, charging_info_plan = (
            self._handle_comprehensive_charging_info_request(
                session, event.user_text, turn_id
            )
        )
        if charging_info:
            return charging_info_plan

        soc_to_empty, soc_to_empty_plan = self._handle_soc_to_empty_request(
            session, event.user_text, turn_id
        )
        if soc_to_empty:
            return soc_to_empty_plan

        active_route_charging, active_route_charging_plan = (
            self._handle_active_route_charging_request(
                session, event.user_text, turn_id
            )
        )
        if active_route_charging:
            return active_route_charging_plan

        charger_call, charger_call_plan = (
            self._handle_active_route_charger_call_request(
                session, event.user_text, turn_id
            )
        )
        if charger_call:
            return charger_call_plan

        local_charging_search, local_charging_search_plan = (
            self._handle_local_charging_search_request(
                session, event.user_text, turn_id
            )
        )
        if local_charging_search:
            return local_charging_search_plan

        local_charging_selection, local_charging_selection_plan = (
            self._handle_local_charging_selection_request(
                session, event.user_text, turn_id
            )
        )
        if local_charging_selection:
            return local_charging_selection_plan

        charging_stop_navigation, charging_stop_navigation_plan = (
            self._handle_charging_stop_navigation_request(
                session, event.user_text, turn_id
            )
        )
        if charging_stop_navigation:
            return charging_stop_navigation_plan

        trip_followup, trip_followup_plan = self._handle_trip_followup_request(
            session, event.user_text, turn_id
        )
        if trip_followup:
            return trip_followup_plan

        contact_call, contact_call_plan = self._handle_displayed_contact_call_request(
            session, event.user_text, turn_id
        )
        if contact_call:
            return contact_call_plan

        contact_share, contact_share_plan = self._handle_contact_record_share_request(
            session, event.user_text, turn_id
        )
        if contact_share:
            return contact_share_plan

        contact_selection, contact_selection_plan = (
            self._handle_displayed_contact_selection(session, event.user_text, turn_id)
        )
        if contact_selection:
            return contact_selection_plan

        route_selection, route_selection_plan = (
            self._handle_destination_replacement_route_selection(
                session, event.user_text, turn_id
            )
        )
        if route_selection:
            return route_selection_plan

        driver_warming_followup, driver_warming_plan = (
            self._handle_driver_warming_followup(session, event.user_text, turn_id)
        )
        if driver_warming_followup:
            return driver_warming_plan

        displayed_poi_call, displayed_poi_plan = (
            self._handle_displayed_poi_call_request(session, event.user_text, turn_id)
        )
        if displayed_poi_call:
            return displayed_poi_plan

        displayed_poi_navigation, displayed_poi_navigation_plan = (
            self._handle_displayed_poi_navigation_request(
                session, event.user_text, turn_id
            )
        )
        if displayed_poi_navigation:
            return displayed_poi_navigation_plan

        descriptive_destination, descriptive_destination_plan = (
            self._handle_descriptive_destination_request(
                session, event.user_text, turn_id
            )
        )
        if descriptive_destination:
            return descriptive_destination_plan

        grounding_text = event.user_text
        extracted: IntentFrame | None = None
        carried_temperature_source: str | None = None
        deterministic_seed = IntentFrame(
            language=self._language(session),
            call_for_action=False,
            goals=[],
            intent_source_turn_ids=[turn_id],
            intent_kind=IntentKind.CONVERSATION,
        )
        deterministic_resume = recover_navigation_resume_intent(
            grounding_text,
            deterministic_seed,
            turn_id=turn_id,
        )
        deterministic_create = recover_simple_navigation_create_intent(
            grounding_text,
            deterministic_seed,
            turn_id=turn_id,
        )
        deterministic_destination = (
            recover_named_navigation_destination_replacement_intent(
                grounding_text,
                deterministic_seed,
                turn_id=turn_id,
            )
        )
        deterministic_destination_preview = _destination_replacement_preview_intent(
            grounding_text,
            turn_id=turn_id,
            language=self._language(session),
        )
        deterministic_named_delete = (
            recover_named_navigation_final_destination_delete_intent(
                grounding_text,
                deterministic_seed,
                turn_id=turn_id,
            )
        )
        deterministic_waypoint_delete = (
            recover_named_navigation_waypoint_delete_intent(
                grounding_text,
                deterministic_seed,
                turn_id=turn_id,
            )
        )
        fresh_resume_command = (
            deterministic_resume is not deterministic_seed
            and deterministic_resume.call_for_action
            and deterministic_resume.intent_kind is IntentKind.ACTION
            and len(deterministic_resume.goals) == 1
            and deterministic_resume.goals[0].semantic_operation == _NAVIGATION_RESUME
            and deterministic_resume.goals[0].desired_outcome == {}
        )
        fresh_create_command = (
            deterministic_create is not deterministic_seed
            and deterministic_create.call_for_action
            and deterministic_create.intent_kind is IntentKind.ACTION
            and len(deterministic_create.goals) == 1
            and deterministic_create.goals[0].semantic_operation
            in _NAVIGATION_CREATE_OPERATIONS
            and set(deterministic_create.goals[0].desired_outcome) == {"location"}
        )
        fresh_destination_command = (
            deterministic_destination is not deterministic_seed
            and deterministic_destination.call_for_action
            and deterministic_destination.intent_kind is IntentKind.ACTION
            and len(deterministic_destination.goals) == 1
            and deterministic_destination.goals[0].semantic_operation
            == _NAVIGATION_REPLACE_DESTINATION
            and set(deterministic_destination.goals[0].desired_outcome)
            in (
                {"new_destination_name"},
                {"new_destination_name", "route_choice_alias"},
                {"new_destination_name", "previous_destination_name"},
                {
                    "new_destination_name",
                    "previous_destination_name",
                    "route_choice_alias",
                },
            )
            and deterministic_destination.goals[0].desired_outcome.get(
                "route_choice_alias"
            )
            in {None, "fastest", "shortest"}
        )
        fresh_generic_named_delete = (
            deterministic_named_delete is not deterministic_seed
            and deterministic_named_delete.call_for_action
            and deterministic_named_delete.intent_kind is IntentKind.ACTION
            and len(deterministic_named_delete.goals) == 1
            and deterministic_named_delete.goals[0].semantic_operation
            == _NAVIGATION_DELETE_DESTINATION
            and set(deterministic_named_delete.goals[0].desired_outcome)
            == {"destination_name_to_delete"}
        )
        fresh_named_waypoint_delete = (
            deterministic_waypoint_delete is not deterministic_seed
            and deterministic_waypoint_delete.call_for_action
            and deterministic_waypoint_delete.intent_kind is IntentKind.ACTION
            and len(deterministic_waypoint_delete.goals) == 1
            and deterministic_waypoint_delete.goals[0].semantic_operation
            == _NAVIGATION_DELETE_WAYPOINT
            and "waypoint_name_to_delete"
            in deterministic_waypoint_delete.goals[0].desired_outcome
            and set(deterministic_waypoint_delete.goals[0].desired_outcome).issubset(
                {
                    "waypoint_name_to_delete",
                    "remaining_destination_name",
                    "route_choice_alias",
                    "route_destination_name",
                }
            )
            and deterministic_waypoint_delete.goals[0].desired_outcome.get(
                "route_choice_alias"
            )
            in {None, "fastest", "shortest"}
            and (
                "route_destination_name"
                not in deterministic_waypoint_delete.goals[0].desired_outcome
                or deterministic_waypoint_delete.goals[0].desired_outcome.get(
                    "route_choice_alias"
                )
                in {"fastest", "shortest"}
            )
        )
        strict_warming = self._strict_warming_command_supersedes_clarification(
            session, event.user_text, turn_id
        )
        if fresh_resume_command:
            extracted = deterministic_resume
            session.pending_clarifications.clear()
        elif fresh_create_command:
            extracted = deterministic_create
            session.pending_clarifications.clear()
        elif fresh_destination_command:
            extracted = deterministic_destination
            session.pending_clarifications.clear()
        elif deterministic_destination_preview is not None:
            extracted = deterministic_destination_preview
            session.pending_clarifications.clear()
        elif fresh_named_waypoint_delete:
            extracted = deterministic_waypoint_delete
            session.pending_clarifications.clear()
        elif fresh_generic_named_delete:
            extracted = deterministic_named_delete
            session.pending_clarifications.clear()
        elif strict_warming is not None:
            grounding_text, extracted, carried_temperature_source = strict_warming
            session.pending_clarifications.clear()
        elif self._strict_relative_seat_command_supersedes_clarification(
            session, event.user_text, turn_id
        ):
            session.pending_clarifications.clear()
        else:
            had_pending_clarification = bool(session.pending_clarifications)
            clarification = self._resolve_pending_clarification(
                session, event.user_text, turn_id
            )
            if had_pending_clarification or clarification is not None:
                return clarification

        if session.policy_text is None:
            return self._text_plan(
                session,
                "I don't have the current safety policy, so I did not perform an action.",
            )
        extracted = extracted or _sunshade_match_intent(
            event.user_text, turn_id=turn_id
        )
        extracted = extracted or _ambient_car_color_intent(
            event.user_text, turn_id=turn_id
        )
        extracted = extracted or _occupancy_reading_lights_intent(
            event.user_text, turn_id=turn_id
        )
        extracted = extracted or _fully_open_window_close_intent(
            event.user_text, turn_id=turn_id
        )
        extracted = extracted or _absolute_climate_temperature_intent(
            event.user_text, turn_id=turn_id
        )
        extracted = extracted or _absolute_fan_speed_intent(
            event.user_text, turn_id=turn_id
        )
        extracted = extracted or _fan_speed_preference_intent(
            event.user_text, turn_id=turn_id
        )
        extracted = extracted or _steering_wheel_heating_preference_intent(
            event.user_text, turn_id=turn_id
        )
        extracted = extracted or _trip_range_information_intent(
            grounding_text,
            turn_id=turn_id,
            language=self._language(session),
        )
        extracted = extracted or self._strict_contact_email_recipient_lookup_intent(
            grounding_text,
            turn_id=turn_id,
            language=self._language(session),
        )
        extracted = extracted or self._strict_bare_contact_lookup_intent(
            grounding_text,
            turn_id=turn_id,
            language=self._language(session),
        )
        extracted = extracted or self._strict_contact_last_name_lookup_intent(
            grounding_text,
            turn_id=turn_id,
            language=self._language(session),
        )
        extracted = extracted or self._strict_displayed_contact_group_send_intent(
            session,
            grounding_text,
            turn_id=turn_id,
            language=self._language(session),
        )
        if extracted is None:
            deterministic_navigation = recover_navigation_waypoint_context_intent(
                grounding_text,
                deterministic_seed,
                turn_id=turn_id,
            )
            if deterministic_navigation.goals:
                extracted = deterministic_navigation
        if extracted is None:
            client = self._client_factory(session)
            extracted = IntentExtractor(
                client, semantic_contracts=self.intent_semantic_contracts
            ).extract(
                system_policy=session.policy_text,
                conversation=session.conversation,
            )
        extracted = recover_battery_charge_trip_range_intent(
            grounding_text,
            extracted,
            turn_id=turn_id,
        )
        before_destination_poi_recovery = extracted
        extracted = recover_current_destination_poi_search_intent(
            grounding_text,
            extracted,
            turn_id=turn_id,
        )
        recovered_current_destination_poi = (
            extracted is not before_destination_poi_recovery
        )
        extracted = recover_named_location_poi_search_intent(
            grounding_text,
            extracted,
            turn_id=turn_id,
        )
        extracted = recover_named_navigation_destination_replacement_intent(
            grounding_text,
            extracted,
            turn_id=turn_id,
        )
        extracted = recover_named_navigation_final_destination_delete_intent(
            grounding_text,
            extracted,
            turn_id=turn_id,
        )
        extracted = recover_named_navigation_waypoint_delete_intent(
            grounding_text,
            extracted,
            turn_id=turn_id,
        )
        extracted = recover_navigation_waypoint_context_intent(
            grounding_text,
            extracted,
            turn_id=turn_id,
        )
        before_driver_warming_recovery = extracted
        extracted = recover_driver_warming_intent(
            grounding_text,
            extracted,
            turn_id=turn_id,
        )
        recovered_driver_warming = extracted is not before_driver_warming_recovery
        before_climate_sync_recovery = extracted
        extracted = recover_climate_zone_sync_intent(
            grounding_text,
            extracted,
            turn_id=turn_id,
        )
        recovered_climate_sync = extracted is not before_climate_sync_recovery
        extracted = recover_relative_occupied_seat_heating_intent(
            grounding_text,
            extracted,
            turn_id=turn_id,
        )
        conditional_navigation_grounding = (
            _conditional_arrival_weather_navigation_grounding(
                grounding_text,
                turn_id=turn_id,
                language=self._language(session),
            )
        )
        contact_grounding = self._recover_contact_grounding(
            session, grounding_text, extracted, turn_id=turn_id
        )
        destination_preview_grounding = (
            self._recover_destination_replacement_preview_grounding(
                grounding_text, extracted
            )
        )
        resume_navigation_grounding = None
        if (
            fresh_resume_command
            and len(extracted.goals) == 1
            and extracted.goals[0].semantic_operation == _NAVIGATION_RESUME
            and extracted.goals[0].desired_outcome == {}
        ):
            resume_goal = extracted.goals[0]
            resume_navigation_grounding = IntentGroundingResult(
                filtered_intent=extracted,
                authorized_action_goal_ids=frozenset({resume_goal.goal_id}),
                desired_values_by_goal={resume_goal.goal_id: {}},
            )
        create_command_grounding = None
        if fresh_create_command and len(extracted.goals) == 1:
            create_goal = extracted.goals[0]
            create_command_grounding = IntentGroundingResult(
                filtered_intent=extracted,
                authorized_action_goal_ids=frozenset({create_goal.goal_id}),
                desired_values_by_goal={
                    create_goal.goal_id: dict(create_goal.desired_outcome)
                },
            )
        destination_command_grounding = None
        if fresh_destination_command and len(extracted.goals) == 1:
            destination_goal = extracted.goals[0]
            destination_command_grounding = IntentGroundingResult(
                filtered_intent=extracted,
                authorized_action_goal_ids=frozenset({destination_goal.goal_id}),
                desired_values_by_goal={
                    destination_goal.goal_id: dict(destination_goal.desired_outcome)
                },
            )
        waypoint_delete_grounding = None
        if fresh_named_waypoint_delete and len(extracted.goals) == 1:
            waypoint_goal = extracted.goals[0]
            waypoint_delete_grounding = IntentGroundingResult(
                filtered_intent=extracted,
                authorized_action_goal_ids=frozenset({waypoint_goal.goal_id}),
                desired_values_by_goal={
                    waypoint_goal.goal_id: dict(waypoint_goal.desired_outcome)
                },
            )
        ambient_car_color_grounding = None
        if (
            len(extracted.goals) == 1
            and extracted.goals[0].semantic_operation == _AMBIENT_CAR_COLOR_OPERATION
        ):
            ambient_goal = extracted.goals[0]
            ambient_car_color_grounding = IntentGroundingResult(
                filtered_intent=extracted,
                authorized_action_goal_ids=frozenset({ambient_goal.goal_id}),
                desired_values_by_goal={
                    ambient_goal.goal_id: dict(ambient_goal.desired_outcome)
                },
            )
        occupancy_reading_lights_grounding = None
        if (
            len(extracted.goals) == 1
            and extracted.goals[0].semantic_operation
            == _OCCUPANCY_READING_LIGHTS_OPERATION
        ):
            reading_goal = extracted.goals[0]
            occupancy_reading_lights_grounding = IntentGroundingResult(
                filtered_intent=extracted,
                authorized_action_goal_ids=frozenset({reading_goal.goal_id}),
                desired_values_by_goal={reading_goal.goal_id: {}},
            )
        strict_absolute_control = (
            _fully_open_window_close_intent(grounding_text, turn_id=turn_id)
            or _absolute_climate_temperature_intent(grounding_text, turn_id=turn_id)
            or _absolute_fan_speed_intent(grounding_text, turn_id=turn_id)
            or _fan_speed_preference_intent(grounding_text, turn_id=turn_id)
            or _steering_wheel_heating_preference_intent(
                grounding_text, turn_id=turn_id
            )
        )
        absolute_control_grounding = None
        if (
            strict_absolute_control is not None
            and len(strict_absolute_control.goals) == 1
            and len(extracted.goals) == 1
            and extracted.goals[0].semantic_operation
            == strict_absolute_control.goals[0].semantic_operation
            and extracted.goals[0].desired_outcome
            == strict_absolute_control.goals[0].desired_outcome
        ):
            control_goal = strict_absolute_control.goals[0]
            absolute_control_grounding = IntentGroundingResult(
                filtered_intent=strict_absolute_control,
                authorized_action_goal_ids=frozenset({control_goal.goal_id}),
                desired_values_by_goal={
                    control_goal.goal_id: dict(control_goal.desired_outcome)
                },
            )
        grounding = (
            resume_navigation_grounding
            or create_command_grounding
            or destination_command_grounding
            or waypoint_delete_grounding
            or conditional_navigation_grounding
            or contact_grounding
            or destination_preview_grounding
            or ambient_car_color_grounding
            or occupancy_reading_lights_grounding
            or absolute_control_grounding
            or ground_intent(grounding_text, extracted, self.recipes)
        )
        grounding = _parallel_trip_range_read_grounding(grounding_text, grounding)
        if recovered_climate_sync:
            sync_goals = tuple(extracted.goals)
            if (
                len(sync_goals) == 2
                and tuple(goal.semantic_operation for goal in sync_goals)
                == ("set_climate_temperature", "set_seat_heating")
                and len({goal.desired_outcome.get("seat_zone") for goal in sync_goals})
                == 1
                and all(
                    set(goal.desired_outcome) == {"seat_zone"} for goal in sync_goals
                )
            ):
                grounding = IntentGroundingResult(
                    filtered_intent=extracted,
                    authorized_action_goal_ids=frozenset(
                        goal.goal_id for goal in sync_goals
                    ),
                    desired_values_by_goal={
                        goal.goal_id: dict(goal.desired_outcome) for goal in sync_goals
                    },
                )
            elif (
                len(sync_goals) == 1
                and sync_goals[0].semantic_operation == "set_climate_temperature"
                and set(sync_goals[0].desired_outcome) == {"seat_zone"}
                and sync_goals[0].desired_outcome.get("seat_zone")
                in {"DRIVER", "PASSENGER"}
            ):
                sync_goal = sync_goals[0]
                grounding = IntentGroundingResult(
                    filtered_intent=extracted,
                    authorized_action_goal_ids=frozenset({sync_goal.goal_id}),
                    desired_values_by_goal={
                        sync_goal.goal_id: dict(sync_goal.desired_outcome)
                    },
                )
        if recovered_driver_warming:
            grounding = self._order_initial_driver_warming_grounding(grounding)
        if (
            recovered_current_destination_poi
            and len(extracted.goals) == 1
            and extracted.goals[0].semantic_operation == _CURRENT_DESTINATION_POI_SEARCH
            and extracted.goals[0].desired_outcome == {"category": "restaurants"}
            and not extracted.call_for_action
            and extracted.intent_kind is IntentKind.INFORMATION
        ):
            recovered_goal = extracted.goals[0]
            grounding = IntentGroundingResult(
                filtered_intent=extracted,
                desired_values_by_goal={
                    recovered_goal.goal_id: dict(recovered_goal.desired_outcome)
                },
            )
        recovered = recover_current_day_calendar_intent(
            grounding_text,
            grounding.filtered_intent,
            turn_id=turn_id,
        )
        if recovered is not grounding.filtered_intent:
            grounding = ground_intent(grounding_text, recovered, self.recipes)
        session.intent = grounding.filtered_intent
        session.authorized_action_goal_ids = set(grounding.authorized_action_goal_ids)
        session.grounded_desired_values_by_goal = {
            goal_id: dict(values)
            for goal_id, values in grounding.desired_values_by_goal.items()
        }
        session.grounded_value_sources_by_goal = {
            goal_id: {name: turn_id for name in values}
            for goal_id, values in grounding.desired_values_by_goal.items()
        }
        for goal in session.intent.goals:
            if not (
                goal.desired_outcome.get(_CONTACT_SHARE_EMAIL_MARKER) is True
                or goal.desired_outcome.get(_CONTACT_EMAIL_RECIPIENT_LOOKUP_MARKER)
                is True
            ):
                continue
            recipient_values = {
                name: goal.desired_outcome[name]
                for name in ("first_name", "last_name")
                if name in goal.desired_outcome
            }
            session.grounded_desired_values_by_goal[goal.goal_id] = recipient_values
            session.grounded_value_sources_by_goal[goal.goal_id] = {
                name: turn_id for name in recipient_values
            }
        if carried_temperature_source is not None:
            climate_goals = [
                goal
                for goal in session.intent.goals
                if goal.semantic_operation == "set_climate_temperature"
                and session.grounded_desired_values_by_goal.get(goal.goal_id, {}).get(
                    "temperature"
                )
                == 22
            ]
            if len(climate_goals) == 1:
                session.grounded_value_sources_by_goal[climate_goals[0].goal_id][
                    "temperature"
                ] = carried_temperature_source
        session.derived_value_evidence_by_goal = {}
        session.relative_fan_speed_deltas_by_goal = dict(
            grounding.relative_fan_speed_deltas_by_goal
        )
        session.relative_climate_temperature_deltas_by_goal = dict(
            grounding.relative_climate_temperature_deltas_by_goal
        )
        session.relative_seat_heating_deltas_by_goal = dict(
            grounding.relative_seat_heating_deltas_by_goal
        )
        session.occupied_seat_heating_goal_ids = set(
            grounding.occupied_seat_heating_goal_ids
        )
        if recovered_climate_sync:
            session.climate_sync_source_zones_by_goal = {
                goal.goal_id: (
                    "PASSENGER"
                    if goal.desired_outcome.get("seat_zone") == "DRIVER"
                    else "DRIVER"
                )
                for goal in session.intent.goals
            }
        else:
            session.climate_sync_source_zones_by_goal = {}
        for goal in session.intent.goals:
            values = session.grounded_desired_values_by_goal.get(goal.goal_id, {})
            if (
                goal.semantic_operation == "set_ambient_lights"
                and values.get("enabled") is True
                and "color" in values
                and grounding.derived_values_by_goal.get(goal.goal_id, {}).get(
                    "enabled"
                )
                == "ambient_color_selection_enables_lights_v1"
            ):
                session.grounded_value_sources_by_goal[goal.goal_id].pop(
                    "enabled", None
                )
                self._record_ambient_enabled_derivation(
                    session,
                    goal_id=goal.goal_id,
                    color=values["color"],
                    source_turn_id=turn_id,
                )
        session.goal_dag = self.goal_planner.update(
            session.goal_dag, grounding.filtered_intent
        )
        session.execution_bundle = None
        return None

    @staticmethod
    def _order_initial_driver_warming_grounding(
        grounding: IntentGroundingResult,
    ) -> IntentGroundingResult:
        """Sequence the exact partially specified warming request without defaults."""

        intent = grounding.filtered_intent
        if (
            tuple(goal.semantic_operation for goal in intent.goals)
            != _DRIVER_WARMING_OPERATIONS
            or len(intent.goals) != 3
            or any(goal.depends_on for goal in intent.goals)
            or [goal.desired_outcome for goal in intent.goals]
            != [
                {"temperature": 24, "seat_zone": "DRIVER"},
                {"seat_zone": "DRIVER"},
                {},
            ]
            or grounding.authorized_action_goal_ids
            != frozenset(goal.goal_id for goal in intent.goals)
        ):
            return grounding

        climate, seat, steering = intent.goals
        ordered_goals = [
            climate.model_copy(update={"depends_on": []}, deep=True),
            seat.model_copy(update={"depends_on": [climate.goal_id]}, deep=True),
            steering.model_copy(update={"depends_on": [seat.goal_id]}, deep=True),
        ]
        return grounding.model_copy(
            update={
                "filtered_intent": intent.model_copy(
                    update={"goals": ordered_goals}, deep=True
                )
            },
            deep=True,
        )

    @staticmethod
    def _climate_temperature_zone_sync_goal(
        session: SessionState,
    ) -> tuple[Goal, str] | None:
        if (
            not isinstance(session.intent, IntentFrame)
            or not session.intent.call_for_action
            or len(session.intent.goals) != 1
        ):
            return None
        goal = session.intent.goals[0]
        target = goal.desired_outcome.get("seat_zone")
        source = session.climate_sync_source_zones_by_goal.get(goal.goal_id)
        if (
            goal.semantic_operation != "set_climate_temperature"
            or target not in {"DRIVER", "PASSENGER"}
            or source not in {"DRIVER", "PASSENGER"}
            or source == target
            or set(goal.desired_outcome).difference({"seat_zone", "temperature"})
            or goal.goal_id not in session.authorized_action_goal_ids
        ):
            return None
        return goal, source

    @staticmethod
    def _climate_zone_sync_goals(
        session: SessionState,
    ) -> tuple[Goal, Goal] | None:
        if (
            not isinstance(session.intent, IntentFrame)
            or not session.intent.call_for_action
            or len(session.intent.goals) != 2
        ):
            return None
        climate, seat = session.intent.goals
        if tuple(goal.semantic_operation for goal in (climate, seat)) != (
            "set_climate_temperature",
            "set_seat_heating",
        ):
            return None
        target = climate.desired_outcome.get("seat_zone")
        if (
            target not in {"DRIVER", "PASSENGER"}
            or seat.desired_outcome.get("seat_zone") != target
            or set(climate.desired_outcome).difference({"seat_zone", "temperature"})
            or set(seat.desired_outcome).difference({"seat_zone", "level"})
        ):
            return None
        source = "PASSENGER" if target == "DRIVER" else "DRIVER"
        expected_sources = {climate.goal_id: source, seat.goal_id: source}
        if session.climate_sync_source_zones_by_goal != expected_sources:
            return None
        if not {climate.goal_id, seat.goal_id}.issubset(
            session.authorized_action_goal_ids
        ):
            return None
        return climate, seat

    @staticmethod
    def _register_climate_sync_need(
        session: SessionState, *, goal_id: str, proposition: str
    ) -> str:
        need = EvidenceNeed(
            proposition=proposition,
            required_for_goal_id=goal_id,
            acceptable_sources={"tool_result"},
            freshness="current_state",
        )
        session.evidence.register_need(need)
        assert need.need_id is not None
        return need.need_id

    def _climate_zone_sync_need_ids(
        self, session: SessionState, *, climate_goal_id: str, seat_goal_id: str
    ) -> dict[str, tuple[str, ...]]:
        temperature_need_ids = [
            self._register_climate_sync_need(
                session,
                goal_id=climate_goal_id,
                proposition="relative_climate_temperature_snapshot",
            ),
            *register_policy_read_needs(
                session.evidence,
                goal_id=climate_goal_id,
                required_facts=(
                    "climate_temperature_driver",
                    "climate_temperature_passenger",
                ),
            ),
        ]
        seat_need_id = self._register_climate_sync_need(
            session,
            goal_id=seat_goal_id,
            proposition="relative_seat_heating_snapshot",
        )
        return {
            "get_temperature_inside_car": tuple(dict.fromkeys(temperature_need_ids)),
            "get_seat_heating_level": (seat_need_id,),
        }

    def _next_climate_temperature_zone_sync_workflow(
        self, session: SessionState
    ) -> PlannedOutbound | None:
        sync = self._climate_temperature_zone_sync_goal(session)
        if sync is None:
            return None
        goal, source_zone = sync
        if "temperature" in goal.desired_outcome:
            return None

        proposition = "relative_climate_temperature_snapshot"
        observed = self._derived_navigation_read_value(
            session,
            goal_id=goal.goal_id,
            tool_name="get_temperature_inside_car",
            arguments={},
            proposition=proposition,
        )
        if observed is None:
            if (
                self._successful_goal_read(
                    session,
                    goal_id=goal.goal_id,
                    tool_name="get_temperature_inside_car",
                    arguments={},
                )
                is not None
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            if not session.live_tools.has_tool("get_temperature_inside_car"):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            try:
                arguments = session.live_tools.validate_arguments(
                    "get_temperature_inside_car", {}
                )
            except ToolArgumentValidationError:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNSUPPORTED_PARAMETER
                )

            existing = [
                need
                for need in session.evidence.needs.values()
                if need.required_for_goal_id == goal.goal_id
                and need.proposition == proposition
                and need.need_id is not None
            ]
            if not existing:
                self._register_climate_sync_need(
                    session, goal_id=goal.goal_id, proposition=proposition
                )
            policy_need_ids = register_policy_read_needs(
                session.evidence,
                goal_id=goal.goal_id,
                required_facts=(
                    "climate_temperature_driver",
                    "climate_temperature_passenger",
                ),
            )
            need_ids = tuple(
                need.need_id
                for need in session.evidence.needs.values()
                if need.required_for_goal_id == goal.goal_id
                and need.proposition == proposition
                and need.need_id is not None
            )
            if len(need_ids) != 1:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            call_id = session.next_call_id()
            proposal = DecisionProposal(
                kind=ProposalKind.TOOL_GET,
                goal_ids=[goal.goal_id],
                tool_calls=[
                    ProposedToolCall(
                        tool_name="get_temperature_inside_car",
                        arguments=arguments,
                        call_id=call_id,
                        goal_id=goal.goal_id,
                    )
                ],
            )
            gate = self.precommit.validate(proposal, self._basic_gate_context(session))
            if gate.outcome is not GateOutcome.ALLOW:
                return self._route_gate_failure(session, proposal, gate, goal)
            return PlannedOutbound(
                self.adapter.serialize(gate),
                proposal=proposal,
                decision=gate,
                pending_need_ids={
                    call_id: tuple(dict.fromkeys((*need_ids, *policy_need_ids)))
                },
                policy_operations={call_id: "read_cabin_temperatures"},
            )

        snapshot, temperature_evidence = observed
        if not isinstance(snapshot, Mapping):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        raw_temperature = snapshot.get(
            f"climate_temperature_{source_zone.casefold()}"
        )
        if isinstance(raw_temperature, bool) or not isinstance(
            raw_temperature, (int, float, Decimal)
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        try:
            value = Decimal(str(raw_temperature))
        except InvalidOperation:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        if not value.is_finite():
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        temperature: int | float = (
            int(value) if value == value.to_integral_value() else float(value)
        )
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters={
                "temperature": (
                    temperature,
                    (temperature_evidence,),
                    "climate_temperature_zone_sync_from_source_v1",
                )
            },
        )
        return None

    def _next_climate_zone_sync_read(
        self,
        session: SessionState,
        *,
        climate: Goal,
        seat: Goal,
        need_ids: Mapping[str, tuple[str, ...]],
    ) -> PlannedOutbound | None:
        specifications = (
            (
                climate,
                "get_temperature_inside_car",
                "relative_climate_temperature_snapshot",
                "read_cabin_temperatures",
            ),
            (
                seat,
                "get_seat_heating_level",
                "relative_seat_heating_snapshot",
                "read_seat_heating",
            ),
        )
        missing = [
            specification
            for specification in specifications
            if self._derived_navigation_read_value(
                session,
                goal_id=specification[0].goal_id,
                tool_name=specification[1],
                arguments={},
                proposition=specification[2],
            )
            is None
        ]
        if not missing:
            return None
        invalid_observation = next(
            (
                goal
                for goal, tool_name, _, _ in missing
                if self._successful_goal_read(
                    session,
                    goal_id=goal.goal_id,
                    tool_name=tool_name,
                    arguments={},
                )
                is not None
            ),
            None,
        )
        if invalid_observation is not None:
            self._fail_goals(
                session,
                (invalid_observation.goal_id,),
                "the source-zone reading was malformed or ambiguous",
            )
            return self._limitation_plan(
                session, invalid_observation, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        unavailable = next(
            (
                goal
                for goal, tool_name, _, _ in missing
                if not session.live_tools.has_tool(tool_name)
            ),
            None,
        )
        if unavailable is not None:
            self._fail_goals(
                session,
                (unavailable.goal_id,),
                "the required current zone setting is unavailable",
            )
            return self._limitation_plan(
                session, unavailable, GateOutcome.UNSUPPORTED_CAPABILITY
            )

        proposed_calls: list[ProposedToolCall] = []
        pending_need_ids: dict[str, tuple[str, ...]] = {}
        policy_operations: dict[str, str | None] = {}
        for goal, tool_name, _, policy_operation in missing:
            try:
                arguments = session.live_tools.validate_arguments(tool_name, {})
            except ToolArgumentValidationError:
                self._fail_goals(
                    session,
                    (goal.goal_id,),
                    "the required zone read does not accept a safe empty request",
                )
                return self._limitation_plan(
                    session, goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            call_id = session.next_call_id()
            proposed_calls.append(
                ProposedToolCall(
                    tool_name=tool_name,
                    arguments=arguments,
                    call_id=call_id,
                    goal_id=goal.goal_id,
                )
            )
            pending_need_ids[call_id] = need_ids[tool_name]
            policy_operations[call_id] = policy_operation
        proposal = DecisionProposal(
            kind=ProposalKind.TOOL_GET,
            goal_ids=list(dict.fromkeys(goal.goal_id for goal, _, _, _ in missing)),
            tool_calls=proposed_calls,
        )
        gate = self.precommit.validate(proposal, self._basic_gate_context(session))
        if gate.outcome is not GateOutcome.ALLOW:
            return self._route_gate_failure(session, proposal, gate, missing[0][0])
        return PlannedOutbound(
            self.adapter.serialize(gate),
            proposal=proposal,
            decision=gate,
            pending_need_ids=pending_need_ids,
            policy_operations=policy_operations,
        )

    def _materialize_climate_zone_sync_parameters(
        self, session: SessionState, *, climate: Goal, seat: Goal
    ) -> None:
        temperature_read = self._derived_navigation_read_value(
            session,
            goal_id=climate.goal_id,
            tool_name="get_temperature_inside_car",
            arguments={},
            proposition="relative_climate_temperature_snapshot",
        )
        seat_read = self._derived_navigation_read_value(
            session,
            goal_id=seat.goal_id,
            tool_name="get_seat_heating_level",
            arguments={},
            proposition="relative_seat_heating_snapshot",
        )
        if temperature_read is None or seat_read is None:
            return
        temperature_snapshot, temperature_evidence = temperature_read
        seat_snapshot, seat_evidence = seat_read
        source_zone = session.climate_sync_source_zones_by_goal.get(climate.goal_id)
        if (
            source_zone not in {"DRIVER", "PASSENGER"}
            or not isinstance(temperature_snapshot, Mapping)
            or not isinstance(seat_snapshot, Mapping)
        ):
            return
        raw_temperature = temperature_snapshot.get(
            f"climate_temperature_{source_zone.casefold()}"
        )
        raw_level = seat_snapshot.get(f"seat_heating_{source_zone.casefold()}")
        if (
            isinstance(raw_temperature, bool)
            or not isinstance(raw_temperature, (int, float, Decimal))
            or type(raw_level) is not int
            or not 0 <= raw_level <= 3
        ):
            return
        try:
            temperature_decimal = Decimal(str(raw_temperature))
        except InvalidOperation:
            return
        if not temperature_decimal.is_finite():
            return
        temperature: int | float = (
            int(temperature_decimal)
            if temperature_decimal == temperature_decimal.to_integral_value()
            else float(temperature_decimal)
        )
        self._apply_navigation_derived_parameters(
            session,
            goal=climate,
            parameters={
                "temperature": (
                    temperature,
                    (temperature_evidence,),
                    "climate_zone_sync_from_source_v1",
                )
            },
        )
        self._apply_navigation_derived_parameters(
            session,
            goal=seat,
            parameters={
                "level": (
                    raw_level,
                    (seat_evidence,),
                    "seat_heating_zone_sync_from_source_v1",
                )
            },
        )

    def _climate_zone_sync_partial_plan(
        self, session: SessionState, *, climate: Goal, seat: Goal
    ) -> PlannedOutbound | None:
        statuses = {
            goal.goal_id: session.goal_dag.get(goal.goal_id).status
            for goal in (climate, seat)
        }
        completed_goals = [
            goal
            for goal in (climate, seat)
            if statuses[goal.goal_id] is GoalStatus.DONE
        ]
        failed_goals = [
            goal
            for goal in (climate, seat)
            if statuses[goal.goal_id] in {GoalStatus.FAILED, GoalStatus.BLOCKED}
        ]
        if not completed_goals or not failed_goals:
            return None
        seen: set[str] = set()
        completed: list[str] = []
        for goal in completed_goals:
            for call in session.completed_action_calls_by_goal.get(goal.goal_id, ()):
                fingerprint = call_fingerprint(call.tool_name, call.arguments)
                if fingerprint in seen:
                    continue
                seen.add(fingerprint)
                completed.append(self.responses.describe_call(call))
        blocked = failed_goals[0]
        target = str(blocked.desired_outcome.get("seat_zone", "the target")).casefold()
        if blocked.semantic_operation == "set_climate_temperature":
            value = blocked.desired_outcome.get("temperature")
            blocked_goal = (
                f"set the {target} climate temperature to {value} degrees Celsius"
            )
            reason = (
                "the climate temperature control is unavailable in the current controls"
            )
        else:
            value = blocked.desired_outcome.get("level")
            blocked_goal = f"set the {target} seat heating to level {value}"
            reason = "the seat heating control is unavailable in the current controls"
        session.execution_bundle = None
        return self._text_plan(
            session,
            self.responses.partial_completion(
                completed=completed,
                blocked_goal=blocked_goal,
                reason=reason,
                language=self._language(session),
            ),
            goal_ids=(climate.goal_id, seat.goal_id),
        )

    def _climate_zone_sync_action_plan(
        self, session: SessionState, *, climate: Goal, seat: Goal
    ) -> PlannedOutbound:
        specifications = (
            (
                climate,
                "set_climate_temperature",
                {
                    "temperature": climate.desired_outcome.get("temperature"),
                    "seat_zone": climate.desired_outcome.get("seat_zone"),
                },
            ),
            (
                seat,
                "set_seat_heating",
                {
                    "level": seat.desired_outcome.get("level"),
                    "seat_zone": seat.desired_outcome.get("seat_zone"),
                },
            ),
        )
        calls: list[OfficialToolCall] = []
        goal_ids: list[str] = []
        call_goal_ids: list[str] = []
        operations: list[str] = []
        for goal, tool_name, arguments in specifications:
            if session.goal_dag.get(goal.goal_id).status is not GoalStatus.PENDING:
                continue
            if not session.live_tools.has_tool(tool_name):
                session.goal_dag.set_status(
                    goal.goal_id,
                    GoalStatus.FAILED,
                    block_reason=f"{tool_name} is unavailable in the current controls",
                )
                continue
            try:
                validated = session.live_tools.validate_arguments(tool_name, arguments)
            except ToolArgumentValidationError:
                session.goal_dag.set_status(
                    goal.goal_id,
                    GoalStatus.FAILED,
                    block_reason=f"{tool_name} rejected the derived zone setting",
                )
                continue
            call = OfficialToolCall(tool_name=tool_name, arguments=validated)
            calls.append(call)
            goal_ids.append(goal.goal_id)
            call_goal_ids.append(goal.goal_id)
            operations.append(goal.semantic_operation)
        if not calls:
            return self._text_plan(
                session,
                "I couldn't sync either climate setting because the required controls are unavailable.",
                goal_ids=(climate.goal_id, seat.goal_id),
            )
        session.execution_bundle = ExecutionBundle(
            goal_ids=tuple(goal_ids),
            calls=tuple(calls),
            policy_operations=tuple(operations),
            call_goal_ids=tuple(call_goal_ids),
        )
        return self._validate_bundle_step(session, session.execution_bundle)

    def _next_climate_zone_sync_workflow(
        self, session: SessionState
    ) -> PlannedOutbound | None:
        goals = self._climate_zone_sync_goals(session)
        if goals is None:
            return None
        climate, seat = goals
        bundle = session.execution_bundle
        if bundle is not None:
            if not bundle.complete:
                return None
            return self._climate_zone_sync_partial_plan(
                session, climate=climate, seat=seat
            )

        partial = self._climate_zone_sync_partial_plan(
            session, climate=climate, seat=seat
        )
        if partial is not None:
            return partial
        statuses = tuple(
            session.goal_dag.get(goal.goal_id).status for goal in (climate, seat)
        )
        if any(
            status in {GoalStatus.FAILED, GoalStatus.BLOCKED} for status in statuses
        ):
            blocked = next(
                goal
                for goal, status in zip((climate, seat), statuses, strict=True)
                if status in {GoalStatus.FAILED, GoalStatus.BLOCKED}
            )
            return self._limitation_plan(
                session, blocked, GateOutcome.UNSUPPORTED_CAPABILITY
            )
        need_ids = self._climate_zone_sync_need_ids(
            session,
            climate_goal_id=climate.goal_id,
            seat_goal_id=seat.goal_id,
        )
        read = self._next_climate_zone_sync_read(
            session,
            climate=climate,
            seat=seat,
            need_ids=need_ids,
        )
        if read is not None:
            return read
        self._materialize_climate_zone_sync_parameters(
            session, climate=climate, seat=seat
        )
        refreshed = self._climate_zone_sync_goals(session)
        if refreshed is None:
            return self._text_plan(
                session,
                self._safe_unavailable_text().text or "",
                goal_ids=(climate.goal_id, seat.goal_id),
            )
        climate, seat = refreshed
        if set(climate.desired_outcome) != {"temperature", "seat_zone"} or set(
            seat.desired_outcome
        ) != {"level", "seat_zone"}:
            return self._text_plan(
                session,
                "I couldn't validate both source-zone settings, so I did not change either zone.",
                goal_ids=(climate.goal_id, seat.goal_id),
            )
        return self._climate_zone_sync_action_plan(session, climate=climate, seat=seat)

    def _handle_driver_warming_followup(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        goals = self._driver_warming_goal_triplet(session)
        if goals is None:
            return False, None
        climate, seat, steering = goals
        try:
            statuses = tuple(
                session.goal_dag.get(goal.goal_id).status for goal in goals
            )
        except KeyError:
            return False, None
        if statuses != (
            GoalStatus.DONE,
            GoalStatus.PENDING,
            GoalStatus.PENDING,
        ) or any(
            call.tool_name in {"set_seat_heating", "set_steering_wheel_heating"}
            for goal_id in (seat.goal_id, steering.goal_id)
            for call in session.completed_action_calls_by_goal.get(goal_id, ())
        ):
            return False, None
        if not any(
            call.tool_name == "set_climate_temperature"
            and call.arguments == {"temperature": 24, "seat_zone": "DRIVER"}
            for call in session.completed_action_calls_by_goal.get(climate.goal_id, ())
        ):
            return False, None

        recovery_text = text
        if _DRIVER_WARMING_CONTEXT_LEVEL_REPLY_PATTERN.fullmatch(text) is not None:
            recovery_text = _DRIVER_WARMING_CANONICAL_SHARED_LEVEL_REPLY
        recovered = recover_driver_warming_intent(
            recovery_text,
            session.intent,
            turn_id=turn_id,
        )
        if recovered is session.intent:
            return False, None
        if tuple(
            goal.semantic_operation for goal in recovered.goals
        ) != _DRIVER_WARMING_OPERATIONS[1:] or tuple(
            goal.goal_id for goal in recovered.goals
        ) != (seat.goal_id, steering.goal_id):
            return False, None
        grounding = ground_intent(recovery_text, recovered, self.recipes)
        if len(grounding.filtered_intent.goals) != 2:
            return False, None
        recovered_seat, recovered_steering = grounding.filtered_intent.goals
        if (
            grounding.authorized_action_goal_ids
            != frozenset({seat.goal_id, steering.goal_id})
            or recovered_seat.desired_outcome
            not in ({"level": 2}, {"level": 2, "seat_zone": "DRIVER"})
            or recovered_steering.desired_outcome != {"level": 2}
            or recovered_steering.depends_on != [seat.goal_id]
        ):
            return False, None
        steering_derivations = grounding.derived_values_by_goal.get(
            steering.goal_id, {}
        )
        if steering_derivations not in (
            {},
            {"level": "steering_level_matches_seat_heating_v1"},
        ):
            return False, None

        climate_sources = dict(
            session.grounded_value_sources_by_goal.get(climate.goal_id, {})
        )
        seat_sources = dict(
            session.grounded_value_sources_by_goal.get(seat.goal_id, {})
        )
        if not self._valid_user_value_sources(
            session,
            climate_sources,
            required=("temperature", "seat_zone"),
        ) or not self._valid_user_value_sources(
            session,
            seat_sources,
            required=("seat_zone",),
        ):
            return False, None

        merged_seat = {"seat_zone": "DRIVER", "level": 2}
        merged_goals = [
            climate.model_copy(update={"depends_on": []}, deep=True),
            recovered_seat.model_copy(
                update={
                    "desired_outcome": merged_seat,
                    "depends_on": [climate.goal_id],
                },
                deep=True,
            ),
            recovered_steering.model_copy(
                update={"depends_on": [seat.goal_id]}, deep=True
            ),
        ]
        session.intent = session.intent.model_copy(
            update={
                "call_for_action": True,
                "goals": merged_goals,
                "explicit_slots": {
                    "temperature": 24,
                    "seat_zone": "DRIVER",
                    "level": 2,
                },
                "explicit_constraints": {},
                "explicit_confirmations": [],
                "unresolved_slots": [],
                "intent_source_turn_ids": list(
                    dict.fromkeys([*session.intent.intent_source_turn_ids, turn_id])
                ),
                "goal_mention_order": [goal.goal_id for goal in merged_goals],
                "intent_kind": IntentKind.ACTION,
            },
            deep=True,
        )
        session.authorized_action_goal_ids.update({seat.goal_id, steering.goal_id})
        session.grounded_desired_values_by_goal = {
            climate.goal_id: {
                "temperature": 24,
                "seat_zone": "DRIVER",
            },
            seat.goal_id: dict(merged_seat),
            steering.goal_id: {"level": 2},
        }
        session.grounded_value_sources_by_goal = {
            climate.goal_id: climate_sources,
            seat.goal_id: {**seat_sources, "level": turn_id},
            steering.goal_id: ({"level": turn_id} if not steering_derivations else {}),
        }
        session.derived_value_evidence_by_goal = {}
        if steering_derivations:
            self._record_driver_warming_match_derivation(
                session,
                seat_goal_id=seat.goal_id,
                steering_goal_id=steering.goal_id,
                source_turn_id=turn_id,
            )
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True, None

    @staticmethod
    def _valid_user_value_sources(
        session: SessionState,
        sources: Mapping[str, str],
        *,
        required: tuple[str, ...],
    ) -> bool:
        if any(not isinstance(sources.get(name), str) for name in required):
            return False
        turn_ids = {sources[name] for name in required}
        return all(
            any(
                message.get("role") == "user"
                and message.get("turn_id") == source_turn_id
                and isinstance(message.get("content"), str)
                for message in session.conversation
            )
            for source_turn_id in turn_ids
        )

    @staticmethod
    def _record_driver_warming_match_derivation(
        session: SessionState,
        *,
        seat_goal_id: str,
        steering_goal_id: str,
        source_turn_id: str,
    ) -> None:
        seat_level = Evidence(
            proposition=f"grounded_argument:{seat_goal_id}:level",
            value=2,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.USER,
            source_turn_id=source_turn_id,
            confidence=1.0,
        )
        session.evidence.add(seat_level)
        stored_seat_level = session.evidence.for_proposition(seat_level.proposition)[-1]
        assert stored_seat_level.evidence_id is not None
        steering_level = Evidence(
            proposition=f"derived_argument:{steering_goal_id}:level",
            value=2,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=source_turn_id,
            confidence=1.0,
            derived_from=[stored_seat_level.evidence_id],
            derivation="steering_level_matches_seat_heating_v1",
        )
        session.evidence.add(steering_level)
        stored_steering_level = session.evidence.for_proposition(
            steering_level.proposition
        )[-1]
        assert stored_steering_level.evidence_id is not None
        session.derived_value_evidence_by_goal[steering_goal_id] = {
            "level": stored_steering_level.evidence_id
        }

    @staticmethod
    def _driver_warming_goal_triplet(
        session: SessionState,
    ) -> tuple[Goal, Goal, Goal] | None:
        if (
            not isinstance(session.intent, IntentFrame)
            or len(session.intent.goals) != 3
        ):
            return None
        climate, seat, steering = session.intent.goals
        if (
            tuple(goal.semantic_operation for goal in session.intent.goals)
            != _DRIVER_WARMING_OPERATIONS
            or climate.desired_outcome != {"temperature": 24, "seat_zone": "DRIVER"}
            or seat.desired_outcome
            not in (
                {"seat_zone": "DRIVER"},
                {"seat_zone": "DRIVER", "level": 2},
            )
            or steering.desired_outcome not in ({}, {"level": 2})
            or climate.depends_on
            or seat.depends_on != [climate.goal_id]
            or steering.depends_on != [seat.goal_id]
            or session.intent.goal_mention_order
            != [climate.goal_id, seat.goal_id, steering.goal_id]
        ):
            return None
        return climate, seat, steering

    def _next_driver_warming_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        goals = self._driver_warming_goal_triplet(session)
        if goals is None:
            return None
        climate, seat, steering = goals
        try:
            climate_status = session.goal_dag.get(climate.goal_id).status
            seat_status = session.goal_dag.get(seat.goal_id).status
            steering_status = session.goal_dag.get(steering.goal_id).status
        except KeyError:
            return None
        if any(
            status in {GoalStatus.FAILED, GoalStatus.BLOCKED}
            for status in (climate_status, seat_status, steering_status)
        ):
            return None

        heating_is_unresolved = (
            seat.desired_outcome == {"seat_zone": "DRIVER"}
            and steering.desired_outcome == {}
        )
        if heating_is_unresolved:
            if climate_status is GoalStatus.PENDING:
                return self._driver_warming_action_plan(
                    session,
                    prepared,
                    goal=climate,
                    expected=OfficialToolCall(
                        tool_name="set_climate_temperature",
                        arguments={"temperature": 24, "seat_zone": "DRIVER"},
                    ),
                )
            if (
                climate_status is GoalStatus.DONE
                and seat_status is GoalStatus.PENDING
                and steering_status is GoalStatus.PENDING
            ):
                completion = self._temperature_zone_difference_completion(
                    session,
                    (climate.goal_id,),
                    "I set the driver's temperature to 24 degrees Celsius.",
                )
                return self._text_plan(
                    session,
                    f"{completion} What level would you like for both the driver's "
                    "seat heating and steering wheel heating?",
                    goal_ids=(seat.goal_id, steering.goal_id),
                    kind=ProposalKind.ASK_USER,
                )
            return None

        heating_is_resolved = seat.desired_outcome == {
            "seat_zone": "DRIVER",
            "level": 2,
        } and steering.desired_outcome == {"level": 2}
        if not heating_is_resolved or climate_status is not GoalStatus.DONE:
            return None
        if seat_status is GoalStatus.PENDING:
            if not session.live_tools.has_tool("set_seat_heating"):
                self._fail_goals(
                    session,
                    (seat.goal_id,),
                    "driver seat heating is unavailable in the current controls",
                )
                return self._text_plan(
                    session,
                    "I set the driver's temperature to 24 degrees, but the "
                    "driver's seat heating and steering wheel heating are "
                    "unavailable in the current controls.",
                    goal_ids=(climate.goal_id, seat.goal_id, steering.goal_id),
                )
            evidence_read = self._next_recipe_evidence_read(session, prepared)
            if evidence_read is not None:
                return evidence_read
            return self._driver_warming_action_plan(
                session,
                prepared,
                goal=seat,
                expected=OfficialToolCall(
                    tool_name="set_seat_heating",
                    arguments={"level": 2, "seat_zone": "DRIVER"},
                ),
            )
        if (
            seat_status is not GoalStatus.DONE
            or steering_status is not GoalStatus.PENDING
        ):
            return None
        if not session.live_tools.has_tool("set_steering_wheel_heating"):
            session.goal_dag.set_status(
                steering.goal_id,
                GoalStatus.FAILED,
                block_reason=(
                    "steering wheel heating is unavailable in the current controls"
                ),
            )
            return self._text_plan(
                session,
                "I set the driver's temperature to 24 degrees and completed the "
                "driver's seat heating at level 2. Steering wheel heating is "
                "unavailable in the current controls.",
                goal_ids=(climate.goal_id, seat.goal_id, steering.goal_id),
            )
        return self._driver_warming_action_plan(
            session,
            prepared,
            goal=steering,
            expected=OfficialToolCall(
                tool_name="set_steering_wheel_heating",
                arguments={"level": 2},
            ),
        )

    def _driver_warming_action_plan(
        self,
        session: SessionState,
        prepared: PreparedTurn,
        *,
        goal: Goal,
        expected: OfficialToolCall,
    ) -> PlannedOutbound:
        item = prepared.by_goal_id.get(goal.goal_id)
        target = self._unique_bound_target(item) if item is not None else None
        if target is None or target[1] != expected:
            return self._limitation_plan(
                session,
                goal,
                (
                    GateOutcome.UNSUPPORTED_CAPABILITY
                    if not session.live_tools.has_tool(expected.tool_name)
                    else GateOutcome.UNSUPPORTED_PARAMETER
                ),
            )
        proposal = DecisionProposal(
            kind=ProposalKind.TOOL_SET,
            goal_ids=[goal.goal_id],
            tool_calls=[
                ProposedToolCall(
                    tool_name=expected.tool_name,
                    arguments=expected.arguments,
                    goal_id=goal.goal_id,
                )
            ],
        )
        assert item is not None
        built = self._freeze_execution_bundle(session, prepared, proposal)
        if built is not None:
            return built
        assert session.execution_bundle is not None
        return self._validate_bundle_step(session, session.execution_bundle)

    def _strict_warming_command_supersedes_clarification(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[str, IntentFrame, str] | None:
        """Re-enter one exact multi-control clarification without guessing values."""

        complete_current_command = (
            _STRICT_COMPLETE_WARMING_PATTERN.fullmatch(text) is not None
        )
        if (
            (
                not complete_current_command
                and _STRICT_WARMING_CLARIFICATION_PATTERN.fullmatch(text) is None
            )
            or len(session.pending_clarifications) != 1
            or not isinstance(session.intent, IntentFrame)
        ):
            return None

        request = next(iter(session.pending_clarifications.values()))
        source_turn_id: str | None
        if complete_current_command:
            pending_goal = next(
                (
                    goal
                    for goal in session.intent.goals
                    if goal.goal_id == request.goal_id
                ),
                None,
            )
            if pending_goal is None or pending_goal.semantic_operation not in {
                "set_climate_temperature",
                "set_seat_heating",
                "set_steering_wheel_heating",
            }:
                return None
            source_turn_id = turn_id
        else:
            climate_goals = [
                goal
                for goal in session.intent.goals
                if goal.semantic_operation == "set_climate_temperature"
            ]
            if len(climate_goals) != 1:
                return None
            climate_goal = climate_goals[0]
            if (
                request.goal_id != climate_goal.goal_id
                or canonical_semantic_parameter_name(
                    climate_goal.semantic_operation, request.slot_name
                )
                != "seat_zone"
            ):
                return None

            grounded = session.grounded_desired_values_by_goal.get(
                climate_goal.goal_id, {}
            )
            temperature = grounded.get("temperature")
            if isinstance(temperature, bool):
                return None
            try:
                if Decimal(str(temperature)) != Decimal("22"):
                    return None
            except (InvalidOperation, TypeError, ValueError):
                return None
            source_turn_id = session.grounded_value_sources_by_goal.get(
                climate_goal.goal_id, {}
            ).get("temperature")
            if not isinstance(source_turn_id, str) or not any(
                message.get("role") == "user"
                and message.get("turn_id") == source_turn_id
                and isinstance(message.get("content"), str)
                for message in session.conversation
            ):
                return None

        canonical_text = (
            "Set the climate temperature to 22 degrees for all zones. "
            "Increase the seat heating by two levels for occupied seats. "
            "Turn on the steering wheel heating to level 2."
        )
        digest = hashlib.sha256(
            f"{turn_id}\0strict-warming-clarification\0{text}".encode()
        ).hexdigest()
        climate_goal_id = f"goal-climate-warming-{digest[:12]}"
        steering_goal_id = f"goal-steering-warming-{digest[12:24]}"
        intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[
                Goal(
                    goal_id=climate_goal_id,
                    semantic_operation="set_climate_temperature",
                    desired_outcome={
                        "temperature": 22,
                        "seat_zone": "ALL_ZONES",
                    },
                ),
                Goal(
                    goal_id=steering_goal_id,
                    semantic_operation="set_steering_wheel_heating",
                    desired_outcome={"level": 2},
                ),
            ],
            explicit_slots={
                "temperature": 22,
                "seat_zone": "ALL_ZONES",
                "level": 2,
            },
            intent_source_turn_ids=list(dict.fromkeys((source_turn_id, turn_id))),
            goal_mention_order=[climate_goal_id, steering_goal_id],
            intent_kind=IntentKind.ACTION,
        )
        recovered = recover_relative_occupied_seat_heating_intent(
            canonical_text, intent, turn_id=turn_id
        )
        return canonical_text, recovered, source_turn_id

    def _strict_relative_seat_command_supersedes_clarification(
        self, session: SessionState, text: str, turn_id: str
    ) -> bool:
        """Let one complete relative seat command replace its stale slot prompt."""

        if not session.pending_clarifications or not isinstance(
            session.intent, IntentFrame
        ):
            return False
        pending_seat_slot = False
        goals_by_id = {goal.goal_id: goal for goal in session.intent.goals}
        for request in session.pending_clarifications.values():
            goal = goals_by_id.get(request.goal_id)
            if (
                goal is not None
                and goal.semantic_operation == "set_seat_heating"
                and request.slot_name in {"level", "seat_zone"}
            ):
                pending_seat_slot = True
                break
        if not pending_seat_slot:
            return False
        probe = IntentFrame(
            language=self._language(session),
            call_for_action=False,
            goals=[],
            intent_source_turn_ids=[turn_id],
            intent_kind=IntentKind.CONVERSATION,
        )
        recovered = recover_relative_occupied_seat_heating_intent(
            text, probe, turn_id=turn_id
        )
        return (
            recovered is not probe
            and recovered.call_for_action
            and recovered.intent_kind is IntentKind.ACTION
            and len(recovered.goals) == 1
            and recovered.goals[0].semantic_operation == "set_seat_heating"
            and recovered.goals[0].desired_outcome == {}
        )

    def _resolve_pending_clarification(
        self, session: SessionState, text: str, turn_id: str
    ) -> PlannedOutbound | None:
        if not session.pending_clarifications:
            return None
        request = next(iter(session.pending_clarifications.values()))
        normalized = " ".join(text.casefold().split())
        semantic_operation = None
        if isinstance(session.intent, IntentFrame) and request.goal_id:
            semantic_operation = next(
                (
                    goal.semantic_operation
                    for goal in session.intent.goals
                    if goal.goal_id == request.goal_id
                ),
                None,
            )
        if (
            request.slot_name == "route_choice_alias"
            and request.goal_id is not None
            and _requests_route_alternative_details(text)
        ):
            details = self._route_alternative_detail_plan(
                session, goal_id=request.goal_id
            )
            if details is not None:
                return details
        if request.slot_name == "route_choice_alias":
            matches = self._destination_route_clarification_matches(
                session,
                request=request,
                text=text,
            )
        else:
            exact_matches = [
                option
                for option in request.options
                if (
                    _is_safe_clarification_context(text)
                    and (
                        _argument_identifier(normalized)
                        == _argument_identifier(option.label)
                        or _is_polite_exact_choice(
                            text, request.slot_name, option.label
                        )
                    )
                )
                or _is_operation_scoped_clarification_choice(
                    text,
                    semantic_operation=semantic_operation,
                    slot_name=request.slot_name,
                    option=option.label,
                )
            ]
            if not exact_matches:
                qualitative_label = _qualitative_level_clarification_label(
                    text,
                    semantic_operation=semantic_operation,
                    slot_name=request.slot_name,
                    option_labels=[option.label for option in request.options],
                )
                if qualitative_label is not None:
                    exact_matches = [
                        option
                        for option in request.options
                        if _argument_identifier(option.label)
                        == _argument_identifier(qualitative_label)
                    ]
            matches = exact_matches
            strict_temperature_zone = (
                semantic_operation == "set_climate_temperature"
                and _argument_identifier(request.slot_name) == "seat_zone"
                and (
                    re.search(r"\d", text) is not None
                    or re.search(
                        r"\b(?:ac|air\s+conditioning|email|fan|navigation|seat|"
                        r"steering|sunroof|sunshade|window)\b",
                        text,
                        re.IGNORECASE,
                    )
                    is not None
                )
            )
            if not matches and not strict_temperature_zone:
                mentioned = [
                    option
                    for option in request.options
                    if _contains_option_phrase(text, option.label)
                ]
                matches = (
                    mentioned
                    if len(mentioned) > 1
                    else [
                        option
                        for option in request.options
                        if _contains_assertive_option_phrase(text, option.label)
                    ]
                )
        if len(matches) != 1:
            return self._text_plan(
                session,
                self.responses.clarification(
                    goal=self.responses.humanize(request.slot_name),
                    options=[option.label for option in request.options],
                    language=self._language(session),
                ),
                goal_ids=([request.goal_id] if request.goal_id else ()),
            )

        assert isinstance(session.intent, IntentFrame)
        slots = list(session.intent.unresolved_slots)
        target = next(
            (
                slot
                for slot in slots
                if slot.name == request.slot_name and slot.goal_id == request.goal_id
            ),
            None,
        )
        if target is None:
            session.pending_clarifications.clear()
            return self._text_plan(
                session,
                self.responses.gate_limitation(
                    goal=request.slot_name,
                    outcome=GateOutcome.INVALID_PROPOSAL,
                    language=self._language(session),
                ),
            )
        resolved = self.disambiguation.resolve(
            target,
            clarification=ClarificationAnswer(
                request_id=request.request_id,
                slot_name=request.slot_name,
                candidate_id=matches[0].candidate_id,
                source_turn_id=turn_id,
            ),
        ).slot
        slots = [
            resolved
            if slot.name == resolved.name and slot.goal_id == resolved.goal_id
            else slot
            for slot in slots
        ]
        resolved_value = resolved.chosen.value if resolved.chosen is not None else None
        resolved_goal_before = next(
            (goal for goal in session.intent.goals if goal.goal_id == resolved.goal_id),
            None,
        )
        explicit_route_alias = _explicit_route_alias_reply(text)
        if (
            resolved_goal_before is not None
            and resolved_goal_before.desired_outcome.get(
                _CONDITIONAL_ARRIVAL_WEATHER_NAVIGATION_MARKER
            )
            is True
            and resolved.name == "route_choice_alias"
            and explicit_route_alias is not None
        ):
            resolved_value = explicit_route_alias
        goals = [goal.model_copy(deep=True) for goal in session.intent.goals]
        if resolved.goal_id and resolved.chosen is not None:
            goals = [
                goal.model_copy(
                    update={
                        "desired_outcome": {
                            **goal.desired_outcome,
                            resolved.name: resolved_value,
                        }
                    }
                )
                if goal.goal_id == resolved.goal_id
                else goal
                for goal in goals
            ]
        session.intent = session.intent.model_copy(
            update={"goals": goals, "unresolved_slots": slots}, deep=True
        )
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        if resolved.goal_id and resolved.chosen is not None:
            grounded = dict(
                session.grounded_desired_values_by_goal.get(resolved.goal_id, {})
            )
            grounded[resolved.name] = resolved_value
            session.grounded_desired_values_by_goal[resolved.goal_id] = grounded
            sources = dict(
                session.grounded_value_sources_by_goal.get(resolved.goal_id, {})
            )
            sources[resolved.name] = turn_id
            session.grounded_value_sources_by_goal[resolved.goal_id] = sources
            resolved_goal = next(
                goal
                for goal in session.intent.goals
                if goal.goal_id == resolved.goal_id
            )
            if (
                resolved_goal.semantic_operation == "set_ambient_lights"
                and resolved.name == "color"
                and resolved_goal.desired_outcome.get("enabled") is True
                and "enabled" not in sources
            ):
                self._record_ambient_enabled_derivation(
                    session,
                    goal_id=resolved.goal_id,
                    color=resolved.chosen.value,
                    source_turn_id=turn_id,
                )
        session.pending_clarifications.clear()
        return None

    def _process_tool_results(
        self, session: SessionState, event: InboundEvent
    ) -> ResultIssue | None:
        pending_for_task = [
            call for call in session.pending_calls if call.task_id == event.task_id
        ]
        if not pending_for_task:
            source_turn_id = event.message_id or f"result-turn-{session.budget.steps}"
            session.last_tool_results = list(event.tool_results)
            session.append(
                "environment", list(event.tool_results), turn_id=source_turn_id
            )
            return ResultIssue(
                GateOutcome.INVALID_PROPOSAL,
                (),
                "the tool result belongs to no pending action in this task",
            )
        seen_result_ids = session.seen_result_ids_by_task.setdefault(
            event.task_id, set()
        )
        external_call_ids = session.external_call_ids_by_task.setdefault(
            event.task_id, {}
        )
        matched = match_tool_results(
            list(event.tool_results),
            pending_for_task,
            seen_result_ids=seen_result_ids,
            external_call_ids=external_call_ids,
        )
        source_turn_id = event.message_id or f"result-turn-{session.budget.steps}"
        session.last_tool_results = list(event.tool_results)
        session.append("environment", list(event.tool_results), turn_id=source_turn_id)
        consumed: set[str] = set()
        issue: ResultIssue | None = None

        for result in matched:
            pending = result.pending_call
            if not result.is_actionable or pending is None:
                if not result.duplicate:
                    pending_set = next(
                        (call for call in pending_for_task if call.state_changing),
                        None,
                    )
                    if pending_set is not None:
                        goal_ids = self._abort_execution_bundle(
                            session,
                            reason=(
                                "the state-changing result could not be matched "
                                "to its frozen action"
                            ),
                            source_turn_id=source_turn_id,
                            state_may_have_changed=True,
                        )
                        issue = ResultIssue(
                            GateOutcome.UNAVAILABLE_EVIDENCE,
                            goal_ids or pending_set.goal_ids,
                            "the requested state change could not be verified",
                        )
                        break
                    issue = ResultIssue(
                        GateOutcome.INVALID_PROPOSAL,
                        (),
                        "the tool result could not be matched to a pending action",
                    )
                continue
            consumed.add(pending.call_id)
            validation = self.result_validator.validate(
                result,
                evidence_store=session.evidence,
                source_turn_id=source_turn_id,
            )
            if pending.state_changing:
                completion_arguments = dict(pending.arguments)
                if pending.tool_name in {
                    "navigation_add_one_waypoint",
                    "navigation_delete_waypoint",
                    "navigation_replace_final_destination",
                    "navigation_replace_one_waypoint",
                } and len(pending.goal_ids) == 1:
                    try:
                        completion_goal = session.goal_dag.get(pending.goal_ids[0])
                    except KeyError:
                        completion_goal = None
                    if completion_goal is not None:
                        expected_waypoints = completion_goal.desired_outcome.get(
                            "expected_post_waypoint_ids"
                        )
                        expected_routes = completion_goal.desired_outcome.get(
                            "expected_post_route_ids"
                        )
                        if isinstance(expected_waypoints, list) and isinstance(
                            expected_routes, list
                        ):
                            completion_arguments.update(
                                expected_post_waypoint_ids=expected_waypoints,
                                expected_post_route_ids=expected_routes,
                            )
                completion = self.completion_validator.validate(
                    tool_name=pending.tool_name,
                    arguments=completion_arguments,
                    raw_result=result.content,
                )
                if completion.status is not SetCompletionStatus.SUCCESS:
                    bundle = session.execution_bundle
                    if (
                        pending.tool_name == "set_reading_light"
                        and completion.status is SetCompletionStatus.UNVERIFIABLE
                        and completion.reason
                        == "result_does_not_report_target_arguments:on"
                        and self._result_is_success(result.content)
                        and session.live_tools.has_tool("get_reading_lights_status")
                        and bundle is not None
                        and pending.bundle_index == bundle.next_index
                        and session.pending_set_readback is None
                    ):
                        session.pending_set_readback = PendingSetReadback(
                            pending_call=pending,
                            expected_state_version=(
                                session.evidence.current_state_version
                            ),
                        )
                        session.budget.reset_get_count("get_reading_lights_status", {})
                        continue
                    goal_ids = self._abort_execution_bundle(
                        session,
                        reason="the requested state change could not be verified",
                        source_turn_id=source_turn_id,
                        state_may_have_changed=True,
                    )
                    issue = ResultIssue(
                        GateOutcome.UNAVAILABLE_EVIDENCE,
                        goal_ids or pending.goal_ids,
                        "the requested state change could not be verified",
                    )
                    continue
                session.budget.record_success(
                    pending.tool_name,
                    pending.arguments,
                    state_changing=True,
                )
                self._record_policy_completion(session, pending)
                bundle = session.execution_bundle
                if bundle is not None and pending.bundle_index == bundle.next_index:
                    bundle.advance()
                    if bundle.complete:
                        meeting_charging_analysis = (
                            self._meeting_charging_navigation_bundle_analysis(
                                session,
                                bundle,
                                completion_value=self._successful_result_value(
                                    result.content
                                ),
                            )
                        )
                        if bundle.confirmation_id is not None:
                            session.confirmation_latch.consume_authorization(
                                goal_ids=list(bundle.goal_ids),
                                ordered_actions=list(bundle.calls),
                                current_user_turn=session.budget.user_turns,
                            )
                        for goal_id in bundle.goal_ids:
                            session.completed_action_calls_by_goal[goal_id] = (
                                bundle.calls
                            )
                            session.completed_action_operations_by_goal[goal_id] = (
                                bundle.policy_operations
                            )
                        session.evidence.invalidate_tool_state()
                        for goal_id in bundle.goal_ids:
                            session.goal_dag.set_status(goal_id, GoalStatus.DONE)
                        if meeting_charging_analysis is not None:
                            self._record_meeting_charging_navigation_completion(
                                session,
                                goal_id=bundle.goal_ids[0],
                                analysis=meeting_charging_analysis,
                                source_turn_id=source_turn_id,
                            )
                else:
                    goal_ids = self._abort_execution_bundle(
                        session,
                        reason="the state-changing result arrived out of bundle order",
                        source_turn_id=source_turn_id,
                        state_may_have_changed=True,
                    )
                    issue = ResultIssue(
                        GateOutcome.INVALID_PROPOSAL,
                        goal_ids or pending.goal_ids,
                        "the requested state change could not be verified in order",
                    )
                continue

            if self._result_is_success(result.content):
                self._record_policy_completion(session, pending)
                value = self._successful_result_value(result.content)
                if value is not None:
                    session.successful_read_results.append(
                        SuccessfulReadResult(
                            goal_ids=pending.goal_ids,
                            tool_name=pending.tool_name,
                            arguments=dict(pending.arguments),
                            semantic_operation=pending.policy_operation,
                            call_id=result.provided_call_id or pending.call_id,
                            value=value,
                            source_turn_id=source_turn_id,
                            state_version=session.evidence.current_state_version,
                            task_id=pending.task_id,
                        )
                    )
                    session.successful_read_results = session.successful_read_results[
                        -128:
                    ]
            if validation.insufficient_need_ids:
                if pending.policy_operation == "read_user_preferences":
                    # A missing preference is not a failed user action. Keep the
                    # unsatisfied need as the record that the lookup was attempted;
                    # live-parameter clarification can then collect an explicit
                    # value instead of retrying the read or terminating the turn.
                    continue
                if (
                    pending.tool_name == "get_reading_lights_status"
                    and session.pending_set_readback is not None
                ):
                    self._abort_execution_bundle(
                        session,
                        reason="the reading-light state could not be verified",
                        source_turn_id=source_turn_id,
                        state_may_have_changed=True,
                    )
                issue = ResultIssue(
                    GateOutcome.UNAVAILABLE_EVIDENCE,
                    pending.goal_ids,
                    "I couldn't verify the required current information",
                    source_tool_name=pending.tool_name,
                    validation_issues=validation.issues,
                )

        session.pending_calls = [
            call for call in session.pending_calls if call.call_id not in consumed
        ]
        return issue

    def _record_policy_completion(
        self, session: SessionState, pending: PendingToolCall
    ) -> None:
        operation = pending.policy_operation
        if operation is None or not pending.goal_ids:
            return
        call = OfficialToolCall(
            tool_name=pending.tool_name, arguments=pending.arguments
        )
        bundle_goal_ids = pending.goal_ids
        bundle = session.execution_bundle
        if pending.bundle_index is not None and bundle is not None:
            bundle_goal_ids = bundle.goal_ids
        key = policy_operation_completion_key(
            operation,
            call,
            evidence_state_version=session.evidence.current_state_version,
            bundle_goal_ids=bundle_goal_ids,
        )
        session.completed_policy_operations.add(key)

    def _plan_next(self, session: SessionState) -> PlannedOutbound:
        if session.live_tools is None or session.compiled_policy is None:
            return self._text_plan(
                session,
                "I don't have the current controls and safety policy, so I did not perform an action.",
            )
        if session.pending_calls:
            return self._text_plan(
                session,
                "I am still waiting for the current control result, so I did not start another action.",
            )
        reading_light_readback = self._next_reading_light_readback(session)
        if reading_light_readback is not None:
            return reading_light_readback

        broad_headlights = self._next_broad_headlights_workflow(session)
        if broad_headlights is not None:
            return broad_headlights

        current_weather_fog_lights = (
            self._next_current_weather_fog_lights_workflow(session)
        )
        if current_weather_fog_lights is not None:
            return current_weather_fog_lights

        materialize_recipe_derivations(
            session.evidence,
            source_turn_id=f"derived-step-{session.budget.steps}",
        )
        self._ensure_contextual_slot_needs(session)
        self._materialize_contextual_slot_parameters(session)
        self._ensure_relative_fan_speed_needs(session)
        self._materialize_relative_fan_speed_goal_parameter(session)
        self._ensure_relative_climate_temperature_needs(session)
        self._materialize_relative_climate_temperature_goal_parameter(session)
        self._ensure_relative_seat_heating_needs(session)
        self._materialize_relative_seat_heating_goal_parameters(session)
        self._materialize_navigation_edit_goal_parameters(session)
        self._materialize_system_goal_parameters(session)
        climate_temperature_zone_sync = (
            self._next_climate_temperature_zone_sync_workflow(session)
        )
        if climate_temperature_zone_sync is not None:
            return climate_temperature_zone_sync
        self._materialize_preference_goal_parameters(session)
        self._materialize_sunshade_match_goal_parameter(session)
        climate_zone_sync = self._next_climate_zone_sync_workflow(session)
        if climate_zone_sync is not None:
            return climate_zone_sync
        bundle = session.execution_bundle
        if bundle is not None:
            if bundle.complete:
                session.execution_bundle = None
                meeting_navigation = (
                    self._validated_meeting_charging_navigation_completion(session)
                )
                if (
                    meeting_navigation is not None
                    and meeting_navigation[1].get("navigation_goal_id")
                    in bundle.goal_ids
                ):
                    values = meeting_navigation[1]
                    return self._text_plan(
                        session,
                        "I set navigation first to "
                        f"{values['charging_station_name']} and then to "
                        f"{values['meeting_location_name']} using the fastest routes.",
                        goal_ids=bundle.goal_ids,
                        kind=ProposalKind.COMPLETE,
                    )
                if session.goal_dag.ready_goals:
                    return self._plan_next(session)
                completed_ids = tuple(
                    goal.goal_id
                    for goal in session.goal_dag.goals
                    if goal.status is GoalStatus.DONE
                )
                return self._text_plan(
                    session,
                    self._completion_text(session, completed_ids),
                    goal_ids=completed_ids,
                    kind=ProposalKind.COMPLETE,
                )
            return self._validate_bundle_step(session, bundle)

        if session.intent is None:
            return self._text_plan(
                session, "How can I help with the car?", kind=ProposalKind.RESPOND
            )
        prepared = self._prepare_turn(session)
        target_schema_limitation = self._early_target_schema_limitation(
            session, prepared
        )
        if target_schema_limitation is not None:
            return target_schema_limitation
        if not prepared.goals:
            failed = tuple(
                goal.goal_id
                for goal in session.goal_dag.goals
                if goal.status in {GoalStatus.FAILED, GoalStatus.BLOCKED}
            )
            if failed:
                return self._text_plan(
                    session,
                    self.responses.limitation(
                        goal=self._goal_label(session, failed),
                        reason="the requested state change could not be verified",
                        outcome=GateOutcome.UNAVAILABLE_EVIDENCE,
                        language=self._language(session),
                    ),
                    goal_ids=failed,
                )
            completed = tuple(
                goal.goal_id
                for goal in session.goal_dag.goals
                if goal.status is GoalStatus.DONE
            )
            if completed and len(completed) == len(session.goal_dag.goals):
                return self._text_plan(
                    session,
                    self._completion_text(session, completed),
                    goal_ids=completed,
                    kind=ProposalKind.COMPLETE,
                )
            return self._text_plan(
                session,
                "I don't have a pending action to perform.",
            )

        preference_read = self._next_preference_read(session, prepared)
        if preference_read is not None:
            return preference_read
        contextual_read = self._next_sunshade_match_read(session, prepared)
        if contextual_read is not None:
            return contextual_read
        relative_fan_read = self._next_relative_fan_speed_read(session, prepared)
        if relative_fan_read is not None:
            return relative_fan_read
        relative_temperature_read = self._next_relative_climate_temperature_read(
            session, prepared
        )
        if relative_temperature_read is not None:
            return relative_temperature_read
        relative_seat_heating_read = self._next_relative_seat_heating_read(
            session, prepared
        )
        if relative_seat_heating_read is not None:
            return relative_seat_heating_read
        seat_occupancy_info = self._next_seat_occupancy_information_workflow(
            session, prepared
        )
        if seat_occupancy_info is not None:
            return seat_occupancy_info
        climate_info = self._next_climate_settings_info_workflow(session, prepared)
        if climate_info is not None:
            return climate_info
        charging_info = self._next_comprehensive_charging_info_workflow(
            session, prepared
        )
        if charging_info is not None:
            return charging_info
        soc_to_empty = self._next_soc_to_empty_workflow(session, prepared)
        if soc_to_empty is not None:
            return soc_to_empty
        ambient_car_color = self._next_ambient_car_color_workflow(session, prepared)
        if ambient_car_color is not None:
            return ambient_car_color
        reading_lights = self._next_reading_lights_workflow(session, prepared)
        if reading_lights is not None:
            return reading_lights
        current_day_meeting = self._next_current_day_meeting_workflow(
            session, prepared
        )
        if current_day_meeting is not None:
            return current_day_meeting
        contact_workflow = self._next_contact_workflow(session, prepared)
        if contact_workflow is not None:
            return contact_workflow
        local_trip_email = self._next_local_trip_email_workflow(session, prepared)
        if local_trip_email is not None:
            return local_trip_email
        trip_email = self._next_trip_email_workflow(session, prepared)
        if trip_email is not None:
            return trip_email
        meeting_charging = self._next_meeting_charging_workflow(session, prepared)
        if meeting_charging is not None:
            return meeting_charging
        active_route_charging = self._next_active_route_charging_workflow(
            session, prepared
        )
        if active_route_charging is not None:
            return active_route_charging
        local_charging_search = self._next_local_charging_search_workflow(
            session, prepared
        )
        if local_charging_search is not None:
            return local_charging_search
        local_charging_estimate = self._next_local_charging_estimate_workflow(
            session, prepared
        )
        if local_charging_estimate is not None:
            return local_charging_estimate
        charging_stop_navigation = self._next_charging_stop_navigation_workflow(
            session, prepared
        )
        if charging_stop_navigation is not None:
            return charging_stop_navigation
        trip_charger = self._next_trip_charger_workflow(session, prepared)
        if trip_charger is not None:
            return trip_charger
        driver_warming = self._next_driver_warming_workflow(session, prepared)
        if driver_warming is not None:
            return driver_warming
        navigation_add = self._next_navigation_add_workflow(session, prepared)
        if navigation_add is not None:
            return navigation_add
        next_navigation_stop_poi = self._next_navigation_stop_poi_workflow(
            session, prepared
        )
        if next_navigation_stop_poi is not None:
            return next_navigation_stop_poi
        current_destination_poi = self._next_current_destination_poi_workflow(
            session, prepared
        )
        if current_destination_poi is not None:
            return current_destination_poi
        conditional_navigation = (
            self._next_conditional_arrival_weather_navigation_workflow(
                session, prepared
            )
        )
        if conditional_navigation is not None:
            return conditional_navigation
        poi_search = self._next_named_poi_workflow(session, prepared)
        if poi_search is not None:
            return poi_search
        displayed_poi_call = self._next_displayed_poi_call_action(session, prepared)
        if displayed_poi_call is not None:
            return displayed_poi_call
        displayed_poi_navigation = self._next_displayed_poi_navigation_workflow(
            session, prepared
        )
        if displayed_poi_navigation is not None:
            return displayed_poi_navigation
        navigation_resume = self._next_navigation_resume_workflow(session, prepared)
        if navigation_resume is not None:
            return navigation_resume
        navigation_create = self._next_navigation_create_workflow(session, prepared)
        if navigation_create is not None:
            return navigation_create
        destination_replace = self._next_destination_replace_workflow(session, prepared)
        if destination_replace is not None:
            return destination_replace
        navigation_edit = self._next_navigation_edit_workflow(session, prepared)
        if navigation_edit is not None:
            return navigation_edit
        trip_range = self._next_trip_range_workflow(session, prepared)
        if trip_range is not None:
            return trip_range
        contextual_slot_read = self._next_contextual_slot_read(session, prepared)
        if contextual_slot_read is not None:
            return contextual_slot_read
        live_clarification = self._next_live_parameter_clarification(session, prepared)
        if live_clarification is not None:
            return live_clarification
        limitation = self._pre_planner_limitation(session, prepared)
        if limitation is not None:
            return limitation
        clarification = self._next_clarification(session)
        if clarification is not None:
            return clarification
        navigation_read = self._next_current_navigation_read(session, prepared)
        if navigation_read is not None:
            return navigation_read
        calendar_read = self._next_current_day_calendar_read(session, prepared)
        if calendar_read is not None:
            return calendar_read
        range_read = self._next_grounded_range_read(session, prepared)
        if range_read is not None:
            return range_read
        evidence_read = self._next_recipe_evidence_read(session, prepared)
        if evidence_read is not None:
            return evidence_read
        policy_read = self._next_policy_evidence_read(session, prepared)
        if policy_read is not None:
            return policy_read
        confirmation_action = self._next_policy_confirmation_action(session, prepared)
        if confirmation_action is not None:
            return confirmation_action
        contextual_action = self._next_sunshade_match_action(session, prepared)
        if contextual_action is not None:
            return contextual_action
        if (
            session.relative_fan_speed_deltas_by_goal
            or session.relative_climate_temperature_deltas_by_goal
            or session.relative_seat_heating_deltas_by_goal
        ):
            relative_action = self._deterministic_bound_action(session, prepared)
            if relative_action is not None:
                return relative_action

        client = self._client_factory(session)
        try:
            proposal = ActionPlanner(client).propose_next(
                policy=session.compiled_policy,
                conversation=session.conversation,
                live_tools=session.live_tools,
                live_bindings=[
                    binding for goal in prepared.goals for binding in goal.bindings
                ],
                conditional_closure=[goal.closure for goal in prepared.goals],
                goal_dag=session.goal_dag,
                evidence=session.evidence,
                ambiguities=(session.intent.unresolved_slots if session.intent else ()),
                relevant_recipes=prepared.all_recipes,
                budget=session.budget,
                call_id_factory=session.next_call_id,
            )
        except LLMFailure:
            fallback = self._deterministic_bound_action(session, prepared)
            if fallback is None:
                raise
            logger.warning(
                "Structured planner unavailable; using a uniquely bound action"
            )
            return fallback
        return self._validate_planner_proposal(
            session, prepared, proposal, client=client, replan_used=False
        )

    def _prepare_turn(self, session: SessionState) -> PreparedTurn:
        materialize_recipe_derivations(
            session.evidence,
            source_turn_id=f"derived-step-{session.budget.steps}",
        )
        self._ensure_contextual_slot_needs(session)
        self._materialize_contextual_slot_parameters(session)
        self._ensure_relative_fan_speed_needs(session)
        self._materialize_relative_fan_speed_goal_parameter(session)
        self._ensure_relative_climate_temperature_needs(session)
        self._materialize_relative_climate_temperature_goal_parameter(session)
        self._ensure_relative_seat_heating_needs(session)
        self._materialize_relative_seat_heating_goal_parameters(session)
        prepared: list[PreparedGoal] = []
        for goal in session.goal_dag.ready_goals:
            recipes = self.recipes.select_by_intent_and_policy(goal)
            excluded_read_operations = (
                frozenset({"read_current_navigation_for_create"})
                if goal.semantic_operation in _NAVIGATION_CREATE_OPERATIONS
                and not session.live_tools.has_tool("get_current_navigation_state")
                else frozenset()
            )
            need_map = register_recipe_needs(
                session.evidence,
                goal,
                recipes,
                excluded_read_operations=excluded_read_operations,
            )
            bindings = tuple(
                self.semantic_binder.bind(goal, recipes, session.live_tools)
            )
            closure = self.closure.instantiate(goal, session.evidence, recipes)
            proof = self.semantic_binder.prove_goal_feasibility(
                goal, closure, session.live_tools
            )
            read_need_ids: dict[str, tuple[str, ...]] = {}
            for operation, need_ids in need_map.items():
                candidate_names: list[str] = []
                for recipe in recipes:
                    for read_operation in recipe.read_operations:
                        if read_operation.semantic_operation != operation:
                            continue
                        candidate_names.extend(
                            name
                            for name in read_operation.tool_names
                            if session.live_tools.has_tool(name)
                        )
                for tool_name in dict.fromkeys(candidate_names):
                    read_need_ids[tool_name] = tuple(need_ids)
            prepared.append(
                PreparedGoal(
                    goal=goal,
                    recipes=recipes,
                    bindings=bindings,
                    closure=closure,
                    proof=proof,
                    read_need_ids=read_need_ids,
                )
            )
        return PreparedTurn(tuple(prepared))

    def _next_live_parameter_clarification(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        """Ask for missing or unsupported values using only the live enum domain."""

        if session.intent is None:
            return None
        slots = [slot.model_copy(deep=True) for slot in session.intent.unresolved_slots]
        slots_changed = False
        additions: list[AmbiguitySlot] = []
        blocked_goal: Goal | None = None

        for item in prepared.goals:
            requirement = next(
                (
                    candidate
                    for candidate in item.closure.requirements
                    if candidate.trigger == "goal"
                ),
                None,
            )
            if requirement is None:
                continue
            operation = requirement.operation
            tool_name = next(
                (
                    name
                    for name in operation.tool_names
                    if session.live_tools.has_tool(name)
                ),
                None,
            )
            if tool_name is None:
                continue

            for semantic_name in operation.required_semantic_parameters:
                official_name = operation.parameter_mapping[semantic_name]
                domain = session.live_tools.parameter_domain(tool_name, official_name)
                if domain is None:
                    continue
                matching_slots = [
                    slot
                    for slot in slots
                    if slot.goal_id == item.goal.goal_id
                    and (
                        canonical_semantic_parameter_name(
                            operation.semantic_operation, slot.name
                        )
                        == semantic_name
                        or slot.name == official_name
                    )
                ]
                enum = domain.get("enum")
                has_current = semantic_name in item.goal.desired_outcome
                current = item.goal.desired_outcome.get(semantic_name)
                if not isinstance(enum, list):
                    numeric_options = _bounded_numeric_options(domain)
                    if not has_current and numeric_options:
                        if matching_slots:
                            slots = [
                                slot for slot in slots if slot not in matching_slots
                            ]
                            slots_changed = True
                        additions.append(
                            AmbiguitySlot(
                                name=semantic_name,
                                candidates=[
                                    Candidate(
                                        candidate_id=(
                                            f"live-{item.goal.goal_id}-"
                                            f"{semantic_name}-{index}"
                                        ),
                                        value=value,
                                        label=str(value),
                                    )
                                    for index, value in enumerate(numeric_options)
                                ],
                                goal_id=item.goal.goal_id,
                                source_turn_ids=list(
                                    session.intent.intent_source_turn_ids
                                ),
                            )
                        )
                        continue
                    if not has_current and domain.get("type") == "boolean":
                        if matching_slots:
                            slots = [
                                slot for slot in slots if slot not in matching_slots
                            ]
                            slots_changed = True
                        additions.append(
                            AmbiguitySlot(
                                name=semantic_name,
                                candidates=[
                                    Candidate(
                                        candidate_id=(
                                            f"live-{item.goal.goal_id}-"
                                            f"{semantic_name}-false"
                                        ),
                                        value=False,
                                        label="false",
                                    ),
                                    Candidate(
                                        candidate_id=(
                                            f"live-{item.goal.goal_id}-"
                                            f"{semantic_name}-true"
                                        ),
                                        value=True,
                                        label="true",
                                    ),
                                ],
                                goal_id=item.goal.goal_id,
                                source_turn_ids=list(
                                    session.intent.intent_source_turn_ids
                                ),
                            )
                        )
                        continue
                    if not has_current and domain.get("type") == "string":
                        if matching_slots:
                            slots = [
                                slot for slot in slots if slot not in matching_slots
                            ]
                            slots_changed = True
                        blocked_goal = blocked_goal or item.goal
                    continue
                if not enum or not all(
                    isinstance(value, str) and value.strip() for value in enum
                ):
                    if matching_slots:
                        slots = [slot for slot in slots if slot not in matching_slots]
                        slots_changed = True
                    blocked_goal = blocked_goal or item.goal
                    continue
                if isinstance(current, str):
                    normalized = _argument_identifier(current)
                    matching = [
                        value
                        for value in enum
                        if _argument_identifier(value) == normalized
                    ]
                    if len(matching) == 1:
                        if matching_slots:
                            slots = [
                                slot for slot in slots if slot not in matching_slots
                            ]
                            slots_changed = True
                        continue
                if not 2 <= len(enum) <= 20:
                    if matching_slots:
                        slots = [slot for slot in slots if slot not in matching_slots]
                        slots_changed = True
                    blocked_goal = blocked_goal or item.goal
                    continue

                if matching_slots:
                    slots = [slot for slot in slots if slot not in matching_slots]
                    slots_changed = True

                additions.append(
                    AmbiguitySlot(
                        name=semantic_name,
                        candidates=[
                            Candidate(
                                candidate_id=(
                                    f"live-{item.goal.goal_id}-{semantic_name}-{index}"
                                ),
                                value=value,
                                label=value.casefold().replace("_", " "),
                            )
                            for index, value in enumerate(enum)
                        ],
                        goal_id=item.goal.goal_id,
                        source_turn_ids=list(session.intent.intent_source_turn_ids),
                    )
                )

        if additions or slots_changed:
            session.intent = IntentFrame.model_validate(
                {
                    **session.intent.model_dump(mode="python"),
                    "unresolved_slots": [
                        slot.model_dump(mode="python") for slot in [*slots, *additions]
                    ],
                }
            )
            clarification = self._next_clarification(session)
            if clarification is not None:
                return clarification
        if blocked_goal is not None:
            return self._limitation_plan(
                session, blocked_goal, GateOutcome.UNSUPPORTED_PARAMETER
            )
        return None

    def _relative_temperature_prerequisite_text(
        self,
        session: SessionState,
        prepared: PreparedTurn,
        *,
        blocked: PreparedGoal,
        missing_operation: str,
    ) -> tuple[str, tuple[str, ...]] | None:
        if (
            blocked.goal.semantic_operation != "set_air_conditioning"
            or missing_operation
            not in {
                "close_driver_window_for_ac",
                "close_passenger_window_for_ac",
                "close_driver_rear_window_for_ac",
                "close_passenger_rear_window_for_ac",
            }
        ):
            return None
        temperature_goals = [
            item
            for item in prepared.goals
            if item.goal.goal_id in session.relative_climate_temperature_deltas_by_goal
            and item.goal.semantic_operation == "set_climate_temperature"
            and item.goal.desired_outcome.get("seat_zone") == "ALL_ZONES"
        ]
        if len(temperature_goals) != 1:
            return None
        temperature_goal = temperature_goals[0]
        target_value = temperature_goal.goal.desired_outcome.get("temperature")
        if isinstance(target_value, bool) or not isinstance(
            target_value, (int, float, Decimal)
        ):
            return None
        try:
            target = Decimal(str(target_value))
        except InvalidOperation:
            return None
        if not target.is_finite():
            return None
        parents = [
            observation
            for need in session.evidence.needs.values()
            if need.required_for_goal_id == temperature_goal.goal.goal_id
            and need.proposition == "relative_climate_temperature_snapshot"
            for observation in session.evidence.satisfying_evidence(need)
        ]
        current_values = {
            current
            for observation in parents
            if (
                current := self._relative_climate_temperature_current(
                    observation, seat_zone="ALL_ZONES"
                )
            )
            is not None
        }
        if len(current_values) != 1:
            return None
        current = next(iter(current_values))
        text = self.responses.relative_temperature_prerequisite_limitation(
            current_temperature=format(current.normalize(), "f"),
            target_temperature=format(target.normalize(), "f"),
            language=self._language(session),
        )
        return text, (blocked.goal.goal_id, temperature_goal.goal.goal_id)

    @staticmethod
    def _selected_recipe_target(
        item: PreparedGoal,
    ) -> tuple[str, OperationSpec, bool] | None:
        """Return one target declared by the recipes selected for this goal."""

        target_requirements = [
            requirement
            for requirement in item.closure.requirements
            if requirement.trigger == "goal"
        ]
        if len(target_requirements) != 1:
            return None
        requirement = target_requirements[0]
        recipe = next(
            (recipe for recipe in item.recipes if recipe.id == requirement.recipe_id),
            None,
        )
        if recipe is None:
            return None
        target = recipe.target_operation(item.goal.semantic_operation)
        if target is None or target != requirement.operation:
            return None
        return recipe.id, target, target in recipe.write_operations

    @staticmethod
    def _selected_target_binding(
        item: PreparedGoal, *, recipe_id: str, target: OperationSpec
    ) -> LiveBinding | None:
        matches = [
            binding
            for binding in item.bindings
            if not binding.is_read
            and binding.recipe_id == recipe_id
            and binding.semantic_operation == target.semantic_operation
            and binding.tool_name in target.tool_names
        ]
        return matches[0] if len(matches) == 1 else None

    def _pre_planner_limitation(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if not item.recipes or not item.closure.requirements:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            selected_target = self._selected_recipe_target(item)
            if selected_target is None:
                target_requirement = next(
                    (
                        requirement
                        for requirement in item.closure.requirements
                        if requirement.trigger == "goal"
                    ),
                    None,
                )
                if target_requirement is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                    )
                if not any(
                    session.live_tools.has_tool(name)
                    for name in target_requirement.operation.tool_names
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                    )
                target_binding = None
                target_operation = target_requirement.operation
            else:
                recipe_id, target_operation, target_is_write = selected_target
                if not any(
                    session.live_tools.has_tool(name)
                    for name in target_operation.tool_names
                ):
                    specific = self._selected_operation_limitation_plan(
                        session,
                        item.goal,
                        operation=target_operation,
                        is_write=target_is_write,
                    )
                    if specific is not None:
                        return specific
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                    )
                target_binding = self._selected_target_binding(
                    item, recipe_id=recipe_id, target=target_operation
                )
            if target_binding is not None and target_binding.unsupported_parameters:
                parameter_specific = self._mapped_parameter_limitation_plan(
                    session,
                    item.goal,
                    operation=target_operation,
                    binding=target_binding,
                )
                if parameter_specific is not None:
                    return parameter_specific
            if item.proof.outcome is GateOutcome.UNSUPPORTED_CAPABILITY:
                failed_operation = (
                    item.proof.checked_operations[-1]
                    if item.proof.checked_operations
                    else None
                )
                missing_prerequisite = next(
                    (
                        requirement
                        for requirement in item.closure.requirements
                        if requirement.trigger != "goal"
                        and requirement.operation.semantic_operation == failed_operation
                    ),
                    None,
                )
                if missing_prerequisite is not None:
                    compound = self._relative_temperature_prerequisite_text(
                        session,
                        prepared,
                        blocked=item,
                        missing_operation=(
                            missing_prerequisite.operation.semantic_operation
                        ),
                    )
                    if compound is not None:
                        text, goal_ids = compound
                        return self._text_plan(
                            session,
                            text,
                            goal_ids=goal_ids,
                        )
                    return self._text_plan(
                        session,
                        self.responses.prerequisite_limitation(
                            goal=item.goal.semantic_operation,
                            prerequisite=(
                                missing_prerequisite.operation.semantic_operation
                            ),
                            language=self._language(session),
                        ),
                        goal_ids=[item.goal.goal_id],
                    )
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            if item.proof.outcome is GateOutcome.UNSUPPORTED_PARAMETER and any(
                binding.unsupported_parameters or binding.argument_error
                for binding in item.proof.bindings
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
        return None

    def _early_target_schema_limitation(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        """Preflight only selected target tools and their recipe-mapped fields."""

        for item in prepared.goals:
            selected_target = self._selected_recipe_target(item)
            if selected_target is None:
                continue
            recipe_id, target_operation, target_is_write = selected_target
            if not any(
                session.live_tools.has_tool(name)
                for name in target_operation.tool_names
            ):
                specific = self._selected_operation_limitation_plan(
                    session,
                    item.goal,
                    operation=target_operation,
                    is_write=target_is_write,
                )
                if specific is not None:
                    return specific
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            target_binding = self._selected_target_binding(
                item, recipe_id=recipe_id, target=target_operation
            )
            if target_binding is None:
                continue
            if target_binding.unsupported_parameters:
                specific = self._mapped_parameter_limitation_plan(
                    session,
                    item.goal,
                    operation=target_operation,
                    binding=target_binding,
                )
                if specific is not None:
                    return specific
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            if target_binding.argument_error is not None:
                clarification = self._next_live_parameter_clarification(
                    session, PreparedTurn((item,))
                )
                if clarification is not None:
                    return clarification
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
        return None

    def _next_clarification(self, session: SessionState) -> PlannedOutbound | None:
        if session.intent is None:
            return None
        for slot in session.intent.unresolved_slots:
            resolution = self.disambiguation.resolve(slot)
            if resolution.outcome is GateOutcome.ALLOW:
                continue
            if resolution.outcome is GateOutcome.NEED_USER_DISAMBIGUATION:
                request = resolution.clarification_request
                assert request is not None
                candidates = {
                    candidate.candidate_id: candidate
                    for candidate in slot.remaining_candidates
                }
                safe_options = []
                for option in request.options:
                    candidate = candidates[option.candidate_id]
                    display_value = candidate.value
                    if (
                        isinstance(candidate.value, str)
                        and isinstance(candidate.label, str)
                        and _argument_identifier(candidate.label)
                        == _argument_identifier(candidate.value)
                    ):
                        display_value = candidate.label
                    safe_label = self._explicit_choice_label(display_value)
                    if safe_label is None:
                        assert slot.goal_id is not None
                        return self._limitation_plan(
                            session,
                            session.goal_dag.get(slot.goal_id),
                            GateOutcome.UNAVAILABLE_EVIDENCE,
                        )
                    safe_options.append(
                        option.model_copy(update={"label": safe_label}, deep=True)
                    )
                request = request.model_copy(
                    update={"options": safe_options}, deep=True
                )
                session.pending_clarifications[request.request_id] = request
                return self._text_plan(
                    session,
                    self.responses.clarification(
                        goal=self.responses.humanize(request.slot_name),
                        options=[option.label for option in request.options],
                        language=self._language(session),
                    ),
                    goal_ids=([request.goal_id] if request.goal_id else ()),
                    kind=ProposalKind.ASK_USER,
                )
            return self._text_plan(
                session,
                self.responses.gate_limitation(
                    goal=slot.goal_id or slot.name,
                    outcome=resolution.outcome,
                    language=self._language(session),
                ),
                goal_ids=([slot.goal_id] if slot.goal_id else ()),
            )
        return None

    def _explicit_choice_label(self, value: Any) -> str | None:
        """Expose the exact candidate value that a reply may authorize."""

        if isinstance(value, bool):
            text = "true" if value else "false"
        elif isinstance(value, (str, int, float)):
            text = str(value).strip()
        else:
            return None
        if not text or len(text) > 120:
            return None
        try:
            return self.tts.ensure(text)
        except TTSViolation:
            return None

    def _next_preference_read(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        tool_name = "get_user_preferences"
        if not session.live_tools.has_tool(tool_name):
            return None
        for item in prepared.goals:
            missing: set[str] = set()
            for recipe in item.recipes:
                target = recipe.target_operation(item.goal.semantic_operation)
                if target is None or target not in recipe.write_operations:
                    continue
                missing.update(
                    set(target.required_semantic_parameters).difference(
                        item.goal.desired_outcome
                    )
                )
            spec = _PREFERENCE_READ_BY_OPERATION.get(item.goal.semantic_operation)
            if spec is None:
                continue
            parameter, proposition, category = spec
            if parameter not in missing:
                continue
            existing_needs = [
                need
                for need in session.evidence.needs.values()
                if need.required_for_goal_id == item.goal.goal_id
                and need.proposition == proposition
            ]
            if existing_needs:
                continue
            try:
                arguments = session.live_tools.validate_arguments(
                    tool_name, {"preference_categories": category}
                )
            except ToolArgumentValidationError:
                continue
            need_id = register_preference_need(
                session.evidence,
                goal_id=item.goal.goal_id,
                proposition=proposition,
            )
            call_id = session.next_call_id()
            proposal = DecisionProposal(
                kind=ProposalKind.TOOL_GET,
                goal_ids=[item.goal.goal_id],
                tool_calls=[
                    ProposedToolCall(
                        tool_name=tool_name,
                        arguments=arguments,
                        call_id=call_id,
                        goal_id=item.goal.goal_id,
                    )
                ],
            )
            gate = self.precommit.validate(proposal, self._basic_gate_context(session))
            if gate.outcome is not GateOutcome.ALLOW:
                return self._route_gate_failure(session, proposal, gate, item.goal)
            return PlannedOutbound(
                self.adapter.serialize(gate),
                proposal=proposal,
                decision=gate,
                pending_need_ids=({call_id: (need_id,)} if need_id is not None else {}),
                policy_operations={call_id: "read_user_preferences"},
            )
        return None

    def _next_ambient_car_color_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _AMBIENT_CAR_COLOR_OPERATION:
                continue
            if item.goal.goal_id not in self._authorized_goal_ids(session):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.POLICY_CONFLICT
                )
            if not session.live_tools.has_tool(
                "get_car_color"
            ) or not session.live_tools.has_tool("set_ambient_lights"):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            required = session.live_tools.required_parameters("set_ambient_lights")
            on_domain = session.live_tools.parameter_domain("set_ambient_lights", "on")
            color_domain = session.live_tools.parameter_domain(
                "set_ambient_lights", "lightcolor"
            )
            color_options = (
                color_domain.get("enum") if isinstance(color_domain, Mapping) else None
            )
            if (
                not {"on", "lightcolor"}.issubset(required)
                or not isinstance(on_domain, Mapping)
                or on_domain.get("type") != "boolean"
                or not isinstance(color_options, list)
                or not 1 <= len(color_options) <= 32
                or not all(
                    isinstance(option, str) and option.strip()
                    for option in color_options
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            try:
                session.live_tools.validate_arguments("get_car_color", {})
            except ToolArgumentValidationError:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )

            observed = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_car_color",
                arguments={},
                proposition=_AMBIENT_CAR_COLOR_EVIDENCE,
            )
            if observed is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_car_color",
                        arguments={},
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_car_color",
                    arguments={},
                    semantic_operation="read_car_exterior_color",
                    proposition=_AMBIENT_CAR_COLOR_EVIDENCE,
                )

            raw_color, color_evidence = observed
            if not isinstance(raw_color, str) or not self._voice_result_field(
                raw_color, 32
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            normalized = _argument_identifier(raw_color)
            matches = [
                option
                for option in color_options
                if _argument_identifier(option) == normalized
            ]
            if normalized in {"none", "off"} or len(matches) != 1:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            selected_color = matches[0]
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "color": (
                        selected_color,
                        (color_evidence,),
                        "ambient_color_from_verified_exterior_color_v1",
                    )
                },
            )
            refreshed = self._prepare_turn(session)
            refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
            target = (
                self._unique_bound_target(refreshed_item)
                if refreshed_item is not None
                else None
            )
            expected = {"on": True, "lightcolor": selected_color}
            if (
                target is None
                or target[1].tool_name != "set_ambient_lights"
                or not _argument_value_matches_binding(target[1].arguments, expected)
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            deterministic = self._deterministic_bound_action(session, refreshed)
            return deterministic or self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        return None

    @staticmethod
    def _reading_light_state_fields(position: str) -> tuple[str, ...] | None:
        normalized = _argument_identifier(position)
        mapping = {
            "all": (
                "reading_light_driver",
                "reading_light_passenger",
                "reading_light_driver_rear",
                "reading_light_passenger_rear",
            ),
            "driver": ("reading_light_driver",),
            "passenger": ("reading_light_passenger",),
            "driver_rear": ("reading_light_driver_rear",),
            "right_rear": ("reading_light_driver_rear",),
            "passenger_rear": ("reading_light_passenger_rear",),
            "left_rear": ("reading_light_passenger_rear",),
        }
        return mapping.get(normalized)

    @staticmethod
    def _empty_argument_tool_issue(
        session: SessionState, tool_name: str
    ) -> GateOutcome | None:
        if session.live_tools is None or not session.live_tools.has_tool(tool_name):
            return GateOutcome.UNSUPPORTED_CAPABILITY
        try:
            session.live_tools.validate_arguments(tool_name, {})
        except ToolArgumentValidationError:
            return GateOutcome.UNSUPPORTED_PARAMETER
        return None

    @staticmethod
    def _reading_light_set_schema_available(session: SessionState) -> bool:
        if session.live_tools is None or not session.live_tools.has_tool(
            "set_reading_light"
        ):
            return False
        required = session.live_tools.required_parameters("set_reading_light")
        position = session.live_tools.parameter_domain("set_reading_light", "position")
        enabled = session.live_tools.parameter_domain("set_reading_light", "on")
        positions = position.get("enum") if isinstance(position, Mapping) else None
        if (
            not {"position", "on"}.issubset(required)
            or not isinstance(positions, list)
            or not all(isinstance(item, str) and item.strip() for item in positions)
            or not isinstance(enabled, Mapping)
            or enabled.get("type") != "boolean"
        ):
            return False
        return True

    @classmethod
    def _reading_light_schema_available(cls, session: SessionState) -> bool:
        if not cls._reading_light_set_schema_available(session):
            return False
        return (
            cls._empty_argument_tool_issue(session, "get_reading_lights_status") is None
        )

    def _occupancy_reading_lights_limitation(
        self,
        session: SessionState,
        goal: Goal,
        *,
        missing_kind: MissingCapabilityKind,
        missing_description: str,
    ) -> PlannedOutbound:
        return self._transparent_limitation_plan(
            session,
            goal,
            missing_kind=missing_kind,
            missing_description=missing_description,
            goal_description="match the reading lights to occupied seats",
            unperformed_description="change any reading lights",
        )

    def _next_reading_light_readback(
        self, session: SessionState
    ) -> PlannedOutbound | None:
        verification = session.pending_set_readback
        if verification is None:
            return None
        pending = verification.pending_call
        if (
            pending.tool_name != "set_reading_light"
            or len(pending.goal_ids) != 1
            or not self._reading_light_schema_available(session)
        ):
            goal_ids = self._abort_execution_bundle(
                session,
                reason="the reading-light state could not be read back",
                state_may_have_changed=True,
            )
            goal = session.goal_dag.get((goal_ids or pending.goal_ids)[0])
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        goal_id = pending.goal_ids[0]
        readback_proposition = f"{_READING_LIGHT_STATE_EVIDENCE}:{pending.call_id}"
        try:
            goal = session.goal_dag.get(goal_id)
        except KeyError:
            self._abort_execution_bundle(
                session,
                reason="the reading-light goal no longer existed",
                state_may_have_changed=True,
            )
            return self._text_plan(
                session,
                "I could not verify the requested reading-light state, so I did not continue.",
            )
        existing_readback_need = any(
            need.required_for_goal_id == goal_id
            and need.proposition == readback_proposition
            for need in session.evidence.needs.values()
        )
        if not existing_readback_need:
            self.result_validator.register_extractor(
                readback_proposition,
                ExtractorSpec(
                    "$.result",
                    allowed_tool_names=frozenset({"get_reading_lights_status"}),
                ),
            )
            self._register_single_read_need(
                session,
                goal_id=goal_id,
                proposition=readback_proposition,
            )
        observed = self._derived_navigation_read_value(
            session,
            goal_id=goal_id,
            tool_name="get_reading_lights_status",
            arguments={},
            proposition=readback_proposition,
        )
        if observed is None:
            if (
                self._successful_goal_read(
                    session,
                    goal_id=goal_id,
                    tool_name="get_reading_lights_status",
                    arguments={},
                )
                is not None
            ):
                self._abort_execution_bundle(
                    session,
                    reason="the reading-light readback was malformed",
                    state_may_have_changed=True,
                )
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            prepared = self._prepare_turn(session)
            item = prepared.by_goal_id.get(goal_id)
            if item is None:
                self._abort_execution_bundle(
                    session,
                    reason="the reading-light readback lost its goal",
                    state_may_have_changed=True,
                )
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="get_reading_lights_status",
                arguments={},
                semantic_operation="verify_reading_light_state",
                proposition=readback_proposition,
            )

        state, state_evidence = observed
        position = pending.arguments.get("position")
        enabled = pending.arguments.get("on")
        fields = (
            self._reading_light_state_fields(position)
            if isinstance(position, str)
            else None
        )
        if (
            not isinstance(state, Mapping)
            or fields is None
            or type(enabled) is not bool
            or state_evidence.state_version != verification.expected_state_version
            or any(type(state.get(field)) is not bool for field in fields)
            or any(state[field] is not enabled for field in fields)
        ):
            self._abort_execution_bundle(
                session,
                reason="the reading-light readback did not match the requested state",
                source_turn_id=state_evidence.source_turn_id,
                state_may_have_changed=True,
            )
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )

        bundle = session.execution_bundle
        if (
            bundle is None
            or pending.bundle_index != bundle.next_index
            or bundle.current_call is None
            or call_fingerprint(
                bundle.current_call.tool_name, bundle.current_call.arguments
            )
            != call_fingerprint(pending.tool_name, pending.arguments)
        ):
            self._abort_execution_bundle(
                session,
                reason="the reading-light readback no longer matched its bundle",
                source_turn_id=state_evidence.source_turn_id,
                state_may_have_changed=True,
            )
            return self._limitation_plan(session, goal, GateOutcome.INVALID_PROPOSAL)

        session.budget.record_success(
            pending.tool_name, pending.arguments, state_changing=True
        )
        self._record_policy_completion(session, pending)
        bundle.advance()
        session.pending_set_readback = None
        if bundle.complete:
            if bundle.confirmation_id is not None:
                session.confirmation_latch.consume_authorization(
                    goal_ids=list(bundle.goal_ids),
                    ordered_actions=list(bundle.calls),
                    current_user_turn=session.budget.user_turns,
                )
            for completed_goal_id in bundle.goal_ids:
                session.completed_action_calls_by_goal[completed_goal_id] = bundle.calls
                session.completed_action_operations_by_goal[completed_goal_id] = (
                    bundle.policy_operations
                )
            session.evidence.invalidate_tool_state()
            for completed_goal_id in bundle.goal_ids:
                session.goal_dag.set_status(completed_goal_id, GoalStatus.DONE)
        return self._plan_next(session)

    def _next_reading_lights_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation == "set_reading_light":
                if not self._reading_light_schema_available(session):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                    )
                continue
            if item.goal.semantic_operation != _OCCUPANCY_READING_LIGHTS_OPERATION:
                continue
            if item.goal.goal_id not in self._authorized_goal_ids(session):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.INVALID_PROPOSAL
                )
            occupancy_issue = self._empty_argument_tool_issue(
                session, "get_seats_occupancy"
            )
            if occupancy_issue is not None:
                return self._occupancy_reading_lights_limitation(
                    session,
                    item.goal,
                    missing_kind=MissingCapabilityKind.INFORMATION,
                    missing_description="current seat occupancy",
                )
            state_issue = self._empty_argument_tool_issue(
                session, "get_reading_lights_status"
            )
            if state_issue is not None:
                return self._occupancy_reading_lights_limitation(
                    session,
                    item.goal,
                    missing_kind=MissingCapabilityKind.INFORMATION,
                    missing_description="current reading light status",
                )
            if not self._reading_light_set_schema_available(session):
                return self._occupancy_reading_lights_limitation(
                    session,
                    item.goal,
                    missing_kind=MissingCapabilityKind.CONTROL,
                    missing_description="individual reading light",
                )
            position_domain = session.live_tools.parameter_domain(
                "set_reading_light", "position"
            )
            position_options = (
                position_domain.get("enum")
                if isinstance(position_domain, Mapping)
                else None
            )
            canonical_positions = (
                "DRIVER",
                "PASSENGER",
                "DRIVER_REAR",
                "PASSENGER_REAR",
            )
            if not isinstance(position_options, list) or not set(
                canonical_positions
            ).issubset(position_options):
                return self._occupancy_reading_lights_limitation(
                    session,
                    item.goal,
                    missing_kind=MissingCapabilityKind.CONTROL,
                    missing_description="individual reading light",
                )

            read_specs: tuple[tuple[str, Mapping[str, Any], str, str], ...] = (
                (
                    "get_seats_occupancy",
                    {},
                    "read_seat_occupancy_for_lights",
                    _READING_LIGHT_OCCUPANCY_EVIDENCE,
                ),
                (
                    "get_reading_lights_status",
                    {},
                    "read_current_reading_lights",
                    _READING_LIGHT_STATE_EVIDENCE,
                ),
            )
            observed: dict[str, tuple[Any, Evidence]] = {}
            missing: list[tuple[str, Mapping[str, Any], str, str]] = []
            for tool_name, arguments, operation, proposition in read_specs:
                value = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name=tool_name,
                    arguments=arguments,
                    proposition=proposition,
                )
                if value is not None:
                    observed[proposition] = value
                    continue
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name=tool_name,
                        arguments=arguments,
                    )
                    is not None
                ):
                    missing_description = (
                        "current seat occupancy"
                        if tool_name == "get_seats_occupancy"
                        else "current reading light status"
                    )
                    return self._occupancy_reading_lights_limitation(
                        session,
                        item.goal,
                        missing_kind=MissingCapabilityKind.INFORMATION,
                        missing_description=missing_description,
                    )
                missing.append((tool_name, arguments, operation, proposition))
            if missing:
                return self._parallel_navigation_read_plan(
                    session, item=item, specifications=missing
                )

            occupancy, occupancy_evidence = observed[_READING_LIGHT_OCCUPANCY_EVIDENCE]
            current, current_evidence = observed[_READING_LIGHT_STATE_EVIDENCE]
            if not isinstance(occupancy, Mapping):
                return self._occupancy_reading_lights_limitation(
                    session,
                    item.goal,
                    missing_kind=MissingCapabilityKind.INFORMATION,
                    missing_description="current seat occupancy",
                )
            if not isinstance(current, Mapping):
                return self._occupancy_reading_lights_limitation(
                    session,
                    item.goal,
                    missing_kind=MissingCapabilityKind.INFORMATION,
                    missing_description="current reading light status",
                )
            seats = (
                ("driver", "DRIVER", "reading_light_driver"),
                ("passenger", "PASSENGER", "reading_light_passenger"),
                ("driver_rear", "DRIVER_REAR", "reading_light_driver_rear"),
                (
                    "passenger_rear",
                    "PASSENGER_REAR",
                    "reading_light_passenger_rear",
                ),
            )
            if any(type(occupancy.get(seat)) is not bool for seat, _, _ in seats):
                return self._occupancy_reading_lights_limitation(
                    session,
                    item.goal,
                    missing_kind=MissingCapabilityKind.INFORMATION,
                    missing_description="current seat occupancy",
                )
            if any(type(current.get(light)) is not bool for _, _, light in seats):
                return self._occupancy_reading_lights_limitation(
                    session,
                    item.goal,
                    missing_kind=MissingCapabilityKind.INFORMATION,
                    missing_description="current reading light status",
                )
            changes = [
                (position, enabled)
                for enabled in (True, False)
                for seat, position, light in seats
                if occupancy[seat] is enabled and current[light] is not enabled
            ]
            if not changes:
                session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
                return self._text_plan(
                    session,
                    "The reading lights already match the occupied seats.",
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )

            action_goals: list[Goal] = []
            for index, (position, enabled) in enumerate(changes):
                digest = hashlib.sha256(
                    f"{item.goal.goal_id}\0{index}\0{position}\0{enabled}".encode()
                ).hexdigest()
                action_goals.append(
                    Goal(
                        goal_id=f"goal-reading-light-delta-{digest[:12]}",
                        semantic_operation="set_reading_light",
                        desired_outcome={},
                    )
                )
            assert session.intent is not None
            session.intent = session.intent.model_copy(
                update={
                    "goals": action_goals,
                    "goal_mention_order": [goal.goal_id for goal in action_goals],
                },
                deep=True,
            )
            session.authorized_action_goal_ids = {goal.goal_id for goal in action_goals}
            session.grounded_desired_values_by_goal = {
                goal.goal_id: {} for goal in action_goals
            }
            session.grounded_value_sources_by_goal = {
                goal.goal_id: {} for goal in action_goals
            }
            session.derived_value_evidence_by_goal = {
                goal.goal_id: {} for goal in action_goals
            }
            session.goal_dag = self.goal_planner.update(
                session.goal_dag, session.intent
            )
            for goal, (position, enabled) in zip(action_goals, changes, strict=True):
                self._apply_navigation_derived_parameters(
                    session,
                    goal=goal,
                    parameters={
                        "position": (
                            position,
                            (occupancy_evidence, current_evidence),
                            "reading_light_delta_position_v1",
                        ),
                        "enabled": (
                            enabled,
                            (occupancy_evidence, current_evidence),
                            "reading_light_delta_state_v1",
                        ),
                    },
                )
            refreshed = self._prepare_turn(session)
            targets: list[tuple[Goal, OfficialToolCall]] = []
            for goal in action_goals:
                refreshed_item = refreshed.by_goal_id.get(goal.goal_id)
                target = (
                    self._unique_bound_target(refreshed_item)
                    if refreshed_item is not None
                    else None
                )
                if target is None or target[1].tool_name != "set_reading_light":
                    return self._limitation_plan(
                        session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                targets.append((goal, target[1]))
            session.execution_bundle = ExecutionBundle(
                goal_ids=tuple(goal.goal_id for goal, _ in targets),
                calls=tuple(call for _, call in targets),
                policy_operations=("set_reading_light",) * len(targets),
                call_goal_ids=tuple(goal.goal_id for goal, _ in targets),
            )
            return self._validate_bundle_step(session, session.execution_bundle)
        return None

    def _next_sunshade_match_read(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        user_text = _latest_user_text(session)
        if user_text is None or not _requests_sunshade_match_to_sunroof(user_text):
            return None
        authorized = self._authorized_goal_ids(session)
        for item in prepared.goals:
            if (
                item.goal.goal_id not in authorized
                or item.goal.semantic_operation != "set_sunshade_position"
                or "percentage" in item.goal.desired_outcome
            ):
                continue
            existing = [
                need
                for need in session.evidence.needs.values()
                if need.required_for_goal_id == item.goal.goal_id
                and need.proposition == "sunroof_position"
            ]
            if any(session.evidence.satisfying_evidence(need) for need in existing):
                return None
            if existing:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            candidates = {
                (
                    binding.tool_name,
                    call_fingerprint(binding.tool_name, binding.arguments),
                ): binding
                for binding in item.bindings
                if binding.is_read
                and binding.is_complete
                and binding.semantic_operation == "read_sunroof_and_sunshade"
            }
            if len(candidates) != 1:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            binding = next(iter(candidates.values()))
            need = EvidenceNeed(
                proposition="sunroof_position",
                required_for_goal_id=item.goal.goal_id,
                acceptable_sources={"tool_result"},
                freshness="current_state",
            )
            session.evidence.register_need(need)
            assert need.need_id is not None
            call_id = session.next_call_id()
            proposal = DecisionProposal(
                kind=ProposalKind.TOOL_GET,
                goal_ids=[item.goal.goal_id],
                tool_calls=[
                    ProposedToolCall(
                        tool_name=binding.tool_name,
                        arguments=binding.arguments,
                        call_id=call_id,
                        goal_id=item.goal.goal_id,
                    )
                ],
            )
            decision = self.precommit.validate(
                proposal, self._basic_gate_context(session)
            )
            if decision.outcome is not GateOutcome.ALLOW:
                return self._route_gate_failure(session, proposal, decision, item.goal)
            return PlannedOutbound(
                self.adapter.serialize(decision),
                proposal=proposal,
                decision=decision,
                pending_need_ids={call_id: (need.need_id,)},
                policy_operations={call_id: "read_sunroof_and_sunshade"},
            )
        return None

    def _next_sunshade_match_action(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        user_text = _latest_user_text(session)
        if user_text is None or not _requests_sunshade_match_to_sunroof(user_text):
            return None
        matched = [
            item
            for item in prepared.goals
            if item.goal.semantic_operation == "set_sunshade_position"
            and "percentage" in item.goal.desired_outcome
            and any(
                need.required_for_goal_id == item.goal.goal_id
                and need.proposition == "sunroof_position"
                and session.evidence.satisfying_evidence(need)
                for need in session.evidence.needs.values()
            )
        ]
        if len(matched) != 1:
            return None
        return self._deterministic_bound_action(session, PreparedTurn(tuple(matched)))

    def _next_grounded_range_read(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            initial_soc = item.goal.desired_outcome.get("initial_soc")
            final_soc = item.goal.desired_outcome.get("final_soc")
            if (
                isinstance(initial_soc, bool)
                or isinstance(final_soc, bool)
                or not isinstance(initial_soc, int)
                or not isinstance(final_soc, int)
                or not 0 <= final_soc <= initial_soc <= 100
            ):
                continue
            distance_km = self._observed_range_km(session, item)
            if distance_km is not None:
                return self._text_plan(
                    session,
                    self.responses.range_estimate(
                        initial_soc=initial_soc,
                        final_soc=final_soc,
                        distance_km=distance_km,
                        language=self._language(session),
                    ),
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )
            if self._read_goal_has_result(session, item):
                continue
            candidates = {
                (
                    binding.tool_name,
                    call_fingerprint(binding.tool_name, binding.arguments),
                ): binding
                for binding in item.bindings
                if binding.is_read
                and binding.is_complete
                and binding.semantic_operation == "get_distance_by_soc"
            }
            if len(candidates) != 1:
                continue
            binding = next(iter(candidates.values()))
            call_id = session.next_call_id()
            proposal = DecisionProposal(
                kind=ProposalKind.TOOL_GET,
                goal_ids=[item.goal.goal_id],
                tool_calls=[
                    ProposedToolCall(
                        tool_name=binding.tool_name,
                        arguments=binding.arguments,
                        call_id=call_id,
                        goal_id=item.goal.goal_id,
                    )
                ],
            )
            decision = self.precommit.validate(
                proposal, self._basic_gate_context(session)
            )
            if decision.outcome is not GateOutcome.ALLOW:
                return self._route_gate_failure(session, proposal, decision, item.goal)
            return PlannedOutbound(
                self.adapter.serialize(decision),
                proposal=proposal,
                decision=decision,
                pending_need_ids={
                    call_id: item.read_need_ids.get(binding.tool_name, ())
                },
                policy_operations={call_id: binding.semantic_operation},
            )
        return None

    @staticmethod
    def _successful_goal_read(
        session: SessionState,
        *,
        goal_id: str,
        tool_name: str,
        arguments: Mapping[str, Any],
    ) -> SuccessfulReadResult | None:
        for observation in reversed(session.successful_read_results):
            if (
                goal_id in observation.goal_ids
                and observation.tool_name == tool_name
                and observation.state_version == session.evidence.current_state_version
                and _argument_value_matches_binding(
                    observation.arguments, dict(arguments)
                )
            ):
                return observation
        return None

    @classmethod
    def _adopt_displayed_poi_navigation_read(
        cls, session: SessionState, *, goal_id: str
    ) -> SuccessfulReadResult | None:
        current_version = session.evidence.current_state_version
        source_location_evidence_ids = {
            candidate.source_location_evidence_id
            for candidate in session.displayed_destination_pois
            if candidate.state_version == current_version
        }
        if not source_location_evidence_ids:
            return None
        for observation in reversed(session.successful_read_results):
            if (
                observation.state_version != current_version
                or observation.tool_name != "get_current_navigation_state"
                or not _argument_value_matches_binding(
                    observation.arguments, {"detailed_information": True}
                )
                or cls._navigation_state_signature(observation.value) is None
            ):
                continue
            evidence = cls._evidence_for_goal_read(
                session,
                goal_id=goal_id,
                proposition="current_navigation_state",
                observation=observation,
            )
            if (
                evidence is None
                or evidence.evidence_id not in source_location_evidence_ids
                or evidence.state_version != current_version
            ):
                continue
            adopted = SuccessfulReadResult(
                goal_ids=(goal_id,),
                tool_name=observation.tool_name,
                arguments=dict(observation.arguments),
                semantic_operation="read_current_navigation",
                call_id=observation.call_id,
                value=observation.value,
                source_turn_id=observation.source_turn_id,
                state_version=observation.state_version,
                task_id=observation.task_id,
            )
            session.successful_read_results.append(adopted)
            session.successful_read_results = session.successful_read_results[-128:]
            return adopted
        return None

    @staticmethod
    def _evidence_for_goal_read(
        session: SessionState,
        *,
        goal_id: str,
        proposition: str,
        observation: SuccessfulReadResult,
    ) -> Evidence | None:
        candidates: dict[str, Evidence] = {}
        for need in session.evidence.needs.values():
            if need.required_for_goal_id != goal_id or need.proposition != proposition:
                continue
            for evidence in session.evidence.satisfying_evidence(need):
                if (
                    evidence.source_tool_call_id == observation.call_id
                    and evidence.source_turn_id == observation.source_turn_id
                ):
                    assert evidence.evidence_id is not None
                    candidates[evidence.evidence_id] = evidence
        if len(candidates) != 1:
            return None
        return next(iter(candidates.values()))

    @staticmethod
    def _navigation_state_signature(
        value: Any,
    ) -> tuple[bool, tuple[str, ...], tuple[str, ...]] | None:
        if not isinstance(value, Mapping):
            return None
        active = value.get("navigation_active")
        waypoint_ids = value.get("waypoints_id")
        route_ids = value.get("routes_to_final_destination_id")
        if (
            not isinstance(active, bool)
            or not isinstance(waypoint_ids, list)
            or not isinstance(route_ids, list)
            or any(
                not isinstance(identifier, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(identifier) is None
                for identifier in waypoint_ids
            )
            or any(
                not isinstance(identifier, str)
                or _ROUTE_ID_PATTERN.fullmatch(identifier) is None
                for identifier in route_ids
            )
            or len(set(waypoint_ids)) != len(waypoint_ids)
            or len(set(route_ids)) != len(route_ids)
        ):
            return None
        if active:
            if (
                not 2 <= len(waypoint_ids) <= 15
                or len(route_ids) != len(waypoint_ids) - 1
            ):
                return None
        elif waypoint_ids or route_ids:
            return None
        return active, tuple(waypoint_ids), tuple(route_ids)

    @classmethod
    def _resumable_navigation_snapshot(
        cls,
        session: SessionState,
        *,
        goal_id: str,
    ) -> ResumableNavigationSnapshot | None:
        current_version = session.evidence.current_state_version
        observations = [
            observation
            for observation in session.successful_read_results
            if goal_id in observation.goal_ids
            and observation.tool_name == "get_current_navigation_state"
            and observation.state_version == current_version
            and _argument_value_matches_binding(
                observation.arguments, {"detailed_information": True}
            )
        ]
        if not observations:
            return None
        observation = observations[-1]
        if any(
            not _strict_equal(candidate.value, observation.value)
            for candidate in observations[:-1]
        ):
            return None
        evidence = cls._evidence_for_goal_read(
            session,
            goal_id=goal_id,
            proposition="current_navigation_state",
            observation=observation,
        )
        value = observation.value
        if (
            evidence is None
            or evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.TOOL
            or evidence.state_version != current_version
            or not _strict_equal(evidence.value, value)
            or not isinstance(value, Mapping)
            or value.get("navigation_active") is not False
        ):
            return None

        raw_waypoint_ids = value.get("waypoints_id")
        raw_route_ids = value.get("routes_to_final_destination_id")
        if (
            not isinstance(raw_waypoint_ids, list)
            or not 2 <= len(raw_waypoint_ids) <= 15
            or any(
                not isinstance(identifier, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(identifier) is None
                for identifier in raw_waypoint_ids
            )
            or len(set(raw_waypoint_ids)) != len(raw_waypoint_ids)
            or not isinstance(raw_route_ids, list)
            or len(raw_route_ids) != len(raw_waypoint_ids) - 1
            or any(
                not isinstance(identifier, str)
                or _ROUTE_ID_PATTERN.fullmatch(identifier) is None
                for identifier in raw_route_ids
            )
            or len(set(raw_route_ids)) != len(raw_route_ids)
        ):
            return None

        details = value.get("details")
        if not isinstance(details, Mapping):
            return None
        raw_waypoints = details.get("waypoints")
        raw_routes = details.get("routes")
        if (
            not isinstance(raw_waypoints, list)
            or len(raw_waypoints) != len(raw_waypoint_ids)
            or not isinstance(raw_routes, list)
            or len(raw_routes) != len(raw_route_ids)
        ):
            return None

        waypoint_names: list[str] = []
        for expected_id, waypoint in zip(raw_waypoint_ids, raw_waypoints, strict=True):
            if not isinstance(waypoint, Mapping):
                return None
            name = waypoint.get("name")
            if (
                waypoint.get("id") != expected_id
                or not isinstance(name, str)
                or not cls._voice_result_field(name, 80)
            ):
                return None
            waypoint_names.append(name.strip())

        total_distance = Decimal(0)
        total_minutes = 0
        includes_toll = False
        vias: list[str] = []
        for index, (expected_id, route) in enumerate(
            zip(raw_route_ids, raw_routes, strict=True)
        ):
            if not isinstance(route, Mapping):
                return None
            via = route.get("name_via")
            distance_value = route.get("distance_km")
            hours_value = route.get("duration_hours")
            minutes_value = route.get("duration_minutes")
            road_types = route.get("road_types")
            aliases = route.get("alias")
            route_toll = route.get("includes_toll")
            if (
                route.get("route_id") != expected_id
                or route.get("start_id") != raw_waypoint_ids[index]
                or route.get("destination_id") != raw_waypoint_ids[index + 1]
                or not isinstance(via, str)
                or _ROUTE_VIA_PATTERN.fullmatch(via.strip()) is None
                or isinstance(distance_value, bool)
                or isinstance(hours_value, bool)
                or isinstance(minutes_value, bool)
                or not isinstance(road_types, list)
                or not 1 <= len(road_types) <= 12
                or not isinstance(aliases, list)
                or not 1 <= len(aliases) <= 12
                or not isinstance(route_toll, bool)
                or any(
                    not isinstance(item, str) or not cls._voice_result_field(item, 80)
                    for item in [*road_types, *aliases]
                )
            ):
                return None
            try:
                distance = Decimal(str(distance_value))
                hours_decimal = Decimal(str(hours_value))
                minutes_decimal = Decimal(str(minutes_value))
                hours = int(hours_decimal)
                minutes = int(minutes_decimal)
            except (InvalidOperation, TypeError, ValueError):
                return None
            segment_minutes = hours * 60 + minutes
            if (
                not distance.is_finite()
                or distance <= 0
                or not hours_decimal.is_finite()
                or not minutes_decimal.is_finite()
                or hours_decimal != hours
                or minutes_decimal != minutes
                or not 0 <= hours <= 240
                or not 0 <= minutes <= 59
                or segment_minutes <= 0
            ):
                return None
            total_distance += distance
            total_minutes += segment_minutes
            includes_toll = includes_toll or route_toll
            vias.append(via.strip())

        return ResumableNavigationSnapshot(
            evidence=evidence,
            waypoint_ids=tuple(raw_waypoint_ids),
            route_ids=tuple(raw_route_ids),
            waypoint_names=tuple(waypoint_names),
            vias=tuple(vias),
            distance_km=total_distance,
            duration_minutes=total_minutes,
            includes_toll=includes_toll,
        )

    @staticmethod
    def _navigation_resume_goal(session: SessionState) -> Goal | None:
        if session.intent is None:
            return None
        matches = [
            goal
            for goal in session.intent.goals
            if goal.semantic_operation == _NAVIGATION_RESUME
        ]
        return matches[0] if len(matches) == 1 else None

    @classmethod
    def _resumable_navigation_snapshot_is_current(
        cls,
        session: SessionState,
        *,
        goal_id: str,
        expected_route_ids: Sequence[str] | None = None,
    ) -> bool:
        snapshot = cls._resumable_navigation_snapshot(session, goal_id=goal_id)
        current_location = getattr(session.compiled_policy, "current_location", None)
        current_location_id = (
            current_location.get("id")
            if isinstance(current_location, Mapping)
            else None
        )
        return bool(
            snapshot is not None
            and isinstance(current_location_id, str)
            and _LOCATION_OR_POI_ID_PATTERN.fullmatch(current_location_id) is not None
            and snapshot.waypoint_ids[0] == current_location_id
            and (
                expected_route_ids is None
                or tuple(expected_route_ids) == snapshot.route_ids
            )
        )

    @classmethod
    def _expected_navigation_after_recent_waypoint_add(
        cls, session: SessionState
    ) -> tuple[tuple[str, ...], tuple[str, ...]] | None:
        current_version = session.evidence.current_state_version
        candidates: list[tuple[tuple[str, ...], tuple[str, ...]]] = []
        for goal_id, calls in session.completed_action_calls_by_goal.items():
            add_calls = [
                call
                for call in calls
                if call.tool_name == "navigation_add_one_waypoint"
            ]
            if len(add_calls) != 1:
                continue
            call = add_calls[0]
            old_reads = [
                observation
                for observation in session.successful_read_results
                if goal_id in observation.goal_ids
                and observation.tool_name == "get_current_navigation_state"
                and observation.state_version + 1 == current_version
                and _argument_value_matches_binding(
                    observation.arguments, {"detailed_information": True}
                )
            ]
            if len(old_reads) != 1:
                continue
            signature = cls._navigation_state_signature(old_reads[0].value)
            if signature is None or not signature[0]:
                continue
            _, old_waypoints, old_routes = signature
            before_id = call.arguments.get("waypoint_id_before_new_waypoint")
            after_id = call.arguments.get("waypoint_id_after_new_waypoint")
            added_id = call.arguments.get("waypoint_id_to_add")
            route_to_id = call.arguments.get("route_id_leading_to_new_waypoint")
            route_from_id = call.arguments.get(
                "route_id_leading_away_from_new_waypoint"
            )
            if (
                not isinstance(before_id, str)
                or not isinstance(after_id, str)
                or not isinstance(added_id, str)
                or not isinstance(route_to_id, str)
                or not isinstance(route_from_id, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(added_id) is None
                or _ROUTE_ID_PATTERN.fullmatch(route_to_id) is None
                or _ROUTE_ID_PATTERN.fullmatch(route_from_id) is None
                or added_id in old_waypoints
            ):
                continue
            insertion_indexes = tuple(
                index
                for index in range(len(old_waypoints) - 1)
                if old_waypoints[index] == before_id
                and old_waypoints[index + 1] == after_id
            )
            if len(insertion_indexes) != 1:
                continue
            index = insertion_indexes[0]
            expected_waypoints = (
                *old_waypoints[: index + 1],
                added_id,
                *old_waypoints[index + 1 :],
            )
            expected_routes = (
                *old_routes[:index],
                route_to_id,
                route_from_id,
                *old_routes[index + 1 :],
            )
            if len(set(expected_routes)) != len(expected_routes):
                continue
            candidates.append((expected_waypoints, expected_routes))
        return candidates[0] if len(candidates) == 1 else None

    def _destination_navigation_snapshot_is_current(
        self, session: SessionState, *, goal_id: str
    ) -> bool:
        bound = self._successful_goal_read(
            session,
            goal_id=goal_id,
            tool_name="get_current_navigation_state",
            arguments={"detailed_information": True},
        )
        if bound is None:
            return False
        reads = [
            observation
            for observation in session.successful_read_results
            if goal_id in observation.goal_ids
            and observation.tool_name == "get_current_navigation_state"
            and observation.state_version == session.evidence.current_state_version
        ]
        if not reads:
            return False
        bound_signature = self._navigation_state_signature(bound.value)
        latest_signature = self._navigation_state_signature(reads[-1].value)
        return bound_signature is not None and latest_signature == bound_signature

    @classmethod
    def _navigation_state_view(
        cls,
        session: SessionState,
        *,
        goal_id: str,
        proposition: str = "current_navigation_state",
    ) -> NavigationStateView | None:
        observation: SuccessfulReadResult | None = None
        evidence: Evidence | None = None
        for candidate in reversed(session.successful_read_results):
            if (
                goal_id not in candidate.goal_ids
                or candidate.tool_name != "get_current_navigation_state"
                or candidate.state_version != session.evidence.current_state_version
                or not _argument_value_matches_binding(
                    candidate.arguments, {"detailed_information": True}
                )
            ):
                continue
            candidate_evidence = cls._evidence_for_goal_read(
                session,
                goal_id=goal_id,
                proposition=proposition,
                observation=candidate,
            )
            if candidate_evidence is not None:
                observation = candidate
                evidence = candidate_evidence
                break
        if (
            observation is None
            or evidence is None
            or not isinstance(observation.value, Mapping)
        ):
            return None

        active = observation.value.get("navigation_active")
        if not isinstance(active, bool):
            return None
        if not active:
            return NavigationStateView(
                evidence=evidence,
                active=False,
                waypoint_ids=(),
            )

        raw_waypoint_ids = observation.value.get("waypoints_id")
        raw_route_ids = observation.value.get("routes_to_final_destination_id")
        if (
            not isinstance(raw_waypoint_ids, list)
            or not 2 <= len(raw_waypoint_ids) <= 15
            or any(
                not isinstance(value, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(value) is None
                for value in raw_waypoint_ids
            )
            or len(set(raw_waypoint_ids)) != len(raw_waypoint_ids)
            or not isinstance(raw_route_ids, list)
            or len(raw_route_ids) != len(raw_waypoint_ids) - 1
            or len(set(raw_route_ids)) != len(raw_route_ids)
            or any(
                not isinstance(value, str) or _ROUTE_ID_PATTERN.fullmatch(value) is None
                for value in raw_route_ids
            )
        ):
            return None

        waypoint_names: tuple[str, ...] = ()
        details = observation.value.get("details")
        if isinstance(details, Mapping):
            raw_waypoints = details.get("waypoints")
            if not isinstance(raw_waypoints, list) or len(raw_waypoints) != len(
                raw_waypoint_ids
            ):
                return None
            names: list[str] = []
            for expected_id, waypoint in zip(
                raw_waypoint_ids, raw_waypoints, strict=True
            ):
                if not isinstance(waypoint, Mapping):
                    return None
                waypoint_id = waypoint.get("id")
                name = waypoint.get("name")
                if (
                    waypoint_id != expected_id
                    or not isinstance(name, str)
                    or not cls._voice_result_field(name, 80)
                ):
                    return None
                names.append(name.strip())
            waypoint_names = tuple(names)
        return NavigationStateView(
            evidence=evidence,
            active=True,
            waypoint_ids=tuple(raw_waypoint_ids),
            route_ids=tuple(raw_route_ids),
            waypoint_names=waypoint_names,
        )

    @staticmethod
    def _named_final_destination_delete_matches(
        goal: Goal, state: NavigationStateView
    ) -> bool:
        selectors = (
            ("destination_name_to_delete", len(state.waypoint_ids) - 1),
            ("remaining_destination_name", len(state.waypoint_ids) - 2),
        )
        present = [
            (name, expected_index)
            for name, expected_index in selectors
            if name in goal.desired_outcome
        ]
        if not present:
            return True
        if len(state.waypoint_names) != len(state.waypoint_ids):
            return False

        normalized: dict[str, str] = {}
        for name, expected_index in present:
            selected = goal.desired_outcome.get(name)
            if not isinstance(selected, str) or not selected.strip():
                return False
            wanted = _argument_identifier(selected)
            matches = tuple(
                index
                for index, waypoint_name in enumerate(state.waypoint_names)
                if _argument_identifier(waypoint_name) == wanted
            )
            if matches != (expected_index,):
                return False
            normalized[name] = wanted
        return len(set(normalized.values())) == len(normalized)

    def _convert_generic_named_delete_to_waypoint(
        self,
        session: SessionState,
        *,
        goal: Goal,
        state: NavigationStateView,
    ) -> bool:
        if (
            session.intent is None
            or goal.semantic_operation != _NAVIGATION_DELETE_DESTINATION
            or "remaining_destination_name" in goal.desired_outcome
        ):
            return False
        selected = goal.desired_outcome.get("destination_name_to_delete")
        if not isinstance(selected, str) or not selected.strip():
            return False
        converted = goal.model_copy(
            update={
                "semantic_operation": _NAVIGATION_DELETE_WAYPOINT,
                "desired_outcome": {"waypoint_name_to_delete": selected},
            },
            deep=True,
        )
        if self._named_waypoint_delete_index(converted, state) is None:
            return False
        source = session.grounded_value_sources_by_goal.get(goal.goal_id, {}).get(
            "destination_name_to_delete"
        )
        if not isinstance(source, str):
            return False
        session.intent = session.intent.model_copy(
            update={
                "goals": [
                    converted if candidate.goal_id == goal.goal_id else candidate
                    for candidate in session.intent.goals
                ],
                "explicit_slots": {"waypoint_name_to_delete": selected},
                "unresolved_slots": [],
            },
            deep=True,
        )
        session.grounded_desired_values_by_goal[goal.goal_id] = {
            "waypoint_name_to_delete": selected
        }
        session.grounded_value_sources_by_goal[goal.goal_id] = {
            "waypoint_name_to_delete": source
        }
        session.derived_value_evidence_by_goal[goal.goal_id] = {}
        session.pending_clarifications.clear()
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True

    @staticmethod
    def _named_waypoint_delete_index(
        goal: Goal, state: NavigationStateView
    ) -> int | None:
        if len(state.waypoint_ids) < 3:
            return None
        intermediate = tuple(range(1, len(state.waypoint_ids) - 1))
        selected_id = goal.desired_outcome.get("waypoint_id")
        selected_name = goal.desired_outcome.get("waypoint_name_to_delete")
        if isinstance(selected_id, str):
            if _LOCATION_OR_POI_ID_PATTERN.fullmatch(selected_id) is None:
                return None
            matches = tuple(
                index
                for index in intermediate
                if state.waypoint_ids[index] == selected_id
            )
        elif isinstance(selected_name, str) and selected_name.strip():
            if len(state.waypoint_names) != len(state.waypoint_ids):
                return None
            wanted = _argument_identifier(selected_name)
            matches = tuple(
                index
                for index in intermediate
                if _argument_identifier(state.waypoint_names[index]) == wanted
            )
        else:
            return None
        if len(matches) != 1:
            return None

        remaining = goal.desired_outcome.get("remaining_destination_name")
        if remaining is not None:
            if (
                not isinstance(remaining, str)
                or not remaining.strip()
                or len(state.waypoint_names) != len(state.waypoint_ids)
            ):
                return None
            wanted_destination = _argument_identifier(remaining)
            destination_matches = tuple(
                index
                for index, name in enumerate(state.waypoint_names)
                if _argument_identifier(name) == wanted_destination
            )
            if (
                destination_matches != (len(state.waypoint_ids) - 1,)
                or matches[0] != len(state.waypoint_ids) - 2
            ):
                return None
        route_destination = goal.desired_outcome.get("route_destination_name")
        if route_destination is not None:
            if (
                not isinstance(route_destination, str)
                or not route_destination.strip()
                or len(state.waypoint_names) != len(state.waypoint_ids)
            ):
                return None
            wanted_route_destination = _argument_identifier(route_destination)
            route_destination_matches = tuple(
                index
                for index, name in enumerate(state.waypoint_names)
                if _argument_identifier(name) == wanted_route_destination
            )
            if route_destination_matches != (len(state.waypoint_ids) - 1,):
                return None
        return matches[0]

    @staticmethod
    def _matching_waypoint_indexes(
        goal: Goal, state: NavigationStateView
    ) -> tuple[int, ...]:
        intermediate = tuple(range(1, len(state.waypoint_ids) - 1))
        selected_id = goal.desired_outcome.get("waypoint_id_to_replace")
        if (
            isinstance(selected_id, str)
            and _LOCATION_OR_POI_ID_PATTERN.fullmatch(selected_id) is not None
        ):
            return tuple(
                index
                for index in intermediate
                if state.waypoint_ids[index] == selected_id
            )
        selected_name = goal.desired_outcome.get("waypoint_name_to_replace")
        if isinstance(selected_name, str) and selected_name.strip():
            if len(state.waypoint_names) != len(state.waypoint_ids):
                return ()
            wanted = _argument_identifier(selected_name)
            return tuple(
                index
                for index in intermediate
                if _argument_identifier(state.waypoint_names[index]) == wanted
            )
        return intermediate if len(intermediate) == 1 else ()

    @staticmethod
    def _named_add_after_index(goal: Goal, state: NavigationStateView) -> int | None:
        if len(state.waypoint_ids) < 2 or len(state.waypoint_names) != len(
            state.waypoint_ids
        ):
            return None
        candidates = tuple(range(len(state.waypoint_ids)))
        selected_id = goal.desired_outcome.get("previous_waypoint_id")
        selected_name = goal.desired_outcome.get("previous_waypoint_name")
        if isinstance(selected_id, str):
            if _LOCATION_OR_POI_ID_PATTERN.fullmatch(selected_id) is None:
                return None
            matches = tuple(
                index
                for index in candidates
                if state.waypoint_ids[index] == selected_id
            )
        elif isinstance(selected_name, str) and selected_name.strip():
            wanted = _argument_identifier(selected_name)
            matches = tuple(
                index
                for index in candidates
                if _argument_identifier(state.waypoint_names[index]) == wanted
            )
        else:
            next_id = goal.desired_outcome.get("next_waypoint_id")
            next_name = goal.desired_outcome.get("next_waypoint_name")
            next_candidates = tuple(range(1, len(state.waypoint_ids)))
            if isinstance(next_id, str):
                if _LOCATION_OR_POI_ID_PATTERN.fullmatch(next_id) is None:
                    return None
                next_matches = tuple(
                    candidate
                    for candidate in next_candidates
                    if state.waypoint_ids[candidate] == next_id
                )
            elif isinstance(next_name, str) and next_name.strip():
                wanted = _argument_identifier(next_name)
                next_matches = tuple(
                    candidate
                    for candidate in next_candidates
                    if _argument_identifier(state.waypoint_names[candidate]) == wanted
                )
            else:
                return None
            if len(next_matches) != 1:
                return None
            index = next_matches[0] - 1
            matches = (index,)
        if len(matches) != 1:
            return None

        index = matches[0]
        next_id = goal.desired_outcome.get("next_waypoint_id")
        next_name = goal.desired_outcome.get("next_waypoint_name")
        if index == len(state.waypoint_ids) - 1:
            return index if next_id is None and next_name is None else None
        if next_id is not None:
            if (
                not isinstance(next_id, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(next_id) is None
                or state.waypoint_ids[index + 1] != next_id
            ):
                return None
        if next_name is not None:
            if (
                not isinstance(next_name, str)
                or not next_name.strip()
                or _argument_identifier(state.waypoint_names[index + 1])
                != _argument_identifier(next_name)
            ):
                return None
        return index

    @classmethod
    def _strict_fastest_route_id_from_evidence(
        cls,
        evidence: Evidence,
        *,
        start_id: str,
        destination_id: str,
    ) -> str | None:
        options = cls._destination_route_options_from_evidence(
            evidence,
            start_id=start_id,
            destination_id=destination_id,
        )
        if options is None:
            return None
        fastest = [option.route_id for option in options if "fastest" in option.aliases]
        return fastest[0] if len(fastest) == 1 else None

    @classmethod
    def _navigation_edit_route_id_from_evidence(
        cls,
        goal: Goal,
        evidence: Evidence,
        *,
        start_id: str,
        destination_id: str,
    ) -> str | None:
        options = cls._destination_route_options_from_evidence(
            evidence,
            start_id=start_id,
            destination_id=destination_id,
        )
        if options is None:
            return None
        route_choice = goal.desired_outcome.get("route_choice_alias", "fastest")
        if not isinstance(route_choice, str):
            return None
        normalized = _argument_identifier(route_choice)
        if normalized not in {*_ROUTE_ORDINALS, "fastest", "shortest"}:
            return None
        selected = tuple(
            option
            for option in options
            if option.ordinal == normalized or normalized in option.aliases
        )
        return selected[0].route_id if len(selected) == 1 else None

    def _derived_navigation_read_value(
        self,
        session: SessionState,
        *,
        goal_id: str,
        tool_name: str,
        arguments: Mapping[str, Any],
        proposition: str,
    ) -> tuple[Any, Evidence] | None:
        observation = self._successful_goal_read(
            session,
            goal_id=goal_id,
            tool_name=tool_name,
            arguments=arguments,
        )
        if observation is None:
            return None
        evidence = self._evidence_for_goal_read(
            session,
            goal_id=goal_id,
            proposition=proposition,
            observation=observation,
        )
        if evidence is None:
            return None
        return evidence.value, evidence

    def _apply_navigation_derived_parameters(
        self,
        session: SessionState,
        *,
        goal: Goal,
        parameters: Mapping[str, tuple[Any, tuple[Evidence, ...], str]],
    ) -> None:
        if session.intent is None or not parameters:
            return
        desired = dict(goal.desired_outcome)
        grounded = dict(session.grounded_desired_values_by_goal.get(goal.goal_id, {}))
        sources = dict(session.grounded_value_sources_by_goal.get(goal.goal_id, {}))
        derived_ids = dict(session.derived_value_evidence_by_goal.get(goal.goal_id, {}))
        changed = False
        for name, (value, parents, derivation) in parameters.items():
            parent_ids = [
                parent.evidence_id
                for parent in parents
                if parent.evidence_id is not None
            ]
            if not parent_ids or len(parent_ids) != len(parents):
                continue
            observation = Evidence(
                proposition=f"derived_argument:{goal.goal_id}:{name}",
                value=value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"navigation-derived-{goal.goal_id}",
                confidence=min(parent.confidence for parent in parents),
                derived_from=parent_ids,
                derivation=derivation,
            )
            session.evidence.add(observation)
            stored = session.evidence.for_proposition(observation.proposition)[-1]
            assert stored.evidence_id is not None
            if (
                desired.get(name) != value
                or derived_ids.get(name) != stored.evidence_id
            ):
                changed = True
            desired[name] = value
            grounded[name] = value
            sources.pop(name, None)
            derived_ids[name] = stored.evidence_id
        if not changed:
            return
        session.grounded_desired_values_by_goal[goal.goal_id] = grounded
        session.grounded_value_sources_by_goal[goal.goal_id] = sources
        session.derived_value_evidence_by_goal[goal.goal_id] = derived_ids
        goals = [
            item.model_copy(update={"desired_outcome": desired}, deep=True)
            if item.goal_id == goal.goal_id
            else item.model_copy(deep=True)
            for item in session.intent.goals
        ]
        session.intent = session.intent.model_copy(update={"goals": goals}, deep=True)
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)

    @staticmethod
    def _record_navigation_policy_facts(
        session: SessionState, *, goal_id: str, state: NavigationStateView
    ) -> None:
        parent_id = state.evidence.evidence_id
        if parent_id is None:
            return
        source_turn_id = f"navigation-policy-facts-{goal_id}"
        facts = {
            "navigation_active": state.active,
            "waypoints": list(state.waypoint_ids),
        }
        for proposition, value in facts.items():
            existing = [
                evidence
                for evidence in session.evidence.evidence.values()
                if evidence.proposition == proposition
                and evidence.source_turn_id == source_turn_id
                and evidence.source_kind is EvidenceSourceKind.DERIVED
                and evidence.status is EvidenceStatus.KNOWN
                and evidence.value == value
                and evidence.derived_from == [parent_id]
                and evidence.state_version == session.evidence.current_state_version
            ]
            if existing:
                continue
            session.evidence.add(
                Evidence(
                    proposition=proposition,
                    value=value,
                    status=EvidenceStatus.KNOWN,
                    source_kind=EvidenceSourceKind.DERIVED,
                    source_turn_id=source_turn_id,
                    confidence=state.evidence.confidence,
                    derived_from=[parent_id],
                    derivation="validated_detailed_navigation_policy_fact_v1",
                )
            )

    def _materialize_navigation_edit_goal_parameters(
        self, session: SessionState
    ) -> None:
        if session.intent is None:
            return
        for goal in tuple(session.intent.goals):
            if goal.semantic_operation not in {
                _NAVIGATION_ADD_WAYPOINT,
                _NAVIGATION_REPLACE_WAYPOINT,
                _NAVIGATION_DELETE_WAYPOINT,
                _NAVIGATION_DELETE_DESTINATION,
            }:
                continue
            state = self._navigation_state_view(session, goal_id=goal.goal_id)
            if state is None or not state.active:
                continue
            if goal.semantic_operation == _NAVIGATION_ADD_WAYPOINT:
                index = self._named_add_after_index(goal, state)
                if index is None:
                    continue
                location_name = goal.desired_outcome.get("new_waypoint_name")
                if not isinstance(location_name, str) or not location_name.strip():
                    continue
                resolved = self._derived_navigation_read_value(
                    session,
                    goal_id=goal.goal_id,
                    tool_name="get_location_id_by_location_name",
                    arguments={"location": location_name},
                    proposition="resolved_navigation_location_id",
                )
                if resolved is None:
                    continue
                new_waypoint_id, added_location_evidence = resolved
                if (
                    not isinstance(new_waypoint_id, str)
                    or not new_waypoint_id.startswith("loc_")
                    or _LOCATION_OR_POI_ID_PATTERN.fullmatch(new_waypoint_id) is None
                    or new_waypoint_id in state.waypoint_ids
                ):
                    continue
                previous_id = state.waypoint_ids[index]
                append_to_final = index == len(state.waypoint_ids) - 1
                next_id = None if append_to_final else state.waypoint_ids[index + 1]
                route_choice = goal.desired_outcome.get("route_choice_alias")
                uses_fastest_default = route_choice is None or (
                    isinstance(route_choice, str)
                    and _argument_identifier(route_choice) == "fastest"
                )
                add_parameters: dict[str, tuple[Any, tuple[Evidence, ...], str]] = {
                    "new_waypoint_id": (
                        new_waypoint_id,
                        (added_location_evidence,),
                        "resolved_added_waypoint_location_v1",
                    ),
                    "previous_waypoint_id": (
                        previous_id,
                        (state.evidence,),
                        "added_waypoint_neighbor_before_v1",
                    ),
                }
                if next_id is not None:
                    add_parameters["next_waypoint_id"] = (
                        next_id,
                        (state.evidence,),
                        "added_waypoint_neighbor_after_v1",
                    )
                selected_route_to: tuple[str, Evidence] | None = None
                route_to = self._derived_navigation_read_value(
                    session,
                    goal_id=goal.goal_id,
                    tool_name="get_routes_from_start_to_destination",
                    arguments={
                        "start_id": previous_id,
                        "destination_id": new_waypoint_id,
                    },
                    proposition="route_to_replacement_options",
                )
                if route_to is not None:
                    _, route_to_evidence = route_to
                    route_id = self._navigation_edit_route_id_from_evidence(
                        goal,
                        route_to_evidence,
                        start_id=previous_id,
                        destination_id=new_waypoint_id,
                    )
                    if route_id is not None:
                        add_parameters["route_id_leading_to_waypoint"] = (
                            route_id,
                            (
                                state.evidence,
                                added_location_evidence,
                                route_to_evidence,
                            ),
                            (
                                "verified_fastest_route_to_added_waypoint_v1"
                                if uses_fastest_default
                                else "verified_selected_route_to_added_waypoint_v1"
                            ),
                        )
                        selected_route_to = (route_id, route_to_evidence)
                selected_route_from: tuple[str, Evidence] | None = None
                if next_id is not None:
                    route_from = self._derived_navigation_read_value(
                        session,
                        goal_id=goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments={
                            "start_id": new_waypoint_id,
                            "destination_id": next_id,
                        },
                        proposition="route_from_replacement_options",
                    )
                    if route_from is not None:
                        _, route_from_evidence = route_from
                        route_id = self._navigation_edit_route_id_from_evidence(
                            goal,
                            route_from_evidence,
                            start_id=new_waypoint_id,
                            destination_id=next_id,
                        )
                        if route_id is not None:
                            add_parameters[
                                "route_id_leading_away_from_waypoint"
                            ] = (
                                route_id,
                                (
                                    state.evidence,
                                    added_location_evidence,
                                    route_from_evidence,
                                ),
                                (
                                    "verified_fastest_route_from_added_waypoint_v1"
                                    if uses_fastest_default
                                    else "verified_selected_route_from_added_waypoint_v1"
                                ),
                            )
                            selected_route_from = (route_id, route_from_evidence)
                if selected_route_to is not None and (
                    append_to_final or selected_route_from is not None
                ):
                    route_to_id, route_to_evidence = selected_route_to
                    evidence_parents = (
                        state.evidence,
                        added_location_evidence,
                        route_to_evidence,
                        *(
                            (selected_route_from[1],)
                            if selected_route_from is not None
                            else ()
                        ),
                    )
                    expected_waypoints = [
                        *state.waypoint_ids[: index + 1],
                        new_waypoint_id,
                        *state.waypoint_ids[index + 1 :],
                    ]
                    expected_routes = [
                        *state.route_ids[:index],
                        route_to_id,
                        *(
                            [selected_route_from[0]]
                            if selected_route_from is not None
                            else []
                        ),
                        *state.route_ids[index + 1 :],
                    ]
                    add_parameters["expected_post_waypoint_ids"] = (
                        expected_waypoints,
                        evidence_parents,
                        "verified_waypoints_after_add_v1",
                    )
                    add_parameters["expected_post_route_ids"] = (
                        expected_routes,
                        evidence_parents,
                        "verified_routes_after_add_v1",
                    )
                self._apply_navigation_derived_parameters(
                    session, goal=goal, parameters=add_parameters
                )
                continue
            if goal.semantic_operation == _NAVIGATION_DELETE_WAYPOINT:
                index = self._named_waypoint_delete_index(goal, state)
                if index is None:
                    continue
                self._apply_navigation_derived_parameters(
                    session,
                    goal=goal,
                    parameters={
                        "delete_route_start_id": (
                            state.waypoint_ids[index - 1],
                            (state.evidence,),
                            "deleted_waypoint_neighbor_before_v1",
                        ),
                        "delete_route_destination_id": (
                            state.waypoint_ids[index + 1],
                            (state.evidence,),
                            "deleted_waypoint_neighbor_after_v1",
                        ),
                    },
                )
                continue
            if goal.semantic_operation == _NAVIGATION_DELETE_DESTINATION:
                if len(state.waypoint_ids) <= 2:
                    continue
                if not self._named_final_destination_delete_matches(goal, state):
                    continue
                self._apply_navigation_derived_parameters(
                    session,
                    goal=goal,
                    parameters={
                        "destination_id": (
                            state.waypoint_ids[-1],
                            (state.evidence,),
                            "current_navigation_final_destination_v1",
                        )
                    },
                )
                continue

            indexes = self._matching_waypoint_indexes(goal, state)
            if len(indexes) != 1:
                continue
            index = indexes[0]
            old_waypoint_id = state.waypoint_ids[index]
            previous_id = state.waypoint_ids[index - 1]
            next_id = state.waypoint_ids[index + 1]

            new_waypoint_id = goal.desired_outcome.get("new_waypoint_id")
            location_evidence: Evidence | None = None
            if (
                not isinstance(new_waypoint_id, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(new_waypoint_id) is None
            ):
                location_name = goal.desired_outcome.get("new_waypoint_name")
                if not isinstance(location_name, str) or not location_name.strip():
                    continue
                resolved = self._derived_navigation_read_value(
                    session,
                    goal_id=goal.goal_id,
                    tool_name="get_location_id_by_location_name",
                    arguments={"location": location_name},
                    proposition="resolved_navigation_location_id",
                )
                if resolved is None:
                    continue
                resolved_value, location_evidence = resolved
                if (
                    not isinstance(resolved_value, str)
                    or _LOCATION_OR_POI_ID_PATTERN.fullmatch(resolved_value) is None
                ):
                    continue
                new_waypoint_id = resolved_value

            new_parent = location_evidence or state.evidence
            parameters: dict[str, tuple[Any, tuple[Evidence, ...], str]] = {
                "waypoint_id_to_replace": (
                    old_waypoint_id,
                    (state.evidence,),
                    "selected_intermediate_waypoint_v1",
                ),
                "replacement_previous_waypoint_id": (
                    previous_id,
                    (state.evidence,),
                    "replacement_neighbor_before_v1",
                ),
                "replacement_new_waypoint_id": (
                    new_waypoint_id,
                    (new_parent,),
                    "resolved_replacement_waypoint_v1",
                ),
                "replacement_next_waypoint_id": (
                    next_id,
                    (state.evidence,),
                    "replacement_neighbor_after_v1",
                ),
            }
            if location_evidence is not None:
                parameters["new_waypoint_id"] = (
                    new_waypoint_id,
                    (location_evidence,),
                    "resolved_replacement_location_v1",
                )
            route_choice = goal.desired_outcome.get("route_choice_alias")
            uses_fastest_default = route_choice is None or (
                isinstance(route_choice, str)
                and _argument_identifier(route_choice) == "fastest"
            )

            route_to_arguments = {
                "start_id": previous_id,
                "destination_id": new_waypoint_id,
            }
            route_to = self._derived_navigation_read_value(
                session,
                goal_id=goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_to_arguments,
                proposition="route_to_replacement_options",
            )
            replacement_route_to: tuple[str, Evidence] | None = None
            if route_to is not None:
                _, route_to_evidence = route_to
                route_id = self._navigation_edit_route_id_from_evidence(
                    goal,
                    route_to_evidence,
                    start_id=previous_id,
                    destination_id=new_waypoint_id,
                )
                if route_id is not None:
                    parameters["route_id_leading_to_new_waypoint"] = (
                        route_id,
                        (route_to_evidence,),
                        (
                            "unique_fastest_route_to_replacement_v1"
                            if uses_fastest_default
                            else "unique_selected_route_to_replacement_v1"
                        ),
                    )
                    replacement_route_to = (route_id, route_to_evidence)

            route_from_arguments = {
                "start_id": new_waypoint_id,
                "destination_id": next_id,
            }
            route_from = self._derived_navigation_read_value(
                session,
                goal_id=goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_from_arguments,
                proposition="route_from_replacement_options",
            )
            replacement_route_from: tuple[str, Evidence] | None = None
            if route_from is not None:
                _, route_from_evidence = route_from
                route_id = self._navigation_edit_route_id_from_evidence(
                    goal,
                    route_from_evidence,
                    start_id=new_waypoint_id,
                    destination_id=next_id,
                )
                if route_id is not None:
                    parameters["route_id_leading_away_from_new_waypoint"] = (
                        route_id,
                        (route_from_evidence,),
                        (
                            "unique_fastest_route_from_replacement_v1"
                            if uses_fastest_default
                            else "unique_selected_route_from_replacement_v1"
                        ),
                    )
                    replacement_route_from = (route_id, route_from_evidence)
            if (
                replacement_route_to is not None
                and replacement_route_from is not None
            ):
                route_evidence = (
                    state.evidence,
                    replacement_route_to[1],
                    replacement_route_from[1],
                )
                parameters["expected_post_waypoint_ids"] = (
                    [
                        *state.waypoint_ids[:index],
                        new_waypoint_id,
                        *state.waypoint_ids[index + 1 :],
                    ],
                    route_evidence,
                    "verified_waypoints_after_replace_v1",
                )
                parameters["expected_post_route_ids"] = (
                    [
                        *state.route_ids[: index - 1],
                        replacement_route_to[0],
                        replacement_route_from[0],
                        *state.route_ids[index + 1 :],
                    ],
                    route_evidence,
                    "verified_routes_after_replace_v1",
                )
            self._apply_navigation_derived_parameters(
                session, goal=goal, parameters=parameters
            )

    def _navigation_read_plan(
        self,
        session: SessionState,
        *,
        item: PreparedGoal,
        tool_name: str,
        arguments: Mapping[str, Any],
        semantic_operation: str,
        proposition: str,
    ) -> PlannedOutbound:
        if not session.live_tools.has_tool(tool_name):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
            )
        try:
            validated = session.live_tools.validate_arguments(
                tool_name, dict(arguments)
            )
        except ToolArgumentValidationError:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
            )
        need_ids = tuple(
            need.need_id
            for need in session.evidence.needs.values()
            if need.required_for_goal_id == item.goal.goal_id
            and need.proposition == proposition
            and need.need_id is not None
        )
        if len(need_ids) != 1:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        call_id = session.next_call_id()
        proposal = DecisionProposal(
            kind=ProposalKind.TOOL_GET,
            goal_ids=[item.goal.goal_id],
            tool_calls=[
                ProposedToolCall(
                    tool_name=tool_name,
                    arguments=validated,
                    call_id=call_id,
                    goal_id=item.goal.goal_id,
                )
            ],
        )
        decision = self.precommit.validate(proposal, self._basic_gate_context(session))
        if decision.outcome is not GateOutcome.ALLOW:
            return self._route_gate_failure(session, proposal, decision, item.goal)
        return PlannedOutbound(
            self.adapter.serialize(decision),
            proposal=proposal,
            decision=decision,
            pending_need_ids={call_id: need_ids},
            policy_operations={call_id: semantic_operation},
        )

    def _parallel_navigation_read_plan(
        self,
        session: SessionState,
        *,
        item: PreparedGoal,
        specifications: Sequence[tuple[str, Mapping[str, Any], str, str]],
    ) -> PlannedOutbound:
        if not specifications or len({item[0] for item in specifications}) != len(
            specifications
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        proposed_calls: list[ProposedToolCall] = []
        pending_need_ids: dict[str, tuple[str, ...]] = {}
        policy_operations: dict[str, str | None] = {}
        for tool_name, raw_arguments, semantic_operation, proposition in specifications:
            if not session.live_tools.has_tool(tool_name):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            try:
                arguments = session.live_tools.validate_arguments(
                    tool_name, dict(raw_arguments)
                )
            except ToolArgumentValidationError:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            need_ids = tuple(
                need.need_id
                for need in session.evidence.needs.values()
                if need.required_for_goal_id == item.goal.goal_id
                and need.proposition == proposition
                and need.need_id is not None
            )
            if len(need_ids) != 1:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            call_id = session.next_call_id()
            proposed_calls.append(
                ProposedToolCall(
                    tool_name=tool_name,
                    arguments=arguments,
                    call_id=call_id,
                    goal_id=item.goal.goal_id,
                )
            )
            pending_need_ids[call_id] = need_ids
            policy_operations[call_id] = semantic_operation
        proposal = DecisionProposal(
            kind=ProposalKind.TOOL_GET,
            goal_ids=[item.goal.goal_id],
            tool_calls=proposed_calls,
        )
        decision = self.precommit.validate(proposal, self._basic_gate_context(session))
        if decision.outcome is not GateOutcome.ALLOW:
            return self._route_gate_failure(session, proposal, decision, item.goal)
        return PlannedOutbound(
            self.adapter.serialize(decision),
            proposal=proposal,
            decision=decision,
            pending_need_ids=pending_need_ids,
            policy_operations=policy_operations,
        )

    @staticmethod
    def _remember_exact_location_resolution(
        session: SessionState,
        *,
        literal_name: str,
        location_id: str,
        evidence: Evidence,
    ) -> bool:
        if (
            not location_id.startswith("loc_")
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(location_id) is None
            or evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.TOOL
            or evidence.value != location_id
            or evidence.evidence_id is None
            or evidence.source_tool_call_id is None
            or evidence.state_version != session.evidence.current_state_version
        ):
            return False
        try:
            session.remember_resolved_location(
                literal_name=literal_name,
                location_id=location_id,
                source_call_id=evidence.source_tool_call_id,
                source_evidence_id=evidence.evidence_id,
                state_version=evidence.state_version,
            )
        except ValueError:
            return False
        return True

    @staticmethod
    def _cached_location_evidence(
        session: SessionState,
        *,
        goal_id: str,
        literal_name: str,
        proposition: str,
    ) -> tuple[str, Evidence] | None:
        binding = session.resolved_location_binding(
            literal_name,
            state_version=session.evidence.current_state_version,
        )
        if binding is None:
            return None
        observed_ids: set[str] = set()
        for observation in session.successful_read_results:
            if (
                observation.state_version != session.evidence.current_state_version
                or observation.tool_name != "get_location_id_by_location_name"
                or not _argument_value_matches_binding(
                    observation.arguments, {"location": literal_name}
                )
            ):
                continue
            if not isinstance(observation.value, Mapping):
                return None
            observed_id = observation.value.get("id")
            if (
                not isinstance(observed_id, str)
                or not observed_id.startswith("loc_")
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(observed_id) is None
            ):
                return None
            observed_ids.add(observed_id)
        if observed_ids != {binding.location_id}:
            return None
        source = session.evidence.evidence.get(binding.source_evidence_id)
        if (
            source is None
            or source.evidence_id != binding.source_evidence_id
            or source.source_kind is not EvidenceSourceKind.TOOL
            or source.status is not EvidenceStatus.KNOWN
            or source.value != binding.location_id
            or source.source_tool_call_id != binding.source_call_id
            or source.state_version != binding.state_version
            or not binding.location_id.startswith("loc_")
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(binding.location_id) is None
        ):
            return None
        needs = [
            need
            for need in session.evidence.needs.values()
            if need.required_for_goal_id == goal_id
            and need.proposition == proposition
            and "derived" in need.acceptable_sources
        ]
        if len(needs) != 1:
            return None
        source_turn_id = f"cached-location-{goal_id}"
        existing = [
            evidence
            for evidence in session.evidence.evidence.values()
            if evidence.proposition == proposition
            and evidence.source_turn_id == source_turn_id
            and evidence.source_kind is EvidenceSourceKind.DERIVED
            and evidence.status is EvidenceStatus.KNOWN
            and evidence.value == binding.location_id
            and evidence.derived_from == [binding.source_evidence_id]
            and evidence.state_version == session.evidence.current_state_version
        ]
        if len(existing) == 1:
            return binding.location_id, existing[0]
        if existing:
            return None
        session.evidence.add(
            Evidence(
                proposition=proposition,
                value=binding.location_id,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=source_turn_id,
                confidence=source.confidence,
                derived_from=[binding.source_evidence_id],
                derivation="exact_named_location_cache_v1",
            )
        )
        created = [
            evidence
            for evidence in session.evidence.evidence.values()
            if evidence.proposition == proposition
            and evidence.source_turn_id == source_turn_id
            and evidence.source_kind is EvidenceSourceKind.DERIVED
            and evidence.value == binding.location_id
            and evidence.derived_from == [binding.source_evidence_id]
            and evidence.state_version == session.evidence.current_state_version
        ]
        return (binding.location_id, created[0]) if len(created) == 1 else None

    @classmethod
    def _poi_opening_hours_minutes(cls, value: Any) -> tuple[int, int] | None:
        if (
            not isinstance(value, str)
            or value != value.strip()
            or not value
            or len(value) > 120
            or TTSGuard(max_characters=120).violations(value)
            or any(
                unicodedata.category(character) in {"Cc", "Cf", "Cs", "Zl", "Zp"}
                for character in value
            )
        ):
            return None
        match = _POI_OPENING_HOURS_PATTERN.fullmatch(value)
        if match is None:
            return None
        opening = int(match.group("opening_hour")) * 60 + int(
            match.group("opening_minute")
        )
        closing = int(match.group("closing_hour")) * 60 + int(
            match.group("closing_minute")
        )
        if closing > 24 * 60 or closing <= opening:
            return None
        if closing == 24 * 60 and match.group("closing_minute") != "00":
            return None
        return opening, closing

    @staticmethod
    def _poi_opening_hours_for_presentation(
        options: Sequence[DestinationPOIOption],
    ) -> tuple[str, ...] | None:
        if not options or any(option.opening_hours is None for option in options):
            return None
        return tuple(
            option.opening_hours
            for option in options
            if option.opening_hours is not None
        )

    @classmethod
    def _callable_poi_options_from_evidence(
        cls,
        evidence: Evidence,
        *,
        location_id: str,
        category: str,
    ) -> tuple[DestinationPOIOption, ...] | None:
        candidates = evidence.value
        if not isinstance(candidates, list) or not 1 <= len(candidates) <= 10:
            return None
        options: list[DestinationPOIOption] = []
        seen_ids: set[str] = set()
        seen_names: set[str] = set()
        seen_phones: set[str] = set()
        for candidate in candidates:
            if not isinstance(candidate, Mapping):
                return None
            poi_id = candidate.get("id")
            name = candidate.get("name")
            phone_number = candidate.get("phone_number")
            observed_category = candidate.get("category")
            opening_hours = candidate.get("opening_hours")
            if (
                not isinstance(poi_id, str)
                or not poi_id.startswith("poi_")
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(poi_id) is None
                or poi_id in seen_ids
                or not isinstance(name, str)
                or not cls._safe_poi_display_label(name, 120)
                or not isinstance(phone_number, str)
                or phone_number != phone_number.strip()
                or _POI_PHONE_PATTERN.fullmatch(phone_number) is None
                or not 8 <= sum(character.isdigit() for character in phone_number) <= 15
                or not isinstance(observed_category, str)
                or _argument_identifier(observed_category)
                != _argument_identifier(category)
                or candidate.get("corresponding_location_id") != location_id
                or (
                    opening_hours is not None
                    and cls._poi_opening_hours_minutes(opening_hours) is None
                )
            ):
                return None
            normalized_name = " ".join(
                unicodedata.normalize("NFKC", name).casefold().split()
            )
            if (
                not normalized_name
                or normalized_name in seen_names
                or phone_number in seen_phones
            ):
                return None
            seen_ids.add(poi_id)
            seen_names.add(normalized_name)
            seen_phones.add(phone_number)
            options.append(
                DestinationPOIOption(
                    poi_id=poi_id,
                    name=name.strip(),
                    normalized_name=normalized_name,
                    phone_number=phone_number,
                    location_id=location_id,
                    opening_hours=opening_hours,
                )
            )
        return tuple(options)

    @staticmethod
    def _safe_poi_display_label(value: str, limit: int) -> bool:
        cleaned = value.strip()
        return (
            CARGuardOrchestrator._voice_result_field(cleaned, limit)
            and not TTSGuard(max_characters=limit).violations(cleaned)
            and re.search(r"[.!?;:](?:[ ]|$)", cleaned) is None
            and _DISPLAYED_POI_ACTION_CLAIM_PATTERN.search(cleaned) is None
            and _DISPLAYED_POI_CLAUSE_TOKEN_PATTERN.search(cleaned) is None
        )

    def _store_displayed_poi_options(
        self,
        session: SessionState,
        *,
        goal_id: str,
        location_id: str,
        category: str,
        location_evidence: Evidence,
        poi_evidence: Evidence,
    ) -> tuple[DestinationPOIOption, ...] | None:
        session.clear_displayed_destination_pois()
        options = self._callable_poi_options_from_evidence(
            poi_evidence, location_id=location_id, category=category
        )
        if (
            options is None
            or location_evidence.evidence_id is None
            or poi_evidence.evidence_id is None
            or poi_evidence.source_tool_call_id is None
            or poi_evidence.source_kind is not EvidenceSourceKind.TOOL
            or location_evidence.status is not EvidenceStatus.KNOWN
            or poi_evidence.status is not EvidenceStatus.KNOWN
            or location_evidence.state_version != session.evidence.current_state_version
            or poi_evidence.state_version != session.evidence.current_state_version
        ):
            return None
        displayed_value = [
            {
                "id": option.poi_id,
                "name": option.name,
                "phone_number": option.phone_number,
                "location_id": option.location_id,
                "category": category,
                "opening_hours": option.opening_hours,
            }
            for option in options
        ]
        source_turn_id = f"displayed-pois-{goal_id}-{poi_evidence.observation_index}"
        session.evidence.add(
            Evidence(
                proposition="displayed_destination_poi_candidates",
                value=displayed_value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=source_turn_id,
                confidence=min(location_evidence.confidence, poi_evidence.confidence),
                derived_from=[
                    location_evidence.evidence_id,
                    poi_evidence.evidence_id,
                ],
                derivation="validated_displayed_poi_candidates_v1",
            )
        )
        displayed = [
            evidence
            for evidence in session.evidence.for_proposition(
                "displayed_destination_poi_candidates"
            )
            if evidence.source_turn_id == source_turn_id
            and evidence.value == displayed_value
            and evidence.state_version == session.evidence.current_state_version
        ]
        if len(displayed) != 1 or displayed[0].evidence_id is None:
            return None
        candidates = tuple(
            DisplayedPOICandidate(
                normalized_name=option.normalized_name,
                display_name=option.name,
                poi_id=option.poi_id,
                phone_number=option.phone_number,
                location_id=option.location_id,
                source_call_id=poi_evidence.source_tool_call_id,
                source_poi_evidence_id=poi_evidence.evidence_id,
                source_location_evidence_id=location_evidence.evidence_id,
                displayed_evidence_id=displayed[0].evidence_id,
                state_version=session.evidence.current_state_version,
                opening_hours=option.opening_hours,
            )
            for option in options
        )
        try:
            session.remember_displayed_destination_pois(candidates)
        except ValueError:
            return None
        return options

    def _validated_displayed_poi_candidate(
        self, session: SessionState, candidate: DisplayedPOICandidate
    ) -> tuple[DestinationPOIOption, Evidence, Evidence, Evidence] | None:
        current_version = session.evidence.current_state_version
        if candidate.state_version != current_version:
            return None
        poi_evidence = session.evidence.evidence.get(candidate.source_poi_evidence_id)
        location_evidence = session.evidence.evidence.get(
            candidate.source_location_evidence_id
        )
        displayed_evidence = session.evidence.evidence.get(
            candidate.displayed_evidence_id
        )
        if (
            poi_evidence is None
            or location_evidence is None
            or displayed_evidence is None
            or poi_evidence.source_kind is not EvidenceSourceKind.TOOL
            or location_evidence.source_kind is not EvidenceSourceKind.TOOL
            or displayed_evidence.source_kind is not EvidenceSourceKind.DERIVED
            or poi_evidence.status is not EvidenceStatus.KNOWN
            or location_evidence.status is not EvidenceStatus.KNOWN
            or displayed_evidence.status is not EvidenceStatus.KNOWN
            or poi_evidence.source_tool_call_id != candidate.source_call_id
            or location_evidence.value != candidate.location_id
            or poi_evidence.state_version != current_version
            or location_evidence.state_version != current_version
            or displayed_evidence.state_version != current_version
            or displayed_evidence.derived_from
            != [candidate.source_location_evidence_id, candidate.source_poi_evidence_id]
            or displayed_evidence.derivation != "validated_displayed_poi_candidates_v1"
        ):
            return None
        options = self._callable_poi_options_from_evidence(
            poi_evidence,
            location_id=candidate.location_id,
            category="restaurants",
        )
        matching_options = [
            option
            for option in options or ()
            if option.poi_id == candidate.poi_id
            and option.name == candidate.display_name
            and option.normalized_name == candidate.normalized_name
            and option.phone_number == candidate.phone_number
            and option.location_id == candidate.location_id
            and option.opening_hours == candidate.opening_hours
        ]
        expected_row = {
            "id": candidate.poi_id,
            "name": candidate.display_name,
            "phone_number": candidate.phone_number,
            "location_id": candidate.location_id,
            "category": "restaurants",
            "opening_hours": candidate.opening_hours,
        }
        displayed_rows = displayed_evidence.value
        matching_rows = (
            [
                row
                for row in displayed_rows
                if isinstance(row, Mapping) and dict(row) == expected_row
            ]
            if isinstance(displayed_rows, list)
            else []
        )
        if len(matching_options) != 1 or len(matching_rows) != 1:
            return None
        return (
            matching_options[0],
            poi_evidence,
            location_evidence,
            displayed_evidence,
        )

    def _validated_displayed_poi_navigation_binding(
        self,
        session: SessionState,
        goal: Goal,
    ) -> tuple[DisplayedPOICandidate, Evidence] | None:
        if session.intent is None:
            return None
        poi_id = goal.desired_outcome.get("displayed_poi_id")
        destination_name = goal.desired_outcome.get("new_destination_name")
        destination_id = goal.desired_outcome.get("new_destination_id")
        if (
            not isinstance(poi_id, str)
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(poi_id) is None
            or not isinstance(destination_name, str)
            or not self._voice_result_field(destination_name, 120)
            or destination_id != poi_id
        ):
            return None
        normalized_name = " ".join(
            unicodedata.normalize("NFKC", destination_name).casefold().split()
        )
        candidates = [
            candidate
            for candidate in session.displayed_destination_pois
            if candidate.poi_id == poi_id
            and candidate.display_name == destination_name
            and candidate.normalized_name == normalized_name
        ]
        if len(candidates) != 1:
            return None
        candidate = candidates[0]
        validated = self._validated_displayed_poi_candidate(session, candidate)
        if validated is None:
            return None
        _, poi_evidence, location_evidence, displayed_evidence = validated
        parent_ids = [
            location_evidence.evidence_id,
            poi_evidence.evidence_id,
            displayed_evidence.evidence_id,
        ]
        if any(evidence_id is None for evidence_id in parent_ids):
            return None
        expected_selection = {
            "poi_id": candidate.poi_id,
            "name": candidate.display_name,
            "location_id": candidate.location_id,
            "opening_hours": candidate.opening_hours,
        }
        selection_evidence = [
            evidence
            for evidence in session.evidence.for_proposition(
                f"displayed_poi_selection:{goal.goal_id}"
            )
            if evidence.status is EvidenceStatus.KNOWN
            and evidence.source_kind is EvidenceSourceKind.DERIVED
            and evidence.state_version == session.evidence.current_state_version
            and evidence.value == expected_selection
            and evidence.derived_from == parent_ids
            and evidence.derivation
            in {
                "exact_displayed_poi_name_selection_v1",
                "unique_latest_closing_displayed_poi_v1",
            }
        ]
        if len(selection_evidence) != 1 or selection_evidence[0].evidence_id is None:
            return None
        selection = selection_evidence[0]
        grounded = session.grounded_desired_values_by_goal.get(goal.goal_id, {})
        sources = session.grounded_value_sources_by_goal.get(goal.goal_id, {})
        derived_ids = session.derived_value_evidence_by_goal.get(goal.goal_id, {})
        if selection.derivation == "exact_displayed_poi_name_selection_v1":
            if (
                grounded.get("new_destination_name") != candidate.display_name
                or sources.get("new_destination_name")
                not in session.intent.intent_source_turn_ids
                or "new_destination_name" in derived_ids
            ):
                return None
        else:
            derived_name = session.evidence.evidence.get(
                derived_ids.get("new_destination_name", "")
            )
            if (
                grounded.get("new_destination_name") != candidate.display_name
                or "new_destination_name" in sources
                or derived_name is None
                or derived_name.status is not EvidenceStatus.KNOWN
                or derived_name.source_kind is not EvidenceSourceKind.DERIVED
                or derived_name.state_version != session.evidence.current_state_version
                or derived_name.value != candidate.display_name
                or derived_name.derived_from != [selection.evidence_id]
                or derived_name.derivation != "selected_displayed_poi_name_v1"
            ):
                return None
        derived_id = session.derived_value_evidence_by_goal.get(goal.goal_id, {}).get(
            "new_destination_id"
        )
        derived = session.evidence.evidence.get(derived_id or "")
        if (
            derived is None
            or derived.status is not EvidenceStatus.KNOWN
            or derived.source_kind is not EvidenceSourceKind.DERIVED
            or derived.state_version != session.evidence.current_state_version
            or derived.value != candidate.poi_id
            or derived.derived_from != [selection_evidence[0].evidence_id]
            or derived.derivation != "selected_displayed_poi_id_v1"
            or grounded.get("new_destination_id") != candidate.poi_id
            or "new_destination_id" in sources
            or "displayed_poi_id" in sources
            or "displayed_poi_id" in grounded
        ):
            return None
        return candidate, selection

    def _displayed_poi_navigation_limitation(
        self, session: SessionState, *, reason: str
    ) -> PlannedOutbound:
        return self._text_plan(
            session,
            self.responses.limitation(
                goal="replace the current destination with the selected restaurant",
                reason=reason,
                outcome=GateOutcome.UNAVAILABLE_EVIDENCE,
                language=self._language(session),
            ),
        )

    @staticmethod
    def _displayed_poi_navigation_goal(session: SessionState) -> Goal | None:
        if session.intent is None:
            return None
        goals = [
            goal
            for goal in session.intent.goals
            if goal.semantic_operation == _NAVIGATION_REPLACE_DESTINATION
            and isinstance(goal.desired_outcome.get("displayed_poi_id"), str)
        ]
        return goals[0] if len(goals) == 1 else None

    @staticmethod
    def _displayed_poi_final_scope(
        text: str,
    ) -> tuple[str | None, str, str | None] | None:
        matches = [
            match
            for pattern in _DISPLAYED_POI_FINAL_SCOPE_PATTERNS
            if (match := pattern.fullmatch(text)) is not None
        ]
        if len(matches) != 1:
            return None
        groups = matches[0].groupdict()
        name = groups.get("name")
        old = groups.get("old")
        return (
            " ".join(unicodedata.normalize("NFKC", name).strip().split())
            if name is not None
            else None,
            groups["choice"].casefold(),
            " ".join(unicodedata.normalize("NFKC", old).strip().split())
            if old is not None
            else None,
        )

    def _begin_displayed_poi_navigation_selection(
        self,
        session: SessionState,
        *,
        candidate: DisplayedPOICandidate,
        turn_id: str,
        derivation: str,
    ) -> bool:
        validated = self._validated_displayed_poi_candidate(session, candidate)
        if validated is None:
            return False
        _, poi_evidence, location_evidence, displayed_evidence = validated
        parent_ids = [
            evidence.evidence_id
            for evidence in (location_evidence, poi_evidence, displayed_evidence)
        ]
        if any(evidence_id is None for evidence_id in parent_ids):
            return False
        digest = hashlib.sha256(
            f"{turn_id}\0displayed-poi-navigation\0{candidate.poi_id}".encode()
        ).hexdigest()
        goal_id = f"goal-displayed-poi-navigation-{digest[:12]}"
        goal = Goal(
            goal_id=goal_id,
            semantic_operation=_NAVIGATION_REPLACE_DESTINATION,
            desired_outcome={
                "new_destination_name": candidate.display_name,
                "displayed_poi_id": candidate.poi_id,
            },
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=False,
            goals=[goal],
            explicit_slots=(
                {"new_destination_name": candidate.display_name}
                if derivation == "exact_displayed_poi_name_selection_v1"
                else {}
            ),
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal_id],
            intent_kind=IntentKind.SELECTION,
        )
        session.authorized_action_goal_ids = set()
        exact_name_selection = derivation == "exact_displayed_poi_name_selection_v1"
        session.grounded_desired_values_by_goal = {
            goal_id: (
                {"new_destination_name": candidate.display_name}
                if exact_name_selection
                else {}
            )
        }
        session.grounded_value_sources_by_goal = {
            goal_id: {"new_destination_name": turn_id} if exact_name_selection else {}
        }
        session.derived_value_evidence_by_goal = {}
        session.relative_fan_speed_deltas_by_goal = {}
        session.relative_climate_temperature_deltas_by_goal = {}
        session.relative_seat_heating_deltas_by_goal = {}
        session.occupied_seat_heating_goal_ids = set()
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        selection = Evidence(
            proposition=f"displayed_poi_selection:{goal_id}",
            value={
                "poi_id": candidate.poi_id,
                "name": candidate.display_name,
                "location_id": candidate.location_id,
                "opening_hours": candidate.opening_hours,
            },
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=turn_id,
            confidence=min(
                location_evidence.confidence,
                poi_evidence.confidence,
                displayed_evidence.confidence,
            ),
            derived_from=[evidence_id for evidence_id in parent_ids if evidence_id],
            derivation=derivation,
        )
        session.evidence.add(selection)
        stored_selection = session.evidence.for_proposition(selection.proposition)[-1]
        if stored_selection.evidence_id is None:
            return False
        replacement_location = Evidence(
            proposition="replacement_destination_location_id",
            value=candidate.poi_id,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=turn_id,
            confidence=stored_selection.confidence,
            derived_from=[stored_selection.evidence_id],
            derivation="displayed_poi_selection_location_v1",
        )
        session.evidence.add(replacement_location)
        derived_parameters: dict[str, tuple[Any, tuple[Evidence, ...], str]] = {
            "new_destination_id": (
                candidate.poi_id,
                (stored_selection,),
                "selected_displayed_poi_id_v1",
            )
        }
        if not exact_name_selection:
            derived_parameters["new_destination_name"] = (
                candidate.display_name,
                (stored_selection,),
                "selected_displayed_poi_name_v1",
            )
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters=derived_parameters,
        )
        return True

    def _handle_displayed_poi_navigation_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        active_goal = self._displayed_poi_navigation_goal(session)
        if active_goal is None:
            longer_open = (
                _DISPLAYED_POI_LONGER_OPEN_PATTERN.fullmatch(text) is not None
                or _DISPLAYED_POI_LONGER_OPEN_WITH_ROUTE_PATTERN.fullmatch(text)
                is not None
            )
            if not longer_open and re.search(r"\bopen\s+longer\b", text, re.IGNORECASE):
                return True, self._displayed_poi_navigation_limitation(
                    session,
                    reason="the longer-opening request was not an exact current selection",
                )
            candidates: list[DisplayedPOICandidate] = []
            derivation = "exact_displayed_poi_name_selection_v1"
            if longer_open:
                validated = [
                    (
                        candidate,
                        self._validated_displayed_poi_candidate(session, candidate),
                    )
                    for candidate in session.displayed_destination_pois
                ]
                if len(validated) < 2 or any(item is None for _, item in validated):
                    return True, self._displayed_poi_navigation_limitation(
                        session,
                        reason="the current displayed opening hours could not be verified",
                    )
                closing_by_candidate = [
                    (
                        candidate,
                        self._poi_opening_hours_minutes(candidate.opening_hours),
                    )
                    for candidate, _ in validated
                ]
                if any(hours is None for _, hours in closing_by_candidate):
                    return True, self._displayed_poi_navigation_limitation(
                        session,
                        reason="the current displayed opening hours could not be verified",
                    )
                if any(
                    hours is not None and hours[1] <= hours[0]
                    for _, hours in closing_by_candidate
                ):
                    return True, self._displayed_poi_navigation_limitation(
                        session,
                        reason="the current displayed opening hours were not same-day intervals",
                    )
                latest_closing = max(
                    hours[1] for _, hours in closing_by_candidate if hours is not None
                )
                candidates = [
                    candidate
                    for candidate, hours in closing_by_candidate
                    if hours is not None and hours[1] == latest_closing
                ]
                derivation = "unique_latest_closing_displayed_poi_v1"
            else:
                normalized_names: set[str] = set()
                for pattern in _DISPLAYED_POI_INITIAL_SELECTION_PATTERNS:
                    match = pattern.fullmatch(text)
                    if match is None:
                        continue
                    name = " ".join(
                        unicodedata.normalize("NFKC", match.group("name"))
                        .casefold()
                        .split()
                    )
                    normalized_names.add(name)
                candidates = [
                    candidate
                    for candidate in session.displayed_destination_pois
                    if candidate.normalized_name in normalized_names
                ]
                if not candidates:
                    return False, None
            if len(candidates) != 1:
                return True, self._displayed_poi_navigation_limitation(
                    session,
                    reason="the requested restaurant was not one unique current option",
                )
            candidate = candidates[0]
            if not self._begin_displayed_poi_navigation_selection(
                session,
                candidate=candidate,
                turn_id=turn_id,
                derivation=derivation,
            ):
                return True, self._displayed_poi_navigation_limitation(
                    session,
                    reason="the displayed restaurant evidence is stale or inconsistent",
                )
            return True, None

        final_scope = self._displayed_poi_final_scope(text)
        if final_scope is None:
            if _requests_route_alternative_details(text):
                return False, None
            return True, self._displayed_poi_navigation_limitation(
                session,
                reason="an explicit current-destination replacement and route are required",
            )
        final_name, route_choice, old_destination = final_scope
        candidate_matches = [
            candidate
            for candidate in session.displayed_destination_pois
            if candidate.poi_id == active_goal.desired_outcome.get("displayed_poi_id")
            and candidate.normalized_name
            == " ".join(
                unicodedata.normalize("NFKC", str(final_name or candidate.display_name))
                .casefold()
                .split()
            )
        ]
        if len(candidate_matches) != 1:
            return True, self._displayed_poi_navigation_limitation(
                session,
                reason="the explicitly selected restaurant did not match current evidence",
            )
        candidate = candidate_matches[0]
        if self._validated_displayed_poi_candidate(session, candidate) is None:
            return True, self._displayed_poi_navigation_limitation(
                session,
                reason="the displayed restaurant evidence is stale or inconsistent",
            )
        state = self._navigation_state_view(session, goal_id=active_goal.goal_id)
        if (
            state is None
            or not state.active
            or len(state.waypoint_ids) < 2
            or not self._destination_navigation_snapshot_is_current(
                session, goal_id=active_goal.goal_id
            )
            or (
                old_destination is not None
                and (
                    len(state.waypoint_names) != len(state.waypoint_ids)
                    or _argument_identifier(state.waypoint_names[-1])
                    != _argument_identifier(old_destination)
                )
            )
        ):
            return True, self._displayed_poi_navigation_limitation(
                session,
                reason="the active navigation destination could not be reverified",
            )
        route_start_id = active_goal.desired_outcome.get("replacement_route_start_id")
        destination_id = active_goal.desired_outcome.get("new_destination_id")
        if not isinstance(route_start_id, str) or not isinstance(destination_id, str):
            return True, self._displayed_poi_navigation_limitation(
                session,
                reason="the replacement route endpoints could not be reverified",
            )
        route = self._derived_navigation_read_value(
            session,
            goal_id=active_goal.goal_id,
            tool_name="get_routes_from_start_to_destination",
            arguments={"start_id": route_start_id, "destination_id": destination_id},
            proposition="replacement_destination_route_options",
        )
        if (
            route is None
            or self._destination_route_options_from_evidence(
                route[1], start_id=route_start_id, destination_id=destination_id
            )
            is None
        ):
            return True, self._displayed_poi_navigation_limitation(
                session,
                reason="the current replacement route options could not be reverified",
            )
        requests = [
            request
            for request in session.pending_clarifications.values()
            if request.goal_id == active_goal.goal_id
            and request.slot_name == "route_choice_alias"
        ]
        if len(requests) != 1:
            return True, self._displayed_poi_navigation_limitation(
                session,
                reason="the pending replacement route choice was unavailable",
            )
        canonical_choice = f"Use the {route_choice} route."
        if (
            len(
                self._destination_route_clarification_matches(
                    session,
                    request=requests[0],
                    text=canonical_choice,
                )
            )
            != 1
        ):
            return True, self._displayed_poi_navigation_limitation(
                session,
                reason="the requested replacement route was not unique",
            )
        resolution = self._resolve_pending_clarification(
            session, canonical_choice, turn_id
        )
        if resolution is not None:
            return True, resolution
        assert session.intent is not None
        session.intent = session.intent.model_copy(
            update={
                "call_for_action": True,
                "intent_kind": IntentKind.ACTION,
                "intent_source_turn_ids": list(
                    dict.fromkeys([*session.intent.intent_source_turn_ids, turn_id])
                ),
            },
            deep=True,
        )
        session.authorized_action_goal_ids = {active_goal.goal_id}
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True, None

    def _displayed_poi_call_limitation(
        self,
        session: SessionState,
        *,
        name: str,
        outcome: GateOutcome,
        reason: str,
    ) -> PlannedOutbound:
        return self._text_plan(
            session,
            self.responses.limitation(
                goal=f"call {name}",
                reason=reason,
                outcome=outcome,
                language=self._language(session),
            ),
        )

    def _begin_active_route_charger_call_goal(
        self,
        session: SessionState,
        *,
        turn_id: str,
        summary: Evidence,
        station_name: str,
        phone_number: str,
    ) -> None:
        if summary.evidence_id is None:
            return
        digest = hashlib.sha256(
            f"{turn_id}\0active-route-charger-call\0{station_name}".encode()
        ).hexdigest()
        goal_id = f"goal-active-route-charger-call-{digest[:12]}"
        session.evidence.add(
            Evidence(
                proposition="displayed_destination_poi_candidates",
                value=[
                    {
                        "name": station_name,
                        "phone_number": phone_number,
                    }
                ],
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"active-route-charger-display-{goal_id}",
                confidence=summary.confidence,
                derived_from=[summary.evidence_id],
                derivation="active_route_charger_display_v1",
            )
        )
        phone_evidence = Evidence(
            proposition=f"derived_argument:{goal_id}:phone_number",
            value=phone_number,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=f"active-route-charger-phone-{goal_id}",
            confidence=summary.confidence,
            derived_from=[summary.evidence_id],
            derivation="phone_number_from_active_route_charger_v1",
        )
        session.evidence.add(phone_evidence)
        stored_phone = session.evidence.for_proposition(phone_evidence.proposition)[-1]
        assert stored_phone.evidence_id is not None
        goal = Goal(
            goal_id=goal_id,
            semantic_operation=_CALL_DISPLAYED_DESTINATION_POI,
            desired_outcome={
                "poi_name": station_name,
                "phone_number": phone_number,
            },
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[goal],
            explicit_slots={"poi_name": station_name},
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal_id],
            intent_kind=IntentKind.ACTION,
        )
        session.authorized_action_goal_ids = {goal_id}
        session.grounded_desired_values_by_goal = {
            goal_id: {"poi_name": station_name, "phone_number": phone_number}
        }
        session.grounded_value_sources_by_goal = {goal_id: {"poi_name": turn_id}}
        session.derived_value_evidence_by_goal = {
            goal_id: {"phone_number": stored_phone.evidence_id}
        }
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)

    def _validated_active_route_charger_call_offer(
        self, session: SessionState
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        charger = self._validated_active_route_charger_summary(session)
        offers = session.evidence.latest_for_proposition(
            "active_route_charger_call_offer", current_state_only=True
        )
        if charger is None or not offers:
            return None
        charger_evidence, charger_values = charger
        offer = offers[-1]
        expected = {
            "station_name": charger_values["station_name"],
            "phone_number": charger_values["phone_number"],
        }
        if (
            offer.status is not EvidenceStatus.KNOWN
            or offer.source_kind is not EvidenceSourceKind.DERIVED
            or offer.derivation != "active_route_charger_call_offer_v1"
            or offer.derived_from != [charger_evidence.evidence_id]
            or offer.value != expected
        ):
            return None
        return offer, expected

    @staticmethod
    def _active_route_charger_offer_is_immediate(
        session: SessionState, *, offer: Evidence, current_turn_id: str
    ) -> bool:
        user_turn_ids = [
            message.get("turn_id")
            for message in session.conversation
            if message.get("role") == "user" and isinstance(message.get("turn_id"), str)
        ]
        return (
            len(user_turn_ids) >= 2
            and user_turn_ids[-2] == offer.source_turn_id
            and user_turn_ids[-1] == current_turn_id
        )

    def _handle_active_route_charger_call_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        charger = self._validated_active_route_charger_summary(session)
        station_name = charger[1].get("station_name") if charger is not None else None
        phone_inquiry = (
            _active_route_charger_phone_inquiry(text, station_name=station_name)
            if isinstance(station_name, str)
            else False
        )
        if phone_inquiry:
            assert charger is not None
            summary, values = charger
            if summary.evidence_id is None:
                return True, self._text_plan(
                    session,
                    "I could not verify a current phone number for that charging station.",
                )
            session.evidence.add(
                Evidence(
                    proposition="active_route_charger_call_offer",
                    value={
                        "station_name": values["station_name"],
                        "phone_number": values["phone_number"],
                    },
                    status=EvidenceStatus.KNOWN,
                    source_kind=EvidenceSourceKind.DERIVED,
                    source_turn_id=turn_id,
                    confidence=summary.confidence,
                    derived_from=[summary.evidence_id],
                    derivation="active_route_charger_call_offer_v1",
                )
            )
            return True, self._text_plan(
                session,
                f"I found the current phone number for {values['station_name']}: "
                f"{values['phone_number']}. Would you like me to use that exact number?",
            )

        named_call = _active_route_charger_named_call_request(text)
        if (
            _ACTIVE_ROUTE_CHARGER_CALL_CONFIRM_PATTERN.fullmatch(text) is not None
            or named_call is not None
        ):
            offer = self._validated_active_route_charger_call_offer(session)
            if offer is None or charger is None:
                return True, self._text_plan(
                    session,
                    "The charging-station phone evidence is no longer current, so I did not call.",
                )
            if not self._active_route_charger_offer_is_immediate(
                session, offer=offer[0], current_turn_id=turn_id
            ):
                return True, self._text_plan(
                    session,
                    "That phone-number offer was not from the immediately preceding request, so I did not call.",
                )
            if named_call is not None and _argument_identifier(
                named_call
            ) != _argument_identifier(str(offer[1]["station_name"])):
                return True, self._text_plan(
                    session,
                    "That station name did not match the current phone-number offer, so I did not call.",
                )
            if session.live_tools is None or not session.live_tools.has_tool(
                "call_phone_by_number"
            ):
                return True, self._text_plan(
                    session, "Calling is unavailable in the current controls."
                )
            self._begin_active_route_charger_call_goal(
                session,
                turn_id=turn_id,
                summary=charger[0],
                station_name=str(offer[1]["station_name"]),
                phone_number=str(offer[1]["phone_number"]),
            )
            return True, None

        direct_call = _DISPLAYED_POI_CALL_PATTERN.fullmatch(text)
        if direct_call is None:
            return False, None
        requested_name = " ".join(direct_call.group("name").split())
        charger = self._validated_active_route_charger_summary(session)
        prior_names = {
            str(observation.value.get("station_name"))
            for observation in session.evidence.for_proposition(
                "active_route_charger_summary"
            )
            if isinstance(observation.value, Mapping)
        }
        if not any(
            _argument_identifier(name) == _argument_identifier(requested_name)
            for name in prior_names
        ):
            return False, None
        if charger is None or _argument_identifier(
            charger[1].get("station_name", "")
        ) != _argument_identifier(requested_name):
            return True, self._text_plan(
                session,
                "The charging-station phone evidence is no longer current, so I did not call.",
            )
        self._begin_active_route_charger_call_goal(
            session,
            turn_id=turn_id,
            summary=charger[0],
            station_name=str(charger[1]["station_name"]),
            phone_number=str(charger[1]["phone_number"]),
        )
        return True, None

    def _handle_displayed_poi_call_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        match = _DISPLAYED_POI_CALL_PATTERN.fullmatch(text)
        if match is None:
            return False, None
        if not session.displayed_destination_pois:
            return False, None
        name = " ".join(
            unicodedata.normalize("NFKC", match.group("name")).strip().split()
        )
        if not self._voice_result_field(name, 120):
            return True, self._displayed_poi_call_limitation(
                session,
                name="the selected restaurant",
                outcome=GateOutcome.UNAVAILABLE_EVIDENCE,
                reason="the requested restaurant name could not be verified",
            )
        if session.live_tools is None or not session.live_tools.has_tool(
            "call_phone_by_number"
        ):
            return True, self._displayed_poi_call_limitation(
                session,
                name=name,
                outcome=GateOutcome.UNSUPPORTED_CAPABILITY,
                reason="the required calling control is unavailable",
            )

        normalized_name = " ".join(
            unicodedata.normalize("NFKC", name).casefold().split()
        )
        current_version = session.evidence.current_state_version
        matches = [
            candidate
            for candidate in session.displayed_destination_pois
            if candidate.normalized_name == normalized_name
            and candidate.state_version == current_version
        ]
        if len(matches) != 1:
            return True, self._displayed_poi_call_limitation(
                session,
                name=name,
                outcome=GateOutcome.UNAVAILABLE_EVIDENCE,
                reason="that restaurant was not a unique current displayed option",
            )
        candidate = matches[0]
        poi_evidence = session.evidence.evidence.get(candidate.source_poi_evidence_id)
        location_evidence = session.evidence.evidence.get(
            candidate.source_location_evidence_id
        )
        displayed_evidence = session.evidence.evidence.get(
            candidate.displayed_evidence_id
        )
        if (
            poi_evidence is None
            or location_evidence is None
            or displayed_evidence is None
            or poi_evidence.source_kind is not EvidenceSourceKind.TOOL
            or displayed_evidence.source_kind is not EvidenceSourceKind.DERIVED
            or poi_evidence.source_tool_call_id != candidate.source_call_id
            or poi_evidence.state_version != current_version
            or location_evidence.state_version != current_version
            or displayed_evidence.state_version != current_version
            or displayed_evidence.derived_from
            != [
                candidate.source_location_evidence_id,
                candidate.source_poi_evidence_id,
            ]
        ):
            return True, self._displayed_poi_call_limitation(
                session,
                name=name,
                outcome=GateOutcome.UNAVAILABLE_EVIDENCE,
                reason="the displayed restaurant evidence is stale or incomplete",
            )
        observed = self._callable_poi_options_from_evidence(
            poi_evidence,
            location_id=candidate.location_id,
            category="restaurants",
        )
        matching_observed = [
            option
            for option in observed or ()
            if option.poi_id == candidate.poi_id
            and option.normalized_name == candidate.normalized_name
            and option.phone_number == candidate.phone_number
        ]
        displayed_rows = displayed_evidence.value
        matching_displayed = (
            [
                row
                for row in displayed_rows
                if isinstance(row, Mapping)
                and row.get("id") == candidate.poi_id
                and row.get("name") == candidate.display_name
                and row.get("phone_number") == candidate.phone_number
                and row.get("location_id") == candidate.location_id
            ]
            if isinstance(displayed_rows, list)
            else []
        )
        if len(matching_observed) != 1 or len(matching_displayed) != 1:
            return True, self._displayed_poi_call_limitation(
                session,
                name=name,
                outcome=GateOutcome.UNAVAILABLE_EVIDENCE,
                reason="the restaurant phone number could not be uniquely verified",
            )

        digest = hashlib.sha256(
            f"{turn_id}\0displayed-poi-call\0{candidate.poi_id}".encode()
        ).hexdigest()
        goal_id = f"goal-displayed-poi-call-{digest[:12]}"
        phone_evidence = Evidence(
            proposition=f"derived_argument:{goal_id}:phone_number",
            value=candidate.phone_number,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=f"displayed-poi-phone-{goal_id}",
            confidence=min(poi_evidence.confidence, displayed_evidence.confidence),
            derived_from=[
                candidate.source_poi_evidence_id,
                candidate.displayed_evidence_id,
            ],
            derivation="phone_number_from_displayed_poi_evidence_v1",
        )
        session.evidence.add(phone_evidence)
        stored_phone = session.evidence.for_proposition(phone_evidence.proposition)[-1]
        assert stored_phone.evidence_id is not None
        goal = Goal(
            goal_id=goal_id,
            semantic_operation=_CALL_DISPLAYED_DESTINATION_POI,
            desired_outcome={
                "poi_name": candidate.display_name,
                "phone_number": candidate.phone_number,
            },
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[goal],
            explicit_slots={"poi_name": candidate.display_name},
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal_id],
            intent_kind=IntentKind.ACTION,
        )
        session.authorized_action_goal_ids = {goal_id}
        session.grounded_desired_values_by_goal = {
            goal_id: {
                "poi_name": candidate.display_name,
                "phone_number": candidate.phone_number,
            }
        }
        session.grounded_value_sources_by_goal = {goal_id: {"poi_name": turn_id}}
        session.derived_value_evidence_by_goal = {
            goal_id: {"phone_number": stored_phone.evidence_id}
        }
        session.relative_fan_speed_deltas_by_goal = {}
        session.relative_climate_temperature_deltas_by_goal = {}
        session.relative_seat_heating_deltas_by_goal = {}
        session.occupied_seat_heating_goal_ids = set()
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True, None

    def _next_navigation_add_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _NAVIGATION_ADD_WAYPOINT:
                continue
            if not session.live_tools.has_tool("navigation_add_one_waypoint"):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            route_choice = item.goal.desired_outcome.get("route_choice_alias")
            if route_choice is not None and (
                not isinstance(route_choice, str)
                or _argument_identifier(route_choice)
                not in {*_ROUTE_ORDINALS, "fastest", "shortest"}
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )

            state_observation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_current_navigation_state",
                arguments={"detailed_information": True},
            )
            if state_observation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_current_navigation_state",
                    arguments={"detailed_information": True},
                    semantic_operation="read_current_navigation_for_waypoint_add",
                    proposition="current_navigation_state",
                )
            state = self._navigation_state_view(session, goal_id=item.goal.goal_id)
            if state is None or not state.active:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            index = self._named_add_after_index(item.goal, state)
            location_name = item.goal.desired_outcome.get("new_waypoint_name")
            if (
                index is None
                or not isinstance(location_name, str)
                or not self._voice_result_field(location_name, 80)
                or any(
                    _argument_identifier(name) == _argument_identifier(location_name)
                    for name in state.waypoint_names
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            location_arguments = {"location": location_name}
            location = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_location_id_by_location_name",
                arguments=location_arguments,
                proposition="resolved_navigation_location_id",
            )
            if location is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_location_id_by_location_name",
                        arguments=location_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_location_id_by_location_name",
                    arguments=location_arguments,
                    semantic_operation="resolve_added_waypoint_location",
                    proposition="resolved_navigation_location_id",
                )
            new_waypoint_id, location_evidence = location
            if (
                not isinstance(new_waypoint_id, str)
                or new_waypoint_id in state.waypoint_ids
                or not self._remember_exact_location_resolution(
                    session,
                    literal_name=location_name,
                    location_id=new_waypoint_id,
                    evidence=location_evidence,
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            previous_id = state.waypoint_ids[index]
            append_to_final = index == len(state.waypoint_ids) - 1
            next_id = None if append_to_final else state.waypoint_ids[index + 1]
            route_to_arguments = {
                "start_id": previous_id,
                "destination_id": new_waypoint_id,
            }
            route_to = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_to_arguments,
                proposition="route_to_replacement_options",
            )
            if route_to is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=route_to_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=route_to_arguments,
                    semantic_operation="find_route_to_added_waypoint",
                    proposition="route_to_replacement_options",
                )
            _, route_to_evidence = route_to
            if (
                self._navigation_edit_route_id_from_evidence(
                    item.goal,
                    route_to_evidence,
                    start_id=previous_id,
                    destination_id=new_waypoint_id,
                )
                is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            if next_id is None:
                deterministic = self._deterministic_bound_action(session, prepared)
                return deterministic or self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            route_from_arguments = {
                "start_id": new_waypoint_id,
                "destination_id": next_id,
            }
            route_from = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_from_arguments,
                proposition="route_from_replacement_options",
            )
            if route_from is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=route_from_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=route_from_arguments,
                    semantic_operation="find_route_from_added_waypoint",
                    proposition="route_from_replacement_options",
                )
            _, route_from_evidence = route_from
            if (
                self._navigation_edit_route_id_from_evidence(
                    item.goal,
                    route_from_evidence,
                    start_id=new_waypoint_id,
                    destination_id=next_id,
                )
                is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            deterministic = self._deterministic_bound_action(session, prepared)
            return deterministic or self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        return None

    def _next_navigation_stop_poi_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _NEXT_NAVIGATION_STOP_POI_SEARCH:
                continue
            session.clear_displayed_destination_pois()
            if not session.live_tools.has_tool("search_poi_at_location"):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            category = item.goal.desired_outcome.get("category")
            if not isinstance(category, str) or _argument_identifier(category) != (
                "restaurants"
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            state_observation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_current_navigation_state",
                arguments={"detailed_information": True},
            )
            if state_observation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_current_navigation_state",
                    arguments={"detailed_information": True},
                    semantic_operation="read_next_navigation_stop",
                    proposition="current_navigation_state",
                )
            state = self._navigation_state_view(session, goal_id=item.goal.goal_id)
            if (
                state is None
                or not state.active
                or len(state.waypoint_ids) < 3
                or len(state.waypoint_names) != len(state.waypoint_ids)
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            expected_after_add = self._expected_navigation_after_recent_waypoint_add(
                session
            )
            if expected_after_add is not None and (
                state.waypoint_ids != expected_after_add[0]
                or state.route_ids != expected_after_add[1]
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            next_stop_id = state.waypoint_ids[1]
            next_stop_name = state.waypoint_names[1]
            if not self._safe_poi_display_label(next_stop_name, 80):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "next_stop_location_id": (
                        next_stop_id,
                        (state.evidence,),
                        "next_intermediate_stop_from_current_navigation_v1",
                    )
                },
            )
            search_arguments = {
                "location_id": next_stop_id,
                "category_poi": "restaurants",
            }
            search = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="search_poi_at_location",
                arguments=search_arguments,
                proposition="current_destination_poi_candidates",
            )
            if search is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="search_poi_at_location",
                        arguments=search_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="search_poi_at_location",
                    arguments=search_arguments,
                    semantic_operation=_NEXT_NAVIGATION_STOP_POI_SEARCH,
                    proposition="current_destination_poi_candidates",
                )
            _, poi_evidence = search
            options = self._callable_poi_options_from_evidence(
                poi_evidence,
                location_id=next_stop_id,
                category="restaurants",
            )
            if options is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            presentation = self.responses.poi_search_results(
                location=next_stop_name,
                poi_names=tuple(option.name for option in options),
                poi_opening_hours=self._poi_opening_hours_for_presentation(options),
                language=self._language(session),
            )
            planned = self._text_plan(
                session,
                presentation,
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
            if planned.envelope.text != presentation:
                session.clear_displayed_destination_pois()
                return planned
            stored = self._store_displayed_poi_options(
                session,
                goal_id=item.goal.goal_id,
                location_id=next_stop_id,
                category="restaurants",
                location_evidence=state.evidence,
                poi_evidence=poi_evidence,
            )
            if stored != options:
                session.clear_displayed_destination_pois()
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return planned
        return None

    def _next_current_destination_poi_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _CURRENT_DESTINATION_POI_SEARCH:
                continue
            session.clear_displayed_destination_pois()
            category = item.goal.desired_outcome.get("category")
            if not isinstance(category, str) or _argument_identifier(category) != (
                "restaurants"
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            state_observation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_current_navigation_state",
                arguments={"detailed_information": True},
            )
            if state_observation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_current_navigation_state",
                    arguments={"detailed_information": True},
                    semantic_operation="read_current_destination_navigation",
                    proposition="current_navigation_state",
                )
            state = self._navigation_state_view(session, goal_id=item.goal.goal_id)
            if (
                state is None
                or not state.active
                or len(state.waypoint_ids) < 2
                or len(state.waypoint_names) != len(state.waypoint_ids)
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            destination_id = state.waypoint_ids[-1]
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "destination_location_id": (
                        destination_id,
                        (state.evidence,),
                        "final_destination_from_current_navigation_v1",
                    )
                },
            )
            search_arguments = {
                "location_id": destination_id,
                "category_poi": "restaurants",
            }
            search = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="search_poi_at_location",
                arguments=search_arguments,
                proposition="current_destination_poi_candidates",
            )
            if search is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="search_poi_at_location",
                        arguments=search_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="search_poi_at_location",
                    arguments=search_arguments,
                    semantic_operation=_CURRENT_DESTINATION_POI_SEARCH,
                    proposition="current_destination_poi_candidates",
                )
            _, poi_evidence = search
            options = self._callable_poi_options_from_evidence(
                poi_evidence,
                location_id=destination_id,
                category="restaurants",
            )
            destination_name = state.waypoint_names[-1]
            if options is None or not self._safe_poi_display_label(
                destination_name, 80
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            presentation = self.responses.poi_search_results(
                location=destination_name,
                poi_names=tuple(option.name for option in options),
                poi_opening_hours=self._poi_opening_hours_for_presentation(options),
                language=self._language(session),
            )
            planned = self._text_plan(
                session,
                presentation,
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
            if planned.envelope.text != presentation:
                session.clear_displayed_destination_pois()
                return planned
            stored = self._store_displayed_poi_options(
                session,
                goal_id=item.goal.goal_id,
                location_id=destination_id,
                category="restaurants",
                location_evidence=state.evidence,
                poi_evidence=poi_evidence,
            )
            if stored != options:
                session.clear_displayed_destination_pois()
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return planned
        return None

    def _next_displayed_poi_call_action(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _CALL_DISPLAYED_DESTINATION_POI:
                continue
            deterministic = self._deterministic_bound_action(session, prepared)
            return deterministic or self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        return None

    @classmethod
    def _poi_names_from_evidence(
        cls,
        evidence: Evidence,
        *,
        location_id: str,
        category: str,
    ) -> tuple[str, ...] | None:
        candidates = evidence.value
        if not isinstance(candidates, list) or not 1 <= len(candidates) <= 20:
            return None
        names: list[str] = []
        seen_ids: set[str] = set()
        for candidate in candidates:
            if not isinstance(candidate, Mapping):
                return None
            poi_id = candidate.get("id")
            name = candidate.get("name")
            observed_category = candidate.get("category")
            if (
                not isinstance(poi_id, str)
                or not poi_id.startswith("poi_")
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(poi_id) is None
                or poi_id in seen_ids
                or not isinstance(name, str)
                or not cls._voice_result_field(name, 120)
                or not isinstance(observed_category, str)
                or _argument_identifier(observed_category)
                != _argument_identifier(category)
                or candidate.get("corresponding_location_id") != location_id
            ):
                return None
            seen_ids.add(poi_id)
            names.append(name.strip())
        return tuple(names)

    def _next_named_poi_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _POI_SEARCH_AT_LOCATION:
                continue
            session.clear_displayed_destination_pois()
            location_name = item.goal.desired_outcome.get("location_name")
            category = item.goal.desired_outcome.get("category")
            if (
                not isinstance(location_name, str)
                or not self._voice_result_field(location_name, 120)
                or not isinstance(category, str)
                or not self._voice_result_field(category, 80)
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            if not session.live_tools.has_tool("search_poi_at_location"):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            required_search_parameters = session.live_tools.required_parameters(
                "search_poi_at_location"
            )
            search_schema_is_complete = {
                "location_id",
                "category_poi",
            }.issubset(required_search_parameters)
            has_full_navigation_followup = all(
                session.live_tools.has_tool(name)
                for name in (
                    "set_new_navigation",
                    "navigation_replace_final_destination",
                )
            )
            if has_full_navigation_followup and not search_schema_is_complete:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )

            location_arguments = {"location": location_name}
            location = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_location_id_by_location_name",
                arguments=location_arguments,
                proposition="poi_location_id",
            )
            if location is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_location_id_by_location_name",
                        arguments=location_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_location_id_by_location_name",
                    arguments=location_arguments,
                    semantic_operation="resolve_poi_location",
                    proposition="poi_location_id",
                )
            location_id, location_evidence = location
            if not isinstance(
                location_id, str
            ) or not self._remember_exact_location_resolution(
                session,
                literal_name=location_name,
                location_id=location_id,
                evidence=location_evidence,
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            if not search_schema_is_complete:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            try:
                session.live_tools.validate_arguments(
                    "search_poi_at_location",
                    {
                        "location_id": location_id,
                        "category_poi": category,
                    },
                )
            except ToolArgumentValidationError:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "location_id": (
                        location_id,
                        (location_evidence,),
                        "exact_named_poi_location_v1",
                    )
                },
            )

            search_arguments: dict[str, Any] = {
                "location_id": location_id,
                "category_poi": category,
            }
            filters = item.goal.desired_outcome.get("filters")
            if filters is not None:
                if (
                    not isinstance(filters, list)
                    or len(filters) > 12
                    or any(not isinstance(value, str) for value in filters)
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                    )
                search_arguments["filters"] = filters
            search = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="search_poi_at_location",
                arguments=search_arguments,
                proposition="poi_candidates",
            )
            if search is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="search_poi_at_location",
                        arguments=search_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="search_poi_at_location",
                    arguments=search_arguments,
                    semantic_operation=_POI_SEARCH_AT_LOCATION,
                    proposition="poi_candidates",
                )
            _, poi_evidence = search
            poi_names = self._poi_names_from_evidence(
                poi_evidence,
                location_id=location_id,
                category=category,
            )
            if poi_names is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            callable_options: tuple[DestinationPOIOption, ...] | None = None
            if _argument_identifier(category) == "restaurants":
                callable_options = self._callable_poi_options_from_evidence(
                    poi_evidence,
                    location_id=location_id,
                    category=category,
                )
                if callable_options is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                poi_names = tuple(option.name for option in callable_options)
            if not self._safe_poi_display_label(location_name, 120):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            presentation = self.responses.poi_search_results(
                location=location_name,
                poi_names=poi_names,
                poi_opening_hours=(
                    self._poi_opening_hours_for_presentation(callable_options)
                    if callable_options is not None
                    else None
                ),
                language=self._language(session),
            )
            planned = self._text_plan(
                session,
                presentation,
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
            if planned.envelope.text != presentation:
                session.clear_displayed_destination_pois()
                return planned
            if callable_options is not None:
                stored = self._store_displayed_poi_options(
                    session,
                    goal_id=item.goal.goal_id,
                    location_id=location_id,
                    category=category,
                    location_evidence=location_evidence,
                    poi_evidence=poi_evidence,
                )
                if stored != callable_options:
                    session.clear_displayed_destination_pois()
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
            return planned
        return None

    @classmethod
    def _destination_route_options_from_evidence(
        cls,
        evidence: Evidence,
        *,
        start_id: str,
        destination_id: str,
    ) -> tuple[DestinationRouteOption, ...] | None:
        routes = evidence.value
        if not isinstance(routes, list) or not 2 <= len(routes) <= 3:
            return None
        options: list[DestinationRouteOption] = []
        seen_ids: set[str] = set()
        seen_ordinals: set[str] = set()
        for route in routes:
            if not isinstance(route, Mapping):
                return None
            route_id = route.get("route_id")
            raw_aliases = route.get("alias")
            via = route.get("name_via")
            distance_value = route.get("distance_km")
            hours_value = route.get("duration_hours")
            minutes_value = route.get("duration_minutes")
            road_types = route.get("road_types")
            includes_toll = route.get("includes_toll")
            if (
                not isinstance(route_id, str)
                or _ROUTE_ID_PATTERN.fullmatch(route_id) is None
                or route_id in seen_ids
                or route.get("start_id") != start_id
                or route.get("destination_id") != destination_id
                or not isinstance(raw_aliases, list)
                or not raw_aliases
                or len(raw_aliases) > 5
                or any(not isinstance(alias, str) for alias in raw_aliases)
                or not isinstance(via, str)
                or _ROUTE_VIA_PATTERN.fullmatch(via.strip()) is None
                or isinstance(distance_value, bool)
                or not isinstance(distance_value, (int, float, Decimal))
                or isinstance(hours_value, bool)
                or isinstance(minutes_value, bool)
                or not isinstance(hours_value, (int, float, Decimal))
                or not isinstance(minutes_value, (int, float, Decimal))
                or not isinstance(road_types, list)
                or len(road_types) > 12
                or any(
                    not isinstance(road_type, str)
                    or not cls._voice_result_field(road_type, 80)
                    for road_type in road_types
                )
                or not isinstance(includes_toll, bool)
            ):
                return None
            aliases = tuple(_argument_identifier(alias) for alias in raw_aliases)
            allowed_aliases = {*_ROUTE_ORDINALS, "fastest", "shortest"}
            ordinals = [alias for alias in aliases if alias in _ROUTE_ORDINALS]
            if (
                len(set(aliases)) != len(aliases)
                or any(alias not in allowed_aliases for alias in aliases)
                or len(ordinals) != 1
                or ordinals[0] in seen_ordinals
            ):
                return None
            try:
                distance = Decimal(str(distance_value))
                hours_decimal = Decimal(str(hours_value))
                minutes_decimal = Decimal(str(minutes_value))
                hours = int(hours_decimal)
                minutes = int(minutes_decimal)
            except (InvalidOperation, TypeError, ValueError):
                return None
            if (
                not distance.is_finite()
                or distance < 0
                or not hours_decimal.is_finite()
                or not minutes_decimal.is_finite()
                or hours_decimal != hours
                or minutes_decimal != minutes
                or not 0 <= hours <= 240
                or not 0 <= minutes <= 60
                or hours * 60 + minutes > 240 * 60 + 59
            ):
                return None
            seen_ids.add(route_id)
            seen_ordinals.add(ordinals[0])
            options.append(
                DestinationRouteOption(
                    route_id=route_id,
                    ordinal=ordinals[0],
                    aliases=aliases,
                    via=via.strip(),
                    distance_km=distance,
                    duration_minutes=hours * 60 + minutes,
                    includes_toll=includes_toll,
                )
            )
        expected_ordinals = set(_ROUTE_ORDINALS[: len(options)])
        if seen_ordinals != expected_ordinals:
            return None
        fastest = [option for option in options if "fastest" in option.aliases]
        shortest = [option for option in options if "shortest" in option.aliases]
        if len(fastest) != 1 or len(shortest) != 1:
            return None
        minimum_duration = min(option.duration_minutes for option in options)
        minimum_distance = min(option.distance_km for option in options)
        if (
            fastest[0].duration_minutes != minimum_duration
            or shortest[0].distance_km != minimum_distance
            or len(
                {
                    (option.distance_km, option.duration_minutes)
                    for option in options
                }
            )
            != len(options)
        ):
            return None
        order = {ordinal: index for index, ordinal in enumerate(_ROUTE_ORDINALS)}
        return tuple(sorted(options, key=lambda option: order[option.ordinal]))

    @staticmethod
    def _route_options_matching_choice(
        options: Sequence[DestinationRouteOption], route_choice: str
    ) -> tuple[DestinationRouteOption, ...]:
        """Match one validated route by its ordinal or explicit route alias."""

        normalized = _argument_identifier(route_choice)
        if normalized not in {*_ROUTE_ORDINALS, "fastest", "shortest"}:
            return ()
        if normalized == "shortest":
            minimum_distance = min(option.distance_km for option in options)
            if (
                sum(option.distance_km == minimum_distance for option in options)
                != 1
            ):
                return ()
        elif normalized == "fastest":
            minimum_duration = min(option.duration_minutes for option in options)
            if (
                sum(
                    option.duration_minutes == minimum_duration for option in options
                )
                != 1
            ):
                return ()
        return tuple(
            option
            for option in options
            if option.ordinal == normalized or normalized in option.aliases
        )

    def _route_choice_context(
        self, session: SessionState, *, goal: Goal
    ) -> tuple[str, str, str, str] | None:
        proposition = "replacement_destination_route_options"
        if goal.semantic_operation == _NAVIGATION_REPLACE_DESTINATION:
            start_id = goal.desired_outcome.get("replacement_route_start_id")
            destination_id = goal.desired_outcome.get("new_destination_id")
            destination_name = goal.desired_outcome.get("new_destination_name")
        elif goal.semantic_operation == _NAVIGATION_DELETE_WAYPOINT:
            state = self._navigation_state_view(session, goal_id=goal.goal_id)
            waypoint_index = (
                self._named_waypoint_delete_index(goal, state)
                if state is not None and state.active
                else None
            )
            if state is None or waypoint_index is None or not state.waypoint_names:
                return None
            start_id = state.waypoint_ids[waypoint_index - 1]
            destination_id = state.waypoint_ids[waypoint_index + 1]
            destination_name = state.waypoint_names[-1]
            proposition = "waypoint_delete_route_options"
        elif goal.semantic_operation in _NAVIGATION_CREATE_OPERATIONS:
            start_id = goal.desired_outcome.get("start_id")
            destination_id = goal.desired_outcome.get("destination_id")
            destination_name = goal.desired_outcome.get("location")
            proposition = "route_options"
            conditional_proposition = goal.desired_outcome.get(
                "conditional_route_options_proposition"
            )
            if goal.desired_outcome.get(
                _CONDITIONAL_ARRIVAL_WEATHER_NAVIGATION_MARKER
            ) is True and conditional_proposition in {
                "conditional_arrival_route_options",
                "route_options",
            }:
                proposition = conditional_proposition
        elif (
            goal.semantic_operation == _TRIP_RANGE_OPERATION
            and goal.desired_outcome.get(_TRIP_RANGE_ROUTE_SELECTION_MARKER) is True
        ):
            start_id = goal.desired_outcome.get("start_id")
            destination_id = goal.desired_outcome.get("destination_id")
            destination_name = goal.desired_outcome.get("destination_name")
            proposition = "trip_route_options"
        else:
            return None
        if (
            not isinstance(start_id, str)
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(start_id) is None
            or not isinstance(destination_id, str)
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(destination_id) is None
            or not isinstance(destination_name, str)
            or not self._voice_result_field(destination_name, 120)
        ):
            return None
        return start_id, destination_id, destination_name, proposition

    def _route_alternative_detail_plan(
        self, session: SessionState, *, goal_id: str
    ) -> PlannedOutbound | None:
        if session.intent is None:
            return None
        goal = next(
            (
                candidate
                for candidate in session.intent.goals
                if candidate.goal_id == goal_id
            ),
            None,
        )
        if goal is None:
            return None
        context = self._route_choice_context(session, goal=goal)
        if context is None:
            return None
        start_id, destination_id, _, proposition = context
        arguments = {"start_id": start_id, "destination_id": destination_id}
        route = self._derived_navigation_read_value(
            session,
            goal_id=goal_id,
            tool_name="get_routes_from_start_to_destination",
            arguments=arguments,
            proposition=proposition,
        )
        if route is None:
            return None
        _, evidence = route
        options = self._destination_route_options_from_evidence(
            evidence,
            start_id=start_id,
            destination_id=destination_id,
        )
        if options is None:
            return None
        highlighted_ids = {
            option.route_id
            for option in options
            if "fastest" in option.aliases or "shortest" in option.aliases
        }
        alternatives = tuple(
            option for option in options if option.route_id not in highlighted_ids
        )
        if not alternatives:
            return None
        return self._text_plan(
            session,
            self.responses.route_alternative_details(
                route_options=tuple(
                    (
                        option.ordinal,
                        option.via,
                        format(option.distance_km.normalize(), "f"),
                        option.duration_minutes,
                        option.includes_toll,
                    )
                    for option in alternatives
                ),
                language=self._language(session),
            ),
            goal_ids=[goal_id],
            kind=ProposalKind.ASK_USER,
        )

    def _destination_route_clarification_matches(
        self,
        session: SessionState,
        *,
        request: Any,
        text: str,
    ) -> list[ClarificationOption]:
        constraints = _bounded_route_choice_constraints(text)
        if constraints is None:
            explicit_alias = _explicit_route_alias_reply(text)
            if explicit_alias is not None:
                constraints = _RouteChoiceConstraints(
                    aliases=frozenset({explicit_alias})
                )
        if constraints is None or not isinstance(request.goal_id, str):
            return []
        if session.intent is None:
            return []
        slot = next(
            (
                candidate
                for candidate in session.intent.unresolved_slots
                if candidate.goal_id == request.goal_id
                and candidate.name == "route_choice_alias"
            ),
            None,
        )
        if slot is None:
            return []
        candidate_values = {
            candidate.candidate_id: candidate.value for candidate in slot.candidates
        }
        goal = next(
            (
                candidate
                for candidate in session.intent.goals
                if candidate.goal_id == request.goal_id
            ),
            None,
        )
        if goal is None:
            return []
        if (
            goal.semantic_operation == _TRIP_RANGE_OPERATION
            and re.search(
                r"\bstart\s+(?:the\s+)?navigation\b|"
                r"\bset\s+(?:(?:my|the)\s+)?navigation\s+to\b",
                text,
                re.IGNORECASE,
            )
            is not None
        ):
            # A route-range question is read-only. Do not let its choice prompt
            # absorb a new request to start or configure navigation.
            return []
        context = self._route_choice_context(session, goal=goal)
        if context is None:
            return []
        start_id, destination_id, destination_name, proposition = context
        route = self._derived_navigation_read_value(
            session,
            goal_id=goal.goal_id,
            tool_name="get_routes_from_start_to_destination",
            arguments={"start_id": start_id, "destination_id": destination_id},
            proposition=proposition,
        )
        if route is None:
            if constraints.aliases or constraints.deictic or constraints.mentioned:
                return []
            stale_matches: list[ClarificationOption] = []
            for candidate in request.options:
                reference = _parse_route_reference(_route_choice_words(candidate.label))
                if reference is None:
                    continue
                if constraints.ordinals and not constraints.ordinals.issubset(
                    reference.ordinals
                ):
                    continue
                if constraints.vias and any(
                    via not in reference.vias for via in constraints.vias
                ):
                    continue
                stale_matches.append(candidate)
            return stale_matches if len(stale_matches) == 1 else []
        _, evidence = route
        options = self._destination_route_options_from_evidence(
            evidence,
            start_id=start_id,
            destination_id=destination_id,
        )
        if options is None:
            return []
        fastest = next(option for option in options if "fastest" in option.aliases)
        shortest = next(option for option in options if "shortest" in option.aliases)
        highlighted = (fastest,) if fastest == shortest else (fastest, shortest)
        has_explicit_constraint = bool(
            constraints.ordinals or constraints.aliases or constraints.vias
        )
        if constraints.mentioned or (
            constraints.deictic and not has_explicit_constraint
        ):
            initial_presentation = self.responses.destination_route_options(
                destination=destination_name,
                route_highlights=tuple(
                    (
                        option.ordinal,
                        option.via,
                        format(option.distance_km.normalize(), "f"),
                        option.duration_minutes,
                        option.includes_toll,
                    )
                    for option in highlighted
                ),
                further_route_count=len(options) - len(highlighted),
                language=self._language(session),
                replacement_preview=(
                    goal.semantic_operation == _NAVIGATION_REPLACE_DESTINATION
                ),
            )
            latest_assistant_text = next(
                (
                    message.get("content")
                    for message in reversed(session.conversation)
                    if message.get("role") == "assistant"
                    and isinstance(message.get("content"), str)
                ),
                None,
            )
            if latest_assistant_text != initial_presentation:
                return []
        if not has_explicit_constraint:
            if constraints.mentioned:
                selected = [highlighted[0]]
            elif constraints.deictic and len(highlighted) == 1:
                selected = [highlighted[0]]
            else:
                return []
        else:
            selected = list(options)
            for ordinal in constraints.ordinals:
                selected = [option for option in selected if option.ordinal == ordinal]
            for alias in constraints.aliases:
                selected = [option for option in selected if alias in option.aliases]
            for via in constraints.vias:
                selected = [
                    option
                    for option in selected
                    if tuple(
                        token
                        for token in _route_choice_words(option.via)
                        if token != "and"
                    )
                    == via
                ]
        if len(selected) != 1:
            return []
        if constraints.mentioned and selected[0] != highlighted[0]:
            return []
        return [
            candidate
            for candidate in request.options
            if _argument_identifier(
                str(candidate_values.get(candidate.candidate_id, ""))
            )
            == selected[0].ordinal
        ]

    def _ensure_destination_route_clarification(
        self,
        session: SessionState,
        *,
        item: PreparedGoal,
        destination_name: str,
        options: tuple[DestinationRouteOption, ...],
    ) -> PlannedOutbound:
        if session.intent is None:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        candidates = [
            Candidate(
                candidate_id=f"destination-route-{item.goal.goal_id}-{option.ordinal}",
                value=option.ordinal,
                label=f"{option.ordinal} route via {option.via}",
            )
            for option in options
        ]
        slot = AmbiguitySlot(
            name="route_choice_alias",
            candidates=candidates,
            goal_id=item.goal.goal_id,
            source_turn_ids=list(session.intent.intent_source_turn_ids),
        )
        slots = [
            existing.model_copy(deep=True)
            for existing in session.intent.unresolved_slots
            if not (
                existing.goal_id == item.goal.goal_id
                and existing.name == "route_choice_alias"
            )
        ]
        slots.append(slot)
        session.intent = session.intent.model_copy(
            update={"unresolved_slots": slots}, deep=True
        )
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        resolution = self.disambiguation.resolve(slot)
        request = resolution.clarification_request
        if (
            resolution.outcome is not GateOutcome.NEED_USER_DISAMBIGUATION
            or request is None
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        session.pending_clarifications[request.request_id] = request
        fastest = next(option for option in options if "fastest" in option.aliases)
        shortest = next(option for option in options if "shortest" in option.aliases)
        highlighted = (fastest,) if fastest == shortest else (fastest, shortest)
        return self._text_plan(
            session,
            self.responses.destination_route_options(
                destination=destination_name,
                route_highlights=tuple(
                    (
                        option.ordinal,
                        option.via,
                        format(option.distance_km.normalize(), "f"),
                        option.duration_minutes,
                        option.includes_toll,
                    )
                    for option in highlighted
                ),
                further_route_count=len(options) - len(highlighted),
                language=self._language(session),
                replacement_preview=(
                    item.goal.semantic_operation == _NAVIGATION_REPLACE_DESTINATION
                ),
            ),
            goal_ids=[item.goal.goal_id],
            kind=ProposalKind.ASK_USER,
        )

    @staticmethod
    def _conditional_arrival_weather_navigation_goal(
        session: SessionState,
    ) -> Goal | None:
        if not isinstance(session.intent, IntentFrame):
            return None
        matches = [
            goal
            for goal in session.intent.goals
            if goal.semantic_operation in _NAVIGATION_CREATE_OPERATIONS
            and goal.desired_outcome.get(_CONDITIONAL_ARRIVAL_WEATHER_NAVIGATION_MARKER)
            is True
        ]
        return matches[0] if len(matches) == 1 else None

    @classmethod
    def _conditional_navigation_schema_available(
        cls,
        session: SessionState,
        *,
        primary_name: str,
        start_id: str,
    ) -> bool:
        if session.live_tools is None:
            return False
        probe_location_id = "loc_conditional_probe"
        probe_route_id = "rll_conditional_probe"
        current_datetime = getattr(session.compiled_policy, "current_datetime", None)
        if not isinstance(current_datetime, Mapping):
            return False
        month = current_datetime.get("month")
        day = current_datetime.get("day")
        hour = current_datetime.get("hour")
        if any(type(value) is not int for value in (month, day, hour)):
            return False
        calls = (
            (
                "get_location_id_by_location_name",
                {"location": primary_name},
            ),
            (
                "get_routes_from_start_to_destination",
                {"start_id": start_id, "destination_id": probe_location_id},
            ),
            (
                "get_weather",
                {
                    "location_or_poi_id": probe_location_id,
                    "month": month,
                    "day": day,
                    "time_hour_24hformat": hour,
                },
            ),
            (
                "search_poi_at_location",
                {
                    "location_id": probe_location_id,
                    "category_poi": "charging_stations",
                },
            ),
            (
                "get_current_navigation_state",
                {"detailed_information": True},
            ),
            ("set_new_navigation", {"route_ids": [probe_route_id]}),
        )
        try:
            return all(
                session.live_tools.has_tool(tool_name)
                and session.live_tools.validate_arguments(tool_name, arguments)
                == arguments
                for tool_name, arguments in calls
            )
        except ToolArgumentValidationError:
            return False

    @classmethod
    def _conditional_route_options_from_evidence(
        cls,
        evidence: Evidence,
        *,
        start_id: str,
        destination_id: str,
    ) -> tuple[DestinationRouteOption, ...] | None:
        routes = evidence.value
        if not isinstance(routes, list) or not 1 <= len(routes) <= 3:
            return None
        options: list[DestinationRouteOption] = []
        seen_ids: set[str] = set()
        seen_ordinals: set[str] = set()
        for route in routes:
            if not isinstance(route, Mapping):
                return None
            route_id = route.get("route_id")
            raw_aliases = route.get("alias")
            via = route.get("name_via")
            distance_value = route.get("distance_km")
            hours_value = route.get("duration_hours")
            minutes_value = route.get("duration_minutes")
            includes_toll = route.get("includes_toll")
            if (
                not isinstance(route_id, str)
                or _ROUTE_ID_PATTERN.fullmatch(route_id) is None
                or route_id in seen_ids
                or route.get("start_id") != start_id
                or route.get("destination_id") != destination_id
                or not isinstance(raw_aliases, list)
                or not raw_aliases
                or len(raw_aliases) > 5
                or any(not isinstance(alias, str) for alias in raw_aliases)
                or not isinstance(via, str)
                or _ROUTE_VIA_PATTERN.fullmatch(via.strip()) is None
                or isinstance(distance_value, bool)
                or not isinstance(distance_value, (int, float, Decimal))
                or isinstance(hours_value, bool)
                or not isinstance(hours_value, (int, float, Decimal))
                or isinstance(minutes_value, bool)
                or not isinstance(minutes_value, (int, float, Decimal))
                or not isinstance(includes_toll, bool)
            ):
                return None
            aliases = tuple(_argument_identifier(alias) for alias in raw_aliases)
            allowed_aliases = {*_ROUTE_ORDINALS, "fastest", "shortest"}
            ordinals = [alias for alias in aliases if alias in _ROUTE_ORDINALS]
            try:
                distance = Decimal(str(distance_value))
                hours_decimal = Decimal(str(hours_value))
                minutes_decimal = Decimal(str(minutes_value))
                hours = int(hours_decimal)
                minutes = int(minutes_decimal)
            except (InvalidOperation, TypeError, ValueError):
                return None
            if (
                len(set(aliases)) != len(aliases)
                or any(alias not in allowed_aliases for alias in aliases)
                or len(ordinals) != 1
                or ordinals[0] in seen_ordinals
                or not distance.is_finite()
                or distance < 0
                or not hours_decimal.is_finite()
                or hours_decimal != hours
                or not minutes_decimal.is_finite()
                or minutes_decimal != minutes
                or not 0 <= hours <= 23
                or not 0 <= minutes <= 59
            ):
                return None
            seen_ids.add(route_id)
            seen_ordinals.add(ordinals[0])
            options.append(
                DestinationRouteOption(
                    route_id=route_id,
                    ordinal=ordinals[0],
                    aliases=aliases,
                    via=via.strip(),
                    distance_km=distance,
                    duration_minutes=hours * 60 + minutes,
                    includes_toll=includes_toll,
                )
            )
        if seen_ordinals != set(_ROUTE_ORDINALS[: len(options)]):
            return None
        fastest = [option for option in options if "fastest" in option.aliases]
        shortest = [option for option in options if "shortest" in option.aliases]
        if (
            len(fastest) != 1
            or len(shortest) != 1
            or fastest[0].duration_minutes
            != min(option.duration_minutes for option in options)
            or shortest[0].distance_km != min(option.distance_km for option in options)
        ):
            return None
        order = {ordinal: index for index, ordinal in enumerate(_ROUTE_ORDINALS)}
        return tuple(sorted(options, key=lambda option: order[option.ordinal]))

    @staticmethod
    def _weather_slot_contains_arrival(
        value: Any,
        *,
        arrival_minute: int,
    ) -> bool | None:
        if not isinstance(value, Mapping):
            return None
        slot = value.get("current_slot")
        if not isinstance(slot, Mapping):
            return None

        def clock_minute(raw: Any, *, end: bool) -> int | None:
            if not isinstance(raw, str):
                return None
            match = re.fullmatch(
                r"(?P<hour>[01][0-9]|2[0-4]):(?P<minute>[0-5][0-9])", raw
            )
            if match is None:
                return None
            hour = int(match.group("hour"))
            minute = int(match.group("minute"))
            if hour == 24 and (minute != 0 or not end):
                return None
            return hour * 60 + minute

        start = clock_minute(slot.get("start_time"), end=False)
        end = clock_minute(slot.get("end_time"), end=True)
        condition = slot.get("condition")
        if (
            start is None
            or end is None
            or not start <= arrival_minute < end
            or not isinstance(condition, str)
            or re.fullmatch(r"[A-Za-z][A-Za-z _-]{0,79}", condition) is None
        ):
            return None
        normalized = " ".join(re.sub(r"[_-]+", " ", condition.casefold()).split())
        known_dry = {
            "cloudy",
            "cloudy and fog",
            "cloudy and hail",
            "cloudy and thunderstorm",
            "partly cloudy",
            "snowy",
            "sunny",
        }
        known_rain = {
            "cloudy and rain",
            "cloudy and rain and hail",
            "cloudy and rain and thunderstorm",
            "rain",
            "raining",
            "rainy",
        }
        if normalized in known_rain:
            return True
        if normalized in known_dry:
            return False
        return None

    def _conditional_confirmation_reply_conflicts(
        self,
        session: SessionState,
        bundle: ExecutionBundle,
        text: str,
    ) -> bool:
        goal = self._conditional_arrival_weather_navigation_goal(session)
        if (
            goal is None
            or bundle.goal_ids != (goal.goal_id,)
            or len(bundle.calls) != 1
            or bundle.calls[0].tool_name != "set_new_navigation"
        ):
            return False
        selected_destination = goal.desired_outcome.get("selected_destination_name")
        selected_route_label = goal.desired_outcome.get("selected_route_label")
        if not isinstance(selected_destination, str) or not isinstance(
            selected_route_label, str
        ):
            return True

        text_identifier = f"_{_argument_identifier(text)}_"
        selected_identifier = _argument_identifier(selected_destination)
        for key in ("primary_location_name", "fallback_location_name"):
            candidate = goal.desired_outcome.get(key)
            if not isinstance(candidate, str):
                continue
            candidate_identifier = _argument_identifier(candidate)
            if (
                candidate_identifier
                and candidate_identifier != selected_identifier
                and f"_{candidate_identifier}_" in text_identifier
            ):
                return True

        route_reply = re.sub(
            r"\A\s*(?:yes|yeah|yep|sure)\s*[,!.]?\s+",
            "",
            text,
            count=1,
            flags=re.IGNORECASE,
        )
        explicit_route = _explicit_route_alias_reply(route_reply)
        if explicit_route is None:
            return False
        allowed_routes = {
            alias
            for alias in ("fastest", "shortest")
            if re.search(
                rf"\b{re.escape(alias)}\b", selected_route_label, re.IGNORECASE
            )
            is not None
        }
        return explicit_route not in allowed_routes

    def _current_day_meeting_confirmation_reply_kind(
        self,
        session: SessionState,
        bundle: ExecutionBundle,
        text: str,
    ) -> Literal["positive", "negative", "invalid"] | None:
        goal = self._current_day_meeting_goal(session)
        if (
            goal is None
            or bundle.goal_ids != (goal.goal_id,)
            or len(bundle.calls) != 1
            or bundle.calls[0].tool_name != "send_email"
        ):
            return None
        normalized = re.sub(
            r"[^a-z0-9']+",
            " ",
            unicodedata.normalize("NFKC", text)
            .casefold()
            .replace("\u2019", "'"),
        ).strip()
        if _CURRENT_DAY_MEETING_ATOMIC_REJECTION_RE.fullmatch(normalized) is not None:
            return "negative"
        if (
            normalized in _CURRENT_DAY_MEETING_ATOMIC_POSITIVE_RESPONSES
            or _CURRENT_DAY_MEETING_ATOMIC_SEND_CONFIRMATION_RE.fullmatch(normalized)
            is not None
        ):
            return "positive"
        return "invalid"

    def _resume_confirmation_reply_conflicts(
        self,
        session: SessionState,
        bundle: ExecutionBundle,
        text: str,
    ) -> bool:
        goal = self._navigation_resume_goal(session)
        if (
            goal is None
            or bundle.goal_ids != (goal.goal_id,)
            or len(bundle.calls) != 1
            or bundle.calls[0].tool_name != "set_new_navigation"
        ):
            return False
        if re.search(
            r"\b(?:no|cancel|stop|reject|do\s+not|don['\u2019]?t|never\s+mind)\b",
            text,
            re.IGNORECASE,
        ):
            return False
        return (
            re.search(
                r"\b(?:but|change|different|except|instead|only|rather\s+than)\b|"
                r"\b(?:navigate|navigation|route)\s+to\b|"
                r"\bvia\b|"
                r"\b(?:fastest|shortest|first|second|third)\s+route\b",
                text,
                re.IGNORECASE,
            )
            is not None
        )

    @staticmethod
    def _conditional_selected_route_label(
        session: SessionState,
        *,
        route_choice: Any,
        selected: DestinationRouteOption,
    ) -> str:
        if route_choice is None:
            if {"fastest", "shortest"}.issubset(selected.aliases):
                return "fastest and shortest"
            return "only available"
        normalized = _argument_identifier(str(route_choice))
        latest = _latest_user_text(session)
        explicit_alias = (
            _explicit_route_alias_reply(latest) if latest is not None else None
        )
        if explicit_alias is not None and explicit_alias in selected.aliases:
            return explicit_alias
        constraints = (
            _bounded_route_choice_constraints(latest) if latest is not None else None
        )
        explicit_aliases = (
            []
            if constraints is None
            else [alias for alias in constraints.aliases if alias in selected.aliases]
        )
        if len(explicit_aliases) == 1:
            return explicit_aliases[0]
        return normalized

    @staticmethod
    def _unambiguous_conditional_route(
        options: tuple[DestinationRouteOption, ...],
    ) -> DestinationRouteOption | None:
        if len(options) == 1:
            return options[0]
        shared = [
            option
            for option in options
            if {"fastest", "shortest"}.issubset(option.aliases)
        ]
        return shared[0] if len(shared) == 1 else None

    @classmethod
    def _fastest_available_charging_destination(
        cls,
        evidence: Evidence,
        *,
        location_id: str,
    ) -> tuple[str, str] | None:
        rows = evidence.value
        if not isinstance(rows, list) or not 1 <= len(rows) <= 20:
            return None
        candidates: list[tuple[Decimal, str, str]] = []
        seen_ids: set[str] = set()
        for row in rows:
            if not isinstance(row, Mapping):
                return None
            poi_id = row.get("id")
            name = row.get("name")
            plugs = row.get("charging_plugs")
            if (
                not isinstance(poi_id, str)
                or not poi_id.startswith("poi_")
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(poi_id) is None
                or poi_id in seen_ids
                or not isinstance(name, str)
                or not cls._safe_poi_display_label(name, 120)
                or row.get("category") != "charging_stations"
                or row.get("corresponding_location_id") != location_id
                or not isinstance(plugs, list)
                or not plugs
            ):
                return None
            powers: list[Decimal] = []
            for plug in plugs:
                if not isinstance(plug, Mapping):
                    return None
                power = plug.get("power_kw")
                availability = plug.get("availability")
                if (
                    isinstance(power, bool)
                    or not isinstance(power, (int, float, Decimal))
                    or not isinstance(availability, str)
                ):
                    return None
                try:
                    power_value = Decimal(str(power))
                except (InvalidOperation, TypeError, ValueError):
                    return None
                if not power_value.is_finite() or not 0 < power_value <= 1000:
                    return None
                if _argument_identifier(availability) == "available":
                    powers.append(power_value)
            seen_ids.add(poi_id)
            if powers:
                candidates.append((max(powers), poi_id, name))
        if not candidates:
            return None
        maximum = max(candidate[0] for candidate in candidates)
        selected = [candidate for candidate in candidates if candidate[0] == maximum]
        return (selected[0][1], selected[0][2]) if len(selected) == 1 else None

    def _conditional_route_clarification_plan(
        self,
        session: SessionState,
        *,
        item: PreparedGoal,
        start_id: str,
        destination_name: str,
        destination_id: str,
        destination_evidence: Evidence,
        route_evidence: Evidence,
        route_proposition: str,
        options: tuple[DestinationRouteOption, ...],
    ) -> PlannedOutbound:
        if _LOCATION_OR_POI_ID_PATTERN.fullmatch(
            start_id
        ) is None or route_proposition not in {
            "conditional_arrival_route_options",
            "route_options",
        }:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        self._apply_navigation_derived_parameters(
            session,
            goal=item.goal,
            parameters={
                "location": (
                    destination_name,
                    (destination_evidence,),
                    "conditional_route_clarification_destination_name_v1",
                ),
                "start_id": (
                    start_id,
                    (route_evidence,),
                    "conditional_route_clarification_start_v1",
                ),
                "destination_id": (
                    destination_id,
                    (destination_evidence, route_evidence),
                    "conditional_route_clarification_destination_v1",
                ),
                "conditional_route_options_proposition": (
                    route_proposition,
                    (route_evidence,),
                    "conditional_route_clarification_evidence_scope_v1",
                ),
            },
        )
        refreshed = self._prepare_turn(session)
        refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
        if refreshed_item is None:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        return self._ensure_destination_route_clarification(
            session,
            item=refreshed_item,
            destination_name=destination_name,
            options=options,
        )

    def _next_conditional_arrival_weather_navigation_workflow(
        self,
        session: SessionState,
        prepared: PreparedTurn,
    ) -> PlannedOutbound | None:
        goal = self._conditional_arrival_weather_navigation_goal(session)
        if goal is None:
            return None
        item = prepared.by_goal_id.get(goal.goal_id)
        if item is None:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        primary_name = goal.desired_outcome.get("primary_location_name")
        fallback_name = goal.desired_outcome.get("fallback_location_name")
        route_choice = goal.desired_outcome.get("route_choice_alias")
        current_location = getattr(session.compiled_policy, "current_location", None)
        start_id = (
            current_location.get("id")
            if isinstance(current_location, Mapping)
            else None
        )
        if (
            not isinstance(primary_name, str)
            or not self._safe_poi_display_label(primary_name, 120)
            or not isinstance(fallback_name, str)
            or not self._safe_poi_display_label(fallback_name, 120)
            or (
                route_choice is not None
                and (
                    not isinstance(route_choice, str)
                    or _argument_identifier(route_choice)
                    not in {*_ROUTE_ORDINALS, "fastest", "shortest"}
                )
            )
            or not isinstance(start_id, str)
            or not start_id.startswith("loc_")
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(start_id) is None
            or not self._conditional_navigation_schema_available(
                session, primary_name=primary_name, start_id=start_id
            )
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNSUPPORTED_CAPABILITY
            )

        primary_arguments = {"location": primary_name}
        primary = self._derived_navigation_read_value(
            session,
            goal_id=goal.goal_id,
            tool_name="get_location_id_by_location_name",
            arguments=primary_arguments,
            proposition="resolved_navigation_location_id",
        )
        if primary is None:
            if (
                self._successful_goal_read(
                    session,
                    goal_id=goal.goal_id,
                    tool_name="get_location_id_by_location_name",
                    arguments=primary_arguments,
                )
                is not None
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="get_location_id_by_location_name",
                arguments=primary_arguments,
                semantic_operation="resolve_conditional_primary_location",
                proposition="resolved_navigation_location_id",
            )
        primary_id, primary_evidence = primary
        if (
            not isinstance(primary_id, str)
            or primary_id == start_id
            or not self._remember_exact_location_resolution(
                session,
                literal_name=primary_name,
                location_id=primary_id,
                evidence=primary_evidence,
            )
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )

        primary_route_arguments = {
            "start_id": start_id,
            "destination_id": primary_id,
        }
        self._register_single_read_need(
            session,
            goal_id=goal.goal_id,
            proposition="conditional_arrival_route_options",
        )
        primary_route = self._derived_navigation_read_value(
            session,
            goal_id=goal.goal_id,
            tool_name="get_routes_from_start_to_destination",
            arguments=primary_route_arguments,
            proposition="conditional_arrival_route_options",
        )
        if primary_route is None:
            if (
                self._successful_goal_read(
                    session,
                    goal_id=goal.goal_id,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=primary_route_arguments,
                )
                is not None
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="get_routes_from_start_to_destination",
                arguments=primary_route_arguments,
                semantic_operation="find_conditional_primary_routes",
                proposition="conditional_arrival_route_options",
            )
        _, primary_route_evidence = primary_route
        primary_options = self._conditional_route_options_from_evidence(
            primary_route_evidence,
            start_id=start_id,
            destination_id=primary_id,
        )
        if primary_options is None:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        if route_choice is None:
            primary_default = self._unambiguous_conditional_route(primary_options)
            if primary_default is None:
                return self._conditional_route_clarification_plan(
                    session,
                    item=item,
                    start_id=start_id,
                    destination_name=primary_name,
                    destination_id=primary_id,
                    destination_evidence=primary_evidence,
                    route_evidence=primary_route_evidence,
                    route_proposition="conditional_arrival_route_options",
                    options=primary_options,
                )
            selected_primary = [primary_default]
        else:
            selected_primary = [
                option
                for option in primary_options
                if _argument_identifier(route_choice) in option.aliases
            ]
        current_datetime = getattr(session.compiled_policy, "current_datetime", None)
        if len(selected_primary) != 1 or not isinstance(current_datetime, Mapping):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        month = current_datetime.get("month")
        day = current_datetime.get("day")
        hour = current_datetime.get("hour")
        minute = current_datetime.get("minute")
        if (
            type(month) is not int
            or type(day) is not int
            or type(hour) is not int
            or type(minute) is not int
            or not 1 <= month <= 12
            or not 1 <= day <= 31
            or not 0 <= hour <= 23
            or not 0 <= minute <= 59
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        arrival_minute = hour * 60 + minute + selected_primary[0].duration_minutes
        if not 0 <= arrival_minute < 24 * 60:
            return self._limitation_plan(session, goal, GateOutcome.POLICY_CONFLICT)
        weather_arguments = {
            "location_or_poi_id": primary_id,
            "month": month,
            "day": day,
            "time_hour_24hformat": arrival_minute // 60,
        }
        self._register_single_read_need(
            session,
            goal_id=goal.goal_id,
            proposition="conditional_arrival_weather_snapshot",
        )
        weather = self._derived_navigation_read_value(
            session,
            goal_id=goal.goal_id,
            tool_name="get_weather",
            arguments=weather_arguments,
            proposition="conditional_arrival_weather_snapshot",
        )
        if weather is None:
            if (
                self._successful_goal_read(
                    session,
                    goal_id=goal.goal_id,
                    tool_name="get_weather",
                    arguments=weather_arguments,
                )
                is not None
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="get_weather",
                arguments=weather_arguments,
                semantic_operation="read_conditional_arrival_weather",
                proposition="conditional_arrival_weather_snapshot",
            )
        weather_value, _ = weather
        raining = self._weather_slot_contains_arrival(
            weather_value,
            arrival_minute=arrival_minute,
        )
        if raining is None:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )

        destination_name: str
        destination_id: str
        destination_evidence: Evidence
        route_evidence: Evidence
        selected_route: DestinationRouteOption
        if raining:
            fallback_arguments = {"location": fallback_name}
            self._register_single_read_need(
                session,
                goal_id=goal.goal_id,
                proposition="conditional_fallback_location_id",
            )
            fallback = self._derived_navigation_read_value(
                session,
                goal_id=goal.goal_id,
                tool_name="get_location_id_by_location_name",
                arguments=fallback_arguments,
                proposition="conditional_fallback_location_id",
            )
            if fallback is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=goal.goal_id,
                        tool_name="get_location_id_by_location_name",
                        arguments=fallback_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_location_id_by_location_name",
                    arguments=fallback_arguments,
                    semantic_operation="resolve_conditional_fallback_location",
                    proposition="conditional_fallback_location_id",
                )
            fallback_id, fallback_evidence = fallback
            if (
                not isinstance(fallback_id, str)
                or fallback_id in {start_id, primary_id}
                or not self._remember_exact_location_resolution(
                    session,
                    literal_name=fallback_name,
                    location_id=fallback_id,
                    evidence=fallback_evidence,
                )
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            fallback_route_arguments = {
                "start_id": start_id,
                "destination_id": fallback_id,
            }
            fallback_route = self._derived_navigation_read_value(
                session,
                goal_id=goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=fallback_route_arguments,
                proposition="route_options",
            )
            if fallback_route is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=fallback_route_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=fallback_route_arguments,
                    semantic_operation="find_conditional_fallback_routes",
                    proposition="route_options",
                )
            _, fallback_route_evidence = fallback_route
            fallback_options = self._conditional_route_options_from_evidence(
                fallback_route_evidence,
                start_id=start_id,
                destination_id=fallback_id,
            )
            if fallback_options is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            if route_choice is None:
                fallback_default = self._unambiguous_conditional_route(fallback_options)
                if fallback_default is None:
                    return self._conditional_route_clarification_plan(
                        session,
                        item=item,
                        start_id=start_id,
                        destination_name=fallback_name,
                        destination_id=fallback_id,
                        destination_evidence=fallback_evidence,
                        route_evidence=fallback_route_evidence,
                        route_proposition="route_options",
                        options=fallback_options,
                    )
                selected = [fallback_default]
            else:
                selected = [
                    option
                    for option in fallback_options
                    if _argument_identifier(route_choice) in option.aliases
                ]
            if len(selected) != 1:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            destination_name = fallback_name
            destination_id = fallback_id
            destination_evidence = fallback_evidence
            route_evidence = fallback_route_evidence
            selected_route = selected[0]
        else:
            poi_arguments = {
                "location_id": primary_id,
                "category_poi": "charging_stations",
            }
            self._register_single_read_need(
                session, goal_id=goal.goal_id, proposition="poi_candidates"
            )
            pois = self._derived_navigation_read_value(
                session,
                goal_id=goal.goal_id,
                tool_name="search_poi_at_location",
                arguments=poi_arguments,
                proposition="poi_candidates",
            )
            if pois is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=goal.goal_id,
                        tool_name="search_poi_at_location",
                        arguments=poi_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="search_poi_at_location",
                    arguments=poi_arguments,
                    semantic_operation="find_conditional_charging_stations",
                    proposition="poi_candidates",
                )
            _, poi_evidence = pois
            charging_destination = self._fastest_available_charging_destination(
                poi_evidence,
                location_id=primary_id,
            )
            if charging_destination is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            charging_id, charging_name = charging_destination
            charging_route_arguments = {
                "start_id": start_id,
                "destination_id": charging_id,
            }
            charging_route = self._derived_navigation_read_value(
                session,
                goal_id=goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=charging_route_arguments,
                proposition="route_options",
            )
            if charging_route is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=charging_route_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=charging_route_arguments,
                    semantic_operation="find_routes_to_conditional_charger",
                    proposition="route_options",
                )
            _, charging_route_evidence = charging_route
            charging_options = self._conditional_route_options_from_evidence(
                charging_route_evidence,
                start_id=start_id,
                destination_id=charging_id,
            )
            if charging_options is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            if route_choice is None:
                charging_default = self._unambiguous_conditional_route(charging_options)
                if charging_default is None:
                    return self._conditional_route_clarification_plan(
                        session,
                        item=item,
                        start_id=start_id,
                        destination_name=charging_name,
                        destination_id=charging_id,
                        destination_evidence=poi_evidence,
                        route_evidence=charging_route_evidence,
                        route_proposition="route_options",
                        options=charging_options,
                    )
                selected = [charging_default]
            else:
                selected = [
                    option
                    for option in charging_options
                    if _argument_identifier(route_choice) in option.aliases
                ]
            if len(selected) != 1:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            destination_name = charging_name
            destination_id = charging_id
            destination_evidence = poi_evidence
            route_evidence = charging_route_evidence
            selected_route = selected[0]

        navigation_observation = self._successful_goal_read(
            session,
            goal_id=goal.goal_id,
            tool_name="get_current_navigation_state",
            arguments={"detailed_information": True},
        )
        if navigation_observation is None:
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="get_current_navigation_state",
                arguments={"detailed_information": True},
                semantic_operation="read_current_navigation_for_conditional_create",
                proposition="current_navigation_state",
            )
        state = self._navigation_state_view(session, goal_id=goal.goal_id)
        if (
            state is None
            or state.active
            or self._navigation_state_signature(navigation_observation.value)
            != (False, (), ())
            or not self._destination_navigation_snapshot_is_current(
                session, goal_id=goal.goal_id
            )
        ):
            return self._limitation_plan(session, goal, GateOutcome.POLICY_CONFLICT)
        self._record_navigation_policy_facts(session, goal_id=goal.goal_id, state=state)
        selected_route_label = self._conditional_selected_route_label(
            session,
            route_choice=route_choice,
            selected=selected_route,
        )
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters={
                "location": (
                    destination_name,
                    (destination_evidence,),
                    "conditional_navigation_destination_name_v1",
                ),
                "selected_destination_name": (
                    destination_name,
                    (destination_evidence,),
                    "conditional_navigation_confirmation_destination_v1",
                ),
                "selected_route_label": (
                    selected_route_label,
                    (route_evidence,),
                    "conditional_navigation_confirmation_route_v1",
                ),
                "start_id": (
                    start_id,
                    (route_evidence,),
                    "conditional_navigation_route_start_v1",
                ),
                "route_start_id": (
                    start_id,
                    (route_evidence,),
                    "conditional_navigation_policy_start_v1",
                ),
                "destination_id": (
                    destination_id,
                    (destination_evidence, route_evidence),
                    "conditional_navigation_destination_v1",
                ),
                "route_ids": (
                    [selected_route.route_id],
                    (route_evidence,),
                    "conditional_navigation_selected_route_v1",
                ),
            },
        )
        refreshed = self._prepare_turn(session)
        refreshed_item = refreshed.by_goal_id.get(goal.goal_id)
        target = (
            self._unique_bound_target(refreshed_item)
            if refreshed_item is not None
            else None
        )
        expected = {"route_ids": [selected_route.route_id]}
        if (
            target is None
            or target[1].tool_name != "set_new_navigation"
            or not _argument_value_matches_binding(target[1].arguments, expected)
            or not self._destination_navigation_snapshot_is_current(
                session, goal_id=goal.goal_id
            )
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        deterministic = self._deterministic_bound_action(session, refreshed)
        return deterministic or self._limitation_plan(
            session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
        )

    @staticmethod
    def _navigation_resume_schema_available(session: SessionState) -> bool:
        if not all(
            session.live_tools.has_tool(tool_name)
            for tool_name in (
                "get_current_navigation_state",
                "set_new_navigation",
            )
        ):
            return False
        detailed_domain = session.live_tools.parameter_domain(
            "get_current_navigation_state", "detailed_information"
        )
        route_ids_domain = session.live_tools.parameter_domain(
            "set_new_navigation", "route_ids"
        )
        route_items = (
            route_ids_domain.get("items")
            if isinstance(route_ids_domain, Mapping)
            else None
        )
        if (
            not isinstance(detailed_domain, Mapping)
            or detailed_domain.get("type") != "boolean"
            or not isinstance(route_ids_domain, Mapping)
            or route_ids_domain.get("type") != "array"
            or not isinstance(route_items, Mapping)
            or route_items.get("type") != "string"
            or session.live_tools.required_parameters("set_new_navigation")
            != {"route_ids"}
        ):
            return False
        try:
            session.live_tools.validate_arguments(
                "get_current_navigation_state", {"detailed_information": True}
            )
        except ToolArgumentValidationError:
            return False
        return True

    def _next_navigation_resume_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _NAVIGATION_RESUME:
                continue
            if not all(
                session.live_tools.has_tool(tool_name)
                for tool_name in (
                    "get_current_navigation_state",
                    "set_new_navigation",
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            if not self._navigation_resume_schema_available(session):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )

            navigation_arguments = {"detailed_information": True}
            observed = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_current_navigation_state",
                arguments=navigation_arguments,
                proposition="current_navigation_state",
            )
            if observed is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_current_navigation_state",
                        arguments=navigation_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_current_navigation_state",
                    arguments=navigation_arguments,
                    semantic_operation="read_current_navigation_for_resume",
                    proposition="current_navigation_state",
                )

            state_value, _ = observed
            snapshot = self._resumable_navigation_snapshot(
                session, goal_id=item.goal.goal_id
            )
            if snapshot is None:
                if (
                    isinstance(state_value, Mapping)
                    and state_value.get("navigation_active") is True
                ):
                    return self._text_plan(
                        session,
                        "Navigation is already active, so I did not restart it.",
                        goal_ids=[item.goal.goal_id],
                    )
                if (
                    isinstance(state_value, Mapping)
                    and state_value.get("navigation_active") is False
                    and state_value.get("waypoints_id") == []
                    and state_value.get("routes_to_final_destination_id") == []
                ):
                    return self._text_plan(
                        session,
                        "I could not find a stopped route to resume, so I did not start navigation.",
                        goal_ids=[item.goal.goal_id],
                    )
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            current_location = getattr(
                session.compiled_policy, "current_location", None
            )
            current_location_id = (
                current_location.get("id")
                if isinstance(current_location, Mapping)
                else None
            )
            if (
                not isinstance(current_location_id, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(current_location_id) is None
                or snapshot.waypoint_ids[0] != current_location_id
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.POLICY_CONFLICT
                )

            self._record_navigation_policy_facts(
                session,
                goal_id=item.goal.goal_id,
                state=NavigationStateView(
                    evidence=snapshot.evidence,
                    active=False,
                    waypoint_ids=snapshot.waypoint_ids,
                    route_ids=snapshot.route_ids,
                    waypoint_names=snapshot.waypoint_names,
                ),
            )
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "route_ids": (
                        list(snapshot.route_ids),
                        (snapshot.evidence,),
                        "resumable_route_ids_from_current_navigation_v1",
                    ),
                    "route_start_id": (
                        snapshot.waypoint_ids[0],
                        (snapshot.evidence,),
                        "resumable_route_start_from_current_navigation_v1",
                    ),
                },
            )
            refreshed = self._prepare_turn(session)
            refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
            target = (
                self._unique_bound_target(refreshed_item)
                if refreshed_item is not None
                else None
            )
            expected_arguments = {"route_ids": list(snapshot.route_ids)}
            if (
                target is None
                or target[0] != "set_new_navigation"
                or target[1].tool_name != "set_new_navigation"
                or not _argument_value_matches_binding(
                    target[1].arguments, expected_arguments
                )
                or not self._resumable_navigation_snapshot_is_current(
                    session,
                    goal_id=item.goal.goal_id,
                    expected_route_ids=snapshot.route_ids,
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            policy = self._preview_policy_decision(
                session,
                goal_ids=(item.goal.goal_id,),
                operation=target[0],
                action=target[1],
            )
            if policy.has_blocking_conflict:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.POLICY_CONFLICT
                )
            if policy.required_reads:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            proposal = DecisionProposal(
                kind=ProposalKind.TOOL_SET,
                goal_ids=[item.goal.goal_id],
                tool_calls=[
                    ProposedToolCall(
                        tool_name=target[1].tool_name,
                        arguments=target[1].arguments,
                        goal_id=item.goal.goal_id,
                    )
                ],
            )
            blocked = self._freeze_execution_bundle(session, refreshed, proposal)
            if blocked is not None:
                return blocked
            bundle = session.execution_bundle
            if bundle is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._resume_navigation_confirmation_plan(session, bundle)
        return None

    def _next_navigation_create_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation not in _NAVIGATION_CREATE_OPERATIONS:
                continue
            if not session.live_tools.has_tool("get_current_navigation_state"):
                return None
            if not session.live_tools.has_tool("set_new_navigation"):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            route_ids_domain = session.live_tools.parameter_domain(
                "set_new_navigation", "route_ids"
            )
            route_id_items = (
                route_ids_domain.get("items")
                if isinstance(route_ids_domain, Mapping)
                else None
            )
            if (
                "route_ids"
                not in session.live_tools.required_parameters("set_new_navigation")
                or not isinstance(route_ids_domain, Mapping)
                or route_ids_domain.get("type") != "array"
                or not isinstance(route_id_items, Mapping)
                or route_id_items.get("type") != "string"
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )

            destination_name = item.goal.desired_outcome.get("location")
            if not isinstance(destination_name, str) or not self._voice_result_field(
                destination_name, 120
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            current_location = getattr(
                session.compiled_policy, "current_location", None
            )
            start_id = (
                current_location.get("id")
                if isinstance(current_location, Mapping)
                else None
            )
            if (
                not isinstance(start_id, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(start_id) is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            state_observation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_current_navigation_state",
                arguments={"detailed_information": True},
            )
            if state_observation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_current_navigation_state",
                    arguments={"detailed_information": True},
                    semantic_operation="read_current_navigation_for_create",
                    proposition="current_navigation_state",
                )
            state = self._navigation_state_view(session, goal_id=item.goal.goal_id)
            signature = self._navigation_state_signature(state_observation.value)
            if (
                state is None
                or state.active
                or signature != (False, (), ())
                or not self._destination_navigation_snapshot_is_current(
                    session, goal_id=item.goal.goal_id
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.POLICY_CONFLICT
                )
            self._record_navigation_policy_facts(
                session, goal_id=item.goal.goal_id, state=state
            )

            location_arguments = {"location": destination_name}
            location = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_location_id_by_location_name",
                arguments=location_arguments,
                proposition="resolved_navigation_location_id",
            )
            if location is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_location_id_by_location_name",
                        arguments=location_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_location_id_by_location_name",
                    arguments=location_arguments,
                    semantic_operation="resolve_location",
                    proposition="resolved_navigation_location_id",
                )
            destination_id, location_evidence = location
            if (
                not isinstance(destination_id, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(destination_id) is None
                or destination_id == start_id
                or not self._remember_exact_location_resolution(
                    session,
                    literal_name=destination_name,
                    location_id=destination_id,
                    evidence=location_evidence,
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            route_arguments = {
                "start_id": start_id,
                "destination_id": destination_id,
            }
            route = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_arguments,
                proposition="route_options",
            )
            if route is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=route_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=route_arguments,
                    semantic_operation="find_routes",
                    proposition="route_options",
                )
            _, route_evidence = route
            options = self._destination_route_options_from_evidence(
                route_evidence,
                start_id=start_id,
                destination_id=destination_id,
            )
            if options is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "start_id": (
                        start_id,
                        (route_evidence,),
                        "verified_navigation_create_route_start_v1",
                    ),
                    "route_start_id": (
                        start_id,
                        (route_evidence,),
                        "verified_navigation_create_policy_start_v1",
                    ),
                    "destination_id": (
                        destination_id,
                        (location_evidence, route_evidence),
                        "verified_navigation_create_destination_v1",
                    ),
                },
            )

            goal = next(
                candidate
                for candidate in session.intent.goals
                if candidate.goal_id == item.goal.goal_id
            )
            route_choice = goal.desired_outcome.get("route_choice_alias")
            if route_choice is None:
                refreshed = self._prepare_turn(session)
                refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
                if refreshed_item is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._ensure_destination_route_clarification(
                    session,
                    item=refreshed_item,
                    destination_name=destination_name,
                    options=options,
                )
            if not isinstance(route_choice, str):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            selected = list(
                self._route_options_matching_choice(options, route_choice)
            )
            if len(selected) != 1:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            self._apply_navigation_derived_parameters(
                session,
                goal=goal,
                parameters={
                    "route_ids": (
                        [selected[0].route_id],
                        (route_evidence,),
                        "user_selected_navigation_create_route_v1",
                    )
                },
            )
            refreshed = self._prepare_turn(session)
            refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
            target = (
                self._unique_bound_target(refreshed_item)
                if refreshed_item is not None
                else None
            )
            expected_arguments = {"route_ids": [selected[0].route_id]}
            if (
                target is None
                or target[1].tool_name != "set_new_navigation"
                or not _argument_value_matches_binding(
                    target[1].arguments, expected_arguments
                )
                or not self._destination_navigation_snapshot_is_current(
                    session, goal_id=item.goal.goal_id
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            deterministic = self._deterministic_bound_action(session, refreshed)
            return deterministic or self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        return None

    def _next_displayed_poi_navigation_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if (
                item.goal.semantic_operation != _NAVIGATION_REPLACE_DESTINATION
                or not isinstance(
                    item.goal.desired_outcome.get("displayed_poi_id"), str
                )
            ):
                continue
            if not session.live_tools.has_tool("navigation_replace_final_destination"):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            binding = self._validated_displayed_poi_navigation_binding(
                session, item.goal
            )
            if binding is None:
                return self._displayed_poi_navigation_limitation(
                    session,
                    reason="the selected displayed restaurant could not be reverified",
                )
            candidate, selection_evidence = binding

            state_observation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_current_navigation_state",
                arguments={"detailed_information": True},
            )
            if state_observation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_current_navigation_state",
                    arguments={"detailed_information": True},
                    semantic_operation="read_current_navigation",
                    proposition="current_navigation_state",
                )
            state = self._navigation_state_view(session, goal_id=item.goal.goal_id)
            if (
                state is None
                or not state.active
                or len(state.waypoint_ids) < 2
                or not self._destination_navigation_snapshot_is_current(
                    session, goal_id=item.goal.goal_id
                )
            ):
                return self._displayed_poi_navigation_limitation(
                    session,
                    reason="the current active navigation could not be reverified",
                )
            route_start_id = state.waypoint_ids[-2]
            destination_id = candidate.poi_id
            if destination_id in {route_start_id, state.waypoint_ids[-1]}:
                return self._displayed_poi_navigation_limitation(
                    session,
                    reason="the selected restaurant did not define a replacement destination",
                )
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "replacement_route_start_id": (
                        route_start_id,
                        (state.evidence,),
                        "current_navigation_final_segment_start_v1",
                    ),
                    "new_destination_id": (
                        destination_id,
                        (selection_evidence,),
                        "selected_displayed_poi_id_v1",
                    ),
                },
            )

            route_arguments = {
                "start_id": route_start_id,
                "destination_id": destination_id,
            }
            route = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_arguments,
                proposition="replacement_destination_route_options",
            )
            if route is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=route_arguments,
                    )
                    is not None
                ):
                    return self._displayed_poi_navigation_limitation(
                        session,
                        reason="the replacement route response was inconsistent",
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=route_arguments,
                    semantic_operation="find_routes_to_replacement_destination",
                    proposition="replacement_destination_route_options",
                )
            _, route_evidence = route
            options = self._destination_route_options_from_evidence(
                route_evidence,
                start_id=route_start_id,
                destination_id=destination_id,
            )
            if options is None:
                return self._displayed_poi_navigation_limitation(
                    session,
                    reason="the current replacement route options could not be verified",
                )
            route_choice = item.goal.desired_outcome.get("route_choice_alias")
            if route_choice is None:
                return self._ensure_destination_route_clarification(
                    session,
                    item=item,
                    destination_name=candidate.display_name,
                    options=options,
                )
            if not isinstance(
                route_choice, str
            ) or item.goal.goal_id not in self._authorized_goal_ids(session):
                return self._displayed_poi_navigation_limitation(
                    session,
                    reason="an explicit replacement scope and route are required",
                )
            selected = list(
                self._route_options_matching_choice(options, route_choice)
            )
            if len(selected) != 1:
                return self._displayed_poi_navigation_limitation(
                    session,
                    reason="the selected replacement route was not unique",
                )
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "route_id": (
                        selected[0].route_id,
                        (route_evidence,),
                        "user_selected_route_alias_v1",
                    ),
                    "expected_post_waypoint_ids": (
                        [*state.waypoint_ids[:-1], destination_id],
                        (state.evidence, route_evidence),
                        "verified_destination_replacement_waypoints_v1",
                    ),
                    "expected_post_route_ids": (
                        [*state.route_ids[:-1], selected[0].route_id],
                        (state.evidence, route_evidence),
                        "verified_destination_replacement_routes_v1",
                    ),
                },
            )
            refreshed = self._prepare_turn(session)
            refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
            target = (
                self._unique_bound_target(refreshed_item)
                if refreshed_item is not None
                else None
            )
            expected_arguments = {
                "new_destination_id": destination_id,
                "route_id_leading_to_new_destination": selected[0].route_id,
            }
            if (
                target is None
                or target[1].tool_name != "navigation_replace_final_destination"
                or not _argument_value_matches_binding(
                    target[1].arguments, expected_arguments
                )
                or self._validated_displayed_poi_navigation_binding(
                    session,
                    next(
                        goal
                        for goal in session.intent.goals
                        if goal.goal_id == item.goal.goal_id
                    ),
                )
                is None
                or not self._destination_navigation_snapshot_is_current(
                    session, goal_id=item.goal.goal_id
                )
            ):
                return self._displayed_poi_navigation_limitation(
                    session,
                    reason="the replacement action could not be bound to current evidence",
                )
            deterministic = self._deterministic_bound_action(session, refreshed)
            return deterministic or self._displayed_poi_navigation_limitation(
                session,
                reason="the replacement action could not be safely authorized",
            )
        return None

    def _expected_previous_destination_binding(
        self, session: SessionState, goal: Goal
    ) -> tuple[bool, str | None]:
        """Validate the prior destination and its user-turn provenance."""

        parameter = "previous_destination_name"
        grounded = session.grounded_desired_values_by_goal.get(goal.goal_id, {})
        sources = session.grounded_value_sources_by_goal.get(goal.goal_id, {})
        present = (
            parameter in goal.desired_outcome,
            parameter in grounded,
            parameter in sources,
        )
        if not any(present):
            return True, None
        if not all(present) or not isinstance(session.intent, IntentFrame):
            return False, None
        previous = goal.desired_outcome.get(parameter)
        source_turn_id = sources.get(parameter)
        new_destination = goal.desired_outcome.get("new_destination_name")
        new_destination_source = sources.get("new_destination_name")
        if (
            not isinstance(previous, str)
            or not self._voice_result_field(previous, 80)
            or not _strict_equal(grounded.get(parameter), previous)
            or not _strict_equal(session.intent.explicit_slots.get(parameter), previous)
            or not isinstance(source_turn_id, str)
            or source_turn_id not in session.intent.intent_source_turn_ids
            or (
                source_turn_id == new_destination_source
                and session.intent.intent_source_turn_ids != [source_turn_id]
            )
            or not isinstance(new_destination, str)
            or _argument_identifier(previous) == _argument_identifier(new_destination)
        ):
            return False, None
        return True, previous.strip()

    @staticmethod
    def _navigation_final_destination_matches(
        state: NavigationStateView, expected_name: str
    ) -> bool:
        if len(state.waypoint_names) != len(state.waypoint_ids):
            return False
        expected = _argument_identifier(expected_name)
        matches = tuple(
            index
            for index, name in enumerate(state.waypoint_names)
            if _argument_identifier(name) == expected
        )
        return matches == (len(state.waypoint_ids) - 1,)

    def _stop_destination_replacement_for_reclarification(
        self, session: SessionState, goal: Goal
    ) -> PlannedOutbound:
        """Revoke a stale replacement instead of carrying it into a later turn."""

        goal_id = goal.goal_id
        session.authorized_action_goal_ids.discard(goal_id)
        session.grounded_desired_values_by_goal.pop(goal_id, None)
        session.grounded_value_sources_by_goal.pop(goal_id, None)
        session.derived_value_evidence_by_goal.pop(goal_id, None)
        session.pending_calls = [
            call for call in session.pending_calls if goal_id not in call.goal_ids
        ]
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.evidence.needs = {
            need_id: need
            for need_id, need in session.evidence.needs.items()
            if need.required_for_goal_id != goal_id
        }
        session.confirmation_latch.cancel_all(
            current_user_turn=session.budget.user_turns,
            user_response="destination changed before replacement",
        )
        session.intent = None
        session.goal_dag = GoalDAG()
        return self._text_plan(
            session,
            "The current navigation no longer matches the destination state in "
            "your replacement request, so I stopped without changing navigation. "
            "Please state a new complete replacement request.",
            kind=ProposalKind.ASK_USER,
        )

    def _next_destination_replace_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _NAVIGATION_REPLACE_DESTINATION:
                continue
            if not session.live_tools.has_tool("navigation_replace_final_destination"):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            destination_name = item.goal.desired_outcome.get("new_destination_name")
            if not isinstance(destination_name, str) or not self._voice_result_field(
                destination_name, 120
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            previous_binding_valid, previous_destination_name = (
                self._expected_previous_destination_binding(session, item.goal)
            )
            if not previous_binding_valid:
                return self._stop_destination_replacement_for_reclarification(
                    session, item.goal
                )

            state_observation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_current_navigation_state",
                arguments={"detailed_information": True},
            )
            if state_observation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_current_navigation_state",
                    arguments={"detailed_information": True},
                    semantic_operation="read_current_navigation",
                    proposition="current_navigation_state",
                )
            state = self._navigation_state_view(session, goal_id=item.goal.goal_id)
            if state is None or not state.active or len(state.waypoint_ids) < 2:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            if not self._destination_navigation_snapshot_is_current(
                session, goal_id=item.goal.goal_id
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            if previous_destination_name is not None and not (
                self._navigation_final_destination_matches(
                    state, previous_destination_name
                )
            ):
                return self._stop_destination_replacement_for_reclarification(
                    session, item.goal
                )
            route_start_id = state.waypoint_ids[-2]

            cached_binding = session.resolved_location_binding(
                destination_name,
                state_version=session.evidence.current_state_version,
            )
            location = self._cached_location_evidence(
                session,
                goal_id=item.goal.goal_id,
                literal_name=destination_name,
                proposition="replacement_destination_location_id",
            )
            location_arguments = {"location": destination_name}
            if location is None:
                if cached_binding is not None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                observed = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_location_id_by_location_name",
                    arguments=location_arguments,
                    proposition="replacement_destination_location_id",
                )
                if observed is None:
                    if (
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name="get_location_id_by_location_name",
                            arguments=location_arguments,
                        )
                        is not None
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._navigation_read_plan(
                        session,
                        item=item,
                        tool_name="get_location_id_by_location_name",
                        arguments=location_arguments,
                        semantic_operation="resolve_replacement_destination",
                        proposition="replacement_destination_location_id",
                    )
                observed_id, observed_evidence = observed
                if not isinstance(
                    observed_id, str
                ) or not self._remember_exact_location_resolution(
                    session,
                    literal_name=destination_name,
                    location_id=observed_id,
                    evidence=observed_evidence,
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                location = observed_id, observed_evidence
            destination_id, location_evidence = location
            if destination_id in {route_start_id, state.waypoint_ids[-1]}:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.POLICY_CONFLICT
                )
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "replacement_route_start_id": (
                        route_start_id,
                        (state.evidence,),
                        "current_navigation_final_segment_start_v1",
                    ),
                    "new_destination_id": (
                        destination_id,
                        (location_evidence,),
                        "exact_replacement_destination_location_v1",
                    ),
                },
            )

            route_arguments = {
                "start_id": route_start_id,
                "destination_id": destination_id,
            }
            route = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_arguments,
                proposition="replacement_destination_route_options",
            )
            if route is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=route_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=route_arguments,
                    semantic_operation="find_routes_to_replacement_destination",
                    proposition="replacement_destination_route_options",
                )
            _, route_evidence = route
            options = self._destination_route_options_from_evidence(
                route_evidence,
                start_id=route_start_id,
                destination_id=destination_id,
            )
            if options is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            route_choice = item.goal.desired_outcome.get("route_choice_alias")
            if route_choice is None:
                return self._ensure_destination_route_clarification(
                    session,
                    item=item,
                    destination_name=destination_name,
                    options=options,
                )
            if not isinstance(route_choice, str):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            selected = list(
                self._route_options_matching_choice(options, route_choice)
            )
            if len(selected) != 1:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            fresh_state = (
                self._navigation_state_view(
                    session,
                    goal_id=item.goal.goal_id,
                    proposition=_NAVIGATION_REPLACE_REVERIFY_STATE,
                )
                if previous_destination_name is not None
                else None
            )
            if previous_destination_name is not None and fresh_state is None:
                need = EvidenceNeed(
                    proposition=_NAVIGATION_REPLACE_REVERIFY_STATE,
                    required_for_goal_id=item.goal.goal_id,
                    acceptable_sources={"tool_result"},
                    freshness="current_state",
                )
                session.evidence.register_need(need)
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_current_navigation_state",
                    arguments={"detailed_information": True},
                    semantic_operation="reverify_replacement_navigation",
                    proposition=_NAVIGATION_REPLACE_REVERIFY_STATE,
                )
            if previous_destination_name is not None and (
                fresh_state is None
                or not self._navigation_final_destination_matches(
                    fresh_state, previous_destination_name
                )
                or fresh_state.waypoint_ids != state.waypoint_ids
                or fresh_state.route_ids != state.route_ids
                or not self._destination_navigation_snapshot_is_current(
                    session, goal_id=item.goal.goal_id
                )
            ):
                return self._stop_destination_replacement_for_reclarification(
                    session, item.goal
                )
            completion_state = fresh_state or state
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "replacement_route_start_id": (
                        route_start_id,
                        (completion_state.evidence,),
                        "current_navigation_final_segment_start_v1",
                    ),
                    "route_id": (
                        selected[0].route_id,
                        (route_evidence,),
                        "user_selected_route_alias_v1",
                    ),
                    "expected_post_waypoint_ids": (
                        [*completion_state.waypoint_ids[:-1], destination_id],
                        (completion_state.evidence, route_evidence),
                        "verified_destination_replacement_waypoints_v1",
                    ),
                    "expected_post_route_ids": (
                        [*completion_state.route_ids[:-1], selected[0].route_id],
                        (completion_state.evidence, route_evidence),
                        "verified_destination_replacement_routes_v1",
                    ),
                },
            )
            refreshed = self._prepare_turn(session)
            fresh_state = (
                self._navigation_state_view(
                    session,
                    goal_id=item.goal.goal_id,
                    proposition=_NAVIGATION_REPLACE_REVERIFY_STATE,
                )
                if previous_destination_name is not None
                else None
            )
            if previous_destination_name is not None and (
                fresh_state is None
                or not self._navigation_final_destination_matches(
                    fresh_state, previous_destination_name
                )
                or fresh_state.waypoint_ids != state.waypoint_ids
                or fresh_state.route_ids != state.route_ids
                or not self._destination_navigation_snapshot_is_current(
                    session, goal_id=item.goal.goal_id
                )
            ):
                return self._stop_destination_replacement_for_reclarification(
                    session, item.goal
                )
            session.evidence.needs = {
                need_id: need
                for need_id, need in session.evidence.needs.items()
                if not (
                    need.required_for_goal_id == item.goal.goal_id
                    and need.proposition == _NAVIGATION_REPLACE_REVERIFY_STATE
                )
            }
            deterministic = self._deterministic_bound_action(session, refreshed)
            if deterministic is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            session.evidence.needs = {
                need_id: need
                for need_id, need in session.evidence.needs.items()
                if need.required_for_goal_id != item.goal.goal_id
            }
            session.budget.reset_get_count(
                "get_current_navigation_state", {"detailed_information": True}
            )
            return deterministic
        return None

    def _ensure_waypoint_clarification(
        self,
        session: SessionState,
        *,
        item: PreparedGoal,
        state: NavigationStateView,
    ) -> PlannedOutbound:
        if session.intent is None or len(state.waypoint_names) != len(
            state.waypoint_ids
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        names = list(state.waypoint_names[1:-1])
        if len(names) < 2 or len({_argument_identifier(name) for name in names}) != len(
            names
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        slots = [slot.model_copy(deep=True) for slot in session.intent.unresolved_slots]
        slot = next(
            (
                existing
                for existing in slots
                if existing.goal_id == item.goal.goal_id
                and existing.name == "waypoint_name_to_replace"
            ),
            None,
        )
        if slot is None:
            slots.append(
                AmbiguitySlot(
                    name="waypoint_name_to_replace",
                    candidates=[
                        Candidate(
                            candidate_id=(
                                f"navigation-{item.goal.goal_id}-waypoint-{index}"
                            ),
                            value=name,
                            label=name,
                        )
                        for index, name in enumerate(names, start=1)
                    ],
                    goal_id=item.goal.goal_id,
                    source_turn_ids=list(session.intent.intent_source_turn_ids),
                )
            )
            session.intent = session.intent.model_copy(
                update={"unresolved_slots": slots}, deep=True
            )
            session.goal_dag = self.goal_planner.update(
                session.goal_dag, session.intent
            )
        clarification = self._next_clarification(session)
        if clarification is None:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        return clarification

    def _next_navigation_edit_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            operation = item.goal.semantic_operation
            if operation not in {
                _NAVIGATION_REPLACE_WAYPOINT,
                _NAVIGATION_DELETE_WAYPOINT,
                _NAVIGATION_DELETE_DESTINATION,
            }:
                continue
            if (
                (
                    operation == _NAVIGATION_REPLACE_WAYPOINT
                    and not session.live_tools.has_tool(
                        "navigation_replace_one_waypoint"
                    )
                )
                or (
                    operation == _NAVIGATION_DELETE_DESTINATION
                    and not session.live_tools.has_tool("navigation_delete_destination")
                )
                or (
                    operation == _NAVIGATION_DELETE_WAYPOINT
                    and not session.live_tools.has_tool("navigation_delete_waypoint")
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            state_observation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_current_navigation_state",
                arguments={"detailed_information": True},
            )
            if state_observation is None and operation == _NAVIGATION_REPLACE_WAYPOINT:
                state_observation = self._adopt_displayed_poi_navigation_read(
                    session, goal_id=item.goal.goal_id
                )
            if state_observation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_current_navigation_state",
                    arguments={"detailed_information": True},
                    semantic_operation="read_current_navigation",
                    proposition="current_navigation_state",
                )
            state = self._navigation_state_view(session, goal_id=item.goal.goal_id)
            if state is None or not state.active:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            if operation == _NAVIGATION_DELETE_WAYPOINT:
                self._record_navigation_policy_facts(
                    session, goal_id=item.goal.goal_id, state=state
                )
                index = self._named_waypoint_delete_index(item.goal, state)
                if index is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                start_id = state.waypoint_ids[index - 1]
                destination_id = state.waypoint_ids[index + 1]
                route_arguments = {
                    "start_id": start_id,
                    "destination_id": destination_id,
                }
                route = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=route_arguments,
                    proposition="waypoint_delete_route_options",
                )
                if route is None:
                    if (
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name="get_routes_from_start_to_destination",
                            arguments=route_arguments,
                        )
                        is not None
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._navigation_read_plan(
                        session,
                        item=item,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=route_arguments,
                        semantic_operation="find_route_without_deleted_waypoint",
                        proposition="waypoint_delete_route_options",
                    )
                _, route_evidence = route
                options = self._destination_route_options_from_evidence(
                    route_evidence,
                    start_id=start_id,
                    destination_id=destination_id,
                )
                if options is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )

                route_choice = item.goal.desired_outcome.get("route_choice_alias")
                selected: list[DestinationRouteOption]
                if route_choice is None:
                    selected = [
                        option
                        for option in options
                        if "fastest" in option.aliases and "shortest" in option.aliases
                    ]
                    if len(selected) != 1:
                        destination_name = state.waypoint_names[-1]
                        return self._ensure_destination_route_clarification(
                            session,
                            item=item,
                            destination_name=destination_name,
                            options=options,
                        )
                elif isinstance(route_choice, str):
                    selected = list(
                        self._route_options_matching_choice(options, route_choice)
                    )
                else:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                    )
                if len(selected) != 1:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )

                shared_parents = (state.evidence, route_evidence)
                expected_post_waypoint_ids = [
                    *state.waypoint_ids[:index],
                    *state.waypoint_ids[index + 1 :],
                ]
                expected_post_waypoint_names = [
                    *state.waypoint_names[:index],
                    *state.waypoint_names[index + 1 :],
                ]
                expected_post_route_ids = [
                    *state.route_ids[: index - 1],
                    selected[0].route_id,
                    *state.route_ids[index + 1 :],
                ]
                self._apply_navigation_derived_parameters(
                    session,
                    goal=item.goal,
                    parameters={
                        "waypoint_id": (
                            state.waypoint_ids[index],
                            shared_parents,
                            "verified_deleted_waypoint_v1",
                        ),
                        "waypoint_name_to_delete": (
                            state.waypoint_names[index],
                            shared_parents,
                            "verified_deleted_waypoint_name_v1",
                        ),
                        "remaining_destination_name": (
                            state.waypoint_names[-1],
                            shared_parents,
                            "verified_remaining_destination_name_v1",
                        ),
                        "next_waypoint_name": (
                            state.waypoint_names[index + 1],
                            shared_parents,
                            "verified_next_waypoint_name_v1",
                        ),
                        "replacement_route_id": (
                            selected[0].route_id,
                            shared_parents,
                            "verified_route_without_waypoint_v1",
                        ),
                        "replacement_route_via": (
                            selected[0].via,
                            shared_parents,
                            "verified_route_without_waypoint_via_v1",
                        ),
                        "replacement_route_includes_toll": (
                            selected[0].includes_toll,
                            shared_parents,
                            "verified_route_without_waypoint_toll_v1",
                        ),
                        "replacement_route_is_fastest": (
                            "fastest" in selected[0].aliases,
                            shared_parents,
                            "verified_route_without_waypoint_fastest_v1",
                        ),
                        "expected_post_waypoint_ids": (
                            expected_post_waypoint_ids,
                            shared_parents,
                            "verified_waypoints_after_delete_v1",
                        ),
                        "expected_post_waypoint_names": (
                            expected_post_waypoint_names,
                            shared_parents,
                            "verified_waypoint_names_after_delete_v1",
                        ),
                        "expected_post_route_ids": (
                            expected_post_route_ids,
                            shared_parents,
                            "verified_routes_after_delete_v1",
                        ),
                    },
                )
                refreshed = self._prepare_turn(session)
                deterministic = self._deterministic_bound_action(session, refreshed)
                return deterministic or self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            if operation == _NAVIGATION_DELETE_DESTINATION:
                if len(state.waypoint_ids) <= 2:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.POLICY_CONFLICT
                    )
                if not self._named_final_destination_delete_matches(item.goal, state):
                    if self._convert_generic_named_delete_to_waypoint(
                        session, goal=item.goal, state=state
                    ):
                        return self._plan_next(session)
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                fresh_observation = self._successful_goal_read(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_current_navigation_state",
                    arguments={},
                )
                if fresh_observation is None:
                    return self._navigation_read_plan(
                        session,
                        item=item,
                        tool_name="get_current_navigation_state",
                        arguments={},
                        semantic_operation="navigation.state.read",
                        proposition="current_navigation_state",
                    )
                if not self._destination_navigation_snapshot_is_current(
                    session, goal_id=item.goal.goal_id
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                refreshed = self._prepare_turn(session)
                deterministic = self._deterministic_bound_action(session, refreshed)
                return deterministic or self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            indexes = self._matching_waypoint_indexes(item.goal, state)
            if len(indexes) != 1:
                has_selector = any(
                    isinstance(item.goal.desired_outcome.get(name), str)
                    and bool(str(item.goal.desired_outcome[name]).strip())
                    for name in (
                        "waypoint_id_to_replace",
                        "waypoint_name_to_replace",
                    )
                )
                if has_selector:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._ensure_waypoint_clarification(
                    session, item=item, state=state
                )
            index = indexes[0]
            previous_id = state.waypoint_ids[index - 1]
            next_id = state.waypoint_ids[index + 1]

            new_waypoint_id = item.goal.desired_outcome.get("new_waypoint_id")
            location_name = item.goal.desired_outcome.get("new_waypoint_name")
            if (
                not isinstance(new_waypoint_id, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(new_waypoint_id) is None
            ):
                if not isinstance(location_name, str) or not location_name.strip():
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                    )
                location_arguments = {"location": location_name}
                location_result = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_location_id_by_location_name",
                    arguments=location_arguments,
                    proposition="resolved_navigation_location_id",
                )
                if location_result is None:
                    if (
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name="get_location_id_by_location_name",
                            arguments=location_arguments,
                        )
                        is not None
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._navigation_read_plan(
                        session,
                        item=item,
                        tool_name="get_location_id_by_location_name",
                        arguments=location_arguments,
                        semantic_operation="resolve_replacement_location",
                        proposition="resolved_navigation_location_id",
                    )
                resolved_id, _ = location_result
                if (
                    not isinstance(resolved_id, str)
                    or _LOCATION_OR_POI_ID_PATTERN.fullmatch(resolved_id) is None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                new_waypoint_id = resolved_id

            route_to_arguments = {
                "start_id": previous_id,
                "destination_id": new_waypoint_id,
            }
            route_to = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_to_arguments,
                proposition="route_to_replacement_options",
            )
            if route_to is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=route_to_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=route_to_arguments,
                    semantic_operation="find_route_to_replacement",
                    proposition="route_to_replacement_options",
                )
            _, route_to_evidence = route_to
            if (
                self._navigation_edit_route_id_from_evidence(
                    item.goal,
                    route_to_evidence,
                    start_id=previous_id,
                    destination_id=new_waypoint_id,
                )
                is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            route_from_arguments = {
                "start_id": new_waypoint_id,
                "destination_id": next_id,
            }
            route_from = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_from_arguments,
                proposition="route_from_replacement_options",
            )
            if route_from is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=route_from_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=route_from_arguments,
                    semantic_operation="find_route_from_replacement",
                    proposition="route_from_replacement_options",
                )
            _, route_from_evidence = route_from
            if (
                self._navigation_edit_route_id_from_evidence(
                    item.goal,
                    route_from_evidence,
                    start_id=new_waypoint_id,
                    destination_id=next_id,
                )
                is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            deterministic = self._deterministic_bound_action(session, prepared)
            return deterministic or self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        return None

    def _begin_trip_followup_goal(
        self,
        session: SessionState,
        *,
        turn_id: str,
        desired_outcome: Mapping[str, Any],
        grounded_values: Mapping[str, Any],
    ) -> Goal:
        digest = hashlib.sha256(
            f"{turn_id}\0trip-followup\0{sorted(desired_outcome)}".encode()
        ).hexdigest()
        goal = Goal(
            goal_id=f"goal-trip-followup-{digest[:12]}",
            semantic_operation=_TRIP_RANGE_OPERATION,
            desired_outcome=dict(desired_outcome),
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=False,
            goals=[goal],
            explicit_slots=dict(grounded_values),
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.INFORMATION,
        )
        session.authorized_action_goal_ids = set()
        session.grounded_desired_values_by_goal = {goal.goal_id: dict(grounded_values)}
        session.grounded_value_sources_by_goal = {
            goal.goal_id: {name: turn_id for name in grounded_values}
        }
        session.derived_value_evidence_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return goal

    def _begin_active_route_charging_goal(
        self,
        session: SessionState,
        *,
        turn_id: str,
        search_requested: bool,
        buffer_soc: tuple[int, int] | None = None,
        requested_initial_soc: int | None = None,
    ) -> Goal:
        digest = hashlib.sha256(
            f"{turn_id}\0active-route-charging\0{search_requested}".encode()
        ).hexdigest()
        desired_outcome: dict[str, Any] = {
            _ACTIVE_ROUTE_CHARGING_MARKER: True,
            _ACTIVE_ROUTE_CHARGING_SEARCH_MARKER: search_requested,
        }
        grounded_values: dict[str, Any] = {}
        if requested_initial_soc is not None:
            desired_outcome["requested_initial_state_of_charge"] = requested_initial_soc
            grounded_values["requested_initial_state_of_charge"] = requested_initial_soc
        if buffer_soc is not None:
            initial_soc, final_soc = buffer_soc
            desired_outcome.update(
                {
                    _ACTIVE_ROUTE_BUFFER_SEARCH_MARKER: True,
                    "initial_state_of_charge": initial_soc,
                    "final_state_of_charge": final_soc,
                }
            )
            grounded_values["final_state_of_charge"] = final_soc
        goal = Goal(
            goal_id=f"goal-active-route-charging-{digest[:12]}",
            semantic_operation=_TRIP_RANGE_OPERATION,
            desired_outcome=desired_outcome,
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=False,
            goals=[goal],
            explicit_slots=grounded_values,
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.INFORMATION,
        )
        session.authorized_action_goal_ids = set()
        session.grounded_desired_values_by_goal = {goal.goal_id: dict(grounded_values)}
        session.grounded_value_sources_by_goal = {
            goal.goal_id: {name: turn_id for name in grounded_values}
        }
        session.derived_value_evidence_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return goal

    @staticmethod
    def _completed_destination_replacement(
        session: SessionState,
    ) -> tuple[Goal, str] | None:
        if not isinstance(session.intent, IntentFrame):
            return None
        matches: list[tuple[Goal, str]] = []
        for goal in session.intent.goals:
            destination_name = goal.desired_outcome.get("new_destination_name")
            destination_id = goal.desired_outcome.get("new_destination_id")
            route_id = goal.desired_outcome.get("route_id")
            if (
                goal.semantic_operation != _NAVIGATION_REPLACE_DESTINATION
                or not isinstance(destination_name, str)
                or not isinstance(destination_id, str)
                or not isinstance(route_id, str)
            ):
                continue
            completed = session.completed_action_calls_by_goal.get(goal.goal_id, ())
            if any(
                call.tool_name == "navigation_replace_final_destination"
                and call.arguments.get("new_destination_id") == destination_id
                and call.arguments.get("route_id_leading_to_new_destination")
                == route_id
                for call in completed
            ):
                matches.append((goal, destination_name))
        return matches[0] if len(matches) == 1 else None

    def _handle_active_route_charging_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        replacement = self._completed_destination_replacement(session)
        requested_soc = (
            _active_route_range_question_soc(text, destination_name=replacement[1])
            if replacement is not None
            else None
        )
        if requested_soc is not None:
            self._begin_active_route_charging_goal(
                session,
                turn_id=turn_id,
                search_requested=False,
                requested_initial_soc=requested_soc,
            )
            return True, None

        if _ACTIVE_ROUTE_CHARGING_DECLINE_PATTERN.fullmatch(text) is not None:
            if self._validated_active_route_charger_summary(session) is None:
                return False, None
            return True, self._text_plan(
                session,
                "Understood. I did not add the charging station to navigation.",
            )

        summary = self._validated_active_route_charging_summary(session)
        final_soc = _active_route_buffer_search_soc(text)
        if final_soc is not None:
            if summary is None or summary[1].get("needs_charging") is not True:
                return True, self._text_plan(
                    session,
                    "I could not verify the requested battery buffer against the current route.",
                )
            try:
                initial_soc = int(Decimal(summary[1]["state_of_charge"]))
            except (InvalidOperation, KeyError, TypeError, ValueError):
                return True, self._text_plan(
                    session,
                    "I could not verify the current battery percentage.",
                )
            if not final_soc < initial_soc <= 100:
                return True, self._text_plan(
                    session, "The requested battery buffer was invalid."
                )
            goal = self._begin_active_route_charging_goal(
                session,
                turn_id=turn_id,
                search_requested=True,
                buffer_soc=(initial_soc, final_soc),
            )
            self._apply_navigation_derived_parameters(
                session,
                goal=goal,
                parameters={
                    "initial_state_of_charge": (
                        initial_soc,
                        (summary[0],),
                        "current_soc_from_active_route_summary_v1",
                    )
                },
            )
            return True, None
        search_confirmation = (
            _ACTIVE_ROUTE_CHARGING_SEARCH_CONFIRM_PATTERN.fullmatch(text) is not None
        )
        request = _active_route_charging_request(text)
        if search_confirmation:
            if summary is None or summary[1].get("needs_charging") is not True:
                return False, None
            search_requested = True
        elif request is not None:
            _, search_requested = request
        else:
            return False, None

        self._begin_active_route_charging_goal(
            session,
            turn_id=turn_id,
            search_requested=search_requested,
        )
        return True, None

    def _handle_climate_settings_info_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        airflow_advisory = _airflow_advisory_request(text)
        climate_information = _CLIMATE_SETTINGS_INFO_PATTERN.fullmatch(text) is not None
        if not airflow_advisory and not climate_information:
            return False, None
        if session.live_tools is None:
            return True, self._text_plan(
                session,
                "Current climate information is unavailable, so I did not perform an action.",
            )
        try:
            available = (
                session.live_tools.has_tool("get_climate_settings")
                and session.live_tools.validate_arguments("get_climate_settings", {})
                == {}
            )
        except ToolArgumentValidationError:
            available = False
        if not available:
            return True, self._text_plan(
                session,
                "Current climate information is unavailable, so I did not perform an action.",
            )

        workflow = "airflow-advisory" if airflow_advisory else "climate-settings-info"
        marker = (
            _AIRFLOW_ADVISORY_MARKER
            if airflow_advisory
            else _CLIMATE_SETTINGS_INFO_MARKER
        )
        digest = hashlib.sha256(f"{turn_id}\0{workflow}".encode()).hexdigest()
        goal = Goal(
            goal_id=f"goal-climate-info-{digest[:12]}",
            semantic_operation="read_climate_settings",
            desired_outcome={marker: True},
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=False,
            goals=[goal],
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.INFORMATION,
        )
        session.authorized_action_goal_ids = set()
        session.grounded_desired_values_by_goal = {goal.goal_id: {}}
        session.grounded_value_sources_by_goal = {goal.goal_id: {}}
        session.derived_value_evidence_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True, None

