    def _handle_direct_medium_steering_heating_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        if not _direct_medium_steering_heating_request(text):
            return False, None
        tool_name = "set_steering_wheel_heating"
        if not session.live_tools.has_tool(tool_name):
            return True, self._text_plan(
                session,
                "Steering wheel heating is unavailable in the current controls, so I did not change it.",
            )
        level_domain = session.live_tools.parameter_domain(tool_name, "level")
        try:
            validated = session.live_tools.validate_arguments(tool_name, {"level": 2})
        except ToolArgumentValidationError:
            validated = None
        if (
            not isinstance(level_domain, Mapping)
            or _bounded_numeric_options(level_domain) != (0, 1, 2, 3)
            or validated != {"level": 2}
        ):
            return True, self._text_plan(
                session,
                "I could not map medium to one verified steering wheel heating level, so I did not change it.",
            )

        digest = hashlib.sha256(
            f"{turn_id}\0medium-steering-heating".encode()
        ).hexdigest()
        goal = Goal(
            goal_id=f"goal-medium-steering-{digest[:12]}",
            semantic_operation="set_steering_wheel_heating",
            desired_outcome={"level": 2},
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[goal],
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.ACTION,
        )
        session.authorized_action_goal_ids = {goal.goal_id}
        session.grounded_desired_values_by_goal = {goal.goal_id: {"level": 2}}
        session.grounded_value_sources_by_goal = {goal.goal_id: {}}
        parent = Evidence(
            proposition=f"qualitative_argument:{goal.goal_id}:level",
            value="medium",
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.USER,
            source_turn_id=turn_id,
            confidence=1.0,
        )
        session.evidence.add(parent)
        stored_parent = session.evidence.for_proposition(parent.proposition)[-1]
        assert stored_parent.evidence_id is not None
        derived = Evidence(
            proposition=f"derived_argument:{goal.goal_id}:level",
            value=2,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=turn_id,
            confidence=1.0,
            derived_from=[stored_parent.evidence_id],
            derivation="medium_maps_to_verified_four_level_control_v1",
        )
        session.evidence.add(derived)
        stored_derived = session.evidence.for_proposition(derived.proposition)[-1]
        assert stored_derived.evidence_id is not None
        session.derived_value_evidence_by_goal = {
            goal.goal_id: {"level": stored_derived.evidence_id}
        }
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True, None

