    def _handle_descriptive_destination_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        request = parse_descriptive_navigation_destination_request(text)
        if request is None:
            return False, None
        previous = request.previous_destination_name
        route_choice = request.route_choice_alias
        if previous is None or route_choice is None:
            return False, None
        session.pending_destination_clarification = PendingDestinationClarification(
            previous_destination_name=previous,
            route_choice_alias=route_choice,
            source_turn_id=turn_id,
            source_user_turn=session.budget.user_turns,
        )
        session.intent = None
        session.authorized_action_goal_ids = set()
        session.grounded_desired_values_by_goal = {}
        session.grounded_value_sources_by_goal = {}
        session.derived_value_evidence_by_goal = {}
        session.relative_fan_speed_deltas_by_goal = {}
        session.relative_climate_temperature_deltas_by_goal = {}
        session.relative_seat_heating_deltas_by_goal = {}
        session.occupied_seat_heating_goal_ids = set()
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = GoalDAG()
        return True, self._text_plan(
            session,
            f"Which city do you mean as the replacement for {previous}? "
            f"I will use the {route_choice} route after you name one city.",
            kind=ProposalKind.ASK_USER,
        )

    def _handle_pending_destination_reply(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        pending = session.pending_destination_clarification
        if pending is None:
            return False, None
        session.pending_destination_clarification = None
        if session.budget.user_turns != pending.source_user_turn + 1:
            return True, self._text_plan(
                session,
                "The destination clarification expired, so I did not change navigation.",
            )
        reply = parse_adjacent_navigation_destination_reply(
            text,
            inherited_route_choice=pending.route_choice_alias,
        )
        if reply is None:
            return True, self._text_plan(
                session,
                "I could not verify one city and one route choice, so I did not change navigation.",
            )
        digest = hashlib.sha256(
            f"{turn_id}\0pending-destination\0{reply.destination_name}".encode()
        ).hexdigest()
        goal_id = f"goal-pending-destination-{digest[:12]}"
        desired_outcome: dict[str, Any] = {
            "new_destination_name": reply.destination_name,
            "previous_destination_name": pending.previous_destination_name,
        }
        if reply.route_choice_alias is not None:
            desired_outcome["route_choice_alias"] = reply.route_choice_alias
        goal = Goal(
            goal_id=goal_id,
            semantic_operation=_NAVIGATION_REPLACE_DESTINATION,
            desired_outcome=desired_outcome,
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[goal],
            explicit_slots=dict(desired_outcome),
            intent_source_turn_ids=[pending.source_turn_id, turn_id],
            goal_mention_order=[goal_id],
            intent_kind=IntentKind.ACTION,
        )
        session.authorized_action_goal_ids = {goal_id}
        session.grounded_desired_values_by_goal = {
            goal_id: dict(desired_outcome)
        }
        route_source = (
            turn_id if reply.route_choice_from_reply else pending.source_turn_id
        )
        session.grounded_value_sources_by_goal = {
            goal_id: {
                "new_destination_name": turn_id,
                "previous_destination_name": pending.source_turn_id,
                **(
                    {"route_choice_alias": route_source}
                    if reply.route_choice_alias is not None
                    else {}
                ),
            }
        }
        session.derived_value_evidence_by_goal = {}
        session.relative_fan_speed_deltas_by_goal = {}
        session.relative_climate_temperature_deltas_by_goal = {}
        session.relative_seat_heating_deltas_by_goal = {}
        session.occupied_seat_heating_goal_ids = set()
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True, None

    def _handle_destination_replacement_route_selection(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        selection = _destination_replacement_route_selection(text)
        if selection is None or not isinstance(session.intent, IntentFrame):
            return False, None
        requests = [
            request
            for request in session.pending_clarifications.values()
            if request.slot_name == "route_choice_alias"
            and isinstance(request.goal_id, str)
        ]
        if len(requests) != 1:
            return False, None
        request = requests[0]
        goal = next(
            (
                candidate
                for candidate in session.intent.goals
                if candidate.goal_id == request.goal_id
                and candidate.semantic_operation == _NAVIGATION_REPLACE_DESTINATION
            ),
            None,
        )
        if goal is None:
            return False, None
        context = self._route_choice_context(session, goal=goal)
        if context is None:
            return True, self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        start_id, destination_id, _, proposition = context
        observed = self._derived_navigation_read_value(
            session,
            goal_id=goal.goal_id,
            tool_name="get_routes_from_start_to_destination",
            arguments={"start_id": start_id, "destination_id": destination_id},
            proposition=proposition,
        )
        options = (
            self._destination_route_options_from_evidence(
                observed[1], start_id=start_id, destination_id=destination_id
            )
            if observed is not None
            else None
        )
        choice, requested_distance, includes_toll = selection
        selected = [
            option
            for option in options or ()
            if choice in option.aliases
            and option.distance_km == requested_distance
            and option.includes_toll is includes_toll
        ]
        if len(selected) != 1:
            return True, self._text_plan(
                session,
                "The requested route details did not match one current option, so I did not replace the destination.",
                goal_ids=[goal.goal_id],
            )
        canonical_choice = f"Use the {selected[0].ordinal} route."
        resolution = self._resolve_pending_clarification(
            session, canonical_choice, turn_id
        )
        if resolution is not None:
            return True, resolution
        assert session.intent is not None
        session.intent = session.intent.model_copy(
            update={
                "call_for_action": True,
                "intent_kind": IntentKind.ACTION,
                "intent_source_turn_ids": list(
                    dict.fromkeys([*session.intent.intent_source_turn_ids, turn_id])
                ),
            },
            deep=True,
        )
        session.authorized_action_goal_ids = {goal.goal_id}
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True, None

    def _recover_destination_replacement_preview_grounding(
        self, text: str, extracted: IntentFrame
    ) -> IntentGroundingResult | None:
        if len(extracted.goals) != 1:
            return None
        goal = extracted.goals[0]
        new_destination = goal.desired_outcome.get("new_destination_name")
        if (
            goal.semantic_operation != _NAVIGATION_REPLACE_DESTINATION
            or extracted.call_for_action
            or extracted.intent_kind is not IntentKind.INFORMATION
            or not isinstance(new_destination, str)
            or goal.desired_outcome != {"new_destination_name": new_destination}
            or not self._voice_result_field(new_destination, 120)
            or not _is_destination_replacement_preview_request(
                text, destination_name=new_destination
            )
        ):
            return None
        intent = extracted.model_copy(
            update={
                "call_for_action": False,
                "intent_kind": IntentKind.INFORMATION,
                "goal_mention_order": [goal.goal_id],
            },
            deep=True,
        )
        return IntentGroundingResult(
            filtered_intent=intent,
            desired_values_by_goal={goal.goal_id: dict(goal.desired_outcome)},
        )

    def _recover_contact_grounding(
        self,
        session: SessionState,
        text: str,
        extracted: IntentFrame,
        *,
        turn_id: str,
    ) -> IntentGroundingResult | None:
        """Recover bounded contact reads and contact-sharing email requests."""

        normalized = unicodedata.normalize("NFKC", text).strip()
        if (
            not normalized
            or len(normalized) > 520
            or any(character in normalized for character in '\r\n"`“”')
            or re.search(
                r"\b(?:hypothetically|pretend|quoted|said|told)\b",
                normalized,
                re.IGNORECASE,
            )
            is not None
            or len(extracted.goals) != 1
        ):
            return None
        source = extracted.goals[0]
        folded = normalized.casefold()

        if source.semantic_operation in {
            "find_contact",
            "find_contact_ids",
            "get_contact",
            "resolve_contact",
        }:
            if (
                not re.search(r"\b(?:find|look\s+up|search)\b", folded)
                or not re.search(r"\b(?:contact|people|person)\b", folded)
                or re.search(
                    r"\b(?:do\s+not|don['\u2019]?t|never)\s+"
                    r"(?:find|look\s+up|search)\b",
                    folded,
                )
                is not None
            ):
                return None
            aliases = {
                "first_name": "first_name",
                "last_name": "last_name",
                "contact_first_name": "first_name",
                "contact_last_name": "last_name",
            }
            values: dict[str, str] = {}
            for raw_key, raw_value in source.desired_outcome.items():
                if raw_key == _CONTACT_EMAIL_RECIPIENT_LOOKUP_MARKER:
                    if (
                        raw_value is not True
                        or _STRICT_CONTACT_EMAIL_RECIPIENT_LOOKUP_PATTERN.fullmatch(
                            normalized
                        )
                        is None
                    ):
                        return None
                    continue
                key = aliases.get(raw_key)
                if (
                    key is None
                    or not isinstance(raw_value, str)
                    or not raw_value.strip()
                ):
                    return None
                value = raw_value.strip()
                if key in values and values[key] != value:
                    return None
                values[key] = value
            if not values:
                return None
            if any(
                not self._safe_contact_name(value) or value.casefold() not in folded
                for value in values.values()
            ):
                return None
            read_desired: dict[str, Any] = dict(values)
            if (
                source.desired_outcome.get(_CONTACT_EMAIL_RECIPIENT_LOOKUP_MARKER)
                is True
            ):
                read_desired[_CONTACT_EMAIL_RECIPIENT_LOOKUP_MARKER] = True
            goal = source.model_copy(
                update={
                    "semantic_operation": "find_contact",
                    "desired_outcome": read_desired,
                },
                deep=True,
            )
            intent = extracted.model_copy(
                update={
                    "call_for_action": False,
                    "goals": [goal],
                    "intent_kind": IntentKind.INFORMATION,
                    "goal_mention_order": [goal.goal_id],
                },
                deep=True,
            )
            return IntentGroundingResult(
                filtered_intent=intent,
                desired_values_by_goal={goal.goal_id: read_desired},
            )

        if (
            source.semantic_operation != "send_email"
            or not extracted.call_for_action
            or re.search(r"\b(?:do\s+not|don't|don’t)\s+send\b", folded) is not None
            or not re.search(r"\b(?:send|email)\b", folded)
            or not re.search(r"\b(?:contact|details|information)\b", folded)
        ):
            return None
        group = self._validated_displayed_contact_group(session)
        if group is None:
            return None
        _, group_value = group
        query = group_value["query"]
        source_last_name = query.get("last_name")
        first_name = source.desired_outcome.get("first_name")
        last_name = source.desired_outcome.get("last_name")
        if (
            not isinstance(first_name, str)
            or not self._safe_contact_name(first_name.strip())
            or first_name.strip().casefold() not in folded
            or (
                last_name is not None
                and (
                    not isinstance(last_name, str)
                    or not self._safe_contact_name(last_name.strip())
                    or last_name.strip().casefold() not in folded
                )
            )
            or not isinstance(source_last_name, str)
        ):
            return None
        desired: dict[str, Any] = {
            _CONTACT_SHARE_EMAIL_MARKER: True,
            _CONTACT_SOURCE_LAST_NAME: source_last_name,
            "first_name": first_name.strip(),
        }
        if isinstance(last_name, str):
            desired["last_name"] = last_name.strip()
        goal = source.model_copy(update={"desired_outcome": desired}, deep=True)
        intent = extracted.model_copy(
            update={
                "call_for_action": True,
                "goals": [goal],
                "intent_kind": IntentKind.ACTION,
                "goal_mention_order": [goal.goal_id],
            },
            deep=True,
        )
        return IntentGroundingResult(
            filtered_intent=intent,
            authorized_action_goal_ids=frozenset({goal.goal_id}),
            desired_values_by_goal={goal.goal_id: desired},
        )

    @classmethod
    def _strict_bare_contact_lookup_intent(
        cls, text: str, *, turn_id: str, language: str
    ) -> IntentFrame | None:
        normalized = unicodedata.normalize("NFKC", text).strip()
        match = _STRICT_BARE_CONTACT_LOOKUP_PATTERN.fullmatch(normalized)
        if match is None:
            return None
        first_name = match.group("first_name")
        if not cls._safe_contact_name(first_name):
            return None
        digest = hashlib.sha256(
            f"{turn_id}\0strict-contact-first-name\0{first_name.casefold()}".encode()
        ).hexdigest()
        goal = Goal(
            goal_id=f"goal-contact-first-name-{digest[:12]}",
            semantic_operation="find_contact",
            desired_outcome={"first_name": first_name},
            source=GoalSource.USER,
        )
        return IntentFrame(
            language=language,
            call_for_action=False,
            goals=[goal],
            explicit_slots={"first_name": first_name},
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.INFORMATION,
        )

    @classmethod
    def _strict_contact_email_recipient_lookup_intent(
        cls, text: str, *, turn_id: str, language: str
    ) -> IntentFrame | None:
        normalized = unicodedata.normalize("NFKC", text).strip()
        match = _STRICT_CONTACT_EMAIL_RECIPIENT_LOOKUP_PATTERN.fullmatch(normalized)
        if match is None:
            return None
        first_name = match.group("first_name")
        last_name = match.group("last_name")
        if not all(cls._safe_contact_name(value) for value in (first_name, last_name)):
            return None
        digest = hashlib.sha256(
            f"{turn_id}\0contact-email-recipient\0{first_name.casefold()}\0"
            f"{last_name.casefold()}".encode()
        ).hexdigest()
        desired = {
            "first_name": first_name,
            "last_name": last_name,
            _CONTACT_EMAIL_RECIPIENT_LOOKUP_MARKER: True,
        }
        goal = Goal(
            goal_id=f"goal-contact-email-recipient-{digest[:12]}",
            semantic_operation="find_contact",
            desired_outcome=desired,
            source=GoalSource.USER,
        )
        return IntentFrame(
            language=language,
            call_for_action=False,
            goals=[goal],
            explicit_slots={"first_name": first_name, "last_name": last_name},
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.INFORMATION,
        )

    @classmethod
    def _strict_contact_last_name_lookup_intent(
        cls, text: str, *, turn_id: str, language: str
    ) -> IntentFrame | None:
        normalized = unicodedata.normalize("NFKC", text).strip()
        match = _STRICT_CONTACT_LAST_NAME_LOOKUP_PATTERN.fullmatch(normalized)
        if match is None:
            return None
        last_name = match.group("last_name")
        recipient = match.group("recipient")
        if not cls._safe_contact_name(last_name) or (
            recipient is not None and not cls._safe_contact_name(recipient)
        ):
            return None
        digest = hashlib.sha256(
            f"{turn_id}\0strict-contact-last-name\0{last_name.casefold()}".encode()
        ).hexdigest()
        goal = Goal(
            goal_id=f"goal-contact-last-name-{digest[:12]}",
            semantic_operation="find_contact",
            desired_outcome={"last_name": last_name},
            source=GoalSource.USER,
        )
        return IntentFrame(
            language=language,
            call_for_action=False,
            goals=[goal],
            explicit_slots={"last_name": last_name},
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.INFORMATION,
        )

    def _strict_displayed_contact_group_send_intent(
        self,
        session: SessionState,
        text: str,
        *,
        turn_id: str,
        language: str,
    ) -> IntentFrame | None:
        match = _STRICT_DISPLAYED_CONTACT_GROUP_SEND_PATTERN.fullmatch(
            unicodedata.normalize("NFKC", text).strip()
        )
        group = self._validated_displayed_contact_group(session)
        if match is None or group is None:
            return None
        last_name = match.group("last_name")
        recipient_first_name = match.group("recipient_first_name")
        query_last_name = group[1]["query"].get("last_name")
        if (
            not self._safe_contact_name(last_name)
            or not self._safe_contact_name(recipient_first_name)
            or not isinstance(query_last_name, str)
            or _argument_identifier(last_name) != _argument_identifier(query_last_name)
        ):
            return None
        recipients = [
            record
            for record in group[1]["records"]
            if _argument_identifier(record["first_name"])
            == _argument_identifier(recipient_first_name)
            and _argument_identifier(record["last_name"])
            == _argument_identifier(last_name)
        ]
        if len(recipients) != 1:
            return None
        recipient = recipients[0]
        digest = hashlib.sha256(
            f"{turn_id}\0strict-contact-group-send\0{recipient['contact_id']}".encode()
        ).hexdigest()
        goal = Goal(
            goal_id=f"goal-contact-group-send-{digest[:12]}",
            semantic_operation="send_email",
            desired_outcome={
                "first_name": recipient["first_name"],
                "last_name": recipient["last_name"],
            },
            source=GoalSource.USER,
        )
        return IntentFrame(
            language=language,
            call_for_action=True,
            goals=[goal],
            explicit_slots=dict(goal.desired_outcome),
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.ACTION,
        )

    @staticmethod
    def _safe_contact_name(value: str) -> bool:
        return (
            0 < len(value) <= 80
            and value == value.strip()
            and re.fullmatch(
                r"[^\W\d_][^\W_]*(?:[-'][^\W\d_][^\W_]*)*", value, re.UNICODE
            )
            is not None
        )

    @staticmethod
    def _latest_current_evidence(
        session: SessionState, proposition: str
    ) -> Evidence | None:
        current = [
            item
            for item in session.evidence.for_proposition(proposition)
            if item.status is EvidenceStatus.KNOWN
            and item.state_version == session.evidence.current_state_version
        ]
        return max(current, key=lambda item: item.observation_index, default=None)

    @classmethod
    def _contact_candidates_from_evidence(
        cls,
        evidence: Evidence,
        *,
        query: Mapping[str, str],
    ) -> tuple[tuple[str, str], ...] | None:
        if (
            evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.TOOL
            or not isinstance(evidence.value, Mapping)
            or not evidence.value
        ):
            return None
        candidates: list[tuple[str, str]] = []
        seen_ids: set[str] = set()
        for contact_id, raw_name in evidence.value.items():
            if (
                not isinstance(contact_id, str)
                or _CONTACT_ID_PATTERN.fullmatch(contact_id) is None
                or contact_id in seen_ids
                or not isinstance(raw_name, str)
                or raw_name != raw_name.strip()
                or len(raw_name) > 120
            ):
                return None
            words = raw_name.split()
            if len(words) < 2 or not all(
                cls._safe_contact_name(word) for word in words
            ):
                return None
            if "first_name" in query and _argument_identifier(
                words[0]
            ) != _argument_identifier(query["first_name"]):
                return None
            if "last_name" in query and _argument_identifier(
                words[-1]
            ) != _argument_identifier(query["last_name"]):
                return None
            seen_ids.add(contact_id)
            candidates.append((contact_id, " ".join(word.title() for word in words)))
        return tuple(candidates) or None

    def _store_displayed_contact_candidates(
        self,
        session: SessionState,
        *,
        goal: Goal,
        query: Mapping[str, str],
        candidates: tuple[tuple[str, str], ...],
        raw_evidence: Evidence,
    ) -> Evidence | None:
        if raw_evidence.evidence_id is None:
            return None
        value = {
            "query": dict(query),
            "candidates": [
                {"contact_id": contact_id, "display_name": display_name}
                for contact_id, display_name in candidates
            ],
        }
        current = self._latest_current_evidence(session, _DISPLAYED_CONTACT_CANDIDATES)
        if current is not None and current.value == value:
            return current
        session.evidence.add(
            Evidence(
                proposition=_DISPLAYED_CONTACT_CANDIDATES,
                value=value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"contact-candidates-{goal.goal_id}",
                confidence=raw_evidence.confidence,
                derived_from=[raw_evidence.evidence_id],
                derivation="strict_displayed_contact_candidates_v1",
            )
        )
        return self._latest_current_evidence(session, _DISPLAYED_CONTACT_CANDIDATES)

    def _validated_contact_candidates_evidence(
        self, session: SessionState, summary: Evidence
    ) -> tuple[Evidence, dict[str, Any]] | None:
        if (
            summary.status is not EvidenceStatus.KNOWN
            or summary.state_version != session.evidence.current_state_version
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.derivation != "strict_displayed_contact_candidates_v1"
            or len(summary.derived_from) != 1
            or not isinstance(summary.value, Mapping)
        ):
            return None
        raw = session.evidence.evidence.get(summary.derived_from[0])
        query = summary.value.get("query")
        displayed = summary.value.get("candidates")
        if (
            raw is None
            or raw.state_version != session.evidence.current_state_version
            or not isinstance(query, Mapping)
            or not query
            or not all(
                key in {"first_name", "last_name"}
                and isinstance(value, str)
                and self._safe_contact_name(value)
                for key, value in query.items()
            )
            or not isinstance(displayed, list)
        ):
            return None
        parsed = self._contact_candidates_from_evidence(raw, query=query)
        expected = [
            {"contact_id": contact_id, "display_name": display_name}
            for contact_id, display_name in parsed or ()
        ]
        if parsed is None or displayed != expected:
            return None
        return summary, {"query": dict(query), "candidates": expected}

    def _validated_displayed_contact_candidates(
        self, session: SessionState
    ) -> tuple[Evidence, dict[str, Any]] | None:
        summary = self._latest_current_evidence(session, _DISPLAYED_CONTACT_CANDIDATES)
        return (
            self._validated_contact_candidates_evidence(session, summary)
            if summary is not None
            else None
        )

    @classmethod
    def _contact_records_from_evidence(
        cls,
        evidence: Evidence,
        *,
        candidates: Sequence[Mapping[str, str]],
    ) -> tuple[dict[str, str], ...] | None:
        if (
            evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.TOOL
            or not isinstance(evidence.value, Mapping)
        ):
            return None
        expected_ids = [item["contact_id"] for item in candidates]
        if set(evidence.value) != set(expected_ids):
            return None
        records: list[dict[str, str]] = []
        for candidate in candidates:
            contact_id = candidate["contact_id"]
            display_name = candidate["display_name"]
            raw = evidence.value.get(contact_id)
            if not isinstance(raw, Mapping) or raw.get("id") != contact_id:
                return None
            name = raw.get("name")
            phone = raw.get("phone_number")
            email = raw.get("email")
            if (
                not isinstance(name, Mapping)
                or set(name) != {"first_name", "last_name"}
                or not isinstance(name.get("first_name"), str)
                or not isinstance(name.get("last_name"), str)
                or not cls._safe_contact_name(name["first_name"])
                or not cls._safe_contact_name(name["last_name"])
                or _argument_identifier(f"{name['first_name']} {name['last_name']}")
                != _argument_identifier(display_name)
                or not isinstance(phone, str)
                or phone != phone.strip()
                or not 3 <= len(phone) <= 40
                or re.fullmatch(r"\+?[0-9][0-9 ()-]{1,38}[0-9]", phone) is None
                or not isinstance(email, str)
                or email != email.strip()
                or len(email) > 254
                or _CONTACT_EMAIL_PATTERN.fullmatch(email) is None
            ):
                return None
            records.append(
                {
                    "contact_id": contact_id,
                    "display_name": display_name,
                    "first_name": name["first_name"],
                    "last_name": name["last_name"],
                    "phone_number": phone,
                    "email": email,
                }
            )
        return tuple(records)

    def _store_displayed_contact_group(
        self,
        session: SessionState,
        *,
        goal: Goal,
        candidates_evidence: Evidence,
        info_evidence: Evidence,
        selected_candidates: Sequence[Mapping[str, str]],
    ) -> tuple[Evidence, dict[str, Any]] | None:
        validated = self._validated_contact_candidates_evidence(
            session, candidates_evidence
        )
        if (
            validated is None
            or candidates_evidence.evidence_id is None
            or info_evidence.evidence_id is None
        ):
            return None
        _, candidate_value = validated
        known_candidates = candidate_value["candidates"]
        if (
            not selected_candidates
            or len({item.get("contact_id") for item in selected_candidates})
            != len(selected_candidates)
            or any(dict(item) not in known_candidates for item in selected_candidates)
        ):
            return None
        records = self._contact_records_from_evidence(
            info_evidence, candidates=selected_candidates
        )
        if records is None:
            return None
        session.evidence.add(
            Evidence(
                proposition="contact_information",
                value=info_evidence.value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.TOOL,
                source_turn_id=info_evidence.source_turn_id,
                source_tool_call_id=info_evidence.source_tool_call_id,
                confidence=info_evidence.confidence,
            )
        )
        value = {
            "query": candidate_value["query"],
            "records": list(records),
        }
        session.evidence.add(
            Evidence(
                proposition=_DISPLAYED_CONTACT_GROUP,
                value=value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"contact-group-{goal.goal_id}",
                confidence=min(
                    candidates_evidence.confidence, info_evidence.confidence
                ),
                derived_from=[
                    candidates_evidence.evidence_id,
                    info_evidence.evidence_id,
                ],
                derivation="strict_displayed_contact_group_v1",
            )
        )
        group = self._latest_current_evidence(session, _DISPLAYED_CONTACT_GROUP)
        return (
            self._validated_contact_group_evidence(session, group)
            if group is not None
            else None
        )

    def _validated_contact_group_evidence(
        self, session: SessionState, group: Evidence
    ) -> tuple[Evidence, dict[str, Any]] | None:
        if (
            group.status is not EvidenceStatus.KNOWN
            or group.state_version != session.evidence.current_state_version
            or group.source_kind is not EvidenceSourceKind.DERIVED
            or group.derivation != "strict_displayed_contact_group_v1"
            or len(group.derived_from) != 2
            or not isinstance(group.value, Mapping)
        ):
            return None
        candidates = session.evidence.evidence.get(group.derived_from[0])
        info = session.evidence.evidence.get(group.derived_from[1])
        validated_candidates = (
            self._validated_contact_candidates_evidence(session, candidates)
            if candidates is not None
            else None
        )
        if (
            candidates is None
            or info is None
            or validated_candidates is None
            or info.state_version != session.evidence.current_state_version
        ):
            return None
        candidate_value = validated_candidates[1]
        if not isinstance(info.value, Mapping):
            return None
        selected_ids = set(info.value)
        selected_candidates = [
            candidate
            for candidate in candidate_value["candidates"]
            if candidate["contact_id"] in selected_ids
        ]
        if (
            not selected_candidates
            or {candidate["contact_id"] for candidate in selected_candidates}
            != selected_ids
        ):
            return None
        records = self._contact_records_from_evidence(
            info, candidates=selected_candidates
        )
        expected = {
            "query": candidate_value["query"],
            "records": list(records or ()),
        }
        if records is None or group.value != expected:
            return None
        return group, expected

    def _validated_displayed_contact_group(
        self, session: SessionState
    ) -> tuple[Evidence, dict[str, Any]] | None:
        group = self._latest_current_evidence(session, _DISPLAYED_CONTACT_GROUP)
        return (
            self._validated_contact_group_evidence(session, group)
            if group is not None
            else None
        )

    @staticmethod
    def _contact_group_text(records: Sequence[Mapping[str, str]]) -> str:
        return "I found these current contacts: " + "; ".join(
            f"{record['display_name']}: Phone {record['phone_number']}; Email {record['email']}"
            for record in records
        )

    @staticmethod
    def _latest_assistant_text(session: SessionState) -> str | None:
        return next(
            (
                message.get("content")
                for message in reversed(session.conversation)
                if message.get("role") == "assistant"
                and isinstance(message.get("content"), str)
            ),
            None,
        )

    def _store_contact_share_recipient(
        self,
        session: SessionState,
        *,
        goal: Goal,
        group: tuple[Evidence, dict[str, Any]],
    ) -> tuple[Evidence, dict[str, str]] | None:
        records = group[1]["records"]
        if len(records) != 1 or group[0].evidence_id is None:
            return None
        value = dict(records[0])
        session.evidence.add(
            Evidence(
                proposition=_CONTACT_SHARE_RECIPIENT,
                value=value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"contact-share-recipient-{goal.goal_id}",
                confidence=group[0].confidence,
                derived_from=[group[0].evidence_id],
                derivation="strict_contact_share_recipient_v1",
            )
        )
        return self._validated_contact_share_recipient(session)

    def _validated_contact_share_recipient(
        self, session: SessionState
    ) -> tuple[Evidence, dict[str, str]] | None:
        recipient = self._latest_current_evidence(session, _CONTACT_SHARE_RECIPIENT)
        if (
            recipient is None
            or recipient.source_kind is not EvidenceSourceKind.DERIVED
            or recipient.derivation != "strict_contact_share_recipient_v1"
            or len(recipient.derived_from) != 1
            or not isinstance(recipient.value, Mapping)
        ):
            return None
        parent = session.evidence.evidence.get(recipient.derived_from[0])
        group = (
            self._validated_contact_group_evidence(session, parent)
            if parent is not None
            else None
        )
        if group is None or len(group[1]["records"]) != 1:
            return None
        expected = dict(group[1]["records"][0])
        if recipient.value != expected:
            return None
        return recipient, expected

    def _contact_share_recipient_prompt(
        self, group: Mapping[str, Any], recipient: Mapping[str, str]
    ) -> str:
        return (
            self._contact_group_text(group["records"])
            + f" What contact details would you like me to share with {recipient['first_name']}?"
        )

    def _begin_contact_shared_source_lookup(
        self,
        session: SessionState,
        *,
        turn_id: str,
        first_name: str,
        last_name: str,
    ) -> None:
        digest = hashlib.sha256(
            f"{turn_id}\0contact-shared-source\0{first_name.casefold()}\0"
            f"{last_name.casefold()}".encode()
        ).hexdigest()
        desired = {
            "first_name": first_name,
            "last_name": last_name,
            _CONTACT_SHARED_SOURCE_LOOKUP_MARKER: True,
        }
        goal = Goal(
            goal_id=f"goal-contact-shared-source-{digest[:12]}",
            semantic_operation="find_contact",
            desired_outcome=desired,
            source=GoalSource.USER,
        )
        grounded = {"first_name": first_name, "last_name": last_name}
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=False,
            goals=[goal],
            explicit_slots=grounded,
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.INFORMATION,
        )
        session.authorized_action_goal_ids = set()
        session.grounded_desired_values_by_goal = {goal.goal_id: grounded}
        session.grounded_value_sources_by_goal = {
            goal.goal_id: {name: turn_id for name in grounded}
        }
        session.derived_value_evidence_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)

    def _handle_contact_record_share_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        normalized = unicodedata.normalize("NFKC", text).strip()
        if (
            re.fullmatch(
                r"\s*(?:do\s+not|don['\u2019]?t|never)\s+share\s+.+?[.!]?\s*",
                normalized,
                re.IGNORECASE | re.UNICODE,
            )
            is not None
        ):
            return True, self._text_plan(
                session, "Okay. I did not prepare or send contact details."
            )
        match = _STRICT_CONTACT_RECORD_SHARE_PATTERN.fullmatch(normalized)
        if match is None:
            return False, None
        recipient = self._validated_contact_share_recipient(session)
        if recipient is None:
            return True, self._text_plan(
                session,
                "I could not verify a current email recipient, so I did not prepare contact details.",
            )
        parent = session.evidence.evidence.get(recipient[0].derived_from[0])
        group = (
            self._validated_contact_group_evidence(session, parent)
            if parent is not None
            else None
        )
        if group is None or self._latest_assistant_text(
            session
        ) != self._contact_share_recipient_prompt(group[1], recipient[1]):
            return True, self._text_plan(
                session,
                "The displayed recipient is no longer fresh, so I did not prepare contact details.",
            )
        first_name = match.group("first_name")
        last_name = match.group("last_name")
        if not all(self._safe_contact_name(value) for value in (first_name, last_name)):
            return True, self._text_plan(
                session,
                "I could not validate that contact name, so I did not prepare contact details.",
            )
        self._begin_contact_shared_source_lookup(
            session,
            turn_id=turn_id,
            first_name=first_name,
            last_name=last_name,
        )
        return True, None

    @staticmethod
    def _contact_call_goal(session: SessionState) -> Goal | None:
        if session.intent is None:
            return None
        matches = [
            goal
            for goal in session.intent.goals
            if goal.semantic_operation == "call_phone_by_number"
            and goal.desired_outcome.get(_CONTACT_CALL_MARKER) is True
        ]
        return matches[0] if len(matches) == 1 else None

    def _begin_displayed_contact_call(
        self,
        session: SessionState,
        *,
        turn_id: str,
        group: tuple[Evidence, dict[str, Any]],
        record: Mapping[str, str],
    ) -> None:
        digest = hashlib.sha256(
            f"{turn_id}\0displayed-contact-call\0{record['contact_id']}".encode()
        ).hexdigest()
        goal = Goal(
            goal_id=f"goal-displayed-contact-call-{digest[:12]}",
            semantic_operation="call_phone_by_number",
            desired_outcome={_CONTACT_CALL_MARKER: True},
            source=GoalSource.USER,
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[goal],
            explicit_slots={},
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.ACTION,
        )
        session.authorized_action_goal_ids = {goal.goal_id}
        session.grounded_desired_values_by_goal = {goal.goal_id: {}}
        session.grounded_value_sources_by_goal = {goal.goal_id: {}}
        session.derived_value_evidence_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters={
                "phone_number": (
                    record["phone_number"],
                    (group[0],),
                    "exact_displayed_contact_phone_v1",
                )
            },
        )

    def _handle_displayed_contact_call_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        normalized = unicodedata.normalize("NFKC", text).strip()
        if (
            re.fullmatch(
                r"\s*(?:do\s+not|don['\u2019]?t|never)\s+call\s+.+?[.!]?\s*",
                normalized,
                re.IGNORECASE | re.UNICODE,
            )
            is not None
        ):
            return True, self._text_plan(session, "Okay. I did not place a phone call.")
        match = _STRICT_DISPLAYED_CONTACT_CALL_PATTERN.fullmatch(normalized)
        if match is None:
            return False, None
        group = self._validated_displayed_contact_group(session)
        if group is None or self._latest_assistant_text(
            session
        ) != self._contact_group_text(group[1]["records"]):
            return True, self._text_plan(
                session,
                "I could not verify that contact from the currently displayed record, so I did not place a call.",
            )
        target = " ".join(match.group("target").split())
        records = group[1]["records"]
        if target.casefold() in {"her", "him", "them"}:
            selected = list(records) if len(records) == 1 else []
        else:
            words = target.split()
            if len(words) != 2 or not all(
                self._safe_contact_name(word) for word in words
            ):
                selected = []
            else:
                selected = [
                    record
                    for record in records
                    if _argument_identifier(record["display_name"])
                    == _argument_identifier(target)
                ]
        if len(selected) != 1:
            return True, self._text_plan(
                session,
                "I could not match that request to exactly one currently displayed contact, so I did not place a call.",
            )
        self._begin_displayed_contact_call(
            session,
            turn_id=turn_id,
            group=group,
            record=selected[0],
        )
        return True, None

    def _begin_selected_contact_lookup(
        self,
        session: SessionState,
        *,
        turn_id: str,
        candidate: Mapping[str, str],
        candidates_evidence: Evidence,
    ) -> None:
        digest = hashlib.sha256(
            f"{turn_id}\0contact-selection\0{candidate['contact_id']}".encode()
        ).hexdigest()
        goal = Goal(
            goal_id=f"goal-contact-selection-{digest[:12]}",
            semantic_operation="find_contact",
            desired_outcome={
                "first_name": candidate["display_name"].split()[0],
                "last_name": candidate["display_name"].split()[-1],
            },
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=False,
            goals=[goal],
            explicit_slots=dict(goal.desired_outcome),
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.SELECTION,
        )
        session.authorized_action_goal_ids = set()
        session.grounded_desired_values_by_goal = {
            goal.goal_id: dict(goal.desired_outcome)
        }
        session.grounded_value_sources_by_goal = {
            goal.goal_id: {name: turn_id for name in goal.desired_outcome}
        }
        session.derived_value_evidence_by_goal = {}
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters={
                "contact_ids": (
                    [candidate["contact_id"]],
                    (candidates_evidence,),
                    "exact_displayed_contact_selection_v1",
                )
            },
        )

    def _handle_displayed_contact_selection(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        match = _TRIP_CONTACT_SELECTION_PATTERN.fullmatch(text)
        if match is None:
            return False, None
        name = " ".join(match.group("name").split())
        if len(name.split()) < 2:
            return False, None
        active_email = self._contact_share_email_goal(session)
        displayed = self._validated_displayed_contact_candidates(session)
        if active_email is not None:
            group = self._validated_displayed_contact_group(session)
            if group is None:
                return True, self._limitation_plan(
                    session, active_email, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            candidates = [
                {
                    "contact_id": record["contact_id"],
                    "display_name": record["display_name"],
                }
                for record in group[1]["records"]
                if _argument_identifier(record["display_name"])
                == _argument_identifier(name)
            ]
            if len(candidates) != 1:
                return False, None
            desired = dict(active_email.desired_outcome)
            desired.update(
                {
                    "first_name": candidates[0]["display_name"].split()[0],
                    "last_name": candidates[0]["display_name"].split()[-1],
                }
            )
            replacement = active_email.model_copy(
                update={"desired_outcome": desired}, deep=True
            )
            session.intent = session.intent.model_copy(
                update={"goals": [replacement]}, deep=True
            )
            session.goal_dag = self.goal_planner.update(
                session.goal_dag, session.intent
            )
            grounded = session.grounded_desired_values_by_goal.setdefault(
                replacement.goal_id, {}
            )
            grounded.update(
                {
                    "first_name": desired["first_name"],
                    "last_name": desired["last_name"],
                }
            )
            sources = session.grounded_value_sources_by_goal.setdefault(
                replacement.goal_id, {}
            )
            sources.update({"first_name": turn_id, "last_name": turn_id})
            return True, None
        if displayed is None:
            return False, None
        selected = [
            candidate
            for candidate in displayed[1]["candidates"]
            if _argument_identifier(candidate["display_name"])
            == _argument_identifier(name)
        ]
        if len(selected) != 1:
            return False, None
        self._begin_selected_contact_lookup(
            session,
            turn_id=turn_id,
            candidate=selected[0],
            candidates_evidence=displayed[0],
        )
        return True, None

    @staticmethod
    def _contact_share_email_goal(session: SessionState) -> Goal | None:
        if session.intent is None:
            return None
        matches = [
            goal
            for goal in session.intent.goals
            if goal.semantic_operation == "send_email"
            and goal.desired_outcome.get(_CONTACT_SHARE_EMAIL_MARKER) is True
        ]
        return matches[0] if len(matches) == 1 else None

    @staticmethod
    def _contact_record_share_email_goal(session: SessionState) -> Goal | None:
        if session.intent is None:
            return None
        matches = [
            goal
            for goal in session.intent.goals
            if goal.semantic_operation == "send_email"
            and goal.desired_outcome.get(_CONTACT_RECORD_SHARE_EMAIL_MARKER) is True
        ]
        return matches[0] if len(matches) == 1 else None

    @staticmethod
    def _contact_record_share_body(
        *, recipient: Mapping[str, str], source: Mapping[str, str]
    ) -> str:
        return (
            f"Hi {recipient['first_name']},\n\n"
            f"I wanted to share {source['display_name']}'s contact information with you:\n\n"
            f"Name: {source['display_name']}\n"
            f"Phone: {source['phone_number']}\n"
            f"Email: {source['email']}\n\n"
            "Best regards"
        )

    def _begin_contact_record_share_email(
        self,
        session: SessionState,
        *,
        source_turn_id: str,
        recipient: tuple[Evidence, dict[str, str]],
        source_group: tuple[Evidence, dict[str, Any]],
    ) -> Goal | None:
        records = source_group[1]["records"]
        if len(records) != 1:
            return None
        source = records[0]
        digest = hashlib.sha256(
            f"{source_turn_id}\0contact-record-share-email\0"
            f"{recipient[1]['contact_id']}\0{source['contact_id']}".encode()
        ).hexdigest()
        goal = Goal(
            goal_id=f"goal-contact-record-share-email-{digest[:12]}",
            semantic_operation="send_email",
            desired_outcome={_CONTACT_RECORD_SHARE_EMAIL_MARKER: True},
            source=GoalSource.USER,
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[goal],
            explicit_slots={},
            intent_source_turn_ids=[source_turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.ACTION,
        )
        session.authorized_action_goal_ids = {goal.goal_id}
        session.grounded_desired_values_by_goal = {goal.goal_id: {}}
        session.grounded_value_sources_by_goal = {goal.goal_id: {}}
        session.derived_value_evidence_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        body = self._contact_record_share_body(recipient=recipient[1], source=source)
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters={
                "email_addresses": (
                    [recipient[1]["email"]],
                    (recipient[0],),
                    "exact_contact_record_share_recipient_v1",
                ),
                "message": (
                    body,
                    (recipient[0], source_group[0]),
                    "minimal_contact_record_share_body_v1",
                ),
            },
        )
        return goal

    def _next_displayed_contact_call_workflow(
        self, session: SessionState, item: PreparedGoal
    ) -> PlannedOutbound:
        goal = item.goal
        group = self._validated_displayed_contact_group(session)
        derived_ids = session.derived_value_evidence_by_goal.get(goal.goal_id, {})
        phone_evidence = session.evidence.evidence.get(
            derived_ids.get("phone_number", "")
        )
        if (
            group is None
            or phone_evidence is None
            or phone_evidence.state_version != session.evidence.current_state_version
            or phone_evidence.derived_from != [group[0].evidence_id]
            or phone_evidence.derivation != "exact_displayed_contact_phone_v1"
            or not isinstance(phone_evidence.value, str)
            or session.live_tools is None
            or not session.live_tools.has_tool("call_phone_by_number")
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        try:
            validated_call_arguments = session.live_tools.validate_arguments(
                "call_phone_by_number", {"phone_number": phone_evidence.value}
            )
        except ToolArgumentValidationError:
            return self._limitation_plan(
                session, goal, GateOutcome.UNSUPPORTED_CAPABILITY
            )
        if validated_call_arguments != {"phone_number": phone_evidence.value}:
            return self._limitation_plan(
                session, goal, GateOutcome.UNSUPPORTED_CAPABILITY
            )
        refreshed = self._prepare_turn(session)
        refreshed_item = refreshed.by_goal_id.get(goal.goal_id)
        target = (
            self._unique_bound_target(refreshed_item)
            if refreshed_item is not None
            else None
        )
        if (
            target is None
            or target[1].tool_name != "call_phone_by_number"
            or not _argument_value_matches_binding(
                target[1].arguments, {"phone_number": phone_evidence.value}
            )
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        deterministic = self._deterministic_bound_action(session, refreshed)
        return deterministic or self._limitation_plan(
            session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
        )

    def _next_contact_record_share_email_workflow(
        self, session: SessionState, item: PreparedGoal
    ) -> PlannedOutbound:
        goal = item.goal
        recipient = self._validated_contact_share_recipient(session)
        source_group = self._validated_displayed_contact_group(session)
        derived_ids = session.derived_value_evidence_by_goal.get(goal.goal_id, {})
        email_evidence = session.evidence.evidence.get(
            derived_ids.get("email_addresses", "")
        )
        body_evidence = session.evidence.evidence.get(derived_ids.get("message", ""))
        if (
            recipient is None
            or source_group is None
            or len(source_group[1]["records"]) != 1
            or email_evidence is None
            or body_evidence is None
            or email_evidence.derived_from != [recipient[0].evidence_id]
            or body_evidence.derived_from
            != [recipient[0].evidence_id, source_group[0].evidence_id]
            or email_evidence.derivation != "exact_contact_record_share_recipient_v1"
            or body_evidence.derivation != "minimal_contact_record_share_body_v1"
            or not self._contact_tools_available(session, email=True)
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        expected = {
            "email_addresses": email_evidence.value,
            "content_message": body_evidence.value,
        }
        refreshed = self._prepare_turn(session)
        refreshed_item = refreshed.by_goal_id.get(goal.goal_id)
        target = (
            self._unique_bound_target(refreshed_item)
            if refreshed_item is not None
            else None
        )
        if (
            target is None
            or target[1].tool_name != "send_email"
            or not _argument_value_matches_binding(target[1].arguments, expected)
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        deterministic = self._deterministic_bound_action(session, refreshed)
        return deterministic or self._limitation_plan(
            session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
        )

    @staticmethod
    def _contact_tools_available(session: SessionState, *, email: bool = False) -> bool:
        if session.live_tools is None:
            return False
        probes: list[tuple[str, dict[str, Any]]] = [
            ("get_contact_id_by_contact_name", {"contact_last_name": "Probe"}),
            ("get_contact_information", {"contact_ids": ["con_probe"]}),
        ]
        if email:
            probes.append(
                (
                    "send_email",
                    {
                        "email_addresses": ["probe@example.test"],
                        "content_message": "probe",
                    },
                )
            )
        try:
            if not all(
                session.live_tools.has_tool(name)
                and session.live_tools.validate_arguments(name, arguments) == arguments
                for name, arguments in probes
            ):
                return False
            return (
                not email
                or re.match(
                    r"requires_confirmation(?:\s*[:,]|\s*$)",
                    session.live_tools.description("send_email").lstrip().casefold(),
                )
                is not None
            )
        except ToolArgumentValidationError:
            return False

    def _next_contact_lookup_workflow(
        self, session: SessionState, item: PreparedGoal
    ) -> PlannedOutbound | None:
        goal = item.goal
        if not self._contact_tools_available(session):
            if session.live_tools is not None and session.live_tools.has_tool(
                "send_email"
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            return None
        query = {
            key: value
            for key, value in goal.desired_outcome.items()
            if key in {"first_name", "last_name"} and isinstance(value, str)
        }
        contact_ids = goal.desired_outcome.get("contact_ids")
        candidates_evidence: Evidence | None = None
        candidates: list[dict[str, str]]
        if isinstance(contact_ids, list):
            displayed = self._validated_displayed_contact_candidates(session)
            derived_id = session.derived_value_evidence_by_goal.get(
                goal.goal_id, {}
            ).get("contact_ids")
            derived = session.evidence.evidence.get(derived_id or "")
            if (
                displayed is None
                or derived is None
                or derived.state_version != session.evidence.current_state_version
                or derived.value != contact_ids
                or derived.derived_from != [displayed[0].evidence_id]
                or derived.derivation != "exact_displayed_contact_selection_v1"
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            selected_ids = set(contact_ids)
            candidates = [
                candidate
                for candidate in displayed[1]["candidates"]
                if candidate["contact_id"] in selected_ids
            ]
            if len(candidates) != len(contact_ids):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            candidates_evidence = displayed[0]
        else:
            arguments = {f"contact_{key}": value for key, value in query.items()}
            matches_proposition = f"contact_lookup_matches:{goal.goal_id}"
            if not any(
                need.required_for_goal_id == goal.goal_id
                and need.proposition == matches_proposition
                for need in session.evidence.needs.values()
            ):
                self.result_validator.register_extractor(
                    matches_proposition,
                    ExtractorSpec(
                        "$.result.matches",
                        allowed_tool_names=frozenset(
                            {"get_contact_id_by_contact_name"}
                        ),
                    ),
                )
            self._register_single_read_need(
                session, goal_id=goal.goal_id, proposition=matches_proposition
            )
            observed = self._derived_navigation_read_value(
                session,
                goal_id=goal.goal_id,
                tool_name="get_contact_id_by_contact_name",
                arguments=arguments,
                proposition=matches_proposition,
            )
            if observed is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=goal.goal_id,
                        tool_name="get_contact_id_by_contact_name",
                        arguments=arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_contact_id_by_contact_name",
                    arguments=arguments,
                    semantic_operation="find_contact_ids",
                    proposition=matches_proposition,
                )
            _, raw_evidence = observed
            parsed = self._contact_candidates_from_evidence(raw_evidence, query=query)
            if parsed is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            candidates_evidence = self._store_displayed_contact_candidates(
                session,
                goal=goal,
                query=query,
                candidates=parsed,
                raw_evidence=raw_evidence,
            )
            if candidates_evidence is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            candidates = [
                {"contact_id": contact_id, "display_name": display_name}
                for contact_id, display_name in parsed
            ]
            if set(query) == {"first_name"} and len(candidates) > 1:
                session.goal_dag.set_status(goal.goal_id, GoalStatus.DONE)
                return self._text_plan(
                    session,
                    "I found these current contacts: "
                    + ", ".join(item["display_name"] for item in candidates)
                    + ". Which one do you mean?",
                    goal_ids=[goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )

        info_arguments = {"contact_ids": [item["contact_id"] for item in candidates]}
        info_proposition = f"contact_information:{goal.goal_id}"
        if not any(
            need.required_for_goal_id == goal.goal_id
            and need.proposition == info_proposition
            for need in session.evidence.needs.values()
        ):
            self.result_validator.register_extractor(
                info_proposition,
                ExtractorSpec(
                    "$.result",
                    allowed_tool_names=frozenset({"get_contact_information"}),
                ),
            )
        self._register_single_read_need(
            session, goal_id=goal.goal_id, proposition=info_proposition
        )
        observed_info = self._derived_navigation_read_value(
            session,
            goal_id=goal.goal_id,
            tool_name="get_contact_information",
            arguments=info_arguments,
            proposition=info_proposition,
        )
        if observed_info is None:
            if (
                self._successful_goal_read(
                    session,
                    goal_id=goal.goal_id,
                    tool_name="get_contact_information",
                    arguments=info_arguments,
                )
                is not None
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="get_contact_information",
                arguments=info_arguments,
                semantic_operation="read_contact_information",
                proposition=info_proposition,
            )
        _, info_evidence = observed_info
        assert candidates_evidence is not None
        group = self._store_displayed_contact_group(
            session,
            goal=goal,
            candidates_evidence=candidates_evidence,
            info_evidence=info_evidence,
            selected_candidates=candidates,
        )
        if group is None:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        if goal.desired_outcome.get(_CONTACT_EMAIL_RECIPIENT_LOOKUP_MARKER) is True:
            recipient = self._store_contact_share_recipient(
                session, goal=goal, group=group
            )
            if recipient is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            session.goal_dag.set_status(goal.goal_id, GoalStatus.DONE)
            return self._text_plan(
                session,
                self._contact_share_recipient_prompt(group[1], recipient[1]),
                goal_ids=[goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
        if goal.desired_outcome.get(_CONTACT_SHARED_SOURCE_LOOKUP_MARKER) is True:
            recipient = self._validated_contact_share_recipient(session)
            source_turn_id = session.grounded_value_sources_by_goal.get(
                goal.goal_id, {}
            ).get("first_name")
            if (
                recipient is None
                or len(group[1]["records"]) != 1
                or not isinstance(source_turn_id, str)
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            session.goal_dag.set_status(goal.goal_id, GoalStatus.DONE)
            email_goal = self._begin_contact_record_share_email(
                session,
                source_turn_id=source_turn_id,
                recipient=recipient,
                source_group=group,
            )
            if email_goal is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            refreshed = self._prepare_turn(session)
            refreshed_item = refreshed.by_goal_id.get(email_goal.goal_id)
            if refreshed_item is None:
                return self._limitation_plan(
                    session, email_goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._next_contact_record_share_email_workflow(
                session, refreshed_item
            )
        session.goal_dag.set_status(goal.goal_id, GoalStatus.DONE)
        return self._text_plan(
            session,
            self._contact_group_text(group[1]["records"]),
            goal_ids=[goal.goal_id],
            kind=ProposalKind.COMPLETE,
        )

    @staticmethod
    def _contact_share_body(
        *,
        recipient_first_name: str,
        source_last_name: str,
        records: Sequence[Mapping[str, str]],
    ) -> str:
        details = "\n\n".join(
            f"**{record['display_name']}**\n"
            f"- Phone: {record['phone_number']}\n"
            f"- Email: {record['email']}"
            for record in records
        )
        return (
            f"Hi {recipient_first_name},\n\n"
            f"Here are the contact details for the other {source_last_name} colleagues you asked "
            f"about:\n\n{details}\n\n"
            "Let me know if you need any additional information!\n\n"
            "Best regards"
        )

    def _next_contact_share_email_workflow(
        self, session: SessionState, item: PreparedGoal
    ) -> PlannedOutbound:
        goal = item.goal
        if not self._contact_tools_available(session, email=True):
            return self._limitation_plan(
                session, goal, GateOutcome.UNSUPPORTED_CAPABILITY
            )
        group = self._validated_displayed_contact_group(session)
        source_last_name = goal.desired_outcome.get(_CONTACT_SOURCE_LAST_NAME)
        if (
            group is None
            or not isinstance(source_last_name, str)
            or _argument_identifier(group[1]["query"].get("last_name", ""))
            != _argument_identifier(source_last_name)
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        first_name = goal.desired_outcome.get("first_name")
        last_name = goal.desired_outcome.get("last_name")
        if not isinstance(first_name, str):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        first_matches = [
            record
            for record in group[1]["records"]
            if _argument_identifier(record["first_name"])
            == _argument_identifier(first_name)
        ]
        if not isinstance(last_name, str):
            if not first_matches:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._text_plan(
                session,
                "I found these current contacts: "
                + ", ".join(record["display_name"] for record in first_matches)
                + ". Which exact contact should receive the email?",
                goal_ids=[goal.goal_id],
                kind=ProposalKind.ASK_USER,
            )
        recipients = [
            record
            for record in first_matches
            if _argument_identifier(record["last_name"])
            == _argument_identifier(last_name)
        ]
        if len(recipients) != 1:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        recipient = recipients[0]
        shared = [
            record
            for record in group[1]["records"]
            if record["contact_id"] != recipient["contact_id"]
        ]
        if not shared:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        body = self._contact_share_body(
            recipient_first_name=recipient["first_name"],
            source_last_name=source_last_name,
            records=shared,
        )
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters={
                "email_addresses": (
                    [recipient["email"]],
                    (group[0],),
                    "exact_contact_share_recipient_v1",
                ),
                "message": (
                    body,
                    (group[0],),
                    "minimal_contact_share_body_v1",
                ),
            },
        )
        refreshed = self._prepare_turn(session)
        refreshed_item = refreshed.by_goal_id.get(goal.goal_id)
        target = (
            self._unique_bound_target(refreshed_item)
            if refreshed_item is not None
            else None
        )
        expected = {
            "email_addresses": [recipient["email"]],
            "content_message": body,
        }
        if (
            target is None
            or target[1].tool_name != "send_email"
            or not _argument_value_matches_binding(target[1].arguments, expected)
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        deterministic = self._deterministic_bound_action(session, refreshed)
        return deterministic or self._limitation_plan(
            session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
        )

    def _next_contact_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation == "find_contact":
                return self._next_contact_lookup_workflow(session, item)
            if (
                item.goal.semantic_operation == "call_phone_by_number"
                and item.goal.desired_outcome.get(_CONTACT_CALL_MARKER) is True
            ):
                return self._next_displayed_contact_call_workflow(session, item)
            if (
                item.goal.semantic_operation == "send_email"
                and item.goal.desired_outcome.get(_CONTACT_RECORD_SHARE_EMAIL_MARKER)
                is True
            ):
                return self._next_contact_record_share_email_workflow(session, item)
            if (
                item.goal.semantic_operation == "send_email"
                and item.goal.desired_outcome.get(_CONTACT_SHARE_EMAIL_MARKER) is True
            ):
                return self._next_contact_share_email_workflow(session, item)
        return None

    def _contact_share_email_bundle_is_current(
        self, session: SessionState, bundle: ExecutionBundle
    ) -> bool:
        goal = self._contact_share_email_goal(session)
        group = self._validated_displayed_contact_group(session)
        if (
            goal is None
            or group is None
            or len(bundle.calls) != 1
            or bundle.goal_ids != (goal.goal_id,)
            or bundle.calls[0].tool_name != "send_email"
        ):
            return False
        recipient_ids = session.derived_value_evidence_by_goal.get(goal.goal_id, {})
        recipient_evidence = session.evidence.evidence.get(
            recipient_ids.get("email_addresses", "")
        )
        body_evidence = session.evidence.evidence.get(recipient_ids.get("message", ""))
        if (
            recipient_evidence is None
            or body_evidence is None
            or recipient_evidence.state_version
            != session.evidence.current_state_version
            or body_evidence.state_version != session.evidence.current_state_version
            or recipient_evidence.derived_from != [group[0].evidence_id]
            or body_evidence.derived_from != [group[0].evidence_id]
            or recipient_evidence.derivation != "exact_contact_share_recipient_v1"
            or body_evidence.derivation != "minimal_contact_share_body_v1"
        ):
            return False
        expected = {
            "email_addresses": recipient_evidence.value,
            "content_message": body_evidence.value,
        }
        return _argument_value_matches_binding(bundle.calls[0].arguments, expected)

    def _contact_call_bundle_is_current(
        self, session: SessionState, bundle: ExecutionBundle
    ) -> bool:
        goal = self._contact_call_goal(session)
        group = self._validated_displayed_contact_group(session)
        if (
            goal is None
            or group is None
            or self._latest_assistant_text(session)
            != self._contact_group_text(group[1]["records"])
            or len(bundle.calls) != 1
            or bundle.goal_ids != (goal.goal_id,)
            or bundle.calls[0].tool_name != "call_phone_by_number"
        ):
            return False
        derived_ids = session.derived_value_evidence_by_goal.get(goal.goal_id, {})
        phone_evidence = session.evidence.evidence.get(
            derived_ids.get("phone_number", "")
        )
        if (
            phone_evidence is None
            or phone_evidence.state_version != session.evidence.current_state_version
            or phone_evidence.derived_from != [group[0].evidence_id]
            or phone_evidence.derivation != "exact_displayed_contact_phone_v1"
        ):
            return False
        return _argument_value_matches_binding(
            bundle.calls[0].arguments,
            {"phone_number": phone_evidence.value},
        )

    def _contact_record_share_email_bundle_is_current(
        self, session: SessionState, bundle: ExecutionBundle
    ) -> bool:
        goal = self._contact_record_share_email_goal(session)
        recipient = self._validated_contact_share_recipient(session)
        source_group = self._validated_displayed_contact_group(session)
        if (
            goal is None
            or recipient is None
            or source_group is None
            or len(source_group[1]["records"]) != 1
            or len(bundle.calls) != 1
            or bundle.goal_ids != (goal.goal_id,)
            or bundle.calls[0].tool_name != "send_email"
        ):
            return False
        derived_ids = session.derived_value_evidence_by_goal.get(goal.goal_id, {})
        email_evidence = session.evidence.evidence.get(
            derived_ids.get("email_addresses", "")
        )
        body_evidence = session.evidence.evidence.get(derived_ids.get("message", ""))
        if (
            email_evidence is None
            or body_evidence is None
            or email_evidence.state_version != session.evidence.current_state_version
            or body_evidence.state_version != session.evidence.current_state_version
            or email_evidence.derived_from != [recipient[0].evidence_id]
            or body_evidence.derived_from
            != [recipient[0].evidence_id, source_group[0].evidence_id]
            or email_evidence.derivation != "exact_contact_record_share_recipient_v1"
            or body_evidence.derivation != "minimal_contact_record_share_body_v1"
        ):
            return False
        return _argument_value_matches_binding(
            bundle.calls[0].arguments,
            {
                "email_addresses": email_evidence.value,
                "content_message": body_evidence.value,
            },
        )

    @staticmethod
    def _current_day_meeting_goal(session: SessionState) -> Goal | None:
        if session.intent is None:
            return None
        matches = [
            goal
            for goal in session.intent.goals
            if goal.desired_outcome.get(_CURRENT_DAY_MEETING_MARKER) is True
        ]
        return matches[0] if len(matches) == 1 else None

    @classmethod
    def _calendar_schema_available(cls, session: SessionState) -> bool:
        current = cls._current_datetime_parts(session)
        if current is None or session.live_tools is None:
            return False
        arguments = {"month": current[1], "day": current[2]}
        try:
            return (
                session.live_tools.has_tool("get_entries_from_calendar")
                and session.live_tools.validate_arguments(
                    "get_entries_from_calendar", arguments
                )
                == arguments
            )
        except ToolArgumentValidationError:
            return False

    @classmethod
    def _meeting_email_schema_available(
        cls,
        session: SessionState,
        *,
        named_contact: tuple[str, str] | None,
    ) -> bool:
        if not cls._calendar_schema_available(session) or session.live_tools is None:
            return False
        probes: list[tuple[str, dict[str, Any]]] = [
            ("get_contact_information", {"contact_ids": ["con_probe"]}),
            (
                "send_email",
                {
                    "email_addresses": ["probe@example.test"],
                    "content_message": "probe",
                },
            ),
        ]
        if named_contact is not None:
            probes.append(
                (
                    "get_contact_id_by_contact_name",
                    {
                        "contact_first_name": named_contact[0],
                        "contact_last_name": named_contact[1],
                    },
                )
            )
        try:
            return all(
                session.live_tools.has_tool(tool_name)
                and session.live_tools.validate_arguments(tool_name, arguments)
                == arguments
                for tool_name, arguments in probes
            ) and re.match(
                r"requires_confirmation(?:\s*[:,]|\s*$)",
                session.live_tools.description("send_email").lstrip().casefold(),
            ) is not None
        except ToolArgumentValidationError:
            return False

    @classmethod
    def _meeting_weather_email_missing_capabilities(
        cls, session: SessionState
    ) -> tuple[str, ...]:
        current = cls._current_datetime_parts(session)
        live_tools = session.live_tools
        if live_tools is None:
            return ("weather", "email", "calendar", "contact", "location")
        month = current[1] if current is not None else 1
        day = current[2] if current is not None else 1
        hour = current[3] if current is not None else 0
        probes: tuple[tuple[str, str, dict[str, Any]], ...] = (
            (
                "weather",
                "get_weather",
                {
                    "location_or_poi_id": "loc_probe",
                    "month": month,
                    "day": day,
                    "time_hour_24hformat": hour,
                },
            ),
            (
                "email",
                "send_email",
                {
                    "email_addresses": ["probe@example.test"],
                    "content_message": "probe",
                },
            ),
            (
                "calendar",
                "get_entries_from_calendar",
                {"month": month, "day": day},
            ),
            (
                "contact",
                "get_contact_information",
                {"contact_ids": ["con_probe"]},
            ),
            (
                "location",
                "get_location_id_by_location_name",
                {"location": "Probe City"},
            ),
        )
        missing: list[str] = []
        for capability, tool_name, arguments in probes:
            try:
                available = live_tools.has_tool(tool_name) and (
                    live_tools.validate_arguments(tool_name, arguments) == arguments
                )
                if capability == "email" and available:
                    available = (
                        re.match(
                            r"requires_confirmation(?:\s*[:,]|\s*$)",
                            live_tools.description(tool_name).lstrip().casefold(),
                        )
                        is not None
                    )
            except ToolArgumentValidationError:
                available = False
            if not available:
                missing.append(capability)
        return tuple(missing)

    def _begin_current_day_meeting_goal(
        self,
        session: SessionState,
        *,
        turn_id: str,
        mode: str,
        phase: str,
        topic: str | None,
        query_kind: str | None = None,
        contact_name: tuple[str, str] | None = None,
        request_text: str | None = None,
        request_location: str | None = None,
        contextual_weather: bool = False,
        prior_source_turn_id: str | None = None,
    ) -> Goal:
        digest = hashlib.sha256(
            f"{turn_id}\0current-day-meeting\0{mode}\0{topic or ''}".encode()
        ).hexdigest()
        desired: dict[str, Any] = {
            _CURRENT_DAY_MEETING_MARKER: True,
            _CURRENT_DAY_MEETING_MODE: mode,
            _CURRENT_DAY_MEETING_PHASE: phase,
        }
        grounded: dict[str, Any] = {}
        if topic is not None:
            desired["meeting_topic"] = topic
            grounded["meeting_topic"] = topic
        if query_kind is not None:
            desired["meeting_query_kind"] = query_kind
            grounded["meeting_query_kind"] = query_kind
        if contact_name is not None:
            desired.update(
                contact_first_name=contact_name[0],
                contact_last_name=contact_name[1],
            )
            grounded.update(
                contact_first_name=contact_name[0],
                contact_last_name=contact_name[1],
            )
        if request_text is not None:
            desired["weather_email_request"] = request_text
            grounded["weather_email_request"] = request_text
        if request_location is not None:
            desired["weather_email_location"] = request_location
            grounded["weather_email_location"] = request_location
        if contextual_weather:
            desired[_CURRENT_DAY_MEETING_CONTEXTUAL_WEATHER] = True
        action = mode in {
            _CURRENT_DAY_MEETING_ATTENDEE_EMAIL,
            _CURRENT_DAY_MEETING_NAMED_EMAIL,
            _CURRENT_DAY_MEETING_WEATHER_EMAIL,
        }
        goal = Goal(
            goal_id=f"goal-current-day-meeting-{digest[:12]}",
            semantic_operation="send_email" if action else "get_named_meeting_status",
            desired_outcome=desired,
            source=GoalSource.USER,
        )
        intent_source_turn_ids = list(
            dict.fromkeys(
                source
                for source in (prior_source_turn_id, turn_id)
                if isinstance(source, str) and source
            )
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=action,
            goals=[goal],
            explicit_slots=grounded,
            intent_source_turn_ids=intent_source_turn_ids,
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.ACTION if action else IntentKind.INFORMATION,
        )
        session.authorized_action_goal_ids = {goal.goal_id} if action else set()
        session.grounded_desired_values_by_goal = {goal.goal_id: grounded}
        grounded_sources = {name: turn_id for name in grounded}
        if contextual_weather and prior_source_turn_id is not None:
            for name in ("meeting_topic", "weather_email_location"):
                if name in grounded_sources:
                    grounded_sources[name] = prior_source_turn_id
        session.grounded_value_sources_by_goal = {goal.goal_id: grounded_sources}
        session.derived_value_evidence_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return goal

    def _update_current_day_meeting_goal(
        self,
        session: SessionState,
        goal: Goal,
        *,
        updates: Mapping[str, Any],
    ) -> Goal:
        assert session.intent is not None
        replacement = goal.model_copy(
            update={"desired_outcome": {**goal.desired_outcome, **dict(updates)}},
            deep=True,
        )
        session.intent = session.intent.model_copy(
            update={
                "goals": [
                    replacement if item.goal_id == goal.goal_id else item
                    for item in session.intent.goals
                ]
            },
            deep=True,
        )
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return replacement

    @staticmethod
    def _meeting_candidate_prompt(meetings: Sequence[Mapping[str, Any]]) -> str:
        details = "; ".join(
            f"{meeting['topic']} at {meeting['start_hour']:02d}:"
            f"{meeting['start_minute']:02d} in {meeting['location']}"
            for meeting in meetings
        )
        return (
            f"I found these meetings today: {details}. "
            "Which meeting should receive the reminder?"
        )

    @staticmethod
    def _meeting_selection_ack(meeting: Mapping[str, Any]) -> str:
        return (
            f"I selected the {meeting['topic']} meeting at "
            f"{int(meeting['start_hour']):02d}:"
            f"{int(meeting['start_minute']):02d} in {meeting['location']}. "
            "I will use this exact meeting for your next request."
        )

    @staticmethod
    def _meeting_selection_shape(text: str) -> bool:
        normalized = _meeting_request_text(text)
        if normalized is None:
            return False
        return (
            re.match(
                r"\s*(?:(?:okay|ok)\s*[,!]\s*)?(?:"
                r"i(?:['\u2019]m|\s+am)\s+(?:interested\s+in|"
                r"focusing\s+on|looking\s+at)|"
                r"i\s+(?:want|would\s+like)\s+to\s+"
                r"(?:focus\s+on|select|use)|"
                r"(?:please\s+)?(?:focus\s+on|select|use))\b",
                normalized,
                re.IGNORECASE | re.UNICODE,
            )
            is not None
            and re.search(r"\bmeeting\b", normalized, re.IGNORECASE) is not None
        )

    @staticmethod
    def _meeting_literal_pattern(value: str) -> str:
        return re.escape(value).replace(r"\ ", r"\s+")

    @classmethod
    def _meeting_selection_time_pattern(cls, meeting: Mapping[str, Any]) -> str:
        hour = int(meeting["start_hour"])
        minute = int(meeting["start_minute"])
        display_hour = hour % 12 or 12
        meridiem = "a" if hour < 12 else "p"
        minute_12h = (
            rf"(?::{minute:02d})" if minute else r"(?::00)?"
        )
        return (
            rf"(?:{hour:02d}:{minute:02d}|{hour}:{minute:02d}|"
            rf"0?{display_hour}{minute_12h}\s*{meridiem}\.?(?:\s*)m\.?)"
        )

    @classmethod
    def _selected_meeting_from_adjacent_text(
        cls,
        text: str,
        *,
        meetings: Sequence[Mapping[str, Any]],
    ) -> Mapping[str, Any] | None:
        normalized = _meeting_request_text(text)
        if normalized is None or not cls._meeting_selection_shape(normalized):
            return None
        if re.search(
            r"\b(?:do\s+not|don['\u2019]?t|never|cancel|if|maybe|"
            r"hypothetically|send|email|call|navigate|set|turn)\b",
            normalized,
            re.IGNORECASE,
        ) is not None:
            return None
        prefix = (
            r"\s*(?:(?:okay|ok)\s*[,!]\s*)?(?:"
            r"i(?:['\u2019]m|\s+am)\s+(?:interested\s+in|"
            r"focusing\s+on|looking\s+at)|"
            r"i\s+(?:want|would\s+like)\s+to\s+"
            r"(?:focus\s+on|select|use)|"
            r"(?:please\s+)?(?:focus\s+on|select|use))\s+"
            r"(?:the\s+)?"
        )
        matches: list[Mapping[str, Any]] = []
        for meeting in meetings:
            topic = cls._meeting_literal_pattern(str(meeting["topic"]))
            location = cls._meeting_literal_pattern(str(meeting["location"]))
            time = cls._meeting_selection_time_pattern(meeting)
            details = (
                rf"(?:\s+at\s+{time}(?:\s+in\s+{location})?|"
                rf"\s+in\s+{location}(?:\s+at\s+{time})?)?"
            )
            if re.fullmatch(
                rf"{prefix}{topic}\s+meeting{details}\s*[.!?]*\s*",
                normalized,
                re.IGNORECASE | re.UNICODE,
            ) is not None:
                matches.append(meeting)
        return matches[0] if len(matches) == 1 else None

    def _adjacent_displayed_current_day_calendar(
        self, session: SessionState
    ) -> tuple[Goal, SuccessfulReadResult, tuple[dict[str, Any], ...]] | None:
        current = self._current_datetime_parts(session)
        if current is None or not isinstance(session.intent, IntentFrame):
            return None
        goals = session.intent.goals
        if (
            session.intent.call_for_action
            or len(goals) != 1
            or goals[0].semantic_operation != "get_entries_from_calendar"
            or not goals[0].goal_id.startswith("goal-calendar-")
            or goals[0].desired_outcome.get("month") != current[1]
            or goals[0].desired_outcome.get("day") != current[2]
        ):
            return None
        goal = goals[0]
        try:
            if session.goal_dag.get(goal.goal_id).status is not GoalStatus.DONE:
                return None
        except KeyError:
            return None
        arguments = {"month": current[1], "day": current[2]}
        observations = [
            observation
            for observation in session.successful_read_results
            if observation.goal_ids == (goal.goal_id,)
            and observation.tool_name == "get_entries_from_calendar"
            and observation.state_version == session.evidence.current_state_version
            and _argument_value_matches_binding(observation.arguments, arguments)
        ]
        if len(observations) != 1:
            return None
        observation = observations[0]
        candidate = Evidence(
            proposition=_CURRENT_DAY_MEETING_CALENDAR,
            value=observation.value,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.TOOL,
            source_turn_id=observation.source_turn_id,
            source_tool_call_id=observation.call_id,
            confidence=1.0,
        )
        meetings = self._current_day_meetings_from_evidence(
            candidate, current=current
        )
        if meetings is None:
            return None
        entries = tuple(
            f"{meeting['topic']} at {meeting['start_hour']:02d}:"
            f"{meeting['start_minute']:02d} in {meeting['location']}"
            for meeting in meetings
        )
        expected_summary = self.responses.calendar_summary(
            entries=entries, language=self._language(session)
        )
        if self._latest_assistant_text(session) != expected_summary:
            return None
        return goal, observation, meetings

    def _store_adjacent_selected_current_day_meeting(
        self,
        session: SessionState,
        *,
        goal: Goal,
        observation: SuccessfulReadResult,
        topic: str,
        source_turn_id: str,
    ) -> tuple[Evidence, dict[str, Any]] | None:
        current = self._current_datetime_parts(session)
        if current is None:
            return None
        session.evidence.add(
            Evidence(
                proposition=_CURRENT_DAY_MEETING_CALENDAR,
                value=observation.value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.TOOL,
                source_turn_id=observation.source_turn_id,
                source_tool_call_id=observation.call_id,
                confidence=1.0,
            )
        )
        raw = max(
            (
                evidence
                for evidence in session.evidence.for_proposition(
                    _CURRENT_DAY_MEETING_CALENDAR
                )
                if evidence.state_version == session.evidence.current_state_version
                and evidence.source_tool_call_id == observation.call_id
                and evidence.source_turn_id == observation.source_turn_id
            ),
            key=lambda evidence: evidence.observation_index,
            default=None,
        )
        if raw is None:
            return None
        candidates = self._store_current_day_meeting_candidates(
            session,
            goal=goal,
            raw_evidence=raw,
            current=current,
        )
        if candidates is None:
            return None
        return self._store_selected_current_day_meeting(
            session,
            goal=goal,
            candidates=candidates,
            topic=topic,
            source_turn_id=source_turn_id,
        )

    @staticmethod
    def _contextual_meeting_weather_email_shape(text: str) -> bool:
        normalized = _meeting_request_text(text)
        if normalized is None:
            return False
        email_matches = list(
            _DIRECT_ATTENDEE_WEATHER_EMAIL_RE.finditer(normalized)
        )
        if len(email_matches) != 1:
            return False
        folded = normalized.casefold()
        if (
            "meeting" not in folded
            or re.search(r"\b(?:weather|forecast)\b", folded) is None
            or re.search(r"\b(?:travel|traffic|arrival|trip|impact|delay)\w*\b", folded)
            is None
            or re.search(
                r"\b(?:check|look\s+up)\b[^.!?]{0,160}"
                r"\b(?:weather|forecast)\b",
                normalized,
                re.IGNORECASE,
            )
            is None
        ):
            return False
        match = email_matches[0]
        prefix = normalized[: match.start()]
        tail = normalized[match.end() :]
        deictic = re.search(
            r"\b(?:that|the|its|scheduled)\s+time\b|"
            r"\b(?:the\s+)?(?:specific|meeting)\s+time\b|"
            r"\b(?:there|(?:that|the|its|scheduled)\s+location|"
            r"(?:the\s+)?(?:specific|meeting)\s+location)\b|"
            r"\b(?:(?:the|that|this)\s+)?(?:same|selected)\s+meeting\b",
            normalized,
            re.IGNORECASE,
        )
        meeting_first = prefix.casefold().find("meeting") < prefix.casefold().find(
            "weather"
        )
        topic_omitted_after_email = re.match(
            r"\s+of\s+(?:my|the|our)\s+.+?\s+meeting\b",
            tail,
            re.IGNORECASE | re.UNICODE,
        ) is None
        return deictic is not None or meeting_first or topic_omitted_after_email

    @staticmethod
    def _explicit_meeting_time_references(
        text: str,
    ) -> tuple[tuple[int, int], ...] | None:
        normalized = unicodedata.normalize("NFKC", text)
        references: list[tuple[int, int]] = []
        masked = list(normalized)
        twelve_hour = re.compile(
            r"(?<![\w\d])(?P<hour>0?[1-9]|1[0-2])"
            r"(?::(?P<minute>[0-5]\d))?\s*"
            r"(?P<meridiem>a\.?\s*m\.?|p\.?\s*m\.?)(?!\w)",
            re.IGNORECASE | re.UNICODE,
        )
        for match in twelve_hour.finditer(normalized):
            hour = int(match.group("hour"))
            minute = int(match.group("minute") or "0")
            meridiem = re.sub(r"[.\s]", "", match.group("meridiem").casefold())
            if meridiem == "pm" and hour != 12:
                hour += 12
            elif meridiem == "am" and hour == 12:
                hour = 0
            references.append((hour, minute))
            masked[match.start() : match.end()] = " " * (match.end() - match.start())
        remaining = "".join(masked)
        twenty_four_hour = re.compile(
            r"(?<![\w\d])(?P<hour>[01]?\d|2[0-3]):"
            r"(?P<minute>[0-5]\d)(?!\s*(?:a\.?\s*m\.?|p\.?\s*m\.?))(?!\w)",
            re.IGNORECASE | re.UNICODE,
        )
        for match in twenty_four_hour.finditer(remaining):
            references.append(
                (int(match.group("hour")), int(match.group("minute")))
            )
            masked[match.start() : match.end()] = " " * (match.end() - match.start())
        leftover = "".join(masked)
        if re.search(
            r"(?<![\w\d])\d{1,2}(?::\d{2})?\s*"
            r"(?:a\.?\s*m\.?|p\.?\s*m\.?)(?!\w)",
            leftover,
            re.IGNORECASE | re.UNICODE,
        ) is not None:
            return None
        return tuple(dict.fromkeys(references))

    @classmethod
    def _contextual_meeting_weather_prefix_matches(
        cls,
        prefix: str,
        *,
        meeting: Mapping[str, Any],
    ) -> bool:
        topic = cls._meeting_literal_pattern(str(meeting["topic"]))
        location = cls._meeting_literal_pattern(str(meeting["location"]))
        time = (
            rf"(?:{cls._meeting_selection_time_pattern(meeting)}|"
            r"(?:that|the|its|scheduled)\s+time|"
            r"(?:the\s+)?(?:specific|meeting)\s+time|"
            r"the\s+meeting\s+start\s+time)"
        )
        location_reference = (
            rf"(?:{location}|there|(?:that|the|its|scheduled)\s+location|"
            r"(?:the\s+)?(?:specific|meeting)\s+location)"
        )
        same_meeting = (
            r"(?:(?:the|that|this)\s+)?(?:same|selected)\s+meeting"
        )
        time_location_scope = (
            rf"(?:{time}\s*(?:,?\s*and\s+(?:(?:at|in)\s+)?|"
            rf"(?:at|in)\s+)(?:{location_reference}|location)|"
            rf"{location_reference}\s*(?:,?\s*and\s+(?:at\s+)?|at\s+)"
            rf"(?:{time}|time))"
            rf"(?:\s+(?:of|for)\s+{same_meeting})?"
        )
        discourse = r"(?:(?:okay|ok|please)\s*[,!]\s*)?"
        request = (
            r"(?:(?:can|could|would|will)\s+you\s+(?:please\s+)?|"
            r"please\s+)?"
        )
        check = r"(?:check|look\s+up)\s+(?:on\s+)?(?:the\s+)?(?:weather|forecast)"
        delivery_request = (
            r"(?:(?:can|could|would|will)\s+you\s+(?:please\s+)?|"
            r"i(?:['\u2019]d|\s+would)\s+like\s+to\s+|please\s+)?"
        )
        named_meeting = (
            rf"(?:the|my|our)\s+{topic}\s+meeting"
            rf"(?:\s+in\s+{location})?(?:\s+at\s+{time})?"
        )
        location_scope = rf"{location}(?:\s+at\s+{time})?"
        weather_first = (
            rf"{discourse}{request}{check}\s+(?:for|in)\s+"
            rf"(?:{named_meeting}|{location_scope}|{time_location_scope})"
            r"(?:\s*,?\s*(?:and\s+then|then|and)|"
            r"\s*[.!?]\s*(?:and\s+then|then|after\s+that))"
            rf"\s*,?\s*{delivery_request}"
        )
        meeting_first = (
            rf"{discourse}for\s+(?:the|my|our)\s+{topic}\s+meeting"
            rf"(?:\s+in\s+{location})?(?:\s+at\s+{time})?\s*,?\s*"
            rf"{request}{check}(?:\s+(?:for|at|in)\s+{time_location_scope})?"
            r"\s*[.!?]\s*(?:after\s+that|then)\s*[,]?\s*"
            rf"{delivery_request}"
        )
        return any(
            re.fullmatch(pattern, prefix, re.IGNORECASE | re.UNICODE) is not None
            for pattern in (weather_first, meeting_first)
        )

    @classmethod
    def _contextual_meeting_weather_email_matches(
        cls,
        text: str,
        *,
        meeting: Mapping[str, Any],
        candidates: Sequence[Mapping[str, Any]],
    ) -> bool:
        normalized = _meeting_request_text(text)
        if normalized is None or not cls._contextual_meeting_weather_email_shape(text):
            return False
        recipient_guard_text = re.sub(
            r"\b(?:the\s+)?(?:specific|meeting)\s+(?:"
            r"time\s+and\s+(?:(?:the\s+)?(?:specific|meeting)\s+)?location|"
            r"location\s+and\s+(?:(?:the\s+)?(?:specific|meeting)\s+)?time)\b",
            " ",
            normalized,
            flags=re.IGNORECASE,
        )
        if (
            re.search(
                r"\b(?:do\s+not|don['\u2019]?t|never|no\s+need\s+to|"
                r"hypothetically|pretend|quoted|said|told)\b",
                normalized,
                re.IGNORECASE,
            )
            is not None
            or _SELF_DIRECTED_MEETING_REMINDER_RE.search(normalized) is not None
            or _DIRECT_ADDITIONAL_ATTENDEE_RECIPIENT_RE.search(normalized) is not None
            or _WEATHER_EMAIL_EXTRA_ACTION_RE.search(normalized) is not None
            or _WEATHER_EMAIL_FOLLOWUP_ACTION_RE.search(normalized) is not None
            or _WEATHER_EMAIL_COPY_OR_ADDRESS_RE.search(normalized) is not None
            or _WEATHER_EMAIL_INCLUDE_RECIPIENT_RE.search(normalized) is not None
            or _WEATHER_EMAIL_ADDED_NAMED_RECIPIENT_RE.search(recipient_guard_text)
            is not None
        ):
            return False
        email_matches = list(
            _DIRECT_ATTENDEE_WEATHER_EMAIL_RE.finditer(normalized)
        )
        if len(email_matches) != 1:
            return False
        email_match = email_matches[0]
        if not cls._contextual_meeting_weather_prefix_matches(
            normalized[: email_match.start()], meeting=meeting
        ):
            return False
        masked_delivery = (
            normalized[: email_match.start()]
            + " " * (email_match.end() - email_match.start())
            + normalized[email_match.end() :]
        )
        if re.search(
            r"\b(?:call|email|message|notify|phone|send|text)\b",
            masked_delivery,
            re.IGNORECASE,
        ) is not None:
            return False
        content = normalized[email_match.end() :].strip()
        named_tail = re.match(
            r"(?:of\s+(?:my|the|our)\s+"
            r"[^'\u2018\u2019\u201c\u201d\".!?]{1,120}?\s+meeting|"
            r"of\s+(?:(?:the|that|this)\s+)?(?:same|selected)\s+meeting)\b",
            content,
            re.IGNORECASE | re.UNICODE,
        )
        if named_tail is not None:
            content = content[named_tail.end() :].strip()
        polite_content = re.match(
            r",?\s*please\s*,?\s*", content, re.IGNORECASE | re.UNICODE
        )
        if polite_content is not None:
            content = content[polite_content.end() :].strip()
        if (
            not content
            or re.fullmatch(r"[A-Za-z'\u2019.,!? -]{1,320}", content) is None
            or re.match(
                r"(?:about|because|regarding|with|informing\s+them\s+about|"
                r"to\s+inform\s+them\s+about)\b",
                content,
                re.IGNORECASE,
            )
            is None
        ):
            return False
        words = re.findall(r"[A-Za-z]+", content.casefold())
        if (
            not words
            or any(word not in _WEATHER_EMAIL_APPROVED_CONTENT_WORDS for word in words)
            or not {"weather", "forecast"}.intersection(words)
            or not {"travel", "traffic", "arrival", "arrivals", "trip"}.intersection(
                words
            )
            or not {"affect", "affects", "impact", "impacts", "delay", "delays"}.intersection(
                words
            )
            or "meeting" not in words
        ):
            return False
        topic_word = r"[^\W_][\w'\u2019-]*"
        named_topics = [
            match.group("topic")
            for match in re.finditer(
                rf"\b(?:for|of)\s+(?:the|my|our)\s+"
                rf"(?P<topic>{topic_word}(?:\s+{topic_word}){{0,5}})\s+meeting\b",
                normalized,
                re.IGNORECASE | re.UNICODE,
            )
            if _argument_identifier(match.group("topic"))
            not in {"same", "selected"}
        ]
        selected_topic = _argument_identifier(str(meeting["topic"]))
        if any(_argument_identifier(topic) != selected_topic for topic in named_topics):
            return False
        mentioned_topics = {
            _argument_identifier(str(candidate["topic"]))
            for candidate in candidates
            if _contains_option_phrase(normalized, str(candidate["topic"]))
        }
        if mentioned_topics and mentioned_topics != {selected_topic}:
            return False
        selected_location = _argument_identifier(str(meeting["location"]))
        mentioned_locations = {
            _argument_identifier(str(candidate["location"]))
            for candidate in candidates
            if _contains_option_phrase(normalized, str(candidate["location"]))
        }
        if mentioned_locations:
            if mentioned_locations != {selected_location}:
                return False
        elif re.search(
            r"\b(?:there|(?:that|the|its|scheduled)\s+location|"
            r"(?:the\s+)?(?:specific|meeting)\s+location)\b|"
            r"\b(?:the\s+)?(?:specific|meeting)\s+time\s+and\s+"
            r"(?:(?:the\s+)?(?:specific|meeting)\s+)?location\b",
            normalized,
            re.IGNORECASE,
        ) is None:
            return False
        explicit_times = cls._explicit_meeting_time_references(normalized)
        expected_time = (
            int(meeting["start_hour"]),
            int(meeting["start_minute"]),
        )
        if explicit_times is None:
            return False
        if explicit_times:
            if any(reference != expected_time for reference in explicit_times):
                return False
        elif re.search(
            r"\b(?:that|the|its|scheduled)\s+time\b|"
            r"\b(?:the\s+)?(?:specific|meeting)\s+time\b|"
            r"\b(?:the\s+)?(?:specific|meeting)\s+location\s+and\s+"
            r"(?:(?:the\s+)?(?:specific|meeting)\s+)?time\b|"
            r"\bthe\s+meeting\s+start\s+time\b",
            normalized,
            re.IGNORECASE,
        ) is None:
            return False
        return True

    @staticmethod
    def _meeting_status_text(
        meeting: Mapping[str, Any],
        *,
        current_hour: int,
        current_minute: int,
        query_kind: str,
    ) -> str:
        start = meeting["start_hour"] * 60 + meeting["start_minute"]
        end = start + meeting["duration_minutes"]
        now = current_hour * 60 + current_minute
        start_text = f"{meeting['start_hour']:02d}:{meeting['start_minute']:02d}"
        if query_kind == "start":
            return (
                f"I found that the {meeting['topic']} meeting starts at {start_text} today "
                f"in {meeting['location']}."
            )
        if now < start:
            status = f"has not started yet and starts at {start_text}"
        elif now < end:
            status = f"started at {start_text} and is currently in progress"
        else:
            status = f"started at {start_text} and has already ended"
        return (
            f"I found that the {meeting['topic']} meeting {status}. It is scheduled for "
            f"{meeting['duration_minutes']} minutes in {meeting['location']}."
        )

    @staticmethod
    def _meeting_email_unavailable_plan(
        session: SessionState,
        text_plan: Callable[..., PlannedOutbound],
    ) -> PlannedOutbound:
        return text_plan(
            session,
            "I cannot send that meeting email because the current email, calendar, "
            "or contact capability is unavailable, so I did not prepare or send "
            "an email.",
        )

    @staticmethod
    def _meeting_weather_email_unavailable_plan(
        session: SessionState,
        text_plan: Callable[..., PlannedOutbound],
        *,
        missing_capabilities: tuple[str, ...],
    ) -> PlannedOutbound:
        if len(missing_capabilities) == 1:
            unavailable = (
                f"the current {missing_capabilities[0]} capability is unavailable"
            )
        else:
            names = ", ".join(missing_capabilities[:-1])
            unavailable = (
                f"the current {names}, and {missing_capabilities[-1]} capabilities "
                "are unavailable"
            )
        return text_plan(
            session,
            "I cannot complete that meeting weather email because "
            f"{unavailable}. Therefore, I did not read any calendar, contact, "
            "location, or weather data, and I did not prepare or send an email.",
        )

    def _cancel_current_day_meeting_workflow(
        self,
        session: SessionState,
        goal: Goal,
        *,
        source_turn_id: str,
    ) -> PlannedOutbound:
        session.confirmation_latch.cancel_all(
            current_user_turn=session.budget.user_turns,
            source_turn_id=source_turn_id,
            user_response="meeting_workflow_cancelled",
        )
        session.authorized_action_goal_ids.discard(goal.goal_id)
        session.grounded_desired_values_by_goal.pop(goal.goal_id, None)
        session.grounded_value_sources_by_goal.pop(goal.goal_id, None)
        session.derived_value_evidence_by_goal.pop(goal.goal_id, None)
        session.pending_clarifications = {
            key: request
            for key, request in session.pending_clarifications.items()
            if getattr(request, "goal_id", None) != goal.goal_id
        }
        session.execution_bundle = None
        self._fail_goals(
            session,
            (goal.goal_id,),
            "the user cancelled the meeting email workflow",
        )
        session.intent = None
        return self._text_plan(
            session,
            "Okay. I cancelled the meeting email request and will not send it.",
        )

    def _handle_current_day_meeting_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        active = self._current_day_meeting_goal(session)
        if (
            active is not None
            and active.desired_outcome.get(_CURRENT_DAY_MEETING_PHASE)
            == _CURRENT_DAY_MEETING_SELECT
        ):
            if _MEETING_WORKFLOW_CANCEL_RE.fullmatch(text) is not None:
                return True, self._cancel_current_day_meeting_workflow(
                    session, active, source_turn_id=turn_id
                )
            candidates = self._validated_current_day_meeting_candidates(session)
            if candidates is None:
                return True, self._limitation_plan(
                    session, active, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            prompt = self._meeting_candidate_prompt(candidates[1]["meetings"])
            if self._latest_assistant_text(session) != prompt:
                return True, self._text_plan(
                    session,
                    "The displayed meeting choices are no longer fresh, so I did not prepare an email.",
                )
            normalized = unicodedata.normalize("NFKC", text).strip()
            if _meeting_request_text(normalized) is None:
                return True, self._text_plan(
                    session,
                    "I could not match one exact current-day meeting, so I did "
                    "not start another action.",
                )
            selection = re.sub(
                r"\s*[.!?]+\s*$", "", normalized, flags=re.UNICODE
            )
            selection = re.sub(
                r"^\s*(?:i\s+mean\s+)?(?:the\s+)?", "", selection, flags=re.I
            )
            selection = re.sub(r"\s+meeting\s*$", "", selection, flags=re.I)
            matches = [
                meeting
                for meeting in candidates[1]["meetings"]
                if _argument_identifier(meeting["topic"])
                == _argument_identifier(selection)
            ]
            if len(matches) != 1:
                return True, self._text_plan(
                    session, "Please choose one exact currently displayed meeting."
                )
            updated = self._update_current_day_meeting_goal(
                session,
                active,
                updates={
                    "meeting_topic": matches[0]["topic"],
                    _CURRENT_DAY_MEETING_PHASE: _CURRENT_DAY_MEETING_READ_CONTACTS,
                },
            )
            grounded = session.grounded_desired_values_by_goal.setdefault(
                active.goal_id, {}
            )
            grounded["meeting_topic"] = matches[0]["topic"]
            session.grounded_value_sources_by_goal.setdefault(active.goal_id, {})[
                "meeting_topic"
            ] = turn_id
            if self._store_selected_current_day_meeting(
                session,
                goal=updated,
                candidates=candidates,
                topic=matches[0]["topic"],
            ) is None:
                return True, self._limitation_plan(
                    session, updated, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return True, None

        if (
            active is not None
            and active.desired_outcome.get(_CURRENT_DAY_MEETING_PHASE)
            == _CURRENT_DAY_MEETING_COLLECT_CONTENT
        ):
            if _MEETING_WORKFLOW_CANCEL_RE.fullmatch(text) is not None:
                return True, self._cancel_current_day_meeting_workflow(
                    session, active, source_turn_id=turn_id
                )
            selected_for_content = self._validated_selected_current_day_meeting(
                session
            )
            recipients = self._validated_current_day_meeting_recipients(session)
            if selected_for_content is None or recipients is None:
                return True, self._limitation_plan(
                    session, active, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            meeting = selected_for_content[1]["meeting"]
            prompt = self._meeting_email_content_prompt(meeting)
            if self._latest_assistant_text(session) != prompt:
                return True, self._text_plan(
                    session,
                    "The verified meeting-email context is no longer fresh, so I did not prepare or send an email.",
                    goal_ids=[active.goal_id],
                )
            instruction = self._store_current_day_meeting_content_instruction(
                session,
                goal=active,
                text=text,
                source_turn_id=turn_id,
                meeting=meeting,
            )
            if instruction is None:
                return True, self._text_plan(
                    session,
                    "Please provide a friendly reminder instruction that matches "
                    "the verified meeting time and location.",
                    goal_ids=[active.goal_id],
                )
            self._update_current_day_meeting_goal(
                session,
                active,
                updates={
                    _CURRENT_DAY_MEETING_PHASE: _CURRENT_DAY_MEETING_SEND,
                    "message_style": "friendly_reminder",
                    "message_instruction": instruction.value,
                },
            )
            grounded = session.grounded_desired_values_by_goal.setdefault(
                active.goal_id, {}
            )
            grounded.update(
                message_style="friendly_reminder",
                message_instruction=instruction.value,
            )
            sources = session.grounded_value_sources_by_goal.setdefault(
                active.goal_id, {}
            )
            sources.update(
                message_style=turn_id,
                message_instruction=turn_id,
            )
            return True, None

        displayed_calendar = self._adjacent_displayed_current_day_calendar(session)
        if self._meeting_selection_shape(text):
            if displayed_calendar is None:
                return True, self._text_plan(
                    session,
                    "I could not match that selection to the immediately displayed "
                    "current-day calendar, so I did not start another action.",
                )
            calendar_goal, calendar_observation, meetings = displayed_calendar
            selected_meeting = self._selected_meeting_from_adjacent_text(
                text, meetings=meetings
            )
            if selected_meeting is None:
                return True, self._text_plan(
                    session, "Please choose one exact currently displayed meeting."
                )
            stored = self._store_adjacent_selected_current_day_meeting(
                session,
                goal=calendar_goal,
                observation=calendar_observation,
                topic=str(selected_meeting["topic"]),
                source_turn_id=turn_id,
            )
            if stored is None or stored[1]["meeting"] != selected_meeting:
                return True, self._text_plan(
                    session,
                    "I could not preserve one exact current-day meeting selection, "
                    "so I did not start another action.",
                )
            return True, self._text_plan(
                session, self._meeting_selection_ack(stored[1]["meeting"])
            )

        selected = self._validated_selected_current_day_meeting(session)
        late_followup = _named_late_email_followup(text)
        if late_followup is not None and selected is not None:
            safe, first_name, last_name = late_followup
            if (
                not safe
                or first_name is None
                or last_name is None
                or not self._safe_contact_name(first_name)
                or not self._safe_contact_name(last_name)
            ):
                return True, self._text_plan(
                    session, "Okay. I did not prepare or send a meeting email."
                )
            if not self._meeting_email_schema_available(
                session, named_contact=(first_name, last_name)
            ):
                return True, self._meeting_email_unavailable_plan(
                    session, self._text_plan
                )
            self._begin_current_day_meeting_goal(
                session,
                turn_id=turn_id,
                mode=_CURRENT_DAY_MEETING_NAMED_EMAIL,
                phase=_CURRENT_DAY_MEETING_LOOKUP_CONTACT,
                topic=selected[1]["meeting"]["topic"],
                contact_name=(first_name, last_name),
            )
            return True, None

        conditional = _conditional_named_meeting_email_request(text)
        if conditional is not None:
            safe, topic, first_name, last_name = conditional
            if (
                not safe
                or topic is None
                or first_name is None
                or last_name is None
                or not self._safe_contact_name(first_name)
                or not self._safe_contact_name(last_name)
            ):
                return True, self._text_plan(
                    session, "Okay. I did not read contacts or prepare a meeting email."
                )
            if not self._meeting_email_schema_available(
                session, named_contact=(first_name, last_name)
            ):
                return True, self._meeting_email_unavailable_plan(
                    session, self._text_plan
                )
            self._begin_current_day_meeting_goal(
                session,
                turn_id=turn_id,
                mode=_CURRENT_DAY_MEETING_NAMED_EMAIL,
                phase=_CURRENT_DAY_MEETING_READ_CALENDAR,
                topic=topic,
                contact_name=(first_name, last_name),
            )
            return True, None

        weather_email = _attendee_meeting_weather_email_request(text)
        if weather_email is not None:
            safe, topic, request_text = weather_email
            if not safe or topic is None or request_text is None:
                return True, self._text_plan(
                    session,
                    "Okay. I did not read the meeting weather or prepare an email.",
                )
            syntax = _approved_weather_email_syntax(request_text)
            if syntax is None or _argument_identifier(syntax[0]) != _argument_identifier(
                topic
            ):
                return False, None
            missing_capabilities = self._meeting_weather_email_missing_capabilities(
                session
            )
            if missing_capabilities:
                return True, self._meeting_weather_email_unavailable_plan(
                    session,
                    self._text_plan,
                    missing_capabilities=missing_capabilities,
                )
            if self._current_datetime_parts(session) is None:
                return True, self._text_plan(
                    session,
                    "I cannot complete that meeting weather email because the "
                    "current date and time context is unavailable. Therefore, I "
                    "did not read any calendar, contact, location, or weather data, "
                    "and I did not prepare or send an email.",
                )
            self._begin_current_day_meeting_goal(
                session,
                turn_id=turn_id,
                mode=_CURRENT_DAY_MEETING_WEATHER_EMAIL,
                phase=_CURRENT_DAY_MEETING_READ_CALENDAR,
                topic=topic,
                request_text=request_text,
                request_location=syntax[1],
            )
            return True, None

        if self._contextual_meeting_weather_email_shape(text):
            candidates = self._validated_current_day_meeting_candidates(session)
            if selected is None or candidates is None:
                return True, self._text_plan(
                    session,
                    "I could not bind that weather email to the immediately selected "
                    "meeting, so I did not read contacts or weather and did not "
                    "prepare or send an email.",
                )
            meeting = selected[1]["meeting"]
            expected_ack = self._meeting_selection_ack(meeting)
            if (
                self._latest_assistant_text(session) != expected_ack
                or not self._contextual_meeting_weather_email_matches(
                    text,
                    meeting=meeting,
                    candidates=candidates[1]["meetings"],
                )
            ):
                return True, self._text_plan(
                    session,
                    "I could not bind that weather email to the immediately selected "
                    "meeting, so I did not read contacts or weather and did not "
                    "prepare or send an email.",
                )
            missing_capabilities = self._meeting_weather_email_missing_capabilities(
                session
            )
            if missing_capabilities:
                return True, self._meeting_weather_email_unavailable_plan(
                    session,
                    self._text_plan,
                    missing_capabilities=missing_capabilities,
                )
            if self._current_datetime_parts(session) is None:
                return True, self._text_plan(
                    session,
                    "I cannot complete that meeting weather email because the "
                    "current date and time context is unavailable. Therefore, I "
                    "did not read any calendar, contact, location, or weather data, "
                    "and I did not prepare or send an email.",
                )
            self._begin_current_day_meeting_goal(
                session,
                turn_id=turn_id,
                mode=_CURRENT_DAY_MEETING_WEATHER_EMAIL,
                phase=_CURRENT_DAY_MEETING_READ_CALENDAR,
                topic=str(meeting["topic"]),
                request_text=text,
                request_location=str(meeting["location"]),
                contextual_weather=True,
                prior_source_turn_id=selected[0].source_turn_id,
            )
            return True, None

        attendee = _attendee_meeting_email_request(text)
        if attendee is not None:
            safe, topic = attendee
            if not safe:
                return True, self._text_plan(
                    session, "Okay. I did not read the calendar or prepare an email."
                )
            if not self._meeting_email_schema_available(
                session, named_contact=None
            ):
                return True, self._meeting_email_unavailable_plan(
                    session, self._text_plan
                )
            self._begin_current_day_meeting_goal(
                session,
                turn_id=turn_id,
                mode=_CURRENT_DAY_MEETING_ATTENDEE_EMAIL,
                phase=_CURRENT_DAY_MEETING_READ_CALENDAR,
                topic=topic,
            )
            return True, None

        status_request = _named_meeting_status_request(text)
        if status_request is None:
            return False, None
        topic, query_kind = status_request
        if selected is not None:
            meeting = selected[1]["meeting"]
            if _argument_identifier(meeting["topic"]) == _argument_identifier(topic):
                current = self._current_datetime_parts(session)
                if current is None:
                    return True, self._text_plan(
                        session,
                        "I cannot verify the current time, so I cannot determine the meeting status.",
                    )
                return True, self._text_plan(
                    session,
                    self._meeting_status_text(
                        meeting,
                        current_hour=current[3],
                        current_minute=current[4],
                        query_kind=query_kind,
                    ),
                )
        if not self._calendar_schema_available(session):
            return True, self._text_plan(
                session,
                "I cannot check the current meeting because the calendar capability is unavailable.",
            )
        self._begin_current_day_meeting_goal(
            session,
            turn_id=turn_id,
            mode=_CURRENT_DAY_MEETING_STATUS,
            phase=_CURRENT_DAY_MEETING_READ_CALENDAR,
            topic=topic,
            query_kind=query_kind,
        )
        return True, None

    @classmethod
    def _current_day_meetings_from_evidence(
        cls,
        evidence: Evidence,
        *,
        current: tuple[int, int, int, int, int],
    ) -> tuple[dict[str, Any], ...] | None:
        if (
            evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.TOOL
            or not isinstance(evidence.value, Mapping)
            or set(evidence.value) != {"date", "meetings"}
        ):
            return None
        date = evidence.value.get("date")
        meetings = evidence.value.get("meetings")
        if (
            not isinstance(date, Mapping)
            or set(date) != {"year", "month", "day"}
            or tuple(date.get(key) for key in ("year", "month", "day"))
            != current[:3]
            or not isinstance(meetings, list)
            or not 1 <= len(meetings) <= 20
        ):
            return None
        parsed: list[dict[str, Any]] = []
        for meeting in meetings:
            if (
                not isinstance(meeting, Mapping)
                or set(meeting)
                != {"start", "duration", "location", "attendees", "topic"}
            ):
                return None
            start = meeting.get("start")
            topic = meeting.get("topic")
            duration = meeting.get("duration")
            location = meeting.get("location")
            attendee_ids = meeting.get("attendees")
            if not isinstance(start, Mapping) or set(start) != {"hour", "minute"}:
                return None
            hour_raw = start.get("hour")
            minute_raw = start.get("minute")
            if (
                isinstance(hour_raw, str)
                and re.fullmatch(r"\d{1,2}", hour_raw) is not None
            ):
                hour = int(hour_raw)
            elif type(hour_raw) is int:
                hour = hour_raw
            else:
                return None
            if (
                isinstance(minute_raw, str)
                and re.fullmatch(r"\d{1,2}", minute_raw) is not None
            ):
                minute = int(minute_raw)
            elif type(minute_raw) is int:
                minute = minute_raw
            else:
                return None
            if isinstance(duration, str):
                duration_match = re.fullmatch(r"(?P<minutes>\d{1,4})min", duration)
                duration_minutes = (
                    int(duration_match.group("minutes"))
                    if duration_match is not None
                    else 0
                )
            elif type(duration) is int:
                duration_minutes = duration
            else:
                return None
            if (
                not 0 <= hour <= 23
                or not 0 <= minute <= 59
                or not 1 <= duration_minutes <= 1440
                or not isinstance(topic, str)
                or not cls._voice_result_field(topic.strip(), 120)
                or TTSGuard(max_characters=120).violations(topic.strip())
                or not isinstance(location, str)
                or not cls._safe_poi_display_label(location, 120)
                or not isinstance(attendee_ids, list)
                or len(attendee_ids) > 20
                or len(set(attendee_ids)) != len(attendee_ids)
                or any(
                    not isinstance(contact_id, str)
                    or _CONTACT_ID_PATTERN.fullmatch(contact_id) is None
                    for contact_id in attendee_ids
                )
            ):
                return None
            parsed.append(
                {
                    "topic": topic.strip(),
                    "start_hour": hour,
                    "start_minute": minute,
                    "duration_minutes": duration_minutes,
                    "location": location.strip(),
                    "attendee_ids": list(attendee_ids),
                }
            )
        return tuple(parsed)

    def _store_current_day_meeting_candidates(
        self,
        session: SessionState,
        *,
        goal: Goal,
        raw_evidence: Evidence,
        current: tuple[int, int, int, int, int],
    ) -> tuple[Evidence, dict[str, Any]] | None:
        meetings = self._current_day_meetings_from_evidence(
            raw_evidence, current=current
        )
        if meetings is None or raw_evidence.evidence_id is None:
            return None
        value = {
            "date": {"year": current[0], "month": current[1], "day": current[2]},
            "meetings": list(meetings),
        }
        session.evidence.add(
            Evidence(
                proposition=_CURRENT_DAY_MEETING_CANDIDATES,
                value=value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"meeting-candidates-{goal.goal_id}",
                confidence=raw_evidence.confidence,
                derived_from=[raw_evidence.evidence_id],
                derivation="strict_current_day_meeting_candidates_v1",
            )
        )
        return self._validated_current_day_meeting_candidates(session)

    def _validated_current_day_meeting_candidates_evidence(
        self, session: SessionState, summary: Evidence
    ) -> tuple[Evidence, dict[str, Any]] | None:
        current = self._current_datetime_parts(session)
        if (
            current is None
            or summary.status is not EvidenceStatus.KNOWN
            or summary.state_version != session.evidence.current_state_version
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.derivation != "strict_current_day_meeting_candidates_v1"
            or len(summary.derived_from) != 1
            or not isinstance(summary.value, Mapping)
        ):
            return None
        raw = session.evidence.evidence.get(summary.derived_from[0])
        meetings = (
            self._current_day_meetings_from_evidence(raw, current=current)
            if raw is not None
            and raw.state_version == session.evidence.current_state_version
            else None
        )
        expected = {
            "date": {"year": current[0], "month": current[1], "day": current[2]},
            "meetings": list(meetings or ()),
        }
        if meetings is None or summary.value != expected:
            return None
        return summary, expected

    def _validated_current_day_meeting_candidates(
        self, session: SessionState
    ) -> tuple[Evidence, dict[str, Any]] | None:
        evidence = self._latest_current_evidence(
            session, _CURRENT_DAY_MEETING_CANDIDATES
        )
        return (
            self._validated_current_day_meeting_candidates_evidence(session, evidence)
            if evidence is not None
            else None
        )

    def _store_selected_current_day_meeting(
        self,
        session: SessionState,
        *,
        goal: Goal,
        candidates: tuple[Evidence, dict[str, Any]],
        topic: str,
        source_turn_id: str | None = None,
    ) -> tuple[Evidence, dict[str, Any]] | None:
        matches = [
            meeting
            for meeting in candidates[1]["meetings"]
            if _argument_identifier(meeting["topic"]) == _argument_identifier(topic)
        ]
        if len(matches) != 1 or candidates[0].evidence_id is None:
            return None
        value = {
            "date": dict(candidates[1]["date"]),
            "meeting": dict(matches[0]),
        }
        session.evidence.add(
            Evidence(
                proposition=_SELECTED_CURRENT_DAY_MEETING,
                value=value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=(
                    source_turn_id or f"selected-meeting-{goal.goal_id}"
                ),
                confidence=candidates[0].confidence,
                derived_from=[candidates[0].evidence_id],
                derivation="unique_current_day_named_meeting_v1",
            )
        )
        return self._validated_selected_current_day_meeting(session)

    def _validated_selected_current_day_meeting_evidence(
        self, session: SessionState, selected: Evidence
    ) -> tuple[Evidence, dict[str, Any]] | None:
        if (
            selected.status is not EvidenceStatus.KNOWN
            or selected.state_version != session.evidence.current_state_version
            or selected.source_kind is not EvidenceSourceKind.DERIVED
            or selected.derivation != "unique_current_day_named_meeting_v1"
            or len(selected.derived_from) != 1
            or not isinstance(selected.value, Mapping)
        ):
            return None
        parent = session.evidence.evidence.get(selected.derived_from[0])
        candidates = (
            self._validated_current_day_meeting_candidates_evidence(session, parent)
            if parent is not None
            else None
        )
        meeting = selected.value.get("meeting")
        if candidates is None or not isinstance(meeting, Mapping):
            return None
        exact = [
            candidate
            for candidate in candidates[1]["meetings"]
            if candidate == meeting
        ]
        expected = {
            "date": dict(candidates[1]["date"]),
            "meeting": dict(meeting),
        }
        if len(exact) != 1 or selected.value != expected:
            return None
        return selected, expected

    def _validated_selected_current_day_meeting(
        self, session: SessionState
    ) -> tuple[Evidence, dict[str, Any]] | None:
        evidence = self._latest_current_evidence(
            session, _SELECTED_CURRENT_DAY_MEETING
        )
        return (
            self._validated_selected_current_day_meeting_evidence(session, evidence)
            if evidence is not None
            else None
        )

    @classmethod
    def _meeting_contact_records_from_evidence(
        cls,
        evidence: Evidence,
        *,
        expected_ids: Sequence[str],
        expected_name: tuple[str, str] | None = None,
    ) -> tuple[dict[str, str], ...] | None:
        if (
            evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.TOOL
            or not isinstance(evidence.value, Mapping)
            or not expected_ids
            or len(set(expected_ids)) != len(expected_ids)
            or set(evidence.value) != set(expected_ids)
        ):
            return None
        records: list[dict[str, str]] = []
        for contact_id in expected_ids:
            raw = evidence.value.get(contact_id)
            if not isinstance(raw, Mapping) or raw.get("id") != contact_id:
                return None
            name = raw.get("name")
            email = raw.get("email")
            if (
                not isinstance(name, Mapping)
                or set(name) != {"first_name", "last_name"}
                or not isinstance(name.get("first_name"), str)
                or not isinstance(name.get("last_name"), str)
                or not cls._safe_contact_name(name["first_name"])
                or not cls._safe_contact_name(name["last_name"])
                or not isinstance(email, str)
                or email != email.strip()
                or len(email) > 254
                or _CONTACT_EMAIL_PATTERN.fullmatch(email) is None
            ):
                return None
            if expected_name is not None and (
                _argument_identifier(name["first_name"])
                != _argument_identifier(expected_name[0])
                or _argument_identifier(name["last_name"])
                != _argument_identifier(expected_name[1])
            ):
                return None
            records.append(
                {
                    "contact_id": contact_id,
                    "first_name": name["first_name"],
                    "last_name": name["last_name"],
                    "display_name": f"{name['first_name']} {name['last_name']}",
                    "email": email,
                }
            )
        if len({record["email"].casefold() for record in records}) != len(records):
            return None
        return tuple(records)

    def _store_current_day_meeting_recipients(
        self,
        session: SessionState,
        *,
        goal: Goal,
        selected: tuple[Evidence, dict[str, Any]],
        information: Evidence,
        lookup: Evidence | None,
    ) -> tuple[Evidence, dict[str, Any]] | None:
        mode = goal.desired_outcome.get(_CURRENT_DAY_MEETING_MODE)
        meeting = selected[1]["meeting"]
        expected_name: tuple[str, str] | None = None
        if mode in {
            _CURRENT_DAY_MEETING_ATTENDEE_EMAIL,
            _CURRENT_DAY_MEETING_WEATHER_EMAIL,
        }:
            expected_ids = meeting["attendee_ids"]
            parents = [selected[0], information]
            derivation = "verified_meeting_attendee_recipients_v1"
        elif mode == _CURRENT_DAY_MEETING_NAMED_EMAIL:
            first_name = goal.desired_outcome.get("contact_first_name")
            last_name = goal.desired_outcome.get("contact_last_name")
            if (
                lookup is None
                or not isinstance(first_name, str)
                or not isinstance(last_name, str)
            ):
                return None
            candidates = self._contact_candidates_from_evidence(
                lookup,
                query={"first_name": first_name, "last_name": last_name},
            )
            if candidates is None or len(candidates) != 1:
                return None
            expected_ids = [candidates[0][0]]
            expected_name = (first_name, last_name)
            parents = [selected[0], lookup, information]
            derivation = "verified_named_meeting_recipient_v1"
        else:
            return None
        records = self._meeting_contact_records_from_evidence(
            information,
            expected_ids=expected_ids,
            expected_name=expected_name,
        )
        parent_ids = [parent.evidence_id for parent in parents]
        if records is None or any(parent_id is None for parent_id in parent_ids):
            return None
        session.evidence.add(
            Evidence(
                proposition="contact_information",
                value=information.value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.TOOL,
                source_turn_id=information.source_turn_id,
                source_tool_call_id=information.source_tool_call_id,
                confidence=information.confidence,
            )
        )
        value = {
            "mode": mode,
            "meeting_topic": meeting["topic"],
            "records": list(records),
        }
        session.evidence.add(
            Evidence(
                proposition=_CURRENT_DAY_MEETING_RECIPIENTS,
                value=value,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"meeting-recipients-{goal.goal_id}",
                confidence=min(parent.confidence for parent in parents),
                derived_from=[
                    parent_id for parent_id in parent_ids if parent_id is not None
                ],
                derivation=derivation,
            )
        )
        return self._validated_current_day_meeting_recipients(session)

    def _validated_current_day_meeting_recipients(
        self, session: SessionState
    ) -> tuple[Evidence, dict[str, Any]] | None:
        goal = self._current_day_meeting_goal(session)
        selected = self._validated_selected_current_day_meeting(session)
        summary = self._latest_current_evidence(
            session, _CURRENT_DAY_MEETING_RECIPIENTS
        )
        if (
            goal is None
            or selected is None
            or summary is None
            or summary.status is not EvidenceStatus.KNOWN
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.state_version != session.evidence.current_state_version
            or not isinstance(summary.value, Mapping)
        ):
            return None
        mode = goal.desired_outcome.get(_CURRENT_DAY_MEETING_MODE)
        derivations: dict[str, str] = {
            _CURRENT_DAY_MEETING_ATTENDEE_EMAIL: (
                "verified_meeting_attendee_recipients_v1"
            ),
            _CURRENT_DAY_MEETING_WEATHER_EMAIL: (
                "verified_meeting_attendee_recipients_v1"
            ),
            _CURRENT_DAY_MEETING_NAMED_EMAIL: "verified_named_meeting_recipient_v1",
        }
        expected_derivation = derivations.get(mode) if isinstance(mode, str) else None
        expected_parent_count = (
            2
            if mode
            in {
                _CURRENT_DAY_MEETING_ATTENDEE_EMAIL,
                _CURRENT_DAY_MEETING_WEATHER_EMAIL,
            }
            else 3
        )
        parents = [
            session.evidence.evidence.get(parent_id)
            for parent_id in summary.derived_from
        ]
        if (
            expected_derivation is None
            or summary.derivation != expected_derivation
            or len(parents) != expected_parent_count
            or any(
                parent is None
                or parent.state_version != session.evidence.current_state_version
                for parent in parents
            )
            or parents[0] is not selected[0]
        ):
            return None
        meeting = selected[1]["meeting"]
        lookup: Evidence | None = None
        information = parents[-1]
        assert information is not None
        expected_name: tuple[str, str] | None = None
        if mode in {
            _CURRENT_DAY_MEETING_ATTENDEE_EMAIL,
            _CURRENT_DAY_MEETING_WEATHER_EMAIL,
        }:
            expected_ids = meeting["attendee_ids"]
        else:
            lookup = parents[1]
            first_name = goal.desired_outcome.get("contact_first_name")
            last_name = goal.desired_outcome.get("contact_last_name")
            if (
                lookup is None
                or not isinstance(first_name, str)
                or not isinstance(last_name, str)
            ):
                return None
            query = {"first_name": first_name, "last_name": last_name}
            candidates = self._contact_candidates_from_evidence(lookup, query=query)
            if candidates is None or len(candidates) != 1:
                return None
            expected_ids = [candidates[0][0]]
            expected_name = (first_name, last_name)
            if not self._tool_evidence_matches_arguments(
                session,
                lookup,
                tool_name="get_contact_id_by_contact_name",
                arguments={
                    "contact_first_name": first_name,
                    "contact_last_name": last_name,
                },
            ):
                return None
        records = self._meeting_contact_records_from_evidence(
            information,
            expected_ids=expected_ids,
            expected_name=expected_name,
        )
        if records is None or not self._tool_evidence_matches_arguments(
            session,
            information,
            tool_name="get_contact_information",
            arguments={"contact_ids": list(expected_ids)},
        ):
            return None
        expected = {
            "mode": mode,
            "meeting_topic": meeting["topic"],
            "records": list(records),
        }
        return (summary, expected) if summary.value == expected else None

    def _validated_current_day_meeting_location(
        self, session: SessionState
    ) -> tuple[Evidence, str] | None:
        goal = self._current_day_meeting_goal(session)
        selected = self._validated_selected_current_day_meeting(session)
        evidence = self._latest_current_evidence(
            session, _CURRENT_DAY_MEETING_LOCATION
        )
        if (
            goal is None
            or selected is None
            or goal.desired_outcome.get(_CURRENT_DAY_MEETING_MODE)
            != _CURRENT_DAY_MEETING_WEATHER_EMAIL
            or evidence is None
            or evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.TOOL
            or evidence.state_version != session.evidence.current_state_version
            or not isinstance(evidence.value, str)
            or not evidence.value.startswith("loc_")
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(evidence.value) is None
            or goal.desired_outcome.get("meeting_location_id") != evidence.value
            or not self._tool_evidence_matches_arguments(
                session,
                evidence,
                tool_name="get_location_id_by_location_name",
                arguments={"location": selected[1]["meeting"]["location"]},
            )
        ):
            return None
        return evidence, evidence.value

    def _validated_current_day_meeting_weather(
        self, session: SessionState
    ) -> tuple[Evidence, dict[str, str]] | None:
        current = self._current_datetime_parts(session)
        selected = self._validated_selected_current_day_meeting(session)
        location = self._validated_current_day_meeting_location(session)
        evidence = self._latest_current_evidence(
            session, _CURRENT_DAY_MEETING_WEATHER
        )
        if current is None or selected is None or location is None or evidence is None:
            return None
        meeting = selected[1]["meeting"]
        arguments = {
            "location_or_poi_id": location[1],
            "month": current[1],
            "day": current[2],
            "time_hour_24hformat": meeting["start_hour"],
        }
        snapshot = self._meeting_weather_snapshot_from_evidence(
            evidence,
            expected_hour=meeting["start_hour"],
            expected_minute=meeting["start_minute"],
        )
        if snapshot is None or not self._tool_evidence_matches_arguments(
            session,
            evidence,
            tool_name="get_weather",
            arguments=arguments,
        ):
            return None
        return evidence, snapshot

    @staticmethod
    def _meeting_content_instruction_proposition(goal_id: str) -> str:
        return f"{_CURRENT_DAY_MEETING_CONTENT_INSTRUCTION}:{goal_id}"

    def _store_current_day_meeting_content_instruction(
        self,
        session: SessionState,
        *,
        goal: Goal,
        text: str,
        source_turn_id: str,
        meeting: Mapping[str, Any],
    ) -> Evidence | None:
        normalized = _meeting_request_text(text)
        if normalized is None or not self._friendly_meeting_content_followup(
            normalized, meeting=meeting
        ):
            return None
        instruction = Evidence(
            proposition=self._meeting_content_instruction_proposition(goal.goal_id),
            value=normalized,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.USER,
            source_turn_id=source_turn_id,
            confidence=1.0,
        )
        session.evidence.add(instruction)
        stored = session.evidence.for_proposition(instruction.proposition)[-1]
        return stored

    def _validated_current_day_meeting_content_instruction(
        self,
        session: SessionState,
        *,
        goal: Goal,
        meeting: Mapping[str, Any],
    ) -> Evidence | None:
        proposition = self._meeting_content_instruction_proposition(goal.goal_id)
        observations = session.evidence.latest_for_proposition(proposition)
        instruction = observations[0] if len(observations) == 1 else None
        desired = goal.desired_outcome.get("message_instruction")
        grounded = session.grounded_desired_values_by_goal.get(goal.goal_id, {})
        sources = session.grounded_value_sources_by_goal.get(goal.goal_id, {})
        if (
            instruction is None
            or instruction.status is not EvidenceStatus.KNOWN
            or instruction.source_kind is not EvidenceSourceKind.USER
            or instruction.state_version != session.evidence.current_state_version
            or not isinstance(instruction.value, str)
            or instruction.value != desired
            or grounded.get("message_instruction") != instruction.value
            or sources.get("message_instruction") != instruction.source_turn_id
            or not self._valid_user_value_sources(
                session, sources, required=("message_instruction",)
            )
            or not self._friendly_meeting_content_followup(
                instruction.value, meeting=meeting
            )
        ):
            return None
        source_messages = [
            message
            for message in session.conversation
            if message.get("role") == "user"
            and message.get("turn_id") == instruction.source_turn_id
        ]
        if len(source_messages) != 1 or not isinstance(
            source_messages[0].get("content"), str
        ):
            return None
        return (
            instruction
            if _meeting_request_text(source_messages[0]["content"])
            == instruction.value
            else None
        )

    @staticmethod
    def _meeting_email_content_prompt(meeting: Mapping[str, Any]) -> str:
        return (
            f"I verified the current attendees for {meeting['topic']}. "
            "What friendly reminder tone or meeting details should I use for the draft?"
        )

    @staticmethod
    def _meeting_time_12h(meeting: Mapping[str, Any]) -> str:
        hour = int(meeting["start_hour"])
        minute = int(meeting["start_minute"])
        suffix = "AM" if hour < 12 else "PM"
        display_hour = hour % 12 or 12
        return f"{display_hour}:{minute:02d} {suffix}"

    @staticmethod
    def _meeting_time_24h(meeting: Mapping[str, Any]) -> str:
        return f"{int(meeting['start_hour']):02d}:{int(meeting['start_minute']):02d}"

    @staticmethod
    def _meeting_delay_minutes(
        meeting: Mapping[str, Any], *, current_hour: int, current_minute: int
    ) -> int:
        return max(
            0,
            current_hour * 60
            + current_minute
            - (int(meeting["start_hour"]) * 60 + int(meeting["start_minute"])),
        )

    @classmethod
    def _friendly_meeting_content_followup(
        cls, text: str, *, meeting: Mapping[str, Any]
    ) -> bool:
        normalized = _meeting_request_text(text)
        if normalized is None:
            return False
        folded = normalized.casefold()
        if (
            re.search(r"\bfriendly\s+reminder\b", folded) is None
            or re.search(r"\bmeeting\b", folded) is None
            or re.search(
                r"\b(?:do\s+not|don['\u2019]?t|never)\s+(?:include|send)\b",
                folded,
            )
            is not None
            or not _contains_option_phrase(normalized, str(meeting["location"]))
        ):
            return False
        hour = int(meeting["start_hour"])
        minute = int(meeting["start_minute"])
        time_references = {
            f"{hour:02d}:{minute:02d}".casefold(),
            cls._meeting_time_12h(meeting).casefold(),
        }
        return any(reference in folded for reference in time_references)

    @classmethod
    def _meeting_weather_request_matches_meeting(
        cls,
        text: str,
        *,
        meeting: Mapping[str, Any],
        requested_location: str | None = None,
    ) -> bool:
        normalized = _meeting_request_text(text)
        syntax = (
            _approved_weather_email_syntax(normalized)
            if normalized is not None
            else None
        )
        prefix_details = (
            _weather_email_prefix_details(normalized)
            if normalized is not None
            else None
        )
        location = requested_location or (syntax[1] if syntax is not None else None)
        if (
            normalized is None
            or syntax is None
            or prefix_details is None
            or not isinstance(location, str)
            or _argument_identifier(location)
            != _argument_identifier(str(meeting["location"]))
        ):
            return False
        if prefix_details[3]:
            return True
        return prefix_details[2] == (
            int(meeting["start_hour"]),
            int(meeting["start_minute"]),
        )

    @classmethod
    def _meeting_attendee_email_body(cls, meeting: Mapping[str, Any]) -> str:
        return (
            f"Hi everyone! This is a friendly reminder about our {meeting['topic']} "
            f"meeting today at {cls._meeting_time_24h(meeting)} in "
            f"{meeting['location']}. Looking forward to seeing you all there!"
        )

    @staticmethod
    def _meeting_weather_snapshot_from_evidence(
        evidence: Evidence,
        *,
        expected_hour: int,
        expected_minute: int,
    ) -> dict[str, str] | None:
        if (
            evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.TOOL
            or not isinstance(evidence.value, Mapping)
            or set(evidence.value) != {"current_slot", "next_slot"}
            or not 0 <= expected_hour <= 23
            or not 0 <= expected_minute <= 59
        ):
            return None
        slot = evidence.value.get("current_slot")
        if not isinstance(slot, Mapping):
            return None
        required = {
            "start_time",
            "end_time",
            "temperature_c",
            "wind_speed_kph",
            "humidity_percent",
            "condition",
        }
        if set(slot) != required:
            return None
        start_time = slot.get("start_time")
        end_time = slot.get("end_time")
        condition = slot.get("condition")
        temperature_raw = slot.get("temperature_c")
        wind_raw = slot.get("wind_speed_kph")
        humidity_raw = slot.get("humidity_percent")
        if (
            not isinstance(start_time, str)
            or re.fullmatch(r"(?:[01]\d|2[0-3]):[0-5]\d", start_time) is None
            or not isinstance(end_time, str)
            or re.fullmatch(r"(?:[01]\d|2[0-3]):[0-5]\d", end_time) is None
            or not isinstance(condition, str)
            or re.fullmatch(r"[A-Za-z][A-Za-z0-9_ -]{0,79}", condition) is None
            or isinstance(temperature_raw, bool)
            or isinstance(wind_raw, bool)
            or isinstance(humidity_raw, bool)
        ):
            return None
        try:
            temperature = Decimal(str(temperature_raw))
            wind_speed = Decimal(str(wind_raw))
            humidity = Decimal(str(humidity_raw))
        except (InvalidOperation, TypeError, ValueError):
            return None
        start_hour, start_minute = (int(part) for part in start_time.split(":"))
        end_hour, end_minute = (int(part) for part in end_time.split(":"))
        start_total = start_hour * 60 + start_minute
        end_total = end_hour * 60 + end_minute
        if end_total == 0 and start_total > 0:
            end_total = 24 * 60
        expected_total = expected_hour * 60 + expected_minute
        if (
            not temperature.is_finite()
            or not Decimal("-80") <= temperature <= 80
            or not wind_speed.is_finite()
            or not Decimal(0) <= wind_speed <= 500
            or not humidity.is_finite()
            or not Decimal(0) <= humidity <= 100
            or not start_total < end_total <= 24 * 60
            or not start_total <= expected_total < end_total
        ):
            return None
        condition_label = re.sub(
            r"\s+", " ", condition.replace("_and_", " with ").replace("_", " ")
        ).strip()
        if not condition_label or TTSGuard(max_characters=80).violations(
            condition_label
        ):
            return None
        return {
            "condition": condition,
            "condition_label": condition_label,
            "temperature_c": format(temperature.normalize(), "f"),
            "start_time": start_time,
            "end_time": end_time,
        }

    @classmethod
    def _meeting_weather_email_body(
        cls, meeting: Mapping[str, Any], weather: Mapping[str, str]
    ) -> str:
        condition = weather["condition"].casefold()
        temperature = Decimal(weather["temperature_c"])
        advice: list[str] = []
        if "rain" in condition:
            advice.append("bring an umbrella")
        if any(marker in condition for marker in ("snow", "hail", "ice")):
            advice.append("allow extra time for difficult road conditions")
        if temperature <= 10:
            advice.append("dress warmly")
        elif temperature >= 28:
            advice.append("plan for the heat and stay hydrated")
        preparation = (
            ", and ".join(advice) if advice else "plan for the forecast conditions"
        )
        return (
            f"Hi team, I wanted to share a weather update for our {meeting['topic']} "
            f"meeting today at {cls._meeting_time_24h(meeting)} in "
            f"{meeting['location']}. The forecast is {weather['condition_label']} "
            f"with a temperature around {weather['temperature_c']} degrees Celsius. "
            f"Please {preparation}. The conditions may affect traffic and travel, "
            "so consider leaving a little earlier. Let me know if the weather "
            "affects your ability to attend. Best regards"
        )

    @staticmethod
    def _named_meeting_apology_body(
        meeting: Mapping[str, Any],
        *,
        recipient_first_name: str,
        current_hour: int,
        current_minute: int,
    ) -> str:
        delay_minutes = CARGuardOrchestrator._meeting_delay_minutes(
            meeting,
            current_hour=current_hour,
            current_minute=current_minute,
        )
        return (
            f"Hi {recipient_first_name}, "
            f"I wanted to reach out regarding our {meeting['topic']} meeting that "
            f"started at {CARGuardOrchestrator._meeting_time_24h(meeting)} "
            f"today. I'm running about {delay_minutes} minutes late and apologize "
            "for the delay. I should be there shortly. Thank you for your patience. "
            "Best regards"
        )

    def _current_day_meeting_read_evidence(
        self,
        session: SessionState,
        *,
        goal_id: str,
        tool_name: str,
        arguments: Mapping[str, Any],
        proposition: str,
    ) -> Evidence | None:
        observation = self._successful_goal_read(
            session,
            goal_id=goal_id,
            tool_name=tool_name,
            arguments=arguments,
        )
        if observation is None:
            return None
        return self._evidence_for_goal_read(
            session,
            goal_id=goal_id,
            proposition=proposition,
            observation=observation,
        )

    def _adopt_current_day_meeting_calendar_evidence(
        self,
        session: SessionState,
        *,
        arguments: Mapping[str, Any],
        current: tuple[int, int, int, int, int],
    ) -> Evidence | None:
        matches = [
            observation
            for observation in session.successful_read_results
            if observation.tool_name == "get_entries_from_calendar"
            and observation.state_version == session.evidence.current_state_version
            and _argument_value_matches_binding(
                observation.arguments, dict(arguments)
            )
        ]
        if not matches or any(
            not _strict_equal(observation.value, matches[-1].value)
            for observation in matches
        ):
            return None
        source = matches[-1]
        candidate = Evidence(
            proposition=_CURRENT_DAY_MEETING_CALENDAR,
            value=source.value,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.TOOL,
            source_turn_id=source.source_turn_id,
            source_tool_call_id=source.call_id,
            confidence=1.0,
        )
        if self._current_day_meetings_from_evidence(candidate, current=current) is None:
            return None
        session.evidence.add(candidate)
        stored = session.evidence.for_proposition(_CURRENT_DAY_MEETING_CALENDAR)[-1]
        return (
            stored
            if stored.state_version == session.evidence.current_state_version
            else None
        )

    def _next_current_day_meeting_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        item = next(
            (
                candidate
                for candidate in prepared.goals
                if candidate.goal.desired_outcome.get(_CURRENT_DAY_MEETING_MARKER)
                is True
            ),
            None,
        )
        if item is None:
            return None
        goal = item.goal
        desired = goal.desired_outcome
        phase = desired.get(_CURRENT_DAY_MEETING_PHASE)
        mode = desired.get(_CURRENT_DAY_MEETING_MODE)
        current = self._current_datetime_parts(session)
        if current is None:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )

        if phase == _CURRENT_DAY_MEETING_READ_CALENDAR:
            calendar_arguments = {"month": current[1], "day": current[2]}
            self._register_single_read_need(
                session,
                goal_id=goal.goal_id,
                proposition=_CURRENT_DAY_MEETING_CALENDAR,
            )
            observed = self._current_day_meeting_read_evidence(
                session,
                goal_id=goal.goal_id,
                tool_name="get_entries_from_calendar",
                arguments=calendar_arguments,
                proposition=_CURRENT_DAY_MEETING_CALENDAR,
            )
            if observed is None and mode == _CURRENT_DAY_MEETING_WEATHER_EMAIL:
                observed = self._adopt_current_day_meeting_calendar_evidence(
                    session,
                    arguments=calendar_arguments,
                    current=current,
                )
            if observed is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_entries_from_calendar",
                    arguments=calendar_arguments,
                    semantic_operation="read_current_day_meeting_calendar",
                    proposition=_CURRENT_DAY_MEETING_CALENDAR,
                )
            candidates = self._store_current_day_meeting_candidates(
                session,
                goal=goal,
                raw_evidence=observed,
                current=current,
            )
            if candidates is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            topic = desired.get("meeting_topic")
            if topic is None and len(candidates[1]["meetings"]) > 1:
                self._update_current_day_meeting_goal(
                    session,
                    goal,
                    updates={_CURRENT_DAY_MEETING_PHASE: _CURRENT_DAY_MEETING_SELECT},
                )
                return self._text_plan(
                    session,
                    self._meeting_candidate_prompt(candidates[1]["meetings"]),
                    goal_ids=[goal.goal_id],
                    kind=ProposalKind.ASK_USER,
                )
            selected_topic = (
                candidates[1]["meetings"][0]["topic"]
                if topic is None
                else topic
            )
            if not isinstance(selected_topic, str):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            selected = self._store_selected_current_day_meeting(
                session,
                goal=goal,
                candidates=candidates,
                topic=selected_topic,
            )
            if selected is None:
                return self._text_plan(
                    session,
                    "I could not verify one exact current-day meeting, so I did not prepare an email.",
                    goal_ids=[goal.goal_id],
                )
            meeting = selected[1]["meeting"]
            if mode == _CURRENT_DAY_MEETING_STATUS:
                session.goal_dag.set_status(goal.goal_id, GoalStatus.DONE)
                return self._text_plan(
                    session,
                    self._meeting_status_text(
                        meeting,
                        current_hour=current[3],
                        current_minute=current[4],
                        query_kind=str(desired.get("meeting_query_kind", "status")),
                    ),
                    goal_ids=[goal.goal_id],
                )
            if mode == _CURRENT_DAY_MEETING_NAMED_EMAIL:
                start_minutes = (
                    meeting["start_hour"] * 60 + meeting["start_minute"]
                )
                current_minutes = current[3] * 60 + current[4]
                if current_minutes < start_minutes:
                    session.goal_dag.set_status(goal.goal_id, GoalStatus.DONE)
                    return self._text_plan(
                        session,
                        f"I found that the {meeting['topic']} meeting has not started, so I did not prepare or send the conditional late email.",
                        goal_ids=[goal.goal_id],
                    )
                next_phase = _CURRENT_DAY_MEETING_LOOKUP_CONTACT
            elif mode == _CURRENT_DAY_MEETING_ATTENDEE_EMAIL:
                next_phase = _CURRENT_DAY_MEETING_READ_CONTACTS
            elif mode == _CURRENT_DAY_MEETING_WEATHER_EMAIL:
                request_text = desired.get("weather_email_request")
                request_location = desired.get("weather_email_location")
                contextual_weather = (
                    desired.get(_CURRENT_DAY_MEETING_CONTEXTUAL_WEATHER) is True
                )
                request_matches = (
                    self._contextual_meeting_weather_email_matches(
                        request_text,
                        meeting=meeting,
                        candidates=candidates[1]["meetings"],
                    )
                    if contextual_weather and isinstance(request_text, str)
                    else self._meeting_weather_request_matches_meeting(
                        request_text,
                        meeting=meeting,
                        requested_location=request_location,
                    )
                    if isinstance(request_text, str)
                    else False
                )
                if not isinstance(
                    request_text, str
                ) or not isinstance(
                    request_location, str
                ) or not request_matches:
                    return self._text_plan(
                        session,
                        "I could not match the requested weather update to one exact meeting time and location, so I did not prepare an email.",
                        goal_ids=[goal.goal_id],
                    )
                next_phase = _CURRENT_DAY_MEETING_RESOLVE_LOCATION
            else:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            self._update_current_day_meeting_goal(
                session,
                goal,
                updates={
                    "meeting_topic": meeting["topic"],
                    _CURRENT_DAY_MEETING_PHASE: next_phase,
                },
            )
            return self._next_current_day_meeting_workflow(
                session, self._prepare_turn(session)
            )

        selected = self._validated_selected_current_day_meeting(session)
        if selected is None:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )

        if phase == _CURRENT_DAY_MEETING_RESOLVE_LOCATION:
            meeting = selected[1]["meeting"]
            location_arguments = {"location": meeting["location"]}
            self._register_single_read_need(
                session,
                goal_id=goal.goal_id,
                proposition=_CURRENT_DAY_MEETING_LOCATION,
            )
            observed = self._current_day_meeting_read_evidence(
                session,
                goal_id=goal.goal_id,
                tool_name="get_location_id_by_location_name",
                arguments=location_arguments,
                proposition=_CURRENT_DAY_MEETING_LOCATION,
            )
            if observed is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_location_id_by_location_name",
                    arguments=location_arguments,
                    semantic_operation="resolve_current_day_meeting_location",
                    proposition=_CURRENT_DAY_MEETING_LOCATION,
                )
            location_id = observed.value
            if (
                not isinstance(location_id, str)
                or not location_id.startswith("loc_")
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(location_id) is None
                or not self._tool_evidence_matches_arguments(
                    session,
                    observed,
                    tool_name="get_location_id_by_location_name",
                    arguments=location_arguments,
                )
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            self._update_current_day_meeting_goal(
                session,
                goal,
                updates={
                    "meeting_location_id": location_id,
                    _CURRENT_DAY_MEETING_PHASE: _CURRENT_DAY_MEETING_READ_CONTACTS,
                },
            )
            return self._next_current_day_meeting_workflow(
                session, self._prepare_turn(session)
            )

        if phase == _CURRENT_DAY_MEETING_LOOKUP_CONTACT:
            first_name = desired.get("contact_first_name")
            last_name = desired.get("contact_last_name")
            if not isinstance(first_name, str) or not isinstance(last_name, str):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            lookup_arguments = {
                "contact_first_name": first_name,
                "contact_last_name": last_name,
            }
            self._register_single_read_need(
                session,
                goal_id=goal.goal_id,
                proposition=_CURRENT_DAY_MEETING_CONTACT_MATCHES,
            )
            observed = self._current_day_meeting_read_evidence(
                session,
                goal_id=goal.goal_id,
                tool_name="get_contact_id_by_contact_name",
                arguments=lookup_arguments,
                proposition=_CURRENT_DAY_MEETING_CONTACT_MATCHES,
            )
            if observed is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_contact_id_by_contact_name",
                    arguments=lookup_arguments,
                    semantic_operation="lookup_named_meeting_contact",
                    proposition=_CURRENT_DAY_MEETING_CONTACT_MATCHES,
                )
            contact_candidates = self._contact_candidates_from_evidence(
                observed,
                query={"first_name": first_name, "last_name": last_name},
            )
            if contact_candidates is None or len(contact_candidates) != 1:
                return self._text_plan(
                    session,
                    "I could not verify one exact current contact, so I did not prepare or send the meeting email.",
                    goal_ids=[goal.goal_id],
                )
            updated = self._update_current_day_meeting_goal(
                session,
                goal,
                updates={_CURRENT_DAY_MEETING_PHASE: _CURRENT_DAY_MEETING_READ_CONTACTS},
            )
            self._apply_navigation_derived_parameters(
                session,
                goal=updated,
                parameters={
                    "contact_ids": (
                        [contact_candidates[0][0]],
                        (observed,),
                        "unique_named_meeting_contact_v1",
                    )
                },
            )
            return self._next_current_day_meeting_workflow(
                session, self._prepare_turn(session)
            )

        if phase == _CURRENT_DAY_MEETING_READ_CONTACTS:
            lookup: Evidence | None = None
            if mode in {
                _CURRENT_DAY_MEETING_ATTENDEE_EMAIL,
                _CURRENT_DAY_MEETING_WEATHER_EMAIL,
            }:
                contact_ids = selected[1]["meeting"]["attendee_ids"]
            elif mode == _CURRENT_DAY_MEETING_NAMED_EMAIL:
                contact_ids = desired.get("contact_ids")
                lookup = self._latest_current_evidence(
                    session, _CURRENT_DAY_MEETING_CONTACT_MATCHES
                )
            else:
                contact_ids = None
            if (
                not isinstance(contact_ids, list)
                or not contact_ids
                or any(not isinstance(contact_id, str) for contact_id in contact_ids)
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            information_arguments = {"contact_ids": list(contact_ids)}
            self._register_single_read_need(
                session,
                goal_id=goal.goal_id,
                proposition=_CURRENT_DAY_MEETING_CONTACT_INFORMATION,
            )
            observed = self._current_day_meeting_read_evidence(
                session,
                goal_id=goal.goal_id,
                tool_name="get_contact_information",
                arguments=information_arguments,
                proposition=_CURRENT_DAY_MEETING_CONTACT_INFORMATION,
            )
            if observed is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_contact_information",
                    arguments=information_arguments,
                    semantic_operation="read_meeting_contact_information",
                    proposition=_CURRENT_DAY_MEETING_CONTACT_INFORMATION,
                )
            recipients = self._store_current_day_meeting_recipients(
                session,
                goal=goal,
                selected=selected,
                information=observed,
                lookup=lookup,
            )
            if recipients is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            if mode == _CURRENT_DAY_MEETING_ATTENDEE_EMAIL:
                next_phase = _CURRENT_DAY_MEETING_COLLECT_CONTENT
            elif mode == _CURRENT_DAY_MEETING_WEATHER_EMAIL:
                next_phase = _CURRENT_DAY_MEETING_READ_WEATHER
            else:
                next_phase = _CURRENT_DAY_MEETING_SEND
            self._update_current_day_meeting_goal(
                session,
                goal,
                updates={_CURRENT_DAY_MEETING_PHASE: next_phase},
            )
            if next_phase == _CURRENT_DAY_MEETING_COLLECT_CONTENT:
                return self._text_plan(
                    session,
                    self._meeting_email_content_prompt(selected[1]["meeting"]),
                    goal_ids=[goal.goal_id],
                    kind=ProposalKind.ASK_USER,
                )
            return self._next_current_day_meeting_workflow(
                session, self._prepare_turn(session)
            )

        if phase == _CURRENT_DAY_MEETING_READ_WEATHER:
            location = self._validated_current_day_meeting_location(session)
            if location is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            meeting = selected[1]["meeting"]
            weather_arguments = {
                "location_or_poi_id": location[1],
                "month": current[1],
                "day": current[2],
                "time_hour_24hformat": meeting["start_hour"],
            }
            self._register_single_read_need(
                session,
                goal_id=goal.goal_id,
                proposition=_CURRENT_DAY_MEETING_WEATHER,
            )
            observed = self._current_day_meeting_read_evidence(
                session,
                goal_id=goal.goal_id,
                tool_name="get_weather",
                arguments=weather_arguments,
                proposition=_CURRENT_DAY_MEETING_WEATHER,
            )
            if observed is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_weather",
                    arguments=weather_arguments,
                    semantic_operation="read_current_day_meeting_weather",
                    proposition=_CURRENT_DAY_MEETING_WEATHER,
                )
            weather_snapshot = self._meeting_weather_snapshot_from_evidence(
                observed,
                expected_hour=meeting["start_hour"],
                expected_minute=meeting["start_minute"],
            )
            if weather_snapshot is None or not self._tool_evidence_matches_arguments(
                session,
                observed,
                tool_name="get_weather",
                arguments=weather_arguments,
            ):
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            self._update_current_day_meeting_goal(
                session,
                goal,
                updates={_CURRENT_DAY_MEETING_PHASE: _CURRENT_DAY_MEETING_SEND},
            )
            return self._next_current_day_meeting_workflow(
                session, self._prepare_turn(session)
            )

        if phase != _CURRENT_DAY_MEETING_SEND:
            return self._limitation_plan(
                session, goal, GateOutcome.UNSUPPORTED_PARAMETER
            )
        recipients = self._validated_current_day_meeting_recipients(session)
        selected = self._validated_selected_current_day_meeting(session)
        if recipients is None or selected is None:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        records = recipients[1]["records"]
        meeting = selected[1]["meeting"]
        content_instruction: Evidence | None = None
        body_parents: tuple[Evidence, ...]
        body_derivation: str
        if (
            mode == _CURRENT_DAY_MEETING_ATTENDEE_EMAIL
            and desired.get("message_style") == "friendly_reminder"
        ):
            content_instruction = (
                self._validated_current_day_meeting_content_instruction(
                    session, goal=goal, meeting=meeting
                )
            )
            if content_instruction is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            body = self._meeting_attendee_email_body(meeting)
            body_parents = (selected[0], recipients[0], content_instruction)
            body_derivation = (
                "friendly_current_meeting_email_body_from_user_instruction_v1"
            )
        elif mode == _CURRENT_DAY_MEETING_NAMED_EMAIL and len(records) == 1:
            body = self._named_meeting_apology_body(
                meeting,
                recipient_first_name=records[0]["first_name"],
                current_hour=current[3],
                current_minute=current[4],
            )
            body_parents = (selected[0], recipients[0])
            body_derivation = "frozen_current_meeting_email_body_v1"
        elif mode == _CURRENT_DAY_MEETING_WEATHER_EMAIL:
            location = self._validated_current_day_meeting_location(session)
            weather_evidence = self._validated_current_day_meeting_weather(session)
            if location is None or weather_evidence is None:
                return self._limitation_plan(
                    session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            body = self._meeting_weather_email_body(meeting, weather_evidence[1])
            body_parents = (
                selected[0],
                recipients[0],
                location[0],
                weather_evidence[0],
            )
            body_derivation = "current_meeting_weather_email_body_v1"
        else:
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        addresses = [record["email"] for record in records]
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters={
                "email_addresses": (
                    addresses,
                    (selected[0], recipients[0]),
                    "exact_current_meeting_recipients_v1",
                ),
                "message": (
                    body,
                    body_parents,
                    body_derivation,
                ),
            },
        )
        refreshed = self._prepare_turn(session)
        refreshed_item = refreshed.by_goal_id.get(goal.goal_id)
        target = (
            self._unique_bound_target(refreshed_item)
            if refreshed_item is not None
            else None
        )
        expected = {"email_addresses": addresses, "content_message": body}
        if (
            target is None
            or target[1].tool_name != "send_email"
            or not _argument_value_matches_binding(target[1].arguments, expected)
        ):
            return self._limitation_plan(
                session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        deterministic = self._deterministic_bound_action(session, refreshed)
        return deterministic or self._limitation_plan(
            session, goal, GateOutcome.UNAVAILABLE_EVIDENCE
        )

    def _current_day_meeting_email_bundle_is_current(
        self, session: SessionState, bundle: ExecutionBundle
    ) -> bool:
        goal = self._current_day_meeting_goal(session)
        selected = self._validated_selected_current_day_meeting(session)
        recipients = self._validated_current_day_meeting_recipients(session)
        if (
            goal is None
            or selected is None
            or recipients is None
            or goal.desired_outcome.get(_CURRENT_DAY_MEETING_PHASE)
            != _CURRENT_DAY_MEETING_SEND
            or bundle.goal_ids != (goal.goal_id,)
            or len(bundle.calls) != 1
            or bundle.calls[0].tool_name != "send_email"
        ):
            return False
        derived_ids = session.derived_value_evidence_by_goal.get(goal.goal_id, {})
        address_evidence = session.evidence.evidence.get(
            derived_ids.get("email_addresses", "")
        )
        body_evidence = session.evidence.evidence.get(derived_ids.get("message", ""))
        base_parents = [selected[0].evidence_id, recipients[0].evidence_id]
        if (
            address_evidence is None
            or body_evidence is None
            or address_evidence.state_version
            != session.evidence.current_state_version
            or body_evidence.state_version != session.evidence.current_state_version
            or address_evidence.derived_from != base_parents
            or address_evidence.derivation
            != "exact_current_meeting_recipients_v1"
        ):
            return False
        records = recipients[1]["records"]
        meeting = selected[1]["meeting"]
        mode = goal.desired_outcome.get(_CURRENT_DAY_MEETING_MODE)
        if (
            mode == _CURRENT_DAY_MEETING_ATTENDEE_EMAIL
            and goal.desired_outcome.get("message_style") == "friendly_reminder"
        ):
            content_instruction = (
                self._validated_current_day_meeting_content_instruction(
                    session, goal=goal, meeting=meeting
                )
            )
            if (
                content_instruction is None
                or body_evidence.derived_from
                != [*base_parents, content_instruction.evidence_id]
                or body_evidence.derivation
                != "friendly_current_meeting_email_body_from_user_instruction_v1"
            ):
                return False
            expected_body = self._meeting_attendee_email_body(meeting)
        elif mode == _CURRENT_DAY_MEETING_NAMED_EMAIL and len(records) == 1:
            if (
                body_evidence.derived_from != base_parents
                or body_evidence.derivation
                != "frozen_current_meeting_email_body_v1"
            ):
                return False
            current = self._current_datetime_parts(session)
            if current is None:
                return False
            expected_body = self._named_meeting_apology_body(
                meeting,
                recipient_first_name=records[0]["first_name"],
                current_hour=current[3],
                current_minute=current[4],
            )
        elif mode == _CURRENT_DAY_MEETING_WEATHER_EMAIL:
            location = self._validated_current_day_meeting_location(session)
            weather = self._validated_current_day_meeting_weather(session)
            if (
                location is None
                or weather is None
                or body_evidence.derived_from
                != [
                    *base_parents,
                    location[0].evidence_id,
                    weather[0].evidence_id,
                ]
                or body_evidence.derivation
                != "current_meeting_weather_email_body_v1"
            ):
                return False
            expected_body = self._meeting_weather_email_body(meeting, weather[1])
        else:
            return False
        expected_addresses = [record["email"] for record in records]
        if (
            address_evidence.value != expected_addresses
            or body_evidence.value != expected_body
        ):
            return False
        expected = {
            "email_addresses": expected_addresses,
            "content_message": expected_body,
        }
        return _argument_value_matches_binding(bundle.calls[0].arguments, expected)

    def _begin_trip_email_goal(
        self,
        session: SessionState,
        *,
        turn_id: str,
        first_name: str,
        requested_contact_name: str | None = None,
    ) -> Goal:
        digest = hashlib.sha256(
            f"{turn_id}\0trip-email\0{first_name}".encode()
        ).hexdigest()
        desired_outcome: dict[str, Any] = {
            _TRIP_EMAIL_MARKER: True,
            "first_name": first_name,
        }
        grounded_values: dict[str, Any] = {"first_name": first_name}
        if requested_contact_name is not None:
            desired_outcome["requested_contact_name"] = requested_contact_name
            grounded_values["requested_contact_name"] = requested_contact_name
        goal = Goal(
            goal_id=f"goal-trip-email-{digest[:12]}",
            semantic_operation="send_email",
            desired_outcome=desired_outcome,
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[goal],
            explicit_slots=grounded_values,
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.ACTION,
        )
        session.authorized_action_goal_ids = {goal.goal_id}
        session.grounded_desired_values_by_goal = {goal.goal_id: grounded_values}
        session.grounded_value_sources_by_goal = {
            goal.goal_id: {name: turn_id for name in grounded_values}
        }
        session.derived_value_evidence_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return goal

    @staticmethod
    def _trip_email_goal(session: SessionState) -> Goal | None:
        if session.intent is None:
            return None
        matches = [
            goal
            for goal in session.intent.goals
            if goal.semantic_operation == "send_email"
            and goal.desired_outcome.get(_TRIP_EMAIL_MARKER) is True
        ]
        return matches[0] if len(matches) == 1 else None

    @staticmethod
    def _trip_email_schema_available(
        session: SessionState, *, first_name: str, full: bool
    ) -> bool:
        if session.live_tools is None:
            return False
        required = [
            (
                "send_email",
                {
                    "email_addresses": ["probe@example.com"],
                    "content_message": "probe",
                },
            )
        ]
        if full:
            required.extend(
                [
                    (
                        "get_contact_id_by_contact_name",
                        {"contact_first_name": first_name},
                    ),
                    (
                        "get_contact_information",
                        {"contact_ids": ["con_probe"]},
                    ),
                ]
            )
        try:
            valid = all(
                session.live_tools.has_tool(tool_name)
                and session.live_tools.validate_arguments(tool_name, arguments)
                == arguments
                for tool_name, arguments in required
            )
            description = (
                session.live_tools.description("send_email").lstrip().casefold()
            )
            return (
                valid
                and re.match(r"requires_confirmation(?:\s*[:,]|\s*$)", description)
                is not None
            )
        except ToolArgumentValidationError:
            return False

    @staticmethod
    def _local_trip_email_goal(session: SessionState) -> Goal | None:
        if session.intent is None:
            return None
        matches = [
            goal
            for goal in session.intent.goals
            if goal.desired_outcome.get(_LOCAL_TRIP_EMAIL_MARKER) is True
        ]
        return matches[0] if len(matches) == 1 else None

    def _handle_local_trip_email_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        initial = _local_trip_email_initial_details(text)
        if initial is not None:
            identity = self._current_location_identity(session)
            if identity is None:
                return True, self._text_plan(
                    session,
                    "I could not verify the current trip origin, so I did not collect or send any travel details.",
                )
            first_name, last_name, destination_name = initial
            grounded = {
                "first_name": first_name,
                "last_name": last_name,
                "destination_name": destination_name,
            }
            self._begin_local_charging_goal(
                session,
                turn_id=turn_id,
                semantic_operation=_TRIP_RANGE_OPERATION,
                desired_outcome={
                    **grounded,
                    _LOCAL_TRIP_EMAIL_MARKER: True,
                    _LOCAL_TRIP_EMAIL_PHASE: _LOCAL_TRIP_EMAIL_INITIAL,
                    "navigation_deferred": True,
                },
                grounded_values=grounded,
                action=False,
            )
            return True, None

        context = self._validated_local_trip_email_context(session)
        normalized = _bounded_workflow_utterance(text, limit=640)
        if context is None or normalized is None:
            return False, None

        looks_like_charge_assessment = (
            re.search(r"\bhow\s+long\b", normalized, re.I) is not None
            and re.search(r"\bcharg(?:e|ing)\b", normalized, re.I) is not None
            and re.search(
                r"\b(?:another|additional)\s+charging\s+stop\b|"
                r"\bcharging\s+stop\s+along\s+the\s+way\b",
                normalized,
                re.I,
            )
            is not None
        )
        if looks_like_charge_assessment:
            selection = self._charging_selection_request(session, normalized)
            if selection is None:
                return True, self._text_plan(
                    session,
                    "I could not verify one displayed station, its available DC plug, and the requested charge range, so I did not calculate the trip update.",
                )
            station, plug, start_soc, target_soc, displayed, trip = selection
            charge_grounded: dict[str, Any] = {
                "charging_station_name": station.name,
                "target_state_of_charge": target_soc,
            }
            goal = self._begin_local_charging_goal(
                session,
                turn_id=turn_id,
                semantic_operation=_LOCAL_CHARGING_ESTIMATE_OPERATION,
                desired_outcome={
                    **charge_grounded,
                    "start_state_of_charge": start_soc,
                    _LOCAL_TRIP_EMAIL_MARKER: True,
                    _LOCAL_TRIP_EMAIL_PHASE: _LOCAL_TRIP_EMAIL_CHARGE,
                    "navigation_deferred": True,
                },
                grounded_values=charge_grounded,
                action=False,
            )
            self._apply_navigation_derived_parameters(
                session,
                goal=goal,
                parameters={
                    "charging_station_id": (
                        station.station_id,
                        (displayed,),
                        "selected_local_trip_email_station_v1",
                    ),
                    "charging_station_plug_id": (
                        plug.plug_id,
                        (displayed,),
                        "highest_available_local_trip_email_dc_plug_v1",
                    ),
                    "start_state_of_charge": (
                        start_soc,
                        (trip,),
                        "current_local_trip_email_soc_v1",
                    ),
                },
            )
            return True, None

        full_name_draft = re.search(
            r"\bdraft\s+(?:(?:a|an|the|that)\s+)?email\s+to\s+"
            r"(?P<first>[^\W\d_]{1,80})\s+(?P<last>[^\W\d_]{1,80})\b",
            normalized,
            re.IGNORECASE | re.UNICODE,
        )
        verified_full_name_draft = (
            full_name_draft is not None
            and re.search(
                r"\b(?:include|overview|details?|information|professional|friendly)\b",
                normalized,
                re.IGNORECASE,
            )
            is not None
            and re.search(
                r"\b(?:do\s+not|don['\u2019]?t|never)\s+draft\b",
                normalized,
                re.IGNORECASE,
            )
            is None
        )
        looks_like_draft = verified_full_name_draft or (
            re.search(r"\bemail\b", normalized, re.I) is not None
            and re.search(r"\b(?:mention|update|include)\b", normalized, re.I)
            is not None
            and re.search(r"\bsend\b", normalized, re.I) is not None
            and re.search(
                r"\b(?:another|additional)\s+(?:charging\s+)?stop\b",
                normalized,
                re.I,
            )
            is not None
        )
        if looks_like_draft:
            charge = self._validated_local_trip_email_charge_summary(session)
            first_name = str(context[1]["recipient_first_name"])
            last_name = str(context[1]["recipient_last_name"])
            display_name = str(context[1]["recipient_display_name"])
            named_recipient = re.search(
                r"\bemail\s+to\s+(?P<name>[^,.!?]{1,120})",
                normalized,
                re.IGNORECASE | re.UNICODE,
            )
            if (
                charge is None
                or (
                    full_name_draft is not None
                    and _argument_identifier(
                        f"{full_name_draft.group('first')} "
                        f"{full_name_draft.group('last')}"
                    )
                    != _argument_identifier(display_name)
                )
                or (
                    full_name_draft is None
                    and named_recipient is not None
                    and _argument_identifier(first_name)
                    not in _argument_identifier(named_recipient.group("name"))
                )
                or not self._trip_email_schema_available(
                    session, first_name=first_name, full=False
                )
            ):
                return True, self._text_plan(
                    session,
                    "I could not verify the complete route, charging, and recipient details, so I did not prepare an email for sending.",
                )
            grounded = {"first_name": first_name, "last_name": last_name}
            self._begin_local_charging_goal(
                session,
                turn_id=turn_id,
                semantic_operation="send_email",
                desired_outcome={
                    **grounded,
                    _TRIP_EMAIL_MARKER: True,
                    _LOCAL_TRIP_EMAIL_MARKER: True,
                    _LOCAL_TRIP_EMAIL_PHASE: _LOCAL_TRIP_EMAIL_SEND,
                },
                grounded_values=grounded,
                action=True,
            )
            return True, None

        looks_like_range = (
            re.search(r"\b(?:current|remaining)\s+range\b", normalized, re.I)
            is not None
            and re.search(r"\b(?:enough|trip|route)\b", normalized, re.I) is not None
        )
        if looks_like_range:
            destination_name = str(context[1]["destination_name"])
            grounded = {"destination_name": destination_name}
            self._begin_local_charging_goal(
                session,
                turn_id=turn_id,
                semantic_operation=_TRIP_RANGE_OPERATION,
                desired_outcome={
                    **grounded,
                    _LOCAL_TRIP_EMAIL_MARKER: True,
                    _LOCAL_TRIP_EMAIL_PHASE: _LOCAL_TRIP_EMAIL_RANGE,
                    "navigation_deferred": True,
                },
                grounded_values=grounded,
                action=False,
            )
            return True, None
        return False, None

    def _begin_local_charging_goal(
        self,
        session: SessionState,
        *,
        turn_id: str,
        semantic_operation: str,
        desired_outcome: Mapping[str, Any],
        grounded_values: Mapping[str, Any],
        action: bool,
    ) -> Goal:
        digest = hashlib.sha256(
            f"{turn_id}\0{semantic_operation}\0{sorted(desired_outcome)}".encode()
        ).hexdigest()
        goal = Goal(
            goal_id=f"goal-local-charging-{digest[:12]}",
            semantic_operation=semantic_operation,
            desired_outcome=dict(desired_outcome),
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=action,
            goals=[goal],
            explicit_slots=dict(grounded_values),
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.ACTION if action else IntentKind.INFORMATION,
        )
        session.authorized_action_goal_ids = {goal.goal_id} if action else set()
        session.grounded_desired_values_by_goal = {goal.goal_id: dict(grounded_values)}
        session.grounded_value_sources_by_goal = {
            goal.goal_id: {name: turn_id for name in grounded_values}
        }
        session.derived_value_evidence_by_goal = {}
        session.relative_fan_speed_deltas_by_goal = {}
        session.relative_climate_temperature_deltas_by_goal = {}
        session.relative_seat_heating_deltas_by_goal = {}
        session.occupied_seat_heating_goal_ids = set()
        session.climate_sync_source_zones_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return goal

    @staticmethod
    def _current_location_identity(
        session: SessionState,
    ) -> tuple[str, str] | None:
        current = getattr(session.compiled_policy, "current_location", None)
        location_id = current.get("id") if isinstance(current, Mapping) else None
        name = current.get("name") if isinstance(current, Mapping) else None
        if (
            not isinstance(location_id, str)
            or not location_id.startswith("loc_")
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(location_id) is None
            or not isinstance(name, str)
            or not CARGuardOrchestrator._safe_poi_display_label(name, 120)
        ):
            return None
        return location_id, name.strip()

    @staticmethod
    def _current_datetime_parts(
        session: SessionState,
    ) -> tuple[int, int, int, int, int] | None:
        current = getattr(session.compiled_policy, "current_datetime", None)
        if not isinstance(current, Mapping):
            return None
        year = current.get("year")
        month = current.get("month")
        day = current.get("day")
        hour = current.get("hour")
        minute = current.get("minute")
        if (
            type(year) is not int
            or type(month) is not int
            or type(day) is not int
            or type(hour) is not int
            or type(minute) is not int
        ):
            return None
        values = (year, month, day, hour, minute)
        if (
            not 1 <= values[1] <= 12
            or not 1 <= values[2] <= 31
            or not 0 <= values[3] <= 23
            or not 0 <= values[4] <= 59
        ):
            return None
        return values[0], values[1], values[2], values[3], values[4]

    def _handle_meeting_charging_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        buffers = _meeting_charging_initial_buffers(text)
        if buffers is not None:
            identity = self._current_location_identity(session)
            current_datetime = self._current_datetime_parts(session)
            if identity is None or current_datetime is None:
                return True, self._text_plan(
                    session,
                    "I could not verify the current location and time, so I did not plan a charging stop.",
                )
            arrival_buffer, range_buffer = buffers
            grounded = {
                "arrival_buffer_minutes": arrival_buffer,
                "range_buffer_km": range_buffer,
            }
            self._begin_local_charging_goal(
                session,
                turn_id=turn_id,
                semantic_operation=_TRIP_RANGE_OPERATION,
                desired_outcome={
                    **grounded,
                    _MEETING_CHARGING_MARKER: True,
                    _MEETING_CHARGING_PHASE: _MEETING_CHARGING_DISCOVERY,
                },
                grounded_values=grounded,
                action=False,
            )
            return True, None

        normalized = _bounded_workflow_utterance(text, limit=640)
        accepts_occupied_selection = (
            normalized is not None
            and _meeting_charging_accepts_occupied_selection(normalized)
        )
        looks_like_selection = (
            normalized is not None
            and re.search(r"\boccupied\b|\bcurrent\s+availability\b", normalized, re.I)
            is not None
            and (
                re.search(r"\bcalculation\b", normalized, re.I) is not None
                or accepts_occupied_selection
            )
            and _meeting_charging_explicit_selection(normalized)
            and re.search(r"\b(?:fastest|\d{1,4}\s*kW)\b", normalized, re.I) is not None
        )
        lower_bound = (
            None
            if normalized is None
            else re.search(
                r"\b(?:more\s+than|greater\s+than|over)\s+"
                r"(?P<value>\d{1,4})\s+minutes?\b",
                normalized,
                re.IGNORECASE,
            )
        )
        upper_bound = (
            None
            if normalized is None
            else re.search(
                r"\b(?:less\s+than|under|below)\s+"
                r"(?P<value>\d{1,4})\s+minutes?\b",
                normalized,
                re.IGNORECASE,
            )
        )
        between_bounds = (
            None
            if normalized is None
            else re.search(
                r"\bbetween\s+(?P<lower>\d{1,4})\s+and\s+"
                r"(?P<upper>\d{1,4})\s+minutes?\b",
                normalized,
                re.IGNORECASE,
            )
        )
        reported_maximum = (
            None
            if normalized is None
            else re.search(
                r"\bmaximum\s+charging\s+time\s+is\s+"
                r"(?P<value>\d{1,4})\s+minutes?\b",
                normalized,
                re.IGNORECASE,
            )
        )
        looks_like_call = (
            normalized is not None
            and re.search(r"\bmaximum\s+charging\s+time\b", normalized, re.I)
            is not None
            and _meeting_charging_explicit_action_request(
                normalized, action_pattern=_MEETING_CHARGING_CALL_ACTION
            )
            and re.search(r"\b(?:provider|station)\b", normalized, re.I) is not None
            and re.search(r"\breserve\b", normalized, re.I) is not None
            and (
                (lower_bound is not None and upper_bound is not None)
                or between_bounds is not None
                or reported_maximum is not None
            )
        )
        if looks_like_call and normalized is not None:
            completion = self._validated_meeting_charging_navigation_completion(session)
            if completion is None:
                return True, self._text_plan(
                    session,
                    "I am waiting for a verified successful navigation result, so I did not place the call.",
                )
            if between_bounds is not None:
                lower = int(between_bounds.group("lower"))
                upper = int(between_bounds.group("upper"))
            elif lower_bound is not None and upper_bound is not None:
                assert lower_bound is not None and upper_bound is not None
                lower = int(lower_bound.group("value"))
                upper = int(upper_bound.group("value"))
            else:
                lower = upper = -1
            values = completion[1]
            maximum = values.get("maximum_charging_minutes")
            phone_number = values.get("charging_station_phone_number")
            reported_value = (
                int(reported_maximum.group("value"))
                if reported_maximum is not None
                else None
            )
            bounded_condition = (
                reported_value is None
                and 0 <= lower < upper <= 1440
                and type(maximum) is int
                and lower < maximum < upper
            )
            reported_condition = (
                type(reported_value) is int
                and type(maximum) is int
                and reported_value == maximum
            )
            if (
                type(maximum) is not int
                or not (bounded_condition or reported_condition)
                or not isinstance(phone_number, str)
                or _POI_PHONE_PATTERN.fullmatch(phone_number) is None
            ):
                return True, self._text_plan(
                    session,
                    "The verified maximum charging time did not satisfy that call condition, so I did not place the call.",
                )
            call_grounded: dict[str, Any] = {"call_purpose": "reserve_charging_plug"}
            if reported_condition:
                call_grounded.update(
                    call_condition="reported_maximum_matches",
                    reported_maximum_minutes=reported_value,
                )
            else:
                call_grounded.update(
                    call_condition="maximum_within_open_interval",
                    maximum_lower_bound_minutes=lower,
                    maximum_upper_bound_minutes=upper,
                )
            goal = self._begin_local_charging_goal(
                session,
                turn_id=turn_id,
                semantic_operation=_MEETING_CHARGING_CALL_OPERATION,
                desired_outcome={
                    **call_grounded,
                    _MEETING_CHARGING_MARKER: True,
                    _MEETING_CHARGING_PHASE: _MEETING_CHARGING_CALL,
                },
                grounded_values=call_grounded,
                action=True,
            )
            self._apply_navigation_derived_parameters(
                session,
                goal=goal,
                parameters={
                    "phone_number": (
                        phone_number,
                        (completion[0],),
                        "meeting_charging_provider_phone_v1",
                    )
                },
            )
            return True, None

        navigation_condition = (
            None
            if normalized is None
            else re.search(
                r"\bminimum\s+charging\s+time\b[^.!?]{0,80}"
                r"\b(?:under|less\s+than)\s+(?P<threshold>\d{1,4})\s+minutes?\b",
                normalized,
                re.IGNORECASE,
            )
        )
        looks_like_navigation = (
            normalized is not None
            and _meeting_charging_explicit_action_request(
                normalized, action_pattern=_MEETING_CHARGING_NAVIGATION_ACTION
            )
            and re.search(r"\b(?:and\s+)?then\b", normalized, re.IGNORECASE) is not None
            and _MEETING_CHARGING_FASTEST_ALL_ROUTES.search(normalized) is not None
        )
        if (
            looks_like_navigation
            and not looks_like_selection
            and normalized is not None
        ):
            analysis = self._validated_meeting_charging_analysis(session)
            if analysis is None:
                return True, self._text_plan(
                    session,
                    "I could not verify the charging calculation, so I did not start navigation.",
                )
            values = analysis[1]
            station_name = values.get("charging_station_name")
            meeting_name = values.get("meeting_location_name")
            minimum = values.get("minimum_charging_minutes")
            threshold = (
                int(navigation_condition.group("threshold"))
                if navigation_condition is not None
                else None
            )
            ordered_references = (
                isinstance(station_name, str)
                and isinstance(meeting_name, str)
                and _meeting_charging_has_ordered_route_references(
                    normalized,
                    station_name=station_name,
                    meeting_name=meeting_name,
                )
            )
            condition_matches = type(minimum) is int and (
                threshold is None or (0 < threshold <= 1440 and minimum < threshold)
            )
            if not condition_matches or not ordered_references:
                return True, self._text_plan(
                    session,
                    "The verified charging condition or route order did not match, so I did not start navigation.",
                )
            route_ids = [
                values.get("first_segment_route_id"),
                values.get("second_segment_route_id"),
            ]
            if (
                any(not isinstance(route_id, str) for route_id in route_ids)
                or len(set(route_ids)) != 2
            ):
                return True, self._text_plan(
                    session,
                    "I could not verify both route segments, so I did not start navigation.",
                )
            navigation_grounded: dict[str, Any] = {
                "navigation_condition": (
                    _MEETING_CHARGING_THRESHOLD_CONDITION
                    if threshold is not None
                    else _MEETING_CHARGING_UNCONDITIONAL_NAVIGATION
                ),
                "route_selection": "fastest",
                "stop_order": "charger_then_meeting",
            }
            if threshold is not None:
                navigation_grounded["minimum_threshold_minutes"] = threshold
            goal = self._begin_local_charging_goal(
                session,
                turn_id=turn_id,
                semantic_operation=_MEETING_CHARGING_NAVIGATION_OPERATION,
                desired_outcome={
                    **navigation_grounded,
                    _MEETING_CHARGING_MARKER: True,
                    _MEETING_CHARGING_PHASE: _MEETING_CHARGING_NAVIGATION,
                },
                grounded_values=navigation_grounded,
                action=True,
            )
            self._apply_navigation_derived_parameters(
                session,
                goal=goal,
                parameters={
                    "location": (
                        meeting_name,
                        (analysis[0],),
                        "meeting_charging_destination_name_v1",
                    ),
                    "selected_destination_name": (
                        meeting_name,
                        (analysis[0],),
                        "meeting_charging_selected_destination_v1",
                    ),
                    "selected_route_label": (
                        "fastest route for both segments",
                        (analysis[0],),
                        "meeting_charging_selected_routes_v1",
                    ),
                    "start_id": (
                        values["current_location_id"],
                        (analysis[0],),
                        "meeting_charging_current_start_v1",
                    ),
                    "destination_id": (
                        values["meeting_location_id"],
                        (analysis[0],),
                        "meeting_charging_destination_id_v1",
                    ),
                    "route_ids": (
                        route_ids,
                        (analysis[0],),
                        "meeting_charging_ordered_routes_v1",
                    ),
                },
            )
            return True, None

        if not looks_like_selection or normalized is None:
            return False, None
        discovery = self._validated_meeting_charging_discovery(session)
        if discovery is None:
            return True, self._text_plan(
                session,
                "I could not verify the current meeting and charger choices, so I did not calculate a charging window.",
            )
        values = discovery[1]
        station_name = values.get("charging_station_name")
        plug_power = values.get("charging_station_plug_power_kw")
        availability = values.get("charging_station_plug_availability")
        station_reference = isinstance(station_name, str) and (
            _contains_option_phrase(normalized, station_name)
            or re.search(
                r"\b(?:that|the)\s+(?:charging\s+)?(?:station|charger)\b|"
                r"\bfastest\s+(?:charger|plug)\b",
                normalized,
                re.IGNORECASE,
            )
            is not None
        )
        if (
            not isinstance(station_name, str)
            or not isinstance(plug_power, str)
            or availability != "occupied"
            or not station_reference
            or re.search(rf"\b{re.escape(plug_power)}\s*kW\b", normalized, re.I) is None
            or not accepts_occupied_selection
        ):
            return True, self._text_plan(
                session,
                "Please select one exact displayed plug and explicitly accept its current availability before I calculate the charging window.",
            )
        selection_grounded: dict[str, Any] = {
            "selected_charging_station_name": station_name,
            "selected_charging_plug_power_kw": plug_power,
            "accepted_plug_availability": "occupied",
            "route_selection": "fastest",
        }
        if looks_like_navigation:
            meeting_name = values.get("meeting_location_name")
            meeting_reference = isinstance(meeting_name, str) and (
                _contains_option_phrase(normalized, meeting_name)
                or re.search(
                    r"\b(?:my|the)\s+meeting\s+location\b",
                    normalized,
                    re.IGNORECASE,
                )
                is not None
            )
            if navigation_condition is None or not meeting_reference:
                return True, self._text_plan(
                    session,
                    "I could not verify the conditional route order, so I did not start navigation.",
                )
            selection_grounded["minimum_threshold_minutes"] = int(
                navigation_condition.group("threshold")
            )
            selection_grounded["navigation_condition"] = (
                _MEETING_CHARGING_THRESHOLD_CONDITION
            )
            selection_grounded["navigation_requested_after_calculation"] = True
        self._begin_local_charging_goal(
            session,
            turn_id=turn_id,
            semantic_operation=_TRIP_RANGE_OPERATION,
            desired_outcome={
                **selection_grounded,
                _MEETING_CHARGING_MARKER: True,
                _MEETING_CHARGING_PHASE: _MEETING_CHARGING_ANALYSIS,
            },
            grounded_values=selection_grounded,
            action=False,
        )
        return True, None

    def _begin_meeting_charging_navigation_goal(
        self,
        session: SessionState,
        *,
        turn_id: str,
        analysis: tuple[Evidence, Mapping[str, Any]],
        threshold: int,
    ) -> Goal | None:
        evidence, values = analysis
        route_ids = [
            values.get("first_segment_route_id"),
            values.get("second_segment_route_id"),
        ]
        meeting_name = values.get("meeting_location_name")
        current_location_id = values.get("current_location_id")
        meeting_location_id = values.get("meeting_location_id")
        minimum = values.get("minimum_charging_minutes")
        if (
            type(minimum) is not int
            or type(threshold) is not int
            or not 0 < threshold <= 1440
            or minimum >= threshold
            or not isinstance(meeting_name, str)
            or not isinstance(current_location_id, str)
            or not isinstance(meeting_location_id, str)
            or any(not isinstance(route_id, str) for route_id in route_ids)
            or len(set(route_ids)) != 2
        ):
            return None
        grounded = {
            "minimum_threshold_minutes": threshold,
            "navigation_condition": _MEETING_CHARGING_THRESHOLD_CONDITION,
            "route_selection": "fastest",
            "stop_order": "charger_then_meeting",
        }
        goal = self._begin_local_charging_goal(
            session,
            turn_id=turn_id,
            semantic_operation=_MEETING_CHARGING_NAVIGATION_OPERATION,
            desired_outcome={
                **grounded,
                _MEETING_CHARGING_MARKER: True,
                _MEETING_CHARGING_PHASE: _MEETING_CHARGING_NAVIGATION,
            },
            grounded_values=grounded,
            action=True,
        )
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters={
                "location": (
                    meeting_name,
                    (evidence,),
                    "meeting_charging_destination_name_v1",
                ),
                "selected_destination_name": (
                    meeting_name,
                    (evidence,),
                    "meeting_charging_selected_destination_v1",
                ),
                "selected_route_label": (
                    "fastest route for both segments",
                    (evidence,),
                    "meeting_charging_selected_routes_v1",
                ),
                "start_id": (
                    current_location_id,
                    (evidence,),
                    "meeting_charging_current_start_v1",
                ),
                "destination_id": (
                    meeting_location_id,
                    (evidence,),
                    "meeting_charging_destination_id_v1",
                ),
                "route_ids": (
                    route_ids,
                    (evidence,),
                    "meeting_charging_ordered_routes_v1",
                ),
            },
        )
        return goal

    def _handle_local_charging_search_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        normalized = _bounded_workflow_utterance(text, limit=420)
        if (
            normalized is None
            or re.search(r"\b(?:find|search(?:\s+for)?)\b", normalized, re.I) is None
            or re.search(r"\bcharg(?:er|ers|ing\s+stations?)\b", normalized, re.I)
            is None
            or re.search(
                r"\b(?:nearby|near\s+me|current\s+location|here\s+in\s+"
                r"[^,.!?]{1,120})\b",
                normalized,
                re.I,
            )
            is None
        ):
            return False, None
        if (
            re.search(
                r"\b(?:do\s+not|don['\u2019]?t|never)\s+"
                r"(?:want\s+to\s+)?(?:find|search(?:\s+for)?)\b",
                normalized,
                re.IGNORECASE,
            )
            is not None
        ):
            return True, self._text_plan(
                session,
                "Okay. I did not search for another charging station.",
            )
        along_route = re.search(r"\balong\s+(?:the\s+)?route\b", normalized, re.I)
        rejects_route = re.search(
            r"\b(?:not|don['\u2019]?t\s+(?:search|look))\b[^.!?]{0,40}"
            r"\balong\s+(?:the\s+)?route\b",
            normalized,
            re.I,
        )
        if along_route is not None and rejects_route is None:
            return False, None
        identity = self._current_location_identity(session)
        summary = self._validated_trip_route_summary(
            session, require_range_shortfall=False
        )
        if identity is None or summary is None:
            return True, self._text_plan(
                session,
                "I could not verify the current trip and location, so I did not search for a charging station.",
            )
        location_id, current_name = identity
        location_match = re.search(
            r"\b(?:nearby\s+in|here\s+in)\s+"
            r"(?P<location>[^,.!?]{1,120}?)"
            r"(?=\s+(?:first|before)\b|[,!?]|$)",
            normalized,
            re.IGNORECASE | re.UNICODE,
        )
        requested_name = (
            " ".join(location_match.group("location").strip().split())
            if location_match is not None
            else current_name
        )
        if _argument_identifier(requested_name) != _argument_identifier(current_name):
            return True, self._text_plan(
                session,
                "That request did not match the verified current location, so I did not search.",
            )
        grounded = {
            "location_name": current_name,
            "category": "charging_stations",
            "filters": ["charging_stations::has_available_plug"],
        }
        desired = {
            **grounded,
            "current_location_id": location_id,
            "navigation_deferred": True,
        }
        self._begin_local_charging_goal(
            session,
            turn_id=turn_id,
            semantic_operation=_LOCAL_CHARGING_SEARCH_OPERATION,
            desired_outcome=desired,
            grounded_values=grounded,
            action=False,
        )
        return True, None

    @classmethod
    def _local_charging_options_from_evidence(
        cls, evidence: Evidence, *, location_id: str
    ) -> tuple[LocalChargingStationOption, ...] | None:
        rows = evidence.value
        if not isinstance(rows, list) or not 1 <= len(rows) <= 20:
            return None
        options: list[LocalChargingStationOption] = []
        station_ids: set[str] = set()
        station_names: set[str] = set()
        plug_ids: set[str] = set()
        for row in rows:
            if not isinstance(row, Mapping):
                return None
            station_id = row.get("id")
            name = row.get("name")
            phone = row.get("phone_number")
            opening = row.get("opening_hours")
            position = row.get("position")
            longitude = (
                position.get("longitude") if isinstance(position, Mapping) else None
            )
            latitude = (
                position.get("latitude") if isinstance(position, Mapping) else None
            )
            plugs = row.get("charging_plugs")
            if (
                not isinstance(station_id, str)
                or not station_id.startswith("poi_")
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(station_id) is None
                or station_id in station_ids
                or not isinstance(name, str)
                or not cls._safe_poi_display_label(name, 120)
                or not isinstance(phone, str)
                or _POI_PHONE_PATTERN.fullmatch(phone) is None
                or not isinstance(opening, str)
                or cls._poi_opening_hours_minutes(opening) is None
                or row.get("category") != "charging_stations"
                or row.get("corresponding_location_id") != location_id
                or isinstance(longitude, bool)
                or isinstance(latitude, bool)
                or not isinstance(longitude, (int, float, Decimal))
                or not isinstance(latitude, (int, float, Decimal))
                or not isinstance(plugs, list)
                or not 1 <= len(plugs) <= 20
            ):
                return None
            try:
                longitude_value = Decimal(str(longitude))
                latitude_value = Decimal(str(latitude))
            except (InvalidOperation, TypeError, ValueError):
                return None
            if (
                not longitude_value.is_finite()
                or not latitude_value.is_finite()
                or not -180 <= longitude_value <= 180
                or not -90 <= latitude_value <= 90
            ):
                return None
            normalized_name = " ".join(
                unicodedata.normalize("NFKC", name).casefold().split()
            )
            if not normalized_name or normalized_name in station_names:
                return None
            parsed_plugs: list[ChargingPlugOption] = []
            for plug in plugs:
                if not isinstance(plug, Mapping):
                    return None
                plug_id = plug.get("plug_id")
                power_type = plug.get("power_type")
                power = plug.get("power_kw")
                availability = plug.get("availability")
                if (
                    not isinstance(plug_id, str)
                    or _CHARGING_PLUG_ID_PATTERN.fullmatch(plug_id) is None
                    or plug_id in plug_ids
                    or not isinstance(power_type, str)
                    or power_type.upper() not in {"AC", "DC"}
                    or isinstance(power, bool)
                    or not isinstance(power, (int, float, Decimal))
                    or not isinstance(availability, str)
                ):
                    return None
                try:
                    power_value = Decimal(str(power))
                except (InvalidOperation, TypeError, ValueError):
                    return None
                availability_value = _argument_identifier(availability)
                if (
                    not power_value.is_finite()
                    or not 0 < power_value <= 1000
                    or availability_value not in _LOCAL_CHARGING_AVAILABILITY_VALUES
                ):
                    return None
                plug_ids.add(plug_id)
                parsed_plugs.append(
                    ChargingPlugOption(
                        plug_id=plug_id,
                        power_type=power_type.upper(),
                        power_kw=power_value,
                        availability=availability_value,
                    )
                )
            if not any(plug.availability == "available" for plug in parsed_plugs):
                return None
            station_ids.add(station_id)
            station_names.add(normalized_name)
            options.append(
                LocalChargingStationOption(
                    station_id=station_id,
                    name=name.strip(),
                    normalized_name=normalized_name,
                    location_id=location_id,
                    phone_number=phone,
                    opening_hours=opening,
                    plugs=tuple(parsed_plugs),
                )
            )
        return tuple(options)

    @staticmethod
    def _local_charging_options_value(
        options: Sequence[LocalChargingStationOption],
    ) -> list[dict[str, Any]]:
        return [
            {
                "station_id": option.station_id,
                "name": option.name,
                "location_id": option.location_id,
                "phone_number": option.phone_number,
                "opening_hours": option.opening_hours,
                "plugs": [
                    {
                        "plug_id": plug.plug_id,
                        "power_type": plug.power_type,
                        "power_kw": format(plug.power_kw.normalize(), "f"),
                        "availability": plug.availability,
                    }
                    for plug in option.plugs
                ],
            }
            for option in options
        ]

    def _store_displayed_local_charging_options(
        self,
        session: SessionState,
        *,
        goal: Goal,
        raw_evidence: Evidence,
        trip_evidence: Evidence,
        location_id: str,
        options: Sequence[LocalChargingStationOption],
    ) -> Evidence | None:
        parent_ids = [raw_evidence.evidence_id, trip_evidence.evidence_id]
        if any(parent_id is None for parent_id in parent_ids):
            return None
        observation = Evidence(
            proposition="displayed_local_charging_options",
            value={
                "location_id": location_id,
                "navigation_deferred": True,
                "stations": self._local_charging_options_value(options),
            },
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=f"local-charging-display-{goal.goal_id}",
            confidence=min(raw_evidence.confidence, trip_evidence.confidence),
            derived_from=[parent_id for parent_id in parent_ids if parent_id],
            derivation="validated_local_charging_display_v1",
        )
        session.evidence.add(observation)
        stored = session.evidence.latest_for_proposition(
            observation.proposition, current_state_only=True
        )
        return stored[-1] if stored else None

    def _validated_displayed_local_charging_options(
        self, session: SessionState
    ) -> tuple[Evidence, tuple[LocalChargingStationOption, ...]] | None:
        displayed = session.evidence.latest_for_proposition(
            "displayed_local_charging_options", current_state_only=True
        )
        trip = self._validated_trip_route_summary(
            session, require_range_shortfall=False
        )
        if not displayed or trip is None:
            return None
        evidence = displayed[-1]
        value = evidence.value
        if (
            evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.DERIVED
            or evidence.derivation != "validated_local_charging_display_v1"
            or not isinstance(value, Mapping)
            or value.get("navigation_deferred") is not True
            or evidence.state_version != session.evidence.current_state_version
        ):
            return None
        parents = [
            session.evidence.evidence.get(item) for item in evidence.derived_from
        ]
        if len(parents) != 2 or any(parent is None for parent in parents):
            return None
        by_proposition = {
            parent.proposition: parent for parent in parents if parent is not None
        }
        raw = by_proposition.get("local_charging_station_candidates")
        trip_evidence, trip_values = trip
        location_id = value.get("location_id")
        if (
            raw is None
            or by_proposition.get("trip_route_assessment_summary") is not trip_evidence
            or not isinstance(location_id, str)
            or trip_values.get("start_id") != location_id
            or raw.source_kind is not EvidenceSourceKind.TOOL
            or raw.status is not EvidenceStatus.KNOWN
            or raw.state_version != session.evidence.current_state_version
        ):
            return None
        options = self._local_charging_options_from_evidence(
            raw, location_id=location_id
        )
        if options is None or value.get(
            "stations"
        ) != self._local_charging_options_value(options):
            return None
        latest_reads = [
            result
            for result in session.successful_read_results
            if result.tool_name == "search_poi_at_location"
            and result.state_version == session.evidence.current_state_version
        ]
        if (
            not latest_reads
            or latest_reads[-1].call_id != raw.source_tool_call_id
            or latest_reads[-1].source_turn_id != raw.source_turn_id
            or not _argument_value_matches_binding(
                latest_reads[-1].arguments,
                {
                    "location_id": location_id,
                    "category_poi": "charging_stations",
                    "filters": ["charging_stations::has_available_plug"],
                },
            )
        ):
            return None
        return evidence, options

    @staticmethod
    def _highest_available_dc_plug(
        station: LocalChargingStationOption,
    ) -> ChargingPlugOption | None:
        candidates = [
            plug
            for plug in station.plugs
            if plug.power_type == "DC" and plug.availability == "available"
        ]
        if not candidates:
            return None
        maximum = max(plug.power_kw for plug in candidates)
        selected = [plug for plug in candidates if plug.power_kw == maximum]
        return selected[0] if len(selected) == 1 else None

    def _charging_selection_request(
        self, session: SessionState, text: str
    ) -> (
        tuple[
            LocalChargingStationOption, ChargingPlugOption, int, int, Evidence, Evidence
        ]
        | None
    ):
        normalized = _bounded_workflow_utterance(text, limit=420)
        displayed = self._validated_displayed_local_charging_options(session)
        trip = self._validated_trip_route_summary(
            session, require_range_shortfall=False
        )
        if normalized is None or displayed is None or trip is None:
            return None
        if (
            re.search(r"\bhow\s+long\b", normalized, re.I) is None
            or re.search(r"\bcharg(?:e|ing)\b", normalized, re.I) is None
            or re.search(
                r"\b(?:set\s+up|start|begin)\s+(?:the\s+)?navigation\b|\bnavigate\b",
                normalized,
                re.I,
            )
            is not None
        ):
            return None
        target_match = re.search(
            r"\b(?:to|until)\s+(?P<target>\d{1,3})\s*"
            r"(?:percent\b|%(?!\w))",
            normalized,
            re.I,
        )
        start_match = re.search(
            r"\bfrom\s+(?:my\s+current\s+)?(?P<start>\d{1,3})\s*"
            r"(?:percent\b|%(?!\w))",
            normalized,
            re.I,
        )
        current_match = re.search(
            r"\b(?:i(?:['\u2019]?m|\s+am)\s+(?:currently\s+)?at|"
            r"my\s+(?:current\s+)?(?:charge|battery|state\s+of\s+charge)\s+"
            r"(?:is|at))\s*(?P<current>\d{1,3})\s*"
            r"(?:percent\b|%(?!\w))",
            normalized,
            re.I,
        )
        if target_match is None:
            return None
        matches = [
            option
            for option in displayed[1]
            if _contains_option_phrase(normalized, option.name)
        ]
        if (
            len(matches) != 1
            or re.search(
                r"\b(?:choose|go\s+to|go\s+with|select|use|at)\b",
                normalized,
                re.I,
            )
            is None
        ):
            return None
        state_of_charge = trip[1].get("state_of_charge")
        try:
            current_soc = Decimal(str(state_of_charge))
            target_soc = int(target_match.group("target"))
            explicit_starts = {
                int(match.group(group_name))
                for match, group_name in (
                    (start_match, "start"),
                    (current_match, "current"),
                )
                if match is not None
            }
            if len(explicit_starts) > 1:
                return None
            start_soc = next(iter(explicit_starts), int(current_soc))
        except (InvalidOperation, TypeError, ValueError):
            return None
        if (
            not current_soc.is_finite()
            or current_soc != int(current_soc)
            or start_soc != int(current_soc)
            or not 0 <= start_soc < target_soc <= 100
        ):
            return None
        plug = self._highest_available_dc_plug(matches[0])
        if plug is None:
            return None
        return matches[0], plug, start_soc, target_soc, displayed[0], trip[0]

    def _handle_local_charging_selection_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        normalized = _bounded_workflow_utterance(text, limit=420)
        looks_like_request = (
            normalized is not None
            and re.search(r"\bhow\s+long\b", normalized, re.I) is not None
            and re.search(r"\bcharg(?:e|ing)\b", normalized, re.I) is not None
        )
        if not looks_like_request:
            return False, None
        selection = self._charging_selection_request(session, text)
        if selection is None:
            return True, self._text_plan(
                session,
                "I could not verify one displayed station, an available DC plug, and the requested charge range, so I did not calculate it.",
            )
        station, plug, start_soc, target_soc, displayed, trip = selection
        explicit = {
            "charging_station_name": station.name,
            "start_state_of_charge": start_soc,
            "target_state_of_charge": target_soc,
        }
        goal = self._begin_local_charging_goal(
            session,
            turn_id=turn_id,
            semantic_operation=_LOCAL_CHARGING_ESTIMATE_OPERATION,
            desired_outcome={**explicit, "navigation_deferred": True},
            grounded_values=explicit,
            action=False,
        )
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters={
                "charging_station_id": (
                    station.station_id,
                    (displayed,),
                    "selected_displayed_charging_station_v1",
                ),
                "charging_station_plug_id": (
                    plug.plug_id,
                    (displayed,),
                    "highest_available_dc_plug_v1",
                ),
                "current_location_id": (
                    station.location_id,
                    (trip,),
                    "compiled_current_location_for_charging_route_v1",
                ),
            },
        )
        return True, None

    @staticmethod
    def _charging_duration_minutes(
        value: Any, *, start_soc: int, target_soc: int
    ) -> int | None:
        expected_key = f"time_from_{start_soc}_until_{target_soc}_percent_soc"
        if not isinstance(value, Mapping) or set(value) != {expected_key}:
            return None
        raw = value.get(expected_key)
        if not isinstance(raw, str):
            return None
        match = re.fullmatch(
            r"\s*(?P<minutes>\d{1,4})\s*(?:min|minutes?)\s*", raw, re.I
        )
        if match is None:
            return None
        minutes = int(match.group("minutes"))
        return minutes if 0 < minutes <= 1440 else None

    @staticmethod
    def _selected_local_charging_plan_value(
        *,
        station: LocalChargingStationOption,
        plug: ChargingPlugOption,
        destination_name: str,
        destination_id: str,
        first_route_id: str,
        start_soc: int,
        target_soc: int,
        duration_minutes: int,
    ) -> dict[str, Any]:
        return {
            "current_location_id": station.location_id,
            "charging_station_id": station.station_id,
            "charging_station_name": station.name,
            "charging_station_plug_id": plug.plug_id,
            "charging_station_plug_power_kw": format(plug.power_kw.normalize(), "f"),
            "destination_name": destination_name,
            "destination_id": destination_id,
            "first_segment_route_id": first_route_id,
            "start_state_of_charge": start_soc,
            "target_state_of_charge": target_soc,
            "charging_duration_minutes": duration_minutes,
            "navigation_deferred": True,
        }

    def _store_selected_local_charging_plan(
        self,
        session: SessionState,
        *,
        goal: Goal,
        station: LocalChargingStationOption,
        plug: ChargingPlugOption,
        destination_name: str,
        destination_id: str,
        first_route_id: str,
        start_soc: int,
        target_soc: int,
        duration_minutes: int,
        displayed_evidence: Evidence,
        trip_evidence: Evidence,
        route_evidence: Evidence,
        calculation_evidence: Evidence,
    ) -> Evidence | None:
        parents = (
            displayed_evidence,
            trip_evidence,
            route_evidence,
            calculation_evidence,
        )
        parent_ids = [parent.evidence_id for parent in parents]
        if any(parent_id is None for parent_id in parent_ids):
            return None
        observation = Evidence(
            proposition="selected_local_charging_plan",
            value=self._selected_local_charging_plan_value(
                station=station,
                plug=plug,
                destination_name=destination_name,
                destination_id=destination_id,
                first_route_id=first_route_id,
                start_soc=start_soc,
                target_soc=target_soc,
                duration_minutes=duration_minutes,
            ),
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=f"selected-local-charging-plan-{goal.goal_id}",
            confidence=min(parent.confidence for parent in parents),
            derived_from=[parent_id for parent_id in parent_ids if parent_id],
            derivation="validated_selected_local_charging_plan_v1",
        )
        session.evidence.add(observation)
        stored = session.evidence.latest_for_proposition(
            observation.proposition, current_state_only=True
        )
        return stored[-1] if stored else None

    def _validated_selected_local_charging_plan(
        self, session: SessionState
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        candidates = session.evidence.latest_for_proposition(
            "selected_local_charging_plan", current_state_only=True
        )
        displayed = self._validated_displayed_local_charging_options(session)
        trip = self._validated_trip_route_summary(
            session, require_range_shortfall=False
        )
        if not candidates or displayed is None or trip is None:
            return None
        evidence = candidates[-1]
        values = evidence.value
        if (
            evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.DERIVED
            or evidence.derivation != "validated_selected_local_charging_plan_v1"
            or evidence.state_version != session.evidence.current_state_version
            or not isinstance(values, Mapping)
            or values.get("navigation_deferred") is not True
        ):
            return None
        parents = [
            session.evidence.evidence.get(item) for item in evidence.derived_from
        ]
        if len(parents) != 4 or any(parent is None for parent in parents):
            return None
        by_proposition = {
            parent.proposition: parent for parent in parents if parent is not None
        }
        route_evidence = by_proposition.get("local_charging_first_segment_routes")
        calculation_evidence = by_proposition.get("local_charging_time_result")
        if (
            by_proposition.get("displayed_local_charging_options") is not displayed[0]
            or by_proposition.get("trip_route_assessment_summary") is not trip[0]
            or route_evidence is None
            or calculation_evidence is None
            or route_evidence.source_kind is not EvidenceSourceKind.TOOL
            or calculation_evidence.source_kind is not EvidenceSourceKind.TOOL
            or route_evidence.state_version != session.evidence.current_state_version
            or calculation_evidence.state_version
            != session.evidence.current_state_version
        ):
            return None
        station_matches = [
            station
            for station in displayed[1]
            if station.station_id == values.get("charging_station_id")
            and station.name == values.get("charging_station_name")
        ]
        if len(station_matches) != 1:
            return None
        station = station_matches[0]
        plug = self._highest_available_dc_plug(station)
        start_soc = values.get("start_state_of_charge")
        target_soc = values.get("target_state_of_charge")
        destination_name = trip[1].get("destination_name")
        destination_id = trip[1].get("destination_id")
        if (
            plug is None
            or type(start_soc) is not int
            or type(target_soc) is not int
            or not isinstance(destination_name, str)
            or not isinstance(destination_id, str)
            or values.get("charging_station_plug_id") != plug.plug_id
        ):
            return None
        options = self._conditional_route_options_from_evidence(
            route_evidence,
            start_id=station.location_id,
            destination_id=station.station_id,
        )
        fastest = (
            []
            if options is None
            else [option for option in options if "fastest" in option.aliases]
        )
        duration = self._charging_duration_minutes(
            calculation_evidence.value,
            start_soc=start_soc,
            target_soc=target_soc,
        )
        if len(fastest) != 1 or duration is None:
            return None
        route_reads = [
            result
            for result in session.successful_read_results
            if result.call_id == route_evidence.source_tool_call_id
            and result.source_turn_id == route_evidence.source_turn_id
            and result.tool_name == "get_routes_from_start_to_destination"
            and _argument_value_matches_binding(
                result.arguments,
                {
                    "start_id": station.location_id,
                    "destination_id": station.station_id,
                },
            )
        ]
        calculation_reads = [
            result
            for result in session.successful_read_results
            if result.call_id == calculation_evidence.source_tool_call_id
            and result.source_turn_id == calculation_evidence.source_turn_id
            and result.tool_name == "calculate_charging_time_by_soc"
            and _argument_value_matches_binding(
                result.arguments,
                {
                    "charging_station_id": station.station_id,
                    "charging_station_plug_id": plug.plug_id,
                    "start_state_of_charge": start_soc,
                    "target_state_of_charge": target_soc,
                },
            )
        ]
        expected = self._selected_local_charging_plan_value(
            station=station,
            plug=plug,
            destination_name=destination_name,
            destination_id=destination_id,
            first_route_id=fastest[0].route_id,
            start_soc=start_soc,
            target_soc=target_soc,
            duration_minutes=duration,
        )
        if len(route_reads) != 1 or len(calculation_reads) != 1 or values != expected:
            return None
        return evidence, values

    @staticmethod
    def _route_selection_near_name(text: str, name: str) -> str | None:
        aliases: set[str] = set()
        for clause in re.split(
            r"[.!?;]+|\b(?:and\s+)?then\b", text, flags=re.IGNORECASE
        ):
            if (
                not _contains_option_phrase(clause, name)
                or re.search(r"\b(?:route|leg|segment|option)\b", clause, re.I) is None
            ):
                continue
            aliases.update(
                alias
                for alias in ("fastest", "shortest")
                if re.search(rf"\b{alias}\b", clause, re.I) is not None
            )
            aliases.update(
                ordinal
                for ordinal in _ROUTE_ORDINALS
                if re.search(
                    rf"\b{ordinal}\s+(?:route|option)\b|"
                    rf"\b(?:route|option)\s+(?:number\s+)?{ordinal}\b",
                    clause,
                    re.I,
                )
                is not None
            )
        return next(iter(aliases)) if len(aliases) == 1 else None

    @staticmethod
    def _route_vias_near_name(text: str, name: str) -> set[str]:
        vias: set[str] = set()
        for clause in re.split(
            r"[.!?;]+|\b(?:and\s+)?then\b|\bafter\s+that\b|\bafterwards\b",
            text,
            flags=re.IGNORECASE,
        ):
            if not _contains_option_phrase(clause, name):
                continue
            vias.update(
                " ".join(match.group(0).upper().split())
                for match in _ROUTE_VIA_PATTERN.finditer(clause)
            )
        return vias

    def _charging_stop_navigation_constraints(
        self, session: SessionState, text: str
    ) -> tuple[Evidence, Mapping[str, Any], str, str] | None:
        normalized = _bounded_workflow_utterance(text, limit=640)
        plan = self._validated_selected_local_charging_plan(session)
        if normalized is None or plan is None:
            return None
        if (
            re.search(
                r"\b(?:set\s+up|start|begin)\s+(?:the\s+)?navigation\b|"
                r"\bnavigate\b",
                normalized,
                re.I,
            )
            is None
            or re.search(
                r"\b(?:do\s+not|don['\u2019]?t|never|not\s+yet)\b[^.!?]{0,50}"
                r"\b(?:navigate|navigation)\b",
                normalized,
                re.I,
            )
            is not None
        ):
            return None
        station_name = plan[1].get("charging_station_name")
        destination_name = plan[1].get("destination_name")
        if (
            not isinstance(station_name, str)
            or not isinstance(destination_name, str)
            or not _contains_option_phrase(normalized, station_name)
            or not _contains_option_phrase(normalized, destination_name)
        ):
            return None
        if (
            re.search(r"\b(?:compare|comparison)\b", normalized, re.I) is not None
            or re.search(
                rf"\b(?:not|without|except)\s+(?:the\s+)?"
                rf"{re.escape(station_name)}\b",
                normalized,
                re.I,
            )
            is not None
        ):
            return None
        has_stop_order = (
            re.search(r"\bfirst\b", normalized, re.I) is not None
            or (
                re.search(r"\bcharging\s+stop\s+(?:at|in)\b", normalized, re.I)
                is not None
                and _contains_option_phrase(normalized, station_name)
            )
            or (
                re.search(r"\b(?:and\s+)?then\b", normalized, re.I) is not None
                and _contains_option_phrase(normalized, station_name)
                and _contains_option_phrase(normalized, destination_name)
            )
        )
        if not has_stop_order:
            return None
        first_selection = self._route_selection_near_name(normalized, station_name)
        second_selection = self._route_selection_near_name(normalized, destination_name)
        if first_selection is None:
            first_leg = re.search(
                r"\bfirst\s+(?:leg|segment)\b[^.!?;]{0,80}"
                r"\b(?P<choice>fastest|shortest|first|second|third)\b",
                normalized,
                re.I,
            )
            if first_leg is None:
                first_leg = re.search(
                    r"\bfor\s+(?:the\s+)?charging\s+station\b"
                    r"[^.!?;]{0,80}\b"
                    r"(?P<choice>fastest|shortest|first|second|third)\b",
                    normalized,
                    re.I,
                )
            first_selection = (
                first_leg.group("choice").casefold() if first_leg is not None else None
            )
        via_matches = self._route_vias_near_name(normalized, destination_name)
        if (
            first_selection != "fastest"
            or second_selection not in _ROUTE_ORDINALS
            or len(via_matches) != 1
        ):
            return None
        return plan[0], plan[1], second_selection, next(iter(via_matches))

    def _handle_charging_stop_navigation_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        normalized = _bounded_workflow_utterance(text, limit=640)
        negated_navigation = (
            normalized is not None
            and re.search(
                r"\b(?:do\s+not|don['\u2019]?t|never|not\s+yet)\b[^.!?]{0,50}"
                r"\b(?:navigate|navigation)\b",
                normalized,
                re.I,
            )
            is not None
        )
        charging_stop_cue = (
            normalized is not None
            and re.search(r"\bcharging\s+stop\b", normalized, re.I) is not None
        )
        selected_plan = self._validated_selected_local_charging_plan(session)
        sequenced_plan_cue = False
        if normalized is not None and selected_plan is not None:
            station_name = selected_plan[1].get("charging_station_name")
            destination_name = selected_plan[1].get("destination_name")
            sequenced_plan_cue = (
                isinstance(station_name, str)
                and isinstance(destination_name, str)
                and _contains_option_phrase(normalized, station_name)
                and _contains_option_phrase(normalized, destination_name)
                and (
                    re.search(
                        r"\b(?:(?:and\s+)?then|after\s+that|afterwards)\b",
                        normalized,
                        re.I,
                    )
                    is not None
                    or (
                        re.search(r"\bfirst\b", normalized, re.I) is not None
                        and re.search(
                            r"\b(?:then|after\s+that|afterwards)\b",
                            normalized,
                            re.I,
                        )
                        is not None
                    )
                )
            )
        looks_like_navigation = (
            normalized is not None
            and not negated_navigation
            and (charging_stop_cue or sequenced_plan_cue)
            and re.search(
                r"\b(?:set\s+up|start|begin)\s+(?:the\s+)?navigation\b|"
                r"\bnavigate\b",
                normalized,
                re.I,
            )
            is not None
        )
        if not looks_like_navigation:
            return False, None
        constraints = self._charging_stop_navigation_constraints(session, text)
        if constraints is None:
            return True, self._text_plan(
                session,
                "I could not verify the charging stop and both route selections, so I did not start navigation.",
            )
        plan_evidence, values, second_selection, via = constraints
        station_name = str(values["charging_station_name"])
        destination_name = str(values["destination_name"])
        explicit = {
            "charging_station_name": station_name,
            "destination_name": destination_name,
            "first_segment_selection": "fastest",
            "second_segment_selection": second_selection,
            "second_segment_via": via,
        }
        goal = self._begin_local_charging_goal(
            session,
            turn_id=turn_id,
            semantic_operation=_CHARGING_STOP_NAVIGATION_OPERATION,
            desired_outcome=explicit,
            grounded_values=explicit,
            action=True,
        )
        self._apply_navigation_derived_parameters(
            session,
            goal=goal,
            parameters={
                "current_location_id": (
                    values["current_location_id"],
                    (plan_evidence,),
                    "charging_plan_current_location_v1",
                ),
                "charging_station_id": (
                    values["charging_station_id"],
                    (plan_evidence,),
                    "charging_plan_station_v1",
                ),
                "destination_id": (
                    values["destination_id"],
                    (plan_evidence,),
                    "charging_plan_destination_v1",
                ),
                "first_segment_route_id": (
                    values["first_segment_route_id"],
                    (plan_evidence,),
                    "charging_plan_first_segment_v1",
                ),
            },
        )
        return True, None

    def _handle_trip_followup_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        if _trip_email_request_requires_schema(text) and not (
            self._trip_email_schema_available(session, first_name="Grace", full=True)
        ):
            return True, self._text_plan(
                session,
                "Email sending is unavailable, so I did not read or send any trip information.",
            )

        preview = _TRIP_ROUTE_PREVIEW_PATTERN.fullmatch(
            text
        ) or _TRIP_ROUTE_PREVIEW_FROM_PATTERN.fullmatch(text)
        short_preview = (
            _TRIP_ROUTE_PREVIEW_SHORT_PATTERN.fullmatch(text)
            if preview is None
            else None
        )
        if short_preview is not None and _TRIP_ROUTE_SHORT_FORBIDDEN_PATTERN.search(
            short_preview.group("destination")
        ):
            return False, None
        preview = preview or short_preview
        if preview is None:
            natural_matches = [
                match
                for pattern in _TRIP_ROUTE_NATURAL_PATTERNS
                if (match := pattern.fullmatch(text)) is not None
            ]
            preview = natural_matches[0] if len(natural_matches) == 1 else None
        if preview is not None:
            destination = " ".join(preview.group("destination").strip().split())
            start_group = preview.groupdict().get("start")
            current_location = getattr(
                session.compiled_policy, "current_location", None
            )
            current_name = (
                current_location.get("name")
                if isinstance(current_location, Mapping)
                else None
            )
            start = (
                " ".join(start_group.strip().split())
                if start_group is not None
                else current_name
            )
            if (
                start_group is not None
                and _TRIP_ROUTE_SHORT_FORBIDDEN_PATTERN.search(start_group) is not None
            ):
                return False, None
            if (
                not self._voice_result_field(destination, 120)
                or not self._safe_poi_display_label(destination, 120)
                or not isinstance(current_name, str)
                or not isinstance(start, str)
                or not self._safe_poi_display_label(start, 120)
                or _argument_identifier(start) != _argument_identifier(current_name)
            ):
                return True, self._text_plan(
                    session,
                    "I could not verify the requested route start, so I did not start navigation.",
                )
            self._begin_trip_followup_goal(
                session,
                turn_id=turn_id,
                desired_outcome={
                    "destination_name": destination,
                    _TRIP_ROUTE_PREVIEW_MARKER: True,
                },
                grounded_values={"destination_name": destination},
            )
            return True, None

        charger = _TRIP_CHARGER_FOLLOWUP_PATTERN.fullmatch(
            text
        ) or _TRIP_CHARGER_CONDITIONAL_PATTERN.fullmatch(text)
        combined_charger = None
        if charger is None:
            combined_charger = _TRIP_CHARGER_EMAIL_COMBINED_PATTERN.fullmatch(text)
            charger = combined_charger
        if charger is not None:
            summary = self._validated_trip_route_summary(
                session, require_range_shortfall=False
            )
            if summary is None:
                return True, self._text_plan(
                    session,
                    "I could not verify a current range-shortfall route, so I did not search for a charging stop.",
                )
            summary_evidence, values = summary
            available_range = values.get("available_range_km")
            if available_range is not None and values.get("can_reach") is not False:
                return True, self._text_plan(
                    session,
                    "The verified current range is sufficient, so I did not search for a charging stop.",
                )
            needs_status = available_range is None
            at_kilometer = int(charger.group("kilometer"))
            route_distance = Decimal(values["route_distance_km"])
            if not 0 <= at_kilometer <= route_distance:
                return True, self._text_plan(
                    session,
                    "The requested charging-stop position was outside the verified route.",
                )
            filters = ["charging_stations::has_dc_plug"]
            desired_outcome: dict[str, Any] = {
                _TRIP_CHARGER_SEARCH_MARKER: True,
                _TRIP_CHARGER_STATUS_MARKER: needs_status,
                "destination_name": values["destination_name"],
                "route_id": values["route_id"],
                "category": "charging_stations",
                "at_kilometer": at_kilometer,
                "filters": filters,
            }
            grounded_values: dict[str, Any] = {
                "category": "charging_stations",
                "at_kilometer": at_kilometer,
                "filters": filters,
            }
            if combined_charger is not None:
                first_name = combined_charger.group("first_name").strip()
                last_name = combined_charger.group("last_name").strip()
                chained_contact_name = f"{first_name} {last_name}"
                desired_outcome.update(
                    {
                        _TRIP_CHARGER_EMAIL_CHAIN_MARKER: True,
                        "first_name": first_name,
                        "requested_contact_name": chained_contact_name,
                    }
                )
                grounded_values.update(
                    {
                        "first_name": first_name,
                        "requested_contact_name": chained_contact_name,
                    }
                )
            goal = self._begin_trip_followup_goal(
                session,
                turn_id=turn_id,
                desired_outcome=desired_outcome,
                grounded_values=grounded_values,
            )
            self._apply_navigation_derived_parameters(
                session,
                goal=goal,
                parameters={
                    "destination_name": (
                        values["destination_name"],
                        (summary_evidence,),
                        "trip_destination_from_verified_summary_v1",
                    ),
                    "route_id": (
                        values["route_id"],
                        (summary_evidence,),
                        "fastest_route_from_verified_trip_summary_v1",
                    ),
                },
            )
            return True, None

        email = _TRIP_EMAIL_FOLLOWUP_PATTERN.fullmatch(
            text
        ) or _TRIP_EMAIL_NAMED_FOLLOWUP_PATTERN.fullmatch(text)
        if email is None:
            natural_email_matches = [
                match
                for pattern in _TRIP_EMAIL_NATURAL_FOLLOWUP_PATTERNS
                if (match := pattern.fullmatch(text)) is not None
            ]
            email = (
                natural_email_matches[0] if len(natural_email_matches) == 1 else None
            )
        if email is not None:
            first_name = email.group("first_name").strip()
            last_name = email.groupdict().get("last_name")
            requested_contact_name = (
                f"{first_name} {last_name.strip()}" if last_name is not None else None
            )
            if (
                self._validated_trip_route_summary(
                    session, require_range_shortfall=True
                )
                is None
                or self._validated_trip_charger_summary(session) is None
                or not self._trip_email_schema_available(
                    session, first_name=first_name, full=True
                )
            ):
                return True, self._text_plan(
                    session,
                    "I could not verify the trip, charging stop, and email controls, so I did not start an email.",
                )
            self._begin_trip_email_goal(
                session,
                turn_id=turn_id,
                first_name=first_name,
                requested_contact_name=requested_contact_name,
            )
            return True, None

        active_email = self._trip_email_goal(session)
        if active_email is None:
            return False, None
        selected = self._select_trip_contact_candidate(session, text)
        if selected is None:
            return True, self._text_plan(
                session,
                "Please select one exact current contact before I prepare the email.",
                goal_ids=[active_email.goal_id],
            )
        display_name, contact_id, candidates_evidence = selected
        if not self._bind_trip_contact_selection(
            session,
            goal=active_email,
            display_name=display_name,
            contact_id=contact_id,
            candidates_evidence=candidates_evidence,
            source_turn_id=turn_id,
        ):
            return True, self._limitation_plan(
                session, active_email, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        return True, None

    @staticmethod
    def _register_single_read_need(
        session: SessionState, *, goal_id: str, proposition: str
    ) -> None:
        matching = [
            need
            for need in session.evidence.needs.values()
            if need.required_for_goal_id == goal_id and need.proposition == proposition
        ]
        if matching:
            return
        session.evidence.register_need(
            EvidenceNeed(
                proposition=proposition,
                required_for_goal_id=goal_id,
                acceptable_sources={"tool_result"},
                freshness="current_state",
            )
        )

    @staticmethod
    def _store_trip_route_summary(
        session: SessionState,
        *,
        goal: Goal,
        destination_name: str,
        start_id: str,
        destination_id: str,
        route: TripRouteAssessment,
        location_evidence: Evidence,
        route_evidence: Evidence,
        charging_evidence: Evidence | None,
        state_of_charge: Decimal | None,
        available_range: Decimal | None,
    ) -> Evidence | None:
        parents = [location_evidence, route_evidence]
        if charging_evidence is not None:
            parents.append(charging_evidence)
        parent_ids = [parent.evidence_id for parent in parents]
        if any(evidence_id is None for evidence_id in parent_ids):
            return None
        value = {
            "destination_name": destination_name,
            "start_id": start_id,
            "destination_id": destination_id,
            "route_id": route.route_id,
            "route_via": route.via,
            "route_distance_km": format(route.distance_km.normalize(), "f"),
            "route_duration_minutes": route.duration_minutes,
            "includes_toll": route.includes_toll,
            "state_of_charge": (
                format(state_of_charge.normalize(), "f")
                if state_of_charge is not None
                else None
            ),
            "available_range_km": (
                format(available_range.normalize(), "f")
                if available_range is not None
                else None
            ),
            "can_reach": (
                available_range >= route.distance_km
                if available_range is not None
                else None
            ),
        }
        observation = Evidence(
            proposition="trip_route_assessment_summary",
            value=value,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=f"trip-summary-{goal.goal_id}",
            confidence=min(parent.confidence for parent in parents),
            derived_from=[evidence_id for evidence_id in parent_ids if evidence_id],
            derivation="strict_trip_route_assessment_v1",
        )
        session.evidence.add(observation)
        stored = session.evidence.latest_for_proposition(
            observation.proposition, current_state_only=True
        )
        return stored[-1] if stored else None

    def _validated_trip_route_summary(
        self, session: SessionState, *, require_range_shortfall: bool
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        candidates = session.evidence.latest_for_proposition(
            "trip_route_assessment_summary", current_state_only=True
        )
        if not candidates:
            return None
        evidence = candidates[-1]
        values = evidence.value
        if (
            evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.DERIVED
            or evidence.derivation != "strict_trip_route_assessment_v1"
            or not isinstance(values, Mapping)
            or not isinstance(values.get("destination_name"), str)
        ):
            return None
        parents = [
            session.evidence.evidence.get(parent_id)
            for parent_id in evidence.derived_from
        ]
        if (
            len(parents) not in {2, 3}
            or any(parent is None for parent in parents)
            or any(
                parent.status is not EvidenceStatus.KNOWN
                or parent.source_kind is not EvidenceSourceKind.TOOL
                or parent.state_version != session.evidence.current_state_version
                for parent in parents
                if parent is not None
            )
        ):
            return None
        by_proposition = {
            parent.proposition: parent for parent in parents if parent is not None
        }
        if len(by_proposition) != len(parents):
            return None
        location = by_proposition.get("trip_destination_location_id")
        routes = by_proposition.get("trip_route_options")
        charging = by_proposition.get("trip_charging_status")
        if (
            location is None
            or routes is None
            or (len(parents) == 3) != (charging is not None)
        ):
            return None
        destination_name = values["destination_name"]
        destination_id = location.value
        current_location = getattr(session.compiled_policy, "current_location", None)
        start_id = (
            current_location.get("id")
            if isinstance(current_location, Mapping)
            else None
        )
        if (
            not self._voice_result_field(destination_name, 120)
            or not isinstance(destination_id, str)
            or not destination_id.startswith("loc_")
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(destination_id) is None
            or not isinstance(start_id, str)
            or not start_id.startswith("loc_")
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(start_id) is None
        ):
            return None
        location_reads = [
            observation
            for observation in session.successful_read_results
            if observation.source_turn_id == location.source_turn_id
            and observation.call_id == location.source_tool_call_id
            and observation.tool_name == "get_location_id_by_location_name"
            and observation.state_version == session.evidence.current_state_version
            and _argument_value_matches_binding(
                observation.arguments, {"location": destination_name}
            )
            and isinstance(observation.value, Mapping)
            and observation.value.get("id") == destination_id
        ]
        route_reads = [
            observation
            for observation in session.successful_read_results
            if observation.source_turn_id == routes.source_turn_id
            and observation.call_id == routes.source_tool_call_id
            and observation.tool_name == "get_routes_from_start_to_destination"
            and observation.state_version == session.evidence.current_state_version
            and _argument_value_matches_binding(
                observation.arguments,
                {"start_id": start_id, "destination_id": destination_id},
            )
        ]
        if len(location_reads) != 1 or len(route_reads) != 1:
            return None
        selected_route_id = values.get("route_id")
        options = self._destination_route_options_from_evidence(
            routes, start_id=start_id, destination_id=destination_id
        )
        selected = (
            ()
            if not isinstance(selected_route_id, str) or options is None
            else tuple(
                option for option in options if option.route_id == selected_route_id
            )
        )
        if len(selected) != 1:
            return None
        option = selected[0]
        route = TripRouteAssessment(
            distance_km=option.distance_km,
            includes_toll=option.includes_toll,
            route_id=option.route_id,
            via=option.via,
            duration_minutes=option.duration_minutes,
        )
        state_of_charge: Decimal | None = None
        available_range: Decimal | None = None
        if charging is not None:
            charging_values = self._trip_charging_values(charging)
            if charging_values is None:
                return None
            state_of_charge, available_range = charging_values
        expected = {
            "destination_name": destination_name,
            "start_id": start_id,
            "destination_id": destination_id,
            "route_id": route.route_id,
            "route_via": route.via,
            "route_distance_km": format(route.distance_km.normalize(), "f"),
            "route_duration_minutes": route.duration_minutes,
            "includes_toll": route.includes_toll,
            "state_of_charge": (
                format(state_of_charge.normalize(), "f")
                if state_of_charge is not None
                else None
            ),
            "available_range_km": (
                format(available_range.normalize(), "f")
                if available_range is not None
                else None
            ),
            "can_reach": (
                available_range >= route.distance_km
                if available_range is not None
                else None
            ),
        }
        if dict(values) != expected:
            return None
        if require_range_shortfall and (
            available_range is None or available_range >= route.distance_km
        ):
            return None
        return evidence, values

    @staticmethod
    def _tool_evidence_matches_arguments(
        session: SessionState,
        evidence: Evidence,
        *,
        tool_name: str,
        arguments: Mapping[str, Any],
    ) -> bool:
        matches = [
            result
            for result in session.successful_read_results
            if result.call_id == evidence.source_tool_call_id
            and result.source_turn_id == evidence.source_turn_id
            and result.tool_name == tool_name
            and result.state_version == session.evidence.current_state_version
            and _argument_value_matches_binding(result.arguments, dict(arguments))
        ]
        return len(matches) == 1

    def _local_trip_email_context_value(
        self,
        session: SessionState,
        *,
        destination_name: str,
        first_name: str,
        last_name: str,
        location: Evidence,
        routes: Evidence,
        matches: Evidence,
        information: Evidence,
    ) -> dict[str, Any] | None:
        identity = self._current_location_identity(session)
        destination_id = location.value
        if (
            identity is None
            or not isinstance(destination_id, str)
            or not destination_id.startswith("loc_")
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(destination_id) is None
        ):
            return None
        start_id, start_name = identity
        options = self._destination_route_options_from_evidence(
            routes, start_id=start_id, destination_id=destination_id
        )
        candidates = self._trip_contact_candidates_from_evidence(
            matches, first_name=first_name
        )
        requested_name = f"{first_name} {last_name}"
        selected_contacts = [
            (contact_id, display_name)
            for contact_id, display_name in candidates or ()
            if _argument_identifier(display_name)
            == _argument_identifier(requested_name)
        ]
        fastest = [option for option in options or () if "fastest" in option.aliases]
        shortest = [option for option in options or () if "shortest" in option.aliases]
        if (
            options is None
            or len(fastest) != 1
            or len(shortest) != 1
            or len(selected_contacts) != 1
        ):
            return None
        contact_id, selected_name = selected_contacts[0]
        contact = self._trip_contact_information(
            information, contact_id=contact_id, selected_name=selected_name
        )
        if contact is None:
            return None
        email_address, recipient_first_name = contact
        selected_route = fastest[0]
        highlighted_count = 1 if selected_route == shortest[0] else 2
        return {
            "destination_name": destination_name,
            "destination_id": destination_id,
            "start_id": start_id,
            "start_name": start_name,
            "route_id": selected_route.route_id,
            "route_via": selected_route.via,
            "route_distance_km": format(selected_route.distance_km.normalize(), "f"),
            "route_duration_minutes": selected_route.duration_minutes,
            "includes_toll": selected_route.includes_toll,
            "fastest_is_shortest": selected_route == shortest[0],
            "alternative_count": len(options) - highlighted_count,
            "recipient_first_name": recipient_first_name,
            "recipient_last_name": last_name,
            "recipient_display_name": selected_name,
            "recipient_contact_id": contact_id,
            "recipient_email": email_address,
        }

    def _store_local_trip_email_context(
        self,
        session: SessionState,
        *,
        goal: Goal,
        destination_name: str,
        first_name: str,
        last_name: str,
        location: Evidence,
        routes: Evidence,
        matches: Evidence,
        information: Evidence,
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        values = self._local_trip_email_context_value(
            session,
            destination_name=destination_name,
            first_name=first_name,
            last_name=last_name,
            location=location,
            routes=routes,
            matches=matches,
            information=information,
        )
        parents = (location, routes, matches, information)
        if values is None or any(parent.evidence_id is None for parent in parents):
            return None
        observation = Evidence(
            proposition="local_trip_email_context",
            value=values,
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=f"local-trip-email-context-{goal.goal_id}",
            confidence=min(parent.confidence for parent in parents),
            derived_from=[
                parent.evidence_id
                for parent in parents
                if parent.evidence_id is not None
            ],
            derivation="validated_local_trip_email_context_v1",
        )
        session.evidence.add(observation)
        return self._validated_local_trip_email_context(session)

    def _validated_local_trip_email_context(
        self, session: SessionState
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        candidates = session.evidence.latest_for_proposition(
            "local_trip_email_context", current_state_only=True
        )
        if not candidates:
            return None
        summary = candidates[-1]
        values = summary.value
        if (
            summary.status is not EvidenceStatus.KNOWN
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.derivation != "validated_local_trip_email_context_v1"
            or summary.state_version != session.evidence.current_state_version
            or not isinstance(values, Mapping)
            or len(summary.derived_from) != 4
        ):
            return None
        parents = [
            session.evidence.evidence.get(evidence_id)
            for evidence_id in summary.derived_from
        ]
        if any(
            parent is None
            or parent.status is not EvidenceStatus.KNOWN
            or parent.source_kind is not EvidenceSourceKind.TOOL
            or parent.state_version != session.evidence.current_state_version
            for parent in parents
        ):
            return None
        by_proposition = {
            parent.proposition: parent for parent in parents if parent is not None
        }
        if set(by_proposition) != {
            "trip_destination_location_id",
            "trip_route_options",
            "trip_contact_matches",
            "contact_information",
        }:
            return None
        destination_name = values.get("destination_name")
        first_name = values.get("recipient_first_name")
        last_name = values.get("recipient_last_name")
        contact_id = values.get("recipient_contact_id")
        destination_id = values.get("destination_id")
        start_id = values.get("start_id")
        if (
            not isinstance(destination_name, str)
            or not isinstance(first_name, str)
            or not isinstance(last_name, str)
            or not isinstance(contact_id, str)
            or not isinstance(destination_id, str)
            or not isinstance(start_id, str)
        ):
            return None
        location = by_proposition["trip_destination_location_id"]
        routes = by_proposition["trip_route_options"]
        matches = by_proposition["trip_contact_matches"]
        information = by_proposition["contact_information"]
        expected = self._local_trip_email_context_value(
            session,
            destination_name=destination_name,
            first_name=first_name,
            last_name=last_name,
            location=location,
            routes=routes,
            matches=matches,
            information=information,
        )
        if expected is None or dict(values) != expected:
            return None
        exact_arguments = (
            (
                location,
                "get_location_id_by_location_name",
                {"location": destination_name},
            ),
            (
                routes,
                "get_routes_from_start_to_destination",
                {"start_id": start_id, "destination_id": destination_id},
            ),
            (
                matches,
                "get_contact_id_by_contact_name",
                {
                    "contact_first_name": first_name,
                    "contact_last_name": last_name,
                },
            ),
            (
                information,
                "get_contact_information",
                {"contact_ids": [contact_id]},
            ),
        )
        if any(
            not self._tool_evidence_matches_arguments(
                session, evidence, tool_name=tool_name, arguments=arguments
            )
            for evidence, tool_name, arguments in exact_arguments
        ):
            return None
        return summary, values

    @staticmethod
    def _local_trip_email_via_text(via: str) -> str:
        parts = [part.strip() for part in via.split(",") if part.strip()]
        if len(parts) < 2:
            return parts[0] if parts else via.strip()
        if len(parts) == 2:
            return f"{parts[0]} and {parts[1]}"
        return f"{', '.join(parts[:-1])}, and {parts[-1]}"

    def _local_trip_email_charge_value(
        self,
        *,
        trip: Mapping[str, Any],
        station: LocalChargingStationOption,
        plug: ChargingPlugOption,
        start_soc: int,
        target_soc: int,
        duration_minutes: int,
        full_range_km: Decimal,
    ) -> dict[str, Any] | None:
        try:
            route_distance = Decimal(str(trip["route_distance_km"]))
            current_range = Decimal(str(trip["available_range_km"]))
            current_soc = Decimal(str(trip["state_of_charge"]))
        except (InvalidOperation, KeyError, TypeError):
            return None
        if (
            not route_distance.is_finite()
            or not current_range.is_finite()
            or not current_soc.is_finite()
            or current_soc != start_soc
            or not 0 <= start_soc < target_soc <= 100
            or not full_range_km.is_finite()
            or full_range_km <= 0
        ):
            return None
        return {
            "charging_station_id": station.station_id,
            "charging_station_name": station.name,
            "charging_station_plug_id": plug.plug_id,
            "charging_station_plug_power_type": plug.power_type,
            "charging_station_plug_power_kw": format(plug.power_kw.normalize(), "f"),
            "start_state_of_charge": start_soc,
            "target_state_of_charge": target_soc,
            "charging_duration_minutes": duration_minutes,
            "current_range_km": format(current_range.normalize(), "f"),
            "full_range_km": format(full_range_km.normalize(), "f"),
            "additional_stop_needed": full_range_km < route_distance,
        }

    def _store_local_trip_email_charge_summary(
        self,
        session: SessionState,
        *,
        goal: Goal,
        context: Evidence,
        trip: Evidence,
        displayed: Evidence,
        calculation: Evidence,
        full_range: Evidence,
        values: Mapping[str, Any],
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        parents = (context, trip, displayed, calculation, full_range)
        if any(parent.evidence_id is None for parent in parents):
            return None
        session.evidence.add(
            Evidence(
                proposition="local_trip_email_charge_summary",
                value=dict(values),
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"local-trip-email-charge-{goal.goal_id}",
                confidence=min(parent.confidence for parent in parents),
                derived_from=[
                    parent.evidence_id
                    for parent in parents
                    if parent.evidence_id is not None
                ],
                derivation="validated_local_trip_email_charge_summary_v1",
            )
        )
        return self._validated_local_trip_email_charge_summary(session)

    def _validated_local_trip_email_charge_summary(
        self, session: SessionState
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        candidates = session.evidence.latest_for_proposition(
            "local_trip_email_charge_summary", current_state_only=True
        )
        context = self._validated_local_trip_email_context(session)
        trip = self._validated_trip_route_summary(session, require_range_shortfall=True)
        displayed = self._validated_displayed_local_charging_options(session)
        if not candidates or context is None or trip is None or displayed is None:
            return None
        summary = candidates[-1]
        values = summary.value
        if (
            summary.status is not EvidenceStatus.KNOWN
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.derivation != "validated_local_trip_email_charge_summary_v1"
            or summary.state_version != session.evidence.current_state_version
            or not isinstance(values, Mapping)
            or len(summary.derived_from) != 5
        ):
            return None
        parents = [
            session.evidence.evidence.get(evidence_id)
            for evidence_id in summary.derived_from
        ]
        if any(
            parent is None
            or parent.status is not EvidenceStatus.KNOWN
            or parent.state_version != session.evidence.current_state_version
            for parent in parents
        ):
            return None
        by_proposition = {
            parent.proposition: parent for parent in parents if parent is not None
        }
        if set(by_proposition) != {
            "local_trip_email_context",
            "trip_route_assessment_summary",
            "displayed_local_charging_options",
            "local_charging_time_result",
            "local_trip_email_full_range",
        }:
            return None
        if (
            by_proposition["local_trip_email_context"] is not context[0]
            or by_proposition["trip_route_assessment_summary"] is not trip[0]
            or by_proposition["displayed_local_charging_options"] is not displayed[0]
        ):
            return None
        station_name = values.get("charging_station_name")
        station_id = values.get("charging_station_id")
        plug_id = values.get("charging_station_plug_id")
        start_soc = values.get("start_state_of_charge")
        target_soc = values.get("target_state_of_charge")
        if (
            not isinstance(station_name, str)
            or not isinstance(station_id, str)
            or not isinstance(plug_id, str)
            or type(start_soc) is not int
            or type(target_soc) is not int
        ):
            return None
        stations = [
            option
            for option in displayed[1]
            if option.station_id == station_id
            and _argument_identifier(option.name) == _argument_identifier(station_name)
        ]
        if len(stations) != 1:
            return None
        station = stations[0]
        plug = self._highest_available_dc_plug(station)
        if plug is None or plug.plug_id != plug_id:
            return None
        calculation = by_proposition["local_charging_time_result"]
        distance = by_proposition["local_trip_email_full_range"]
        duration = self._charging_duration_minutes(
            calculation.value, start_soc=start_soc, target_soc=target_soc
        )
        full_range_km = self._active_route_buffer_distance_km(
            distance, initial_soc=target_soc, final_soc=0
        )
        expected = (
            self._local_trip_email_charge_value(
                trip=trip[1],
                station=station,
                plug=plug,
                start_soc=start_soc,
                target_soc=target_soc,
                duration_minutes=duration,
                full_range_km=full_range_km,
            )
            if duration is not None and full_range_km is not None
            else None
        )
        if expected is None or dict(values) != expected:
            return None
        if not self._tool_evidence_matches_arguments(
            session,
            calculation,
            tool_name="calculate_charging_time_by_soc",
            arguments={
                "charging_station_id": station_id,
                "charging_station_plug_id": plug_id,
                "start_state_of_charge": start_soc,
                "target_state_of_charge": target_soc,
            },
        ) or not self._tool_evidence_matches_arguments(
            session,
            distance,
            tool_name="get_distance_by_soc",
            arguments={
                "initial_state_of_charge": target_soc,
                "final_state_of_charge": 0,
            },
        ):
            return None
        return summary, values

    def _local_trip_email_body(
        self,
        *,
        context: Mapping[str, Any],
        trip: Mapping[str, Any],
        charge: Mapping[str, Any],
    ) -> str | None:
        duration = context.get("route_duration_minutes")
        charge_duration = charge.get("charging_duration_minutes")
        if (
            type(duration) is not int
            or type(charge_duration) is not int
            or trip.get("can_reach") is not False
            or charge.get("additional_stop_needed") is not True
        ):
            return None
        required_strings = (
            "recipient_first_name",
            "destination_name",
            "start_name",
            "route_via",
            "route_distance_km",
        )
        if any(not isinstance(context.get(key), str) for key in required_strings):
            return None
        charge_strings = (
            "charging_station_name",
            "charging_station_plug_power_type",
            "charging_station_plug_power_kw",
            "current_range_km",
            "full_range_km",
        )
        if any(not isinstance(charge.get(key), str) for key in charge_strings):
            return None
        start_soc = charge.get("start_state_of_charge")
        target_soc = charge.get("target_state_of_charge")
        if type(start_soc) is not int or type(target_soc) is not int:
            return None
        hours, minutes = divmod(duration, 60)
        hour_label = "hour" if hours == 1 else "hours"
        minute_label = "minute" if minutes == 1 else "minutes"
        charge_minute_label = "minute" if charge_duration == 1 else "minutes"
        toll_clause = (
            "with toll roads"
            if context.get("includes_toll") is True
            else "with no toll roads"
        )
        via = self._local_trip_email_via_text(str(context["route_via"]))
        range_label = (
            "full-charge range"
            if target_soc == 100
            else f"range after charging to {target_soc} percent"
        )
        return (
            f"Hi {context['recipient_first_name']},\n\n"
            "I wanted to share the details of my upcoming business trip to "
            f"{context['destination_name']}. I'll be driving from "
            f"{context['start_name']} via {via}. The fastest route is "
            f"approximately {context['route_distance_km']} kilometers and should "
            f"take about {hours} {hour_label} and {minutes} {minute_label}, "
            f"{toll_clause}.\n\n"
            f"My current range of {charge['current_range_km']} kilometers is not "
            "enough for the trip. Before departure, I plan to charge at the "
            f"{charge['charging_station_name']} station in {context['start_name']} "
            f"using its available {charge['charging_station_plug_power_kw']} "
            f"kilowatt {charge['charging_station_plug_power_type']} plug. Charging "
            f"from {start_soc} to {target_soc} percent should take about "
            f"{charge_duration} {charge_minute_label} and provide an estimated "
            f"{range_label} of {charge['full_range_km']} kilometers.\n\n"
            "Because that is still less than the route distance, I'll need at "
            "least one additional charging stop along the way. I haven't planned "
            "that stop yet.\n\n"
            "I'll keep you updated on my travel plans. Let me know if you need any "
            "additional information.\n\n"
            "Best regards"
        )

    @classmethod
    def _active_route_first_segment(
        cls,
        evidence: Evidence,
        *,
        current_location_id: str,
    ) -> tuple[TripRouteAssessment, str, Decimal] | None:
        value = evidence.value
        if not isinstance(value, Mapping) or value.get("navigation_active") is not True:
            return None
        waypoint_ids = value.get("waypoints_id")
        route_ids = value.get("routes_to_final_destination_id")
        details = value.get("details")
        if (
            not isinstance(waypoint_ids, list)
            or not 2 <= len(waypoint_ids) <= 15
            or waypoint_ids[0] != current_location_id
            or len(set(waypoint_ids)) != len(waypoint_ids)
            or any(
                not isinstance(item, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(item) is None
                for item in waypoint_ids
            )
            or not isinstance(route_ids, list)
            or len(route_ids) != len(waypoint_ids) - 1
            or len(set(route_ids)) != len(route_ids)
            or any(
                not isinstance(item, str) or _ROUTE_ID_PATTERN.fullmatch(item) is None
                for item in route_ids
            )
            or not isinstance(details, Mapping)
        ):
            return None
        waypoint_details = details.get("waypoints")
        route_details = details.get("routes")
        if (
            not isinstance(waypoint_details, list)
            or len(waypoint_details) != len(waypoint_ids)
            or not isinstance(route_details, list)
            or len(route_details) != len(route_ids)
        ):
            return None
        names: list[str] = []
        for expected_id, item in zip(waypoint_ids, waypoint_details, strict=True):
            if not isinstance(item, Mapping):
                return None
            name = item.get("name")
            if (
                item.get("id") != expected_id
                or not isinstance(name, str)
                or not cls._voice_result_field(name, 80)
            ):
                return None
            names.append(name.strip())

        first: TripRouteAssessment | None = None
        total_distance = Decimal(0)
        for index, (expected_id, item) in enumerate(
            zip(route_ids, route_details, strict=True)
        ):
            if not isinstance(item, Mapping):
                return None
            distance_value = item.get("distance_km")
            hours_value = item.get("duration_hours")
            minutes_value = item.get("duration_minutes")
            aliases = item.get("alias")
            via = item.get("name_via")
            includes_toll = item.get("includes_toll")
            if (
                item.get("route_id") != expected_id
                or item.get("start_id") != waypoint_ids[index]
                or item.get("destination_id") != waypoint_ids[index + 1]
                or isinstance(distance_value, bool)
                or isinstance(hours_value, bool)
                or isinstance(minutes_value, bool)
                or not isinstance(aliases, list)
                or not aliases
                or len(set(aliases)) != len(aliases)
                or any(not isinstance(alias, str) for alias in aliases)
                or not isinstance(via, str)
                or _ROUTE_VIA_PATTERN.fullmatch(via.strip()) is None
                or not isinstance(includes_toll, bool)
            ):
                return None
            try:
                distance = Decimal(str(distance_value))
                hours_decimal = Decimal(str(hours_value))
                minutes_decimal = Decimal(str(minutes_value))
                hours = int(hours_decimal)
                minutes = int(minutes_decimal)
            except (InvalidOperation, TypeError, ValueError):
                return None
            if (
                not distance.is_finite()
                or distance <= 0
                or hours_decimal != hours
                or minutes_decimal != minutes
                or not 0 <= hours <= 240
                or not 0 <= minutes <= 59
            ):
                return None
            total_distance += distance
            if index == 0:
                normalized_aliases = {_argument_identifier(alias) for alias in aliases}
                if not {"fastest", "shortest"}.issubset(normalized_aliases):
                    return None
                first = TripRouteAssessment(
                    distance_km=distance,
                    includes_toll=includes_toll,
                    route_id=expected_id,
                    via=via.strip(),
                    duration_minutes=hours * 60 + minutes,
                )
        if first is None:
            return None
        return first, names[1], total_distance

    @staticmethod
    def _active_route_matches_completed_navigation_edit(
        session: SessionState, *, navigation: Evidence, first_route_id: str
    ) -> bool:
        value = navigation.value
        route_ids = (
            value.get("routes_to_final_destination_id")
            if isinstance(value, Mapping)
            else None
        )
        waypoint_ids = value.get("waypoints_id") if isinstance(value, Mapping) else None
        if (
            not isinstance(route_ids, list)
            or not route_ids
            or not isinstance(waypoint_ids, list)
            or len(waypoint_ids) != len(route_ids) + 1
            or route_ids[0] != first_route_id
            or any(not isinstance(route_id, str) for route_id in route_ids)
            or any(not isinstance(waypoint_id, str) for waypoint_id in waypoint_ids)
        ):
            return False
        deleted = any(
            call.tool_name == "navigation_delete_waypoint"
            and call.arguments.get("route_id_without_waypoint") == first_route_id
            for calls in session.completed_action_calls_by_goal.values()
            for call in calls
        )
        replaced = any(
            call.tool_name == "navigation_replace_final_destination"
            and call.arguments.get("route_id_leading_to_new_destination")
            == route_ids[-1]
            and call.arguments.get("new_destination_id") == waypoint_ids[-1]
            for calls in session.completed_action_calls_by_goal.values()
            for call in calls
        )
        return deleted or replaced

    @staticmethod
    def _active_route_buffer_distance_km(
        evidence: Evidence, *, initial_soc: int, final_soc: int
    ) -> Decimal | None:
        value = evidence.value
        expected_key = f"distance_km_for_{initial_soc}_until_{final_soc}_percent_soc"
        if (
            evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.TOOL
            or not isinstance(value, Mapping)
            or set(value) != {expected_key}
            or not isinstance(value.get(expected_key), str)
        ):
            return None
        match = re.fullmatch(
            r"\s*(\d+(?:\.\d+)?)\s*km\s*",
            value[expected_key],
            flags=re.IGNORECASE,
        )
        if match is None:
            return None
        try:
            distance = Decimal(match.group(1))
        except InvalidOperation:
            return None
        return distance if distance.is_finite() and distance > 0 else None

    @classmethod
    def _active_route_final_destination_name(
        cls, navigation: Evidence, *, current_location_id: str
    ) -> str | None:
        if cls._active_route_first_segment(
            navigation, current_location_id=current_location_id
        ) is None or not isinstance(navigation.value, Mapping):
            return None
        waypoint_ids = navigation.value.get("waypoints_id")
        details = navigation.value.get("details")
        waypoints = details.get("waypoints") if isinstance(details, Mapping) else None
        if (
            not isinstance(waypoint_ids, list)
            or not waypoint_ids
            or not isinstance(waypoints, list)
            or len(waypoints) != len(waypoint_ids)
            or not isinstance(waypoints[-1], Mapping)
            or waypoints[-1].get("id") != waypoint_ids[-1]
        ):
            return None
        name = waypoints[-1].get("name")
        return (
            name.strip()
            if isinstance(name, str) and cls._voice_result_field(name, 80)
            else None
        )

    @classmethod
    def _active_route_buffer_segment(
        cls,
        navigation: Evidence,
        *,
        current_location_id: str,
        buffer_distance_km: Decimal,
    ) -> tuple[TripRouteAssessment, int] | None:
        if cls._active_route_first_segment(
            navigation, current_location_id=current_location_id
        ) is None or not isinstance(navigation.value, Mapping):
            return None
        details = navigation.value.get("details")
        route_ids = navigation.value.get("routes_to_final_destination_id")
        routes = details.get("routes") if isinstance(details, Mapping) else None
        if not isinstance(route_ids, list) or not isinstance(routes, list):
            return None
        remaining = buffer_distance_km
        for expected_id, route in zip(route_ids, routes, strict=True):
            if not isinstance(route, Mapping):
                return None
            try:
                distance = Decimal(str(route.get("distance_km")))
                hours = int(Decimal(str(route.get("duration_hours"))))
                minutes = int(Decimal(str(route.get("duration_minutes"))))
            except (InvalidOperation, TypeError, ValueError):
                return None
            if remaining > distance:
                remaining -= distance
                continue
            requested_kilometer = int(remaining / Decimal(50)) * 50
            if not 50 <= requested_kilometer < distance:
                return None
            via = route.get("name_via")
            includes_toll = route.get("includes_toll")
            if (
                route.get("route_id") != expected_id
                or not isinstance(expected_id, str)
                or not isinstance(via, str)
                or not isinstance(includes_toll, bool)
            ):
                return None
            return (
                TripRouteAssessment(
                    distance_km=distance,
                    includes_toll=includes_toll,
                    route_id=expected_id,
                    via=via,
                    duration_minutes=hours * 60 + minutes,
                ),
                requested_kilometer,
            )
        return None

    def _validated_active_route_charging_summary(
        self, session: SessionState
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        summaries = session.evidence.latest_for_proposition(
            "active_route_charging_summary", current_state_only=True
        )
        if not summaries:
            return None
        summary = summaries[-1]
        values = summary.value
        if (
            summary.status is not EvidenceStatus.KNOWN
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.derivation != "strict_active_route_charging_summary_v1"
            or not isinstance(values, Mapping)
            or len(summary.derived_from) != 2
        ):
            return None
        parents = [
            session.evidence.evidence.get(evidence_id)
            for evidence_id in summary.derived_from
        ]
        if any(
            parent is None
            or parent.status is not EvidenceStatus.KNOWN
            or parent.source_kind is not EvidenceSourceKind.TOOL
            or parent.state_version != session.evidence.current_state_version
            for parent in parents
        ):
            return None
        by_proposition = {
            parent.proposition: parent for parent in parents if parent is not None
        }
        if set(by_proposition) != {
            "active_route_charging_status",
            "active_route_charging_navigation",
        }:
            return None
        charging = self._trip_charging_values(
            by_proposition["active_route_charging_status"]
        )
        current_location = getattr(session.compiled_policy, "current_location", None)
        current_location_id = (
            current_location.get("id")
            if isinstance(current_location, Mapping)
            else None
        )
        route = (
            self._active_route_first_segment(
                by_proposition["active_route_charging_navigation"],
                current_location_id=current_location_id,
            )
            if isinstance(current_location_id, str)
            else None
        )
        final_destination_name = (
            self._active_route_final_destination_name(
                by_proposition["active_route_charging_navigation"],
                current_location_id=current_location_id,
            )
            if isinstance(current_location_id, str)
            else None
        )
        if charging is None or route is None or final_destination_name is None:
            return None
        state_of_charge, available_range = charging
        segment, destination_name, total_distance = route
        expected = {
            "route_id": segment.route_id,
            "route_distance_km": format(segment.distance_km.normalize(), "f"),
            "remaining_route_distance_km": format(total_distance.normalize(), "f"),
            "destination_name": destination_name,
            "final_destination_name": final_destination_name,
            "state_of_charge": format(state_of_charge.normalize(), "f"),
            "available_range_km": format(available_range.normalize(), "f"),
            "needs_charging": available_range < total_distance,
        }
        if dict(
            values
        ) != expected or not self._active_route_matches_completed_navigation_edit(
            session,
            navigation=by_proposition["active_route_charging_navigation"],
            first_route_id=segment.route_id,
        ):
            return None
        return summary, values

    def _validated_active_route_charger_summary(
        self, session: SessionState
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        route_summary = self._validated_active_route_charging_summary(session)
        charger_summaries = session.evidence.latest_for_proposition(
            "active_route_charger_summary", current_state_only=True
        )
        if route_summary is None or not charger_summaries:
            return None
        route_evidence, route_values = route_summary
        summary = charger_summaries[-1]
        values = summary.value
        if (
            summary.derivation == "strict_active_route_buffer_charger_summary_v1"
            and isinstance(values, Mapping)
        ):
            if (
                summary.status is not EvidenceStatus.KNOWN
                or summary.source_kind is not EvidenceSourceKind.DERIVED
                or len(summary.derived_from) != 3
                or route_evidence.evidence_id not in summary.derived_from
            ):
                return None
            parents = [
                session.evidence.evidence.get(evidence_id)
                for evidence_id in summary.derived_from
                if evidence_id != route_evidence.evidence_id
            ]
            by_proposition = {
                parent.proposition: parent for parent in parents if parent is not None
            }
            distance_evidence = by_proposition.get("active_route_buffer_distance")
            raw = by_proposition.get("active_route_charging_station_candidates")
            initial_soc = values.get("initial_state_of_charge")
            final_soc = values.get("final_state_of_charge")
            if (
                set(by_proposition)
                != {
                    "active_route_buffer_distance",
                    "active_route_charging_station_candidates",
                }
                or distance_evidence is None
                or raw is None
                or any(
                    parent.status is not EvidenceStatus.KNOWN
                    or parent.source_kind is not EvidenceSourceKind.TOOL
                    or parent.state_version != session.evidence.current_state_version
                    for parent in (distance_evidence, raw)
                )
                or type(initial_soc) is not int
                or type(final_soc) is not int
            ):
                return None
            buffer_distance = self._active_route_buffer_distance_km(
                distance_evidence,
                initial_soc=initial_soc,
                final_soc=final_soc,
            )
            navigation = next(
                (
                    session.evidence.evidence.get(evidence_id)
                    for evidence_id in route_evidence.derived_from
                    if (parent := session.evidence.evidence.get(evidence_id))
                    is not None
                    and parent.proposition == "active_route_charging_navigation"
                ),
                None,
            )
            current_location = getattr(
                session.compiled_policy, "current_location", None
            )
            current_location_id = (
                current_location.get("id")
                if isinstance(current_location, Mapping)
                else None
            )
            selected = (
                self._active_route_buffer_segment(
                    navigation,
                    current_location_id=current_location_id,
                    buffer_distance_km=buffer_distance,
                )
                if navigation is not None
                and isinstance(current_location_id, str)
                and buffer_distance is not None
                else None
            )
            if selected is None:
                return None
            route, requested_kilometer = selected
            assessment = self._trip_charger_assessment(
                raw,
                route_id=route.route_id,
                route_distance_km=route.distance_km,
                requested_kilometer=requested_kilometer,
            )
            if assessment is None or buffer_distance is None:
                return None
            expected = {
                "station_id": assessment.station_id,
                "station_name": assessment.name,
                "phone_number": assessment.phone_number,
                "route_id": route.route_id,
                "requested_kilometer": requested_kilometer,
                "route_kilometer": format(assessment.route_kilometer.normalize(), "f"),
                "detour_km": format(assessment.detour_km.normalize(), "f"),
                "detour_minutes": assessment.detour_minutes,
                "available_power_type": assessment.available_power_type,
                "available_power_kw": format(
                    assessment.available_power_kw.normalize(), "f"
                ),
                "initial_state_of_charge": initial_soc,
                "final_state_of_charge": final_soc,
                "buffer_distance_km": format(buffer_distance.normalize(), "f"),
            }
            if dict(values) != expected:
                return None
            return summary, values
        if (
            summary.status is not EvidenceStatus.KNOWN
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.derivation != "strict_active_route_charger_summary_v1"
            or not isinstance(values, Mapping)
            or len(summary.derived_from) != 2
            or route_evidence.evidence_id not in summary.derived_from
        ):
            return None
        raw_ids = [
            evidence_id
            for evidence_id in summary.derived_from
            if evidence_id != route_evidence.evidence_id
        ]
        raw = session.evidence.evidence.get(raw_ids[0]) if len(raw_ids) == 1 else None
        regular_requested_kilometer = values.get("requested_kilometer")
        if (
            raw is None
            or raw.proposition != "active_route_charging_station_candidates"
            or raw.status is not EvidenceStatus.KNOWN
            or raw.source_kind is not EvidenceSourceKind.TOOL
            or raw.state_version != session.evidence.current_state_version
            or type(regular_requested_kilometer) is not int
        ):
            return None
        assessment = self._trip_charger_assessment(
            raw,
            route_id=route_values["route_id"],
            route_distance_km=Decimal(route_values["route_distance_km"]),
            requested_kilometer=regular_requested_kilometer,
        )
        if assessment is None:
            return None
        expected = {
            "station_id": assessment.station_id,
            "station_name": assessment.name,
            "phone_number": assessment.phone_number,
            "route_id": route_values["route_id"],
            "requested_kilometer": regular_requested_kilometer,
            "route_kilometer": format(assessment.route_kilometer.normalize(), "f"),
            "detour_km": format(assessment.detour_km.normalize(), "f"),
            "detour_minutes": assessment.detour_minutes,
            "available_power_type": assessment.available_power_type,
            "available_power_kw": format(
                assessment.available_power_kw.normalize(), "f"
            ),
        }
        try:
            reachable = assessment.route_kilometer + assessment.detour_km <= Decimal(
                route_values["available_range_km"]
            )
        except (InvalidOperation, TypeError):
            return None
        if dict(values) != expected or not reachable:
            return None
        return summary, values

    def _next_active_route_buffer_search(
        self,
        session: SessionState,
        *,
        item: PreparedGoal,
        summary_evidence: Evidence,
    ) -> PlannedOutbound:
        initial_soc = item.goal.desired_outcome.get("initial_state_of_charge")
        final_soc = item.goal.desired_outcome.get("final_state_of_charge")
        if (
            type(initial_soc) is not int
            or type(final_soc) is not int
            or not 0 <= final_soc < initial_soc <= 100
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        summary_values = summary_evidence.value
        final_destination_name = (
            summary_values.get("final_destination_name")
            if isinstance(summary_values, Mapping)
            else None
        )
        if not isinstance(final_destination_name, str):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        distance_arguments = {
            "initial_state_of_charge": initial_soc,
            "final_state_of_charge": final_soc,
        }
        self._register_single_read_need(
            session,
            goal_id=item.goal.goal_id,
            proposition="active_route_buffer_distance",
        )
        observed_distance = self._derived_navigation_read_value(
            session,
            goal_id=item.goal.goal_id,
            tool_name="get_distance_by_soc",
            arguments=distance_arguments,
            proposition="active_route_buffer_distance",
        )
        if observed_distance is None:
            if (
                self._successful_goal_read(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_distance_by_soc",
                    arguments=distance_arguments,
                )
                is not None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="get_distance_by_soc",
                arguments=distance_arguments,
                semantic_operation="get_distance_by_soc",
                proposition="active_route_buffer_distance",
            )
        _, distance_evidence = observed_distance
        buffer_distance = self._active_route_buffer_distance_km(
            distance_evidence, initial_soc=initial_soc, final_soc=final_soc
        )
        navigation_evidence = next(
            (
                session.evidence.evidence.get(evidence_id)
                for evidence_id in summary_evidence.derived_from
                if (parent := session.evidence.evidence.get(evidence_id)) is not None
                and parent.proposition == "active_route_charging_navigation"
            ),
            None,
        )
        current_location = getattr(session.compiled_policy, "current_location", None)
        current_location_id = (
            current_location.get("id")
            if isinstance(current_location, Mapping)
            else None
        )
        selected = (
            self._active_route_buffer_segment(
                navigation_evidence,
                current_location_id=current_location_id,
                buffer_distance_km=buffer_distance,
            )
            if navigation_evidence is not None
            and isinstance(current_location_id, str)
            and buffer_distance is not None
            else None
        )
        if selected is None:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        route, requested_kilometer = selected
        filters = ["charging_stations::has_available_plug"]
        arguments = {
            "route_id": route.route_id,
            "category_poi": "charging_stations",
            "at_kilometer": requested_kilometer,
            "filters": filters,
        }
        self._register_single_read_need(
            session,
            goal_id=item.goal.goal_id,
            proposition="active_route_charging_station_candidates",
        )
        observed = self._derived_navigation_read_value(
            session,
            goal_id=item.goal.goal_id,
            tool_name="search_poi_along_the_route",
            arguments=arguments,
            proposition="active_route_charging_station_candidates",
        )
        if observed is None:
            if (
                self._successful_goal_read(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="search_poi_along_the_route",
                    arguments=arguments,
                )
                is not None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="search_poi_along_the_route",
                arguments=arguments,
                semantic_operation="search_trip_charger_along_route",
                proposition="active_route_charging_station_candidates",
            )
        _, charger_evidence = observed
        raw_candidates = (
            charger_evidence.value.get("pois_found_along_route")
            if isinstance(charger_evidence.value, Mapping)
            else None
        )
        assessment = self._trip_charger_assessment(
            charger_evidence,
            route_id=route.route_id,
            route_distance_km=route.distance_km,
            requested_kilometer=requested_kilometer,
        )
        parent_ids = [
            summary_evidence.evidence_id,
            distance_evidence.evidence_id,
            charger_evidence.evidence_id,
        ]
        if (
            not isinstance(raw_candidates, list)
            or len(raw_candidates) != 1
            or assessment is None
            or any(evidence_id is None for evidence_id in parent_ids)
            or buffer_distance is None
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        session.evidence.add(
            Evidence(
                proposition="active_route_charger_summary",
                value={
                    "station_id": assessment.station_id,
                    "station_name": assessment.name,
                    "phone_number": assessment.phone_number,
                    "route_id": route.route_id,
                    "requested_kilometer": requested_kilometer,
                    "route_kilometer": format(
                        assessment.route_kilometer.normalize(), "f"
                    ),
                    "detour_km": format(assessment.detour_km.normalize(), "f"),
                    "detour_minutes": assessment.detour_minutes,
                    "available_power_type": assessment.available_power_type,
                    "available_power_kw": format(
                        assessment.available_power_kw.normalize(), "f"
                    ),
                    "initial_state_of_charge": initial_soc,
                    "final_state_of_charge": final_soc,
                    "buffer_distance_km": format(buffer_distance.normalize(), "f"),
                },
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"active-route-buffer-charger-{item.goal.goal_id}",
                confidence=min(
                    summary_evidence.confidence,
                    distance_evidence.confidence,
                    charger_evidence.confidence,
                ),
                derived_from=[evidence_id for evidence_id in parent_ids if evidence_id],
                derivation="strict_active_route_buffer_charger_summary_v1",
            )
        )
        validated = self._validated_active_route_charger_summary(session)
        if validated is None:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        _, values = validated
        session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
        return self._text_plan(
            session,
            (
                f"I found {values['station_name']} around kilometer "
                f"{values['route_kilometer']} on the segment toward "
                f"{final_destination_name}, near the "
                f"{values['final_state_of_charge']} percent safety buffer point. It "
                f"has an available {values['available_power_kw']} kilowatt "
                f"{values['available_power_type']} plug. I did not add it to navigation."
            ),
            goal_ids=[item.goal.goal_id],
            kind=ProposalKind.COMPLETE,
        )

    def _next_active_route_charging_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if (
                item.goal.semantic_operation != _TRIP_RANGE_OPERATION
                or item.goal.desired_outcome.get(_ACTIVE_ROUTE_CHARGING_MARKER)
                is not True
            ):
                continue
            summary = self._validated_active_route_charging_summary(session)
            if summary is None:
                charging_arguments: dict[str, Any] = {}
                self._register_single_read_need(
                    session,
                    goal_id=item.goal.goal_id,
                    proposition="active_route_charging_status",
                )
                charging = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_charging_specs_and_status",
                    arguments=charging_arguments,
                    proposition="active_route_charging_status",
                )
                if charging is None:
                    if (
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name="get_charging_specs_and_status",
                            arguments=charging_arguments,
                        )
                        is not None
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._navigation_read_plan(
                        session,
                        item=item,
                        tool_name="get_charging_specs_and_status",
                        arguments=charging_arguments,
                        semantic_operation=_TRIP_RANGE_OPERATION,
                        proposition="active_route_charging_status",
                    )
                _, charging_evidence = charging
                charging_values = self._trip_charging_values(charging_evidence)
                navigation_arguments = {"detailed_information": True}
                self._register_single_read_need(
                    session,
                    goal_id=item.goal.goal_id,
                    proposition="active_route_charging_navigation",
                )
                navigation = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_current_navigation_state",
                    arguments=navigation_arguments,
                    proposition="active_route_charging_navigation",
                )
                if navigation is None:
                    if (
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name="get_current_navigation_state",
                            arguments=navigation_arguments,
                        )
                        is not None
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._navigation_read_plan(
                        session,
                        item=item,
                        tool_name="get_current_navigation_state",
                        arguments=navigation_arguments,
                        semantic_operation="read_current_navigation",
                        proposition="active_route_charging_navigation",
                    )
                _, navigation_evidence = navigation
                current_location = getattr(
                    session.compiled_policy, "current_location", None
                )
                current_location_id = (
                    current_location.get("id")
                    if isinstance(current_location, Mapping)
                    else None
                )
                route = (
                    self._active_route_first_segment(
                        navigation_evidence,
                        current_location_id=current_location_id,
                    )
                    if isinstance(current_location_id, str)
                    else None
                )
                final_destination_name = (
                    self._active_route_final_destination_name(
                        navigation_evidence,
                        current_location_id=current_location_id,
                    )
                    if isinstance(current_location_id, str)
                    else None
                )
                if (
                    charging_values is None
                    or route is None
                    or final_destination_name is None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                segment, destination_name, total_distance = route
                if not self._active_route_matches_completed_navigation_edit(
                    session,
                    navigation=navigation_evidence,
                    first_route_id=segment.route_id,
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                state_of_charge, available_range = charging_values
                requested_initial_soc = item.goal.desired_outcome.get(
                    "requested_initial_state_of_charge"
                )
                if requested_initial_soc is not None and (
                    type(requested_initial_soc) is not int
                    or state_of_charge != Decimal(requested_initial_soc)
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                parent_ids = [
                    charging_evidence.evidence_id,
                    navigation_evidence.evidence_id,
                ]
                if any(evidence_id is None for evidence_id in parent_ids):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                session.evidence.add(
                    Evidence(
                        proposition="active_route_charging_summary",
                        value={
                            "route_id": segment.route_id,
                            "route_distance_km": format(
                                segment.distance_km.normalize(), "f"
                            ),
                            "remaining_route_distance_km": format(
                                total_distance.normalize(), "f"
                            ),
                            "destination_name": destination_name,
                            "final_destination_name": final_destination_name,
                            "state_of_charge": format(state_of_charge.normalize(), "f"),
                            "available_range_km": format(
                                available_range.normalize(), "f"
                            ),
                            "needs_charging": available_range < total_distance,
                        },
                        status=EvidenceStatus.KNOWN,
                        source_kind=EvidenceSourceKind.DERIVED,
                        source_turn_id=f"active-route-charge-{item.goal.goal_id}",
                        confidence=min(
                            charging_evidence.confidence,
                            navigation_evidence.confidence,
                        ),
                        derived_from=[
                            evidence_id for evidence_id in parent_ids if evidence_id
                        ],
                        derivation="strict_active_route_charging_summary_v1",
                    )
                )
                summary = self._validated_active_route_charging_summary(session)
                if summary is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )

            summary_evidence, values = summary
            if (
                item.goal.desired_outcome.get(_ACTIVE_ROUTE_BUFFER_SEARCH_MARKER)
                is True
            ):
                return self._next_active_route_buffer_search(
                    session,
                    item=item,
                    summary_evidence=summary_evidence,
                )
            if values["needs_charging"] is not True:
                session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
                return self._text_plan(
                    session,
                    (
                        f"I checked the active route. Your available range is "
                        f"{values['available_range_km']} "
                        f"kilometers, which covers the "
                        f"{values['remaining_route_distance_km']} kilometer remaining "
                        "route. You do not need a charging stop along the way."
                    ),
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )
            if (
                item.goal.desired_outcome.get(_ACTIVE_ROUTE_CHARGING_SEARCH_MARKER)
                is not True
            ):
                session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
                return self._text_plan(
                    session,
                    (
                        f"I checked the active route. Your available range is "
                        f"{values['available_range_km']} "
                        f"kilometers, but the remaining route is "
                        f"{values['remaining_route_distance_km']} kilometers, so you "
                        "will need "
                        "to charge. Would you like me to search along that route?"
                    ),
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )

            available_range = Decimal(values["available_range_km"])
            route_distance = Decimal(values["route_distance_km"])
            requested_kilometer = int(available_range / Decimal(50)) * 50
            if not 50 <= requested_kilometer < route_distance:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            filters = ["charging_stations::has_available_plug"]
            arguments = {
                "route_id": values["route_id"],
                "filters": filters,
                "category_poi": "charging_stations",
                "at_kilometer": requested_kilometer,
            }
            self._register_single_read_need(
                session,
                goal_id=item.goal.goal_id,
                proposition="active_route_charging_station_candidates",
            )
            observed = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="search_poi_along_the_route",
                arguments=arguments,
                proposition="active_route_charging_station_candidates",
            )
            if observed is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="search_poi_along_the_route",
                        arguments=arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="search_poi_along_the_route",
                    arguments=arguments,
                    semantic_operation="search_trip_charger_along_route",
                    proposition="active_route_charging_station_candidates",
                )
            _, charger_evidence = observed
            raw_candidates = (
                charger_evidence.value.get("pois_found_along_route")
                if isinstance(charger_evidence.value, Mapping)
                else None
            )
            assessment = self._trip_charger_assessment(
                charger_evidence,
                route_id=values["route_id"],
                route_distance_km=route_distance,
                requested_kilometer=requested_kilometer,
            )
            if (
                not isinstance(raw_candidates, list)
                or len(raw_candidates) != 1
                or assessment is None
                or assessment.route_kilometer + assessment.detour_km > available_range
                or summary_evidence.evidence_id is None
                or charger_evidence.evidence_id is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            charger_summary = Evidence(
                proposition="active_route_charger_summary",
                value={
                    "station_id": assessment.station_id,
                    "station_name": assessment.name,
                    "phone_number": assessment.phone_number,
                    "route_id": values["route_id"],
                    "requested_kilometer": requested_kilometer,
                    "route_kilometer": format(
                        assessment.route_kilometer.normalize(), "f"
                    ),
                    "detour_km": format(assessment.detour_km.normalize(), "f"),
                    "detour_minutes": assessment.detour_minutes,
                    "available_power_type": assessment.available_power_type,
                    "available_power_kw": format(
                        assessment.available_power_kw.normalize(), "f"
                    ),
                },
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"active-route-charger-{item.goal.goal_id}",
                confidence=min(
                    summary_evidence.confidence, charger_evidence.confidence
                ),
                derived_from=[
                    summary_evidence.evidence_id,
                    charger_evidence.evidence_id,
                ],
                derivation="strict_active_route_charger_summary_v1",
            )
            session.evidence.add(charger_summary)
            validated = self._validated_active_route_charger_summary(session)
            if validated is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            _, charger_values = validated
            session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
            return self._text_plan(
                session,
                (
                    f"You will need to charge. I found "
                    f"{charger_values['station_name']} around kilometer "
                    f"{charger_values['route_kilometer']} on the route. It has an "
                    f"available {charger_values['available_power_kw']} kilowatt "
                    f"{charger_values['available_power_type']} plug, with a "
                    f"{charger_values['detour_km']} kilometer detour adding about "
                    f"{charger_values['detour_minutes']} minutes. I did not add it "
                    "to navigation."
                ),
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
        return None

    def _next_trip_charger_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if (
                item.goal.semantic_operation != _TRIP_RANGE_OPERATION
                or item.goal.desired_outcome.get(_TRIP_CHARGER_SEARCH_MARKER)
                is not True
            ):
                continue
            summary = self._validated_trip_route_summary(
                session, require_range_shortfall=False
            )
            if summary is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            summary_evidence, values = summary
            if (
                item.goal.desired_outcome.get(_TRIP_CHARGER_STATUS_MARKER) is True
                and values.get("available_range_km") is None
            ):
                charging_arguments: dict[str, Any] = {}
                charging = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_charging_specs_and_status",
                    arguments=charging_arguments,
                    proposition="trip_charging_status",
                )
                if charging is None:
                    if (
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name="get_charging_specs_and_status",
                            arguments=charging_arguments,
                        )
                        is not None
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._navigation_read_plan(
                        session,
                        item=item,
                        tool_name="get_charging_specs_and_status",
                        arguments=charging_arguments,
                        semantic_operation=_TRIP_RANGE_OPERATION,
                        proposition="trip_charging_status",
                    )
                _, charging_evidence = charging
                charging_values = self._trip_charging_values(charging_evidence)
                parents = [
                    session.evidence.evidence.get(parent_id)
                    for parent_id in summary_evidence.derived_from
                ]
                location_evidence = next(
                    (
                        parent
                        for parent in parents
                        if parent is not None
                        and parent.proposition == "trip_destination_location_id"
                    ),
                    None,
                )
                route_evidence = next(
                    (
                        parent
                        for parent in parents
                        if parent is not None
                        and parent.proposition == "trip_route_options"
                    ),
                    None,
                )
                route = (
                    self._detailed_trip_route(
                        route_evidence,
                        start_id=values["start_id"],
                        destination_id=values["destination_id"],
                    )
                    if route_evidence is not None
                    else None
                )
                if (
                    charging_values is None
                    or location_evidence is None
                    or route_evidence is None
                    or route is None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                state_of_charge, available_range = charging_values
                if (
                    self._store_trip_route_summary(
                        session,
                        goal=item.goal,
                        destination_name=values["destination_name"],
                        start_id=values["start_id"],
                        destination_id=values["destination_id"],
                        route=route,
                        location_evidence=location_evidence,
                        route_evidence=route_evidence,
                        charging_evidence=charging_evidence,
                        state_of_charge=state_of_charge,
                        available_range=available_range,
                    )
                    is None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                if available_range >= route.distance_km:
                    return self._text_plan(
                        session,
                        "The verified current range is sufficient, so I did not search for a charging stop.",
                        goal_ids=[item.goal.goal_id],
                        kind=ProposalKind.COMPLETE,
                    )
                summary = self._validated_trip_route_summary(
                    session, require_range_shortfall=True
                )
                if summary is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                summary_evidence, values = summary
            elif values.get("can_reach") is not False:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            route_id = item.goal.desired_outcome.get("route_id")
            category = item.goal.desired_outcome.get("category")
            at_kilometer = item.goal.desired_outcome.get("at_kilometer")
            filters = item.goal.desired_outcome.get("filters")
            if (
                not isinstance(route_id, str)
                or route_id != values.get("route_id")
                or category != "charging_stations"
                or type(at_kilometer) is not int
                or filters != ["charging_stations::has_dc_plug"]
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            arguments = {
                "route_id": route_id,
                "filters": filters,
                "category_poi": category,
                "at_kilometer": at_kilometer,
            }
            self._register_single_read_need(
                session,
                goal_id=item.goal.goal_id,
                proposition="trip_charging_station_candidates",
            )
            observed = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="search_poi_along_the_route",
                arguments=arguments,
                proposition="trip_charging_station_candidates",
            )
            if observed is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="search_poi_along_the_route",
                        arguments=arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="search_poi_along_the_route",
                    arguments=arguments,
                    semantic_operation="search_trip_charger_along_route",
                    proposition="trip_charging_station_candidates",
                )
            _, charger_evidence = observed
            assessment = self._trip_charger_assessment(
                charger_evidence,
                route_id=route_id,
                route_distance_km=Decimal(values["route_distance_km"]),
                requested_kilometer=at_kilometer,
            )
            if assessment is None:
                return self._text_plan(
                    session,
                    "I could not verify an available charging station on the selected route.",
                    goal_ids=[item.goal.goal_id],
                )
            try:
                station_is_reachable = (
                    assessment.route_kilometer + assessment.detour_km
                    <= Decimal(values["available_range_km"])
                )
            except (InvalidOperation, TypeError):
                station_is_reachable = False
            if not station_is_reachable:
                return self._text_plan(
                    session,
                    "The available charging station was beyond the verified current range.",
                    goal_ids=[item.goal.goal_id],
                )
            summary_evidence = summary[0]
            station_summary = Evidence(
                proposition="trip_charger_assessment_summary",
                value={
                    "station_id": assessment.station_id,
                    "station_name": assessment.name,
                    "route_id": route_id,
                    "requested_kilometer": at_kilometer,
                    "route_kilometer": format(
                        assessment.route_kilometer.normalize(), "f"
                    ),
                    "detour_km": format(assessment.detour_km.normalize(), "f"),
                    "detour_minutes": assessment.detour_minutes,
                    "opening_hours": assessment.opening_hours,
                    "dc_occupied": assessment.dc_occupied,
                    "dc_available": assessment.dc_available,
                    "available_power_type": assessment.available_power_type,
                    "available_power_kw": format(
                        assessment.available_power_kw.normalize(), "f"
                    ),
                },
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"trip-charger-{item.goal.goal_id}",
                confidence=min(
                    summary_evidence.confidence, charger_evidence.confidence
                ),
                derived_from=[
                    evidence_id
                    for evidence_id in (
                        summary_evidence.evidence_id,
                        charger_evidence.evidence_id,
                    )
                    if evidence_id is not None
                ],
                derivation="strict_trip_charger_assessment_v1",
            )
            if len(station_summary.derived_from) != 2:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            session.evidence.add(station_summary)
            if item.goal.desired_outcome.get(_TRIP_CHARGER_EMAIL_CHAIN_MARKER) is True:
                first_name = item.goal.desired_outcome.get("first_name")
                requested_contact_name = item.goal.desired_outcome.get(
                    "requested_contact_name"
                )
                source_turn_id = session.grounded_value_sources_by_goal.get(
                    item.goal.goal_id, {}
                ).get("requested_contact_name")
                if (
                    not isinstance(first_name, str)
                    or not isinstance(requested_contact_name, str)
                    or not isinstance(source_turn_id, str)
                    or not self._trip_email_schema_available(
                        session, first_name=first_name, full=True
                    )
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                    )
                email_goal = self._begin_trip_email_goal(
                    session,
                    turn_id=source_turn_id,
                    first_name=first_name,
                    requested_contact_name=requested_contact_name,
                )
                refreshed = self._prepare_turn(session)
                return self._next_trip_email_workflow(
                    session, refreshed
                ) or self._limitation_plan(
                    session, email_goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            if assessment.dc_available:
                availability = "A DC plug is currently available"
            elif assessment.dc_occupied:
                availability = "The DC plugs are currently occupied"
            else:
                availability = "The DC plugs are currently unavailable"
            return self._text_plan(
                session,
                (
                    f"{assessment.name} is around kilometer "
                    f"{assessment.route_kilometer} on the fastest route, with a "
                    f"{assessment.detour_km} kilometer detour adding about "
                    f"{assessment.detour_minutes} minutes. {availability}, and a "
                    f"{assessment.available_power_kw} kilowatt "
                    f"{assessment.available_power_type} plug is available. "
                    "I did not add it to navigation."
                ),
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
        return None

    def _supersede_active_request_state(
        self,
        session: SessionState,
        *,
        source_turn_id: str,
        reason: str,
    ) -> None:
        """Retire an older request before returning a terminal new limitation."""

        old_goal_ids = tuple(goal.goal_id for goal in session.goal_dag.goals)
        self._abort_execution_bundle(
            session,
            reason=reason,
            source_turn_id=source_turn_id,
        )
        self._fail_goals(session, old_goal_ids, reason)
        old_goal_id_set = set(old_goal_ids)
        session.evidence.needs = {
            need_id: need
            for need_id, need in session.evidence.needs.items()
            if need.required_for_goal_id not in old_goal_id_set
        }
        session.authorized_action_goal_ids.clear()
        session.grounded_desired_values_by_goal.clear()
        session.grounded_value_sources_by_goal.clear()
        session.derived_value_evidence_by_goal.clear()
        session.relative_fan_speed_deltas_by_goal.clear()
        session.relative_climate_temperature_deltas_by_goal.clear()
        session.relative_seat_heating_deltas_by_goal.clear()
        session.occupied_seat_heating_goal_ids.clear()
        session.climate_sync_source_zones_by_goal.clear()
        session.pending_clarifications.clear()
        session.pending_destination_clarification = None
        session.intent = None
        session.goal_dag = GoalDAG()

    @staticmethod
    def _broad_headlights_goal(session: SessionState) -> Goal | None:
        if not isinstance(session.intent, IntentFrame):
            return None
        matches = [
            goal
            for goal in session.intent.goals
            if goal.semantic_operation == _BROAD_HEADLIGHTS_OPERATION
            and goal.desired_outcome.get("enabled") is True
            and goal.desired_outcome.get(_BROAD_HEADLIGHTS_MARKER) is True
            and goal.goal_id in session.authorized_action_goal_ids
        ]
        return matches[0] if len(matches) == 1 else None

    def _broad_headlights_limitation(
        self,
        session: SessionState,
        goal: Goal,
        *,
        kind: MissingCapabilityKind,
        missing: str,
    ) -> PlannedOutbound:
        return self._transparent_limitation_plan(
            session,
            goal,
            missing_kind=kind,
            missing_description=missing,
            goal_description="turn on the requested headlights",
            unperformed_description="change the headlights",
        )

    @staticmethod
    def _broad_headlight_set_available(session: SessionState, beam: str) -> bool:
        tool_name = {
            "high": "set_head_lights_high_beams",
            "low": "set_head_lights_low_beams",
        }.get(beam)
        if tool_name is None or not session.live_tools.has_tool(tool_name):
            return False
        try:
            return session.live_tools.validate_arguments(tool_name, {"on": True}) == {
                "on": True
            }
        except ToolArgumentValidationError:
            return False

    def _broad_headlight_snapshot(
        self, session: SessionState, goal: Goal
    ) -> tuple[Mapping[str, bool], Evidence] | None:
        observed = self._derived_navigation_read_value(
            session,
            goal_id=goal.goal_id,
            tool_name="get_exterior_lights_status",
            arguments={},
            proposition=_BROAD_HEADLIGHTS_EVIDENCE,
        )
        if observed is None:
            return None
        value, evidence = observed
        expected = {
            "fog_lights",
            "head_lights_low_beams",
            "head_lights_high_beams",
        }
        if (
            not isinstance(value, Mapping)
            or set(value) != expected
            or any(type(value.get(name)) is not bool for name in expected)
            or evidence.status is not EvidenceStatus.KNOWN
            or evidence.source_kind is not EvidenceSourceKind.TOOL
            or evidence.state_version != session.evidence.current_state_version
            or evidence.evidence_id is None
        ):
            return None
        return value, evidence

    def _select_broad_headlight(
        self,
        session: SessionState,
        goal: Goal,
        *,
        beam: str,
        evidence: Evidence,
        selection_turn_id: str | None = None,
    ) -> bool:
        operation = {"high": "set_high_beams", "low": "set_low_beams"}.get(beam)
        if operation is None or evidence.evidence_id is None or session.intent is None:
            return False
        session.evidence.add(
            Evidence(
                proposition=f"derived_selection:{goal.goal_id}:headlight_beam",
                value=beam,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=selection_turn_id or evidence.source_turn_id,
                confidence=evidence.confidence,
                derived_from=[evidence.evidence_id],
                derivation="unlit_headlight_sibling_from_complete_snapshot_v1",
            )
        )
        selected = goal.model_copy(
            update={
                "semantic_operation": operation,
                "desired_outcome": {"enabled": True},
            },
            deep=True,
        )
        source_turn_ids = list(session.intent.intent_source_turn_ids)
        if selection_turn_id is not None:
            source_turn_ids = list(dict.fromkeys([*source_turn_ids, selection_turn_id]))
        session.intent = session.intent.model_copy(
            update={
                "goals": [selected],
                "unresolved_slots": [],
                "intent_source_turn_ids": source_turn_ids,
            },
            deep=True,
        )
        session.pending_clarifications.clear()
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True

    def _handle_broad_headlights_user_turn(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        goal = self._broad_headlights_goal(session)
        if goal is not None and goal.desired_outcome.get(_BROAD_HEADLIGHTS_CHOICE) is True:
            beam = _broad_headlight_choice(text)
            if beam is None:
                if _independent_action_supersedes_broad_headlight_choice(text):
                    self._supersede_active_request_state(
                        session,
                        source_turn_id=turn_id,
                        reason="a new direct action superseded the pending headlight choice",
                    )
                    return False, None
                clarification = self._next_clarification(session)
                return True, clarification or self._broad_headlights_limitation(
                    session,
                    goal,
                    kind=MissingCapabilityKind.INFORMATION,
                    missing="the requested headlight choice",
                )
            observed = self._broad_headlight_snapshot(session, goal)
            if observed is None:
                return True, self._broad_headlights_limitation(
                    session,
                    goal,
                    kind=MissingCapabilityKind.INFORMATION,
                    missing="an unchanged current headlight status",
                )
            value, evidence = observed
            if value["head_lights_low_beams"] or value["head_lights_high_beams"]:
                return True, self._broad_headlights_limitation(
                    session,
                    goal,
                    kind=MissingCapabilityKind.INFORMATION,
                    missing="an unchanged current headlight status",
                )
            if not self._broad_headlight_set_available(session, beam):
                return True, self._broad_headlights_limitation(
                    session,
                    goal,
                    kind=MissingCapabilityKind.CONTROL,
                    missing=f"{beam} beams",
                )
            if not self._select_broad_headlight(
                session,
                goal,
                beam=beam,
                evidence=evidence,
                selection_turn_id=turn_id,
            ):
                return True, self._broad_headlights_limitation(
                    session,
                    goal,
                    kind=MissingCapabilityKind.INFORMATION,
                    missing="a current headlight selection",
                )
            return True, None

        if not _broad_headlights_request(text):
            return False, None
        self._supersede_active_request_state(
            session,
            source_turn_id=turn_id,
            reason="a new broad-headlights request superseded the prior request",
        )
        digest = hashlib.sha256(f"{turn_id}\0broad-headlights\0{text}".encode()).hexdigest()
        goal = Goal(
            goal_id=f"goal-broad-headlights-{digest[:12]}",
            semantic_operation=_BROAD_HEADLIGHTS_OPERATION,
            desired_outcome={"enabled": True, _BROAD_HEADLIGHTS_MARKER: True},
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[goal],
            explicit_slots={"enabled": True},
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.ACTION,
        )
        session.authorized_action_goal_ids = {goal.goal_id}
        session.grounded_desired_values_by_goal = {goal.goal_id: {"enabled": True}}
        session.grounded_value_sources_by_goal = {goal.goal_id: {"enabled": turn_id}}
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True, None

    def _next_broad_headlights_workflow(
        self, session: SessionState
    ) -> PlannedOutbound | None:
        goal = self._broad_headlights_goal(session)
        if goal is None or session.goal_dag.get(goal.goal_id).status is not GoalStatus.PENDING:
            return None
        observed = self._broad_headlight_snapshot(session, goal)
        if observed is None:
            if self._successful_goal_read(
                session,
                goal_id=goal.goal_id,
                tool_name="get_exterior_lights_status",
                arguments={},
            ) is not None:
                return self._broad_headlights_limitation(
                    session,
                    goal,
                    kind=MissingCapabilityKind.INFORMATION,
                    missing="a complete current exterior-light status",
                )
            if self._empty_argument_tool_issue(
                session, "get_exterior_lights_status"
            ) is not None:
                return self._broad_headlights_limitation(
                    session,
                    goal,
                    kind=MissingCapabilityKind.INFORMATION,
                    missing="current exterior-light status",
                )
            self._register_single_read_need(
                session, goal_id=goal.goal_id, proposition=_BROAD_HEADLIGHTS_EVIDENCE
            )
            register_policy_read_needs(
                session.evidence,
                goal_id=goal.goal_id,
                required_facts=(
                    "fog_lights",
                    "head_lights_low_beams",
                    "head_lights_high_beams",
                ),
            )
            propositions = {
                _BROAD_HEADLIGHTS_EVIDENCE,
                "fog_lights",
                "head_lights_low_beams",
                "head_lights_high_beams",
            }
            need_ids = tuple(
                need.need_id
                for need in session.evidence.needs.values()
                if need.required_for_goal_id == goal.goal_id
                and need.proposition in propositions
                and need.need_id is not None
            )
            if len(need_ids) != len(propositions):
                return self._broad_headlights_limitation(
                    session,
                    goal,
                    kind=MissingCapabilityKind.INFORMATION,
                    missing="current exterior-light status",
                )
            call_id = session.next_call_id()
            proposal = DecisionProposal(
                kind=ProposalKind.TOOL_GET,
                goal_ids=[goal.goal_id],
                tool_calls=[
                    ProposedToolCall(
                        tool_name="get_exterior_lights_status",
                        arguments={},
                        call_id=call_id,
                        goal_id=goal.goal_id,
                    )
                ],
            )
            gate = self.precommit.validate(proposal, self._basic_gate_context(session))
            if gate.outcome is not GateOutcome.ALLOW:
                return self._route_gate_failure(session, proposal, gate, goal)
            return PlannedOutbound(
                self.adapter.serialize(gate),
                proposal=proposal,
                decision=gate,
                pending_need_ids={call_id: need_ids},
                policy_operations={call_id: "vehicle.exterior_lights.read"},
            )

        value, evidence = observed
        low_on = value["head_lights_low_beams"]
        high_on = value["head_lights_high_beams"]
        if low_on and high_on:
            session.goal_dag.set_status(goal.goal_id, GoalStatus.DONE)
            return self._text_plan(
                session,
                "The high and low beams are already on, so I did not repeat either action.",
                goal_ids=[goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
        if not low_on and not high_on:
            if not all(
                self._broad_headlight_set_available(session, beam)
                for beam in ("high", "low")
            ):
                return self._broad_headlights_limitation(
                    session,
                    goal,
                    kind=MissingCapabilityKind.CONTROL,
                    missing="high and low beams",
                )
            selected = goal.model_copy(
                update={
                    "desired_outcome": {
                        **goal.desired_outcome,
                        _BROAD_HEADLIGHTS_CHOICE: True,
                    }
                },
                deep=True,
            )
            assert session.intent is not None
            slot = AmbiguitySlot(
                name=_BROAD_HEADLIGHTS_SLOT,
                candidates=[
                    Candidate(candidate_id="broad-headlights-high", value="high", label="high"),
                    Candidate(candidate_id="broad-headlights-low", value="low", label="low"),
                ],
                goal_id=goal.goal_id,
                source_turn_ids=list(session.intent.intent_source_turn_ids),
            )
            session.intent = session.intent.model_copy(
                update={"goals": [selected], "unresolved_slots": [slot]}, deep=True
            )
            session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
            clarification = self._next_clarification(session)
            return clarification or self._broad_headlights_limitation(
                session,
                goal,
                kind=MissingCapabilityKind.INFORMATION,
                missing="the requested headlight choice",
            )

        beam = "high" if low_on else "low"
        if not self._broad_headlight_set_available(session, beam):
            return self._broad_headlights_limitation(
                session,
                goal,
                kind=MissingCapabilityKind.CONTROL,
                missing=f"{beam} beams",
            )
        if not self._select_broad_headlight(
            session, goal, beam=beam, evidence=evidence
        ):
            return self._broad_headlights_limitation(
                session,
                goal,
                kind=MissingCapabilityKind.INFORMATION,
                missing="a current headlight selection",
            )
        return None

    def _handle_current_weather_fog_lights_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        request = _current_weather_fog_lights_request(text)
        if request is None:
            return False, None
        location = self._current_location_identity(session)
        current = self._current_datetime_parts(session)
        if location is None or current is None:
            self._supersede_active_request_state(
                session,
                source_turn_id=turn_id,
                reason="the new fog-light request lacked current location or time",
            )
            return True, self._text_plan(
                session,
                "I cannot verify the current location and time, so I did not change the fog lights.",
            )
        if (
            request.location_name is not None
            and _argument_identifier(request.location_name)
            != _argument_identifier(location[1])
        ):
            return False, None

        digest = hashlib.sha256(
            f"{turn_id}\0current-weather-fog-lights".encode()
        ).hexdigest()
        desired = {
            "enabled": True,
            _CURRENT_WEATHER_FOG_LIGHTS_MARKER: True,
        }
        goal = Goal(
            goal_id=f"goal-current-weather-fog-lights-{digest[:12]}",
            semantic_operation="set_fog_lights",
            desired_outcome=desired,
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[goal],
            explicit_slots={"enabled": True},
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.ACTION,
        )
        session.authorized_action_goal_ids = {goal.goal_id}
        session.grounded_desired_values_by_goal = {goal.goal_id: {"enabled": True}}
        session.grounded_value_sources_by_goal = {
            goal.goal_id: {"enabled": turn_id}
        }
        session.derived_value_evidence_by_goal = {}
        session.relative_fan_speed_deltas_by_goal = {}
        session.relative_climate_temperature_deltas_by_goal = {}
        session.relative_seat_heating_deltas_by_goal = {}
        session.occupied_seat_heating_goal_ids = set()
        session.climate_sync_source_zones_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True, None

    @staticmethod
    def _current_weather_fog_lights_goal(session: SessionState) -> Goal | None:
        if not isinstance(session.intent, IntentFrame):
            return None
        matches = [
            goal
            for goal in session.intent.goals
            if goal.semantic_operation == "set_fog_lights"
            and goal.desired_outcome.get(_CURRENT_WEATHER_FOG_LIGHTS_MARKER) is True
            and goal.desired_outcome.get("enabled") is True
        ]
        return matches[0] if len(matches) == 1 else None

    def _next_current_weather_fog_lights_workflow(
        self, session: SessionState
    ) -> PlannedOutbound | None:
        goal = self._current_weather_fog_lights_goal(session)
        if goal is None or session.goal_dag.get(goal.goal_id).status is not GoalStatus.PENDING:
            return None
        identity = self._current_location_identity(session)
        current = self._current_datetime_parts(session)
        if identity is None or current is None:
            return self._text_plan(
                session,
                "I cannot verify the current location and time, so I did not change the fog lights.",
                goal_ids=[goal.goal_id],
            )
        arguments = {
            "location_or_poi_id": identity[0],
            "month": current[1],
            "day": current[2],
            "time_hour_24hformat": current[3],
            "time_minutes": current[4],
        }
        observation = self._successful_goal_read(
            session,
            goal_id=goal.goal_id,
            tool_name="get_weather",
            arguments=arguments,
        )
        if observation is not None:
            value = observation.value
            slot = value.get("current_slot") if isinstance(value, Mapping) else None
            condition = slot.get("condition") if isinstance(slot, Mapping) else None
            if (
                not isinstance(condition, str)
                or not condition.strip()
                or condition.strip().casefold() in {"missing", "none", "null", "unknown"}
            ):
                return self._transparent_limitation_plan(
                    session,
                    goal,
                    missing_kind=MissingCapabilityKind.INFORMATION,
                    missing_description="current weather condition",
                    goal_description="change the fog lights safely",
                    unperformed_description="change the fog lights",
                )
            grounded = dict(
                session.grounded_desired_values_by_goal.get(goal.goal_id, {})
            )
            grounded["weather_condition"] = condition.strip()
            session.grounded_desired_values_by_goal[goal.goal_id] = grounded
            return None

        live_tools = session.live_tools
        try:
            available = bool(
                live_tools is not None
                and live_tools.has_tool("get_weather")
                and live_tools.validate_arguments("get_weather", arguments) == arguments
            )
        except ToolArgumentValidationError:
            available = False
        if not available:
            return self._transparent_limitation_plan(
                session,
                goal,
                missing_kind=MissingCapabilityKind.INFORMATION,
                missing_description="current weather condition",
                goal_description="change the fog lights safely",
                unperformed_description="change the fog lights",
            )
        self._register_single_read_need(
            session, goal_id=goal.goal_id, proposition="weather_condition"
        )
        need_ids = tuple(
            need.need_id
            for need in session.evidence.needs.values()
            if need.required_for_goal_id == goal.goal_id
            and need.proposition == "weather_condition"
            and need.need_id is not None
        )
        call_id = session.next_call_id()
        proposal = DecisionProposal(
            kind=ProposalKind.TOOL_GET,
            goal_ids=[goal.goal_id],
            tool_calls=[
                ProposedToolCall(
                    tool_name="get_weather",
                    arguments=arguments,
                    call_id=call_id,
                    goal_id=goal.goal_id,
                )
            ],
        )
        gate = self.precommit.validate(proposal, self._basic_gate_context(session))
        if gate.outcome is not GateOutcome.ALLOW:
            return self._route_gate_failure(session, proposal, gate, goal)
        return PlannedOutbound(
            self.adapter.serialize(gate),
            proposal=proposal,
            decision=gate,
            pending_need_ids={call_id: need_ids},
            policy_operations={call_id: "weather.current.read"},
        )

    @staticmethod
    def _seat_target_domain_supports(
        domain: Mapping[str, Any] | None, target_zone: str
    ) -> bool:
        if domain is None:
            return False
        constant = domain.get("const")
        if constant is not None:
            return constant == target_zone
        enum = domain.get("enum")
        if isinstance(enum, list):
            return target_zone in enum
        return domain.get("type") in {None, "string"}

    def _dependent_seat_sync_capability_issue(
        self,
        session: SessionState,
        request: _DependentSeatHeatingCapabilityRequest,
    ) -> str | None:
        live_tools = session.live_tools
        if live_tools is None:
            return "the current vehicle controls are unavailable"
        required_tools = (
            ("set_climate_temperature", "cabin-temperature control"),
            ("get_seat_heating_level", "current seat-heating level information"),
            ("set_seat_heating", "seat-heating control"),
            ("set_steering_wheel_heating", "steering-wheel heating control"),
        )
        missing = [
            description
            for tool_name, description in required_tools
            if not live_tools.has_tool(tool_name)
        ]
        if missing:
            return f"{', '.join(missing)} is unavailable"

        target = request.target_zone
        try:
            if live_tools.validate_arguments("get_seat_heating_level", {}) != {}:
                return "the current seat-heating level cannot be read safely"
            climate_arguments = {
                "temperature": request.temperature,
                "seat_zone": target,
            }
            if (
                live_tools.validate_arguments(
                    "set_climate_temperature", climate_arguments
                )
                != climate_arguments
            ):
                return "the requested cabin temperature cannot be expressed safely"
        except ToolArgumentValidationError:
            return (
                "the requested cabin temperature or current seat-heating level "
                "cannot be expressed safely"
            )

        if not self._seat_target_domain_supports(
            live_tools.parameter_domain("set_seat_heating", "seat_zone"), target
        ):
            return (
                "the current seat-heating control cannot target the "
                f"{target.casefold()} seat"
            )

        for level in range(4):
            try:
                seat_arguments = {"level": level, "seat_zone": target}
                steering_arguments = {"level": level}
                if (
                    live_tools.validate_arguments(
                        "set_seat_heating", seat_arguments
                    )
                    != seat_arguments
                ):
                    return "the matched seat-heating level cannot be expressed safely"
                if (
                    live_tools.validate_arguments(
                        "set_steering_wheel_heating", steering_arguments
                    )
                    != steering_arguments
                ):
                    return (
                        "the matched steering-wheel heating level cannot be "
                        "expressed safely"
                    )
            except ToolArgumentValidationError as exc:
                if exc.path.endswith("seat_zone") or "seat_zone" in exc.path:
                    return (
                        "the current seat-heating control cannot target the "
                        f"{target.casefold()} seat"
                    )
                if "set_steering_wheel_heating" in str(exc):
                    return (
                        "the matched steering-wheel heating level cannot be "
                        "expressed safely"
                    )
                return (
                    "the matched seat or steering-wheel heating level cannot be "
                    "expressed safely"
                )
        return None

    def _handle_seat_heating_capability_preflight(
        self, session: SessionState, text: str, turn_id: str
    ) -> PlannedOutbound | None:
        dependent = _dependent_seat_heating_capability_request(text)
        if dependent is not None:
            issue = self._dependent_seat_sync_capability_issue(session, dependent)
            if issue is None:
                return None
            self._supersede_active_request_state(
                session,
                source_turn_id=turn_id,
                reason="the new dependent seat-heating request was unavailable",
            )
            target = dependent.target_zone.casefold()
            return self._text_plan(
                session,
                f"I cannot safely match the {target} seat heating because {issue}. "
                "The steering-wheel match depends on that result, so I did not "
                f"change the {target} temperature, {target} seat heating, or "
                "steering-wheel heating.",
            )

        request = _seat_heating_capability_request(text)
        if request is None:
            return None
        live_tools = session.live_tools
        has_control = live_tools is not None and live_tools.has_tool(
            "set_seat_heating"
        )
        missing_zone = bool(
            has_control
            and request.target_zone is not None
            and live_tools.parameter_domain("set_seat_heating", "seat_zone") is None
        )
        if has_control and not missing_zone:
            return None

        digest = hashlib.sha256(
            f"{turn_id}\0seat-heating-capability".encode()
        ).hexdigest()
        desired = (
            {"seat_zone": request.target_zone}
            if request.target_zone is not None
            else {}
        )
        goal = Goal(
            goal_id=f"goal-seat-heating-capability-{digest[:12]}",
            semantic_operation="set_seat_heating",
            desired_outcome=desired,
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=True,
            goals=[goal],
            explicit_slots=dict(desired),
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.ACTION,
        )
        session.authorized_action_goal_ids = set()
        session.grounded_desired_values_by_goal = {goal.goal_id: dict(desired)}
        session.grounded_value_sources_by_goal = {
            goal.goal_id: {name: turn_id for name in desired}
        }
        session.derived_value_evidence_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)

        recipe = self.recipes.get("seat_heating")
        operation = recipe.target_operation("set_seat_heating")
        assert operation is not None and operation in recipe.write_operations
        if not has_control:
            specific = self._selected_operation_limitation_plan(
                session, goal, operation=operation, is_write=True
            )
            return specific or self._limitation_plan(
                session, goal, GateOutcome.UNSUPPORTED_CAPABILITY
            )

        assert live_tools is not None
        binding = self.semantic_binder.bind_operation(
            operation,
            semantic_values=desired,
            recipe_id=recipe.id,
            live_tools=live_tools,
            is_read=False,
        )
        if binding is not None and "seat_zone" in binding.unsupported_parameters:
            specific = self._mapped_parameter_limitation_plan(
                session, goal, operation=operation, binding=binding
            )
            if specific is not None:
                return specific
        return self._limitation_plan(
            session, goal, GateOutcome.UNSUPPORTED_PARAMETER
        )

    def _handle_seat_occupancy_information_request(
        self, session: SessionState, text: str, turn_id: str
    ) -> tuple[bool, PlannedOutbound | None]:
        request = _seat_occupancy_information_request(text)
        if request is None:
            return False, None
        live_tools = session.live_tools
        try:
            available = bool(
                live_tools is not None
                and live_tools.has_tool("get_seats_occupancy")
                and live_tools.validate_arguments("get_seats_occupancy", {}) == {}
            )
        except ToolArgumentValidationError:
            available = False
        if not available:
            self._supersede_active_request_state(
                session,
                source_turn_id=turn_id,
                reason="the new seat-occupancy request was unavailable",
            )
            return True, self._text_plan(
                session,
                "Current seat occupancy information is unavailable. I did not change any vehicle setting.",
            )

        digest = hashlib.sha256(
            f"{turn_id}\0seat-occupancy-information".encode()
        ).hexdigest()
        goal = Goal(
            goal_id=f"goal-seat-occupancy-info-{digest[:12]}",
            semantic_operation="read_seat_occupancy",
            desired_outcome={
                _SEAT_OCCUPANCY_INFO_MARKER: True,
                "include_climate": request.include_climate,
            },
        )
        session.intent = IntentFrame(
            language=self._language(session),
            call_for_action=False,
            goals=[goal],
            intent_source_turn_ids=[turn_id],
            goal_mention_order=[goal.goal_id],
            intent_kind=IntentKind.INFORMATION,
        )
        session.authorized_action_goal_ids = set()
        session.grounded_desired_values_by_goal = {goal.goal_id: {}}
        session.grounded_value_sources_by_goal = {goal.goal_id: {}}
        session.derived_value_evidence_by_goal = {}
        session.pending_clarifications.clear()
        session.execution_bundle = None
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)
        return True, None

    @staticmethod
    def _spoken_items(items: Sequence[str]) -> str:
        if not items:
            return ""
        if len(items) == 1:
            return items[0]
        if len(items) == 2:
            return f"{items[0]} and {items[1]}"
        return f"{', '.join(items[:-1])}, and {items[-1]}"

    def _next_seat_occupancy_information_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if (
                item.goal.semantic_operation != "read_seat_occupancy"
                or item.goal.desired_outcome.get(_SEAT_OCCUPANCY_INFO_MARKER)
                is not True
            ):
                continue
            goal_id = item.goal.goal_id
            self._register_single_read_need(
                session,
                goal_id=goal_id,
                proposition=_SEAT_OCCUPANCY_INFO_EVIDENCE,
            )
            include_climate = (
                item.goal.desired_outcome.get("include_climate") is True
            )
            specifications: list[tuple[str, Mapping[str, Any], str, str]] = []
            occupancy_observation = self._successful_goal_read(
                session,
                goal_id=goal_id,
                tool_name="get_seats_occupancy",
                arguments={},
            )
            if occupancy_observation is None:
                specifications.append(
                    (
                        "get_seats_occupancy",
                        {},
                        "read_seat_occupancy",
                        _SEAT_OCCUPANCY_INFO_EVIDENCE,
                    )
                )

            climate_available = False
            climate_observation: SuccessfulReadResult | None = None
            if include_climate:
                try:
                    climate_available = bool(
                        session.live_tools.has_tool("get_climate_settings")
                        and session.live_tools.validate_arguments(
                            "get_climate_settings", {}
                        )
                        == {}
                    )
                except ToolArgumentValidationError:
                    climate_available = False
                if climate_available:
                    self._register_single_read_need(
                        session, goal_id=goal_id, proposition="fan_speed"
                    )
                    climate_observation = self._successful_goal_read(
                        session,
                        goal_id=goal_id,
                        tool_name="get_climate_settings",
                        arguments={},
                    )
                    if climate_observation is None:
                        specifications.append(
                            (
                                "get_climate_settings",
                                {},
                                "read_climate_settings",
                                "fan_speed",
                            )
                        )
            if specifications:
                return self._parallel_navigation_read_plan(
                    session, item=item, specifications=specifications
                )

            assert occupancy_observation is not None
            occupancy_evidence = self._evidence_for_goal_read(
                session,
                goal_id=goal_id,
                proposition=_SEAT_OCCUPANCY_INFO_EVIDENCE,
                observation=occupancy_observation,
            )
            raw_occupancy = occupancy_observation.value
            seat_names = ("driver", "passenger", "driver_rear", "passenger_rear")
            seats = (
                raw_occupancy.get("seats_occupied")
                if isinstance(raw_occupancy, Mapping)
                else None
            )
            if (
                occupancy_evidence is None
                or not isinstance(raw_occupancy, Mapping)
                or set(raw_occupancy) != {"seats_occupied"}
                or not isinstance(seats, Mapping)
                or set(seats) != set(seat_names)
                or any(type(seats.get(name)) is not bool for name in seat_names)
                or occupancy_evidence.value != seats
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            labels = {
                "driver": "driver seat",
                "passenger": "front passenger seat",
                "driver_rear": "driver-side rear seat",
                "passenger_rear": "passenger-side rear seat",
            }
            occupied = [labels[name] for name in seat_names if seats[name]]
            unoccupied = [labels[name] for name in seat_names if not seats[name]]
            parts = [
                (
                    f"Occupied seats are {self._spoken_items(occupied)}."
                    if occupied
                    else "No seats are currently occupied."
                ),
                (
                    f"Unoccupied seats are {self._spoken_items(unoccupied)}."
                    if unoccupied
                    else "No seats are currently unoccupied."
                ),
            ]

            if include_climate:
                if not climate_available:
                    parts.insert(0, "Current climate settings are unavailable.")
                else:
                    assert climate_observation is not None
                    climate = climate_observation.value
                    expected_fields = {
                        "fan_speed",
                        "fan_airflow_direction",
                        "air_conditioning",
                        "air_circulation",
                        "window_front_defrost",
                        "window_rear_defrost",
                    }
                    if (
                        not isinstance(climate, Mapping)
                        or set(climate) != expected_fields
                        or type(climate.get("fan_speed")) is not int
                        or not 0 <= climate["fan_speed"] <= 5
                        or climate.get("fan_airflow_direction")
                        not in _CLIMATE_AIRFLOW_VALUES
                        or type(climate.get("air_conditioning")) is not bool
                        or climate.get("air_circulation")
                        not in _CLIMATE_CIRCULATION_VALUES
                        or type(climate.get("window_front_defrost")) is not bool
                        or type(climate.get("window_rear_defrost")) is not bool
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    airflow = str(climate["fan_airflow_direction"]).casefold().replace(
                        "_", " "
                    )
                    circulation = str(climate["air_circulation"]).casefold().replace(
                        "_", " "
                    )
                    parts.insert(
                        0,
                        "Current climate settings have air conditioning "
                        f"{'on' if climate['air_conditioning'] else 'off'}, fan speed "
                        f"{climate['fan_speed']}, airflow set to {airflow}, and "
                        f"circulation set to {circulation}.",
                    )

            session.goal_dag.set_status(goal_id, GoalStatus.DONE)
            return self._text_plan(
                session,
                "I found the current seat occupancy. " + " ".join(parts),
                goal_ids=[goal_id],
                kind=ProposalKind.RESPOND,
            )
        return None

    def _next_climate_settings_info_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            airflow_advisory = (
                item.goal.desired_outcome.get(_AIRFLOW_ADVISORY_MARKER) is True
            )
            if (
                item.goal.semantic_operation != "read_climate_settings"
                or (
                    item.goal.desired_outcome.get(_CLIMATE_SETTINGS_INFO_MARKER)
                    is not True
                    and not airflow_advisory
                )
            ):
                continue
            arguments: dict[str, Any] = {}
            self._register_single_read_need(
                session,
                goal_id=item.goal.goal_id,
                proposition="fan_speed",
            )
            observation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_climate_settings",
                arguments=arguments,
            )
            if observation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_climate_settings",
                    arguments=arguments,
                    semantic_operation="read_climate_settings",
                    proposition="fan_speed",
                )
            fan_evidence = self._evidence_for_goal_read(
                session,
                goal_id=item.goal.goal_id,
                proposition="fan_speed",
                observation=observation,
            )
            value = observation.value
            if not isinstance(value, Mapping):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            fan_speed = value.get("fan_speed")
            airflow = value.get("fan_airflow_direction")
            air_conditioning = value.get("air_conditioning")
            circulation = value.get("air_circulation")
            front_defrost = value.get("window_front_defrost")
            rear_defrost = value.get("window_rear_defrost")
            if (
                isinstance(fan_speed, bool)
                or not isinstance(fan_speed, int)
                or not 0 <= fan_speed <= 5
                or fan_evidence is None
                or fan_evidence.value != fan_speed
                or not isinstance(airflow, str)
                or airflow not in _CLIMATE_AIRFLOW_VALUES
                or not isinstance(air_conditioning, bool)
                or not isinstance(circulation, str)
                or circulation not in _CLIMATE_CIRCULATION_VALUES
                or not isinstance(front_defrost, bool)
                or not isinstance(rear_defrost, bool)
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            airflow_label = airflow.casefold().replace("_", " ")
            circulation_label = circulation.casefold().replace("_", " ")
            session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
            if airflow_advisory:
                options: list[str] = []
                if (
                    session.live_tools.has_tool("set_fan_speed")
                    and session.live_tools.parameter_domain("set_fan_speed", "level")
                    is not None
                ):
                    options.append("adjust the fan speed")
                if (
                    session.live_tools.has_tool("set_air_circulation")
                    and session.live_tools.parameter_domain(
                        "set_air_circulation", "mode"
                    )
                    is not None
                ):
                    options.append("change the air circulation mode")
                if (
                    session.live_tools.has_tool("open_close_window")
                    and session.live_tools.parameter_domain(
                        "open_close_window", "window"
                    )
                    is not None
                    and session.live_tools.parameter_domain(
                        "open_close_window", "percentage"
                    )
                    is not None
                ):
                    options.append("adjust the windows")
                if not options:
                    offer = "No airflow adjustment control is currently available."
                elif len(options) == 1:
                    offer = f"I can {options[0]}. Would you like me to do that?"
                else:
                    choices = f"{', '.join(options[:-1])}, or {options[-1]}"
                    offer = f"I can {choices}. Which option would you like?"
                fan_label = "off at level 0" if fan_speed == 0 else f"at level {fan_speed}"
                return self._text_plan(
                    session,
                    (
                        f"The fan is currently {fan_label}, and the air circulation "
                        f"is set to {circulation_label}. {offer}"
                    ),
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.RESPOND,
                )
            return self._text_plan(
                session,
                (
                    "I found the current climate settings. "
                    f"The air conditioning is {'on' if air_conditioning else 'off'}. "
                    f"Fan speed is {fan_speed}, airflow is set to {airflow_label}, "
                    f"and circulation is {circulation_label}. Front defrost is "
                    f"{'on' if front_defrost else 'off'}, and rear defrost is "
                    f"{'on' if rear_defrost else 'off'}."
                ),
                kind=ProposalKind.RESPOND,
            )
        return None

    def _next_comprehensive_charging_info_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if (
                item.goal.semantic_operation != "read_charging_status"
                or item.goal.desired_outcome.get(_CHARGING_STATUS_INFO_MARKER)
                is not True
            ):
                continue
            arguments: dict[str, Any] = {}
            self._register_single_read_need(
                session,
                goal_id=item.goal.goal_id,
                proposition=_CHARGING_STATUS_INFO_EVIDENCE,
            )
            observation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_charging_specs_and_status",
                arguments=arguments,
            )
            if observation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_charging_specs_and_status",
                    arguments=arguments,
                    semantic_operation="read_comprehensive_charging_status",
                    proposition=_CHARGING_STATUS_INFO_EVIDENCE,
                )
            evidence = self._evidence_for_goal_read(
                session,
                goal_id=item.goal.goal_id,
                proposition=_CHARGING_STATUS_INFO_EVIDENCE,
                observation=observation,
            )
            value = observation.value
            expected_fields = {
                "battery_capacity_kwh",
                "max_charging_power_ac",
                "max_charging_power_dc",
                "state_of_charge",
                "remaining_range",
            }
            if (
                not isinstance(value, Mapping)
                or set(value) != expected_fields
                or evidence is None
                or evidence.value != value
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            numeric_values: dict[str, Decimal] = {}
            for field_name in expected_fields.difference({"remaining_range"}):
                raw = value.get(field_name)
                if isinstance(raw, bool) or not isinstance(raw, (int, float, Decimal)):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                try:
                    numeric = Decimal(str(raw))
                except InvalidOperation:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                if not numeric.is_finite():
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                numeric_values[field_name] = numeric

            capacity = numeric_values["battery_capacity_kwh"]
            ac_power = numeric_values["max_charging_power_ac"]
            dc_power = numeric_values["max_charging_power_dc"]
            state_of_charge = numeric_values["state_of_charge"]
            remaining = value.get("remaining_range")
            remaining_match = (
                re.fullmatch(
                    r"\s*(\d+(?:\.\d+)?)\s*km\s*",
                    remaining,
                    re.IGNORECASE,
                )
                if isinstance(remaining, str)
                else None
            )
            remaining_km = (
                Decimal(remaining_match.group(1))
                if remaining_match is not None
                else None
            )
            if (
                not 0 < capacity <= 500
                or not 0 < ac_power <= 2000
                or not 0 < dc_power <= 2000
                or not 0 <= state_of_charge <= 100
                or state_of_charge != state_of_charge.to_integral_value()
                or remaining_km is None
                or not remaining_km.is_finite()
                or not 0 <= remaining_km <= 5000
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
            return self._text_plan(
                session,
                (
                    "I found the current battery and charging information. "
                    f"The battery is at {format(state_of_charge, 'f')} percent "
                    f"with a capacity of {format(capacity.normalize(), 'f')} "
                    "kilowatt-hours. Maximum charging power is "
                    f"{format(ac_power.normalize(), 'f')} kilowatts on AC and "
                    f"{format(dc_power.normalize(), 'f')} kilowatts on DC. "
                    "The remaining driving range is "
                    f"{format(remaining_km.normalize(), 'f')} kilometers."
                ),
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
        return None

    def _next_soc_to_empty_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            initial_soc = item.goal.desired_outcome.get("initial_soc")
            if (
                item.goal.semantic_operation != "get_distance_by_soc"
                or item.goal.desired_outcome.get(_SOC_TO_EMPTY_MARKER) is not True
                or isinstance(initial_soc, bool)
                or not isinstance(initial_soc, int)
                or not 1 <= initial_soc <= 100
            ):
                continue
            tool_name = "get_distance_by_soc"
            if not session.live_tools.has_tool(tool_name):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            required = session.live_tools.required_parameters(tool_name)
            initial_domain = session.live_tools.parameter_domain(
                tool_name, "initial_state_of_charge"
            )
            final_domain = session.live_tools.parameter_domain(
                tool_name, "final_state_of_charge"
            )
            final_default = (
                final_domain.get("default")
                if isinstance(final_domain, Mapping)
                else None
            )
            try:
                final_default_number = Decimal(str(final_default))
            except (InvalidOperation, TypeError, ValueError):
                final_default_number = Decimal("NaN")
            arguments = {"initial_state_of_charge": initial_soc}
            explicit_default_arguments = {
                **arguments,
                "final_state_of_charge": 0,
            }
            try:
                validated_arguments = session.live_tools.validate_arguments(
                    tool_name, arguments
                )
                validated_explicit_default = session.live_tools.validate_arguments(
                    tool_name, explicit_default_arguments
                )
            except ToolArgumentValidationError:
                validated_arguments = None
                validated_explicit_default = None
            if (
                "initial_state_of_charge" not in required
                or "final_state_of_charge" in required
                or not isinstance(initial_domain, Mapping)
                or initial_domain.get("type") not in {"integer", "number"}
                or not isinstance(final_domain, Mapping)
                or final_domain.get("type") not in {"integer", "number"}
                or not final_default_number.is_finite()
                or final_default_number != 0
                or validated_arguments != arguments
                or validated_explicit_default != explicit_default_arguments
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )

            self._register_single_read_need(
                session,
                goal_id=item.goal.goal_id,
                proposition=_SOC_TO_EMPTY_EVIDENCE,
            )
            observation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name=tool_name,
                arguments=arguments,
            )
            if observation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name=tool_name,
                    arguments=arguments,
                    semantic_operation="read_distance_until_empty",
                    proposition=_SOC_TO_EMPTY_EVIDENCE,
                )
            evidence = self._evidence_for_goal_read(
                session,
                goal_id=item.goal.goal_id,
                proposition=_SOC_TO_EMPTY_EVIDENCE,
                observation=observation,
            )
            expected_key = f"distance_km_for_{initial_soc}_until_0_percent_soc"
            value = observation.value
            raw_distance = (
                value.get(expected_key) if isinstance(value, Mapping) else None
            )
            distance_match = (
                re.fullmatch(
                    r"\s*(\d+(?:\.\d+)?)\s*km\s*",
                    raw_distance,
                    re.IGNORECASE,
                )
                if isinstance(raw_distance, str)
                else None
            )
            if (
                not isinstance(value, Mapping)
                or set(value) != {expected_key}
                or evidence is None
                or evidence.value != value
                or distance_match is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            distance = Decimal(distance_match.group(1))
            if not distance.is_finite() or not 0 <= distance <= 5000:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
            return self._text_plan(
                session,
                self.responses.range_estimate(
                    initial_soc=initial_soc,
                    final_soc=0,
                    distance_km=format(distance.normalize(), "f"),
                    language=self._language(session),
                ),
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
        return None

    @classmethod
    def _trip_charger_assessment(
        cls,
        evidence: Evidence,
        *,
        route_id: str,
        route_distance_km: Decimal,
        requested_kilometer: int,
    ) -> TripChargerAssessment | None:
        value = evidence.value
        candidates = (
            value.get("pois_found_along_route") if isinstance(value, Mapping) else None
        )
        if not isinstance(candidates, list) or not 1 <= len(candidates) <= 20:
            return None
        if len(candidates) > 1:
            assessments: list[TripChargerAssessment] = []
            for candidate in candidates:
                narrowed = evidence.model_copy(
                    update={"value": {"pois_found_along_route": [candidate]}},
                    deep=True,
                )
                assessment = cls._trip_charger_assessment(
                    narrowed,
                    route_id=route_id,
                    route_distance_km=route_distance_km,
                    requested_kilometer=requested_kilometer,
                )
                if assessment is None:
                    return None
                assessments.append(assessment)
            highest_available_power = max(
                assessment.available_power_kw for assessment in assessments
            )
            selected = [
                assessment
                for assessment in assessments
                if assessment.available_power_kw == highest_available_power
            ]
            return selected[0] if len(selected) == 1 else None
        station = candidates[0]
        if not isinstance(station, Mapping):
            return None
        station_id = station.get("id")
        name = station.get("name")
        opening_hours = station.get("opening_hours")
        phone_number = station.get("phone_number")
        route_ids = station.get("corresponding_route_ids")
        route_positions = station.get("route_positions")
        if (
            not isinstance(station_id, str)
            or not station_id.startswith("poi_cha_")
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(station_id) is None
            or not isinstance(name, str)
            or not cls._safe_poi_display_label(name, 120)
            or station.get("category") != "charging_stations"
            or cls._poi_opening_hours_minutes(opening_hours) is None
            or not isinstance(phone_number, str)
            or _POI_PHONE_PATTERN.fullmatch(phone_number) is None
            or not isinstance(route_ids, list)
            or not 1 <= len(route_ids) <= 20
            or any(
                not isinstance(candidate_route_id, str)
                or _ROUTE_ID_PATTERN.fullmatch(candidate_route_id) is None
                for candidate_route_id in route_ids
            )
            or len(set(route_ids)) != len(route_ids)
            or route_id not in route_ids
            or not isinstance(route_positions, Mapping)
            or not 1 <= len(route_positions) <= 20
        ):
            return None
        compatible_positions: list[Decimal] = []
        for position_key, position_value in route_positions.items():
            if not isinstance(position_key, str) or not isinstance(
                position_value, Mapping
            ):
                return None
            try:
                position = Decimal(str(position_value.get("at_route_kilometer")))
            except (InvalidOperation, TypeError):
                return None
            if not position.is_finite() or position < 0:
                return None
            if position_key in {route_id, route_id.rsplit("_", 1)[0]}:
                compatible_positions.append(position)
        if len(compatible_positions) != 1:
            return None
        route_kilometer = compatible_positions[0]
        if (
            not route_kilometer.is_finite()
            or route_kilometer < 0
            or route_kilometer > route_distance_km
            or abs(route_kilometer - requested_kilometer) > 25
        ):
            return None

        detour_distance = station.get("detour_from_route_km")
        detour_time = station.get("detour_from_route_time")
        if (
            not isinstance(detour_distance, Mapping)
            or set(detour_distance) != {"detour", "unit"}
            or detour_distance.get("unit") != "km"
            or not isinstance(detour_time, Mapping)
            or set(detour_time) != {"hour", "minutes"}
            or type(detour_time.get("hour")) is not int
            or type(detour_time.get("minutes")) is not int
        ):
            return None
        try:
            detour_km = Decimal(str(detour_distance.get("detour")))
        except (InvalidOperation, TypeError):
            return None
        hour = detour_time["hour"]
        minute = detour_time["minutes"]
        if (
            not detour_km.is_finite()
            or not 0 <= detour_km <= 50
            or not 0 <= hour <= 24
            or not 0 <= minute <= 59
            or hour * 60 + minute > 180
        ):
            return None

        plugs = station.get("charging_plugs")
        if not isinstance(plugs, list) or not 1 <= len(plugs) <= 20:
            return None
        seen_plug_ids: set[str] = set()
        dc_availability: list[str] = []
        available: list[tuple[Decimal, str]] = []
        for plug in plugs:
            if not isinstance(plug, Mapping):
                return None
            plug_id = plug.get("plug_id")
            power_type = plug.get("power_type")
            availability = plug.get("availability")
            if (
                not isinstance(plug_id, str)
                or re.fullmatch(r"plg_[^\W_][\w]*", plug_id, re.UNICODE) is None
                or plug_id in seen_plug_ids
                or power_type not in {"AC", "DC"}
                or availability
                not in {"available", "occupied", "out_of_service", "maintenance"}
                or isinstance(plug.get("power_kw"), bool)
            ):
                return None
            try:
                power_kw = Decimal(str(plug.get("power_kw")))
            except (InvalidOperation, TypeError):
                return None
            if not power_kw.is_finite() or not 0 < power_kw <= 1000:
                return None
            seen_plug_ids.add(plug_id)
            if power_type == "DC":
                dc_availability.append(availability)
            if availability == "available":
                available.append((power_kw, power_type))
        if not dc_availability or not available:
            return None
        maximum_power = max(power for power, _ in available)
        selected_plugs = [item for item in available if item[0] == maximum_power]
        if len(selected_plugs) != 1:
            return None
        return TripChargerAssessment(
            station_id=station_id,
            name=name.strip(),
            phone_number=phone_number,
            route_kilometer=route_kilometer,
            detour_km=detour_km,
            detour_minutes=hour * 60 + minute,
            opening_hours=str(opening_hours),
            dc_occupied=all(item == "occupied" for item in dc_availability),
            dc_available=any(item == "available" for item in dc_availability),
            available_power_type=selected_plugs[0][1],
            available_power_kw=selected_plugs[0][0],
        )

    def _validated_trip_charger_summary(
        self, session: SessionState
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        trip = self._validated_trip_route_summary(session, require_range_shortfall=True)
        candidates = session.evidence.latest_for_proposition(
            "trip_charger_assessment_summary", current_state_only=True
        )
        if trip is None or not candidates:
            return None
        trip_evidence, trip_values = trip
        summary = candidates[-1]
        values = summary.value
        if (
            summary.status is not EvidenceStatus.KNOWN
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.derivation != "strict_trip_charger_assessment_v1"
            or not isinstance(values, Mapping)
            or trip_evidence.evidence_id not in summary.derived_from
            or len(summary.derived_from) != 2
        ):
            return None
        raw_ids = [
            evidence_id
            for evidence_id in summary.derived_from
            if evidence_id != trip_evidence.evidence_id
        ]
        if len(raw_ids) != 1:
            return None
        raw = session.evidence.evidence.get(raw_ids[0])
        if (
            raw is None
            or raw.proposition != "trip_charging_station_candidates"
            or raw.status is not EvidenceStatus.KNOWN
            or raw.source_kind is not EvidenceSourceKind.TOOL
            or raw.state_version != session.evidence.current_state_version
            or type(values.get("requested_kilometer")) is not int
        ):
            return None
        assessment = self._trip_charger_assessment(
            raw,
            route_id=trip_values["route_id"],
            route_distance_km=Decimal(trip_values["route_distance_km"]),
            requested_kilometer=values["requested_kilometer"],
        )
        if assessment is None:
            return None
        expected = {
            "station_id": assessment.station_id,
            "station_name": assessment.name,
            "route_id": trip_values["route_id"],
            "requested_kilometer": values["requested_kilometer"],
            "route_kilometer": format(assessment.route_kilometer.normalize(), "f"),
            "detour_km": format(assessment.detour_km.normalize(), "f"),
            "detour_minutes": assessment.detour_minutes,
            "opening_hours": assessment.opening_hours,
            "dc_occupied": assessment.dc_occupied,
            "dc_available": assessment.dc_available,
            "available_power_type": assessment.available_power_type,
            "available_power_kw": format(
                assessment.available_power_kw.normalize(), "f"
            ),
        }
        try:
            reachable = assessment.route_kilometer + assessment.detour_km <= Decimal(
                trip_values["available_range_km"]
            )
        except (InvalidOperation, TypeError):
            return None
        if dict(values) != expected or not reachable:
            return None
        return summary, values

    @classmethod
    def _trip_contact_candidates_from_evidence(
        cls, evidence: Evidence, *, first_name: str
    ) -> tuple[tuple[str, str], ...] | None:
        matches = evidence.value
        if not isinstance(matches, Mapping) or not 1 <= len(matches) <= 20:
            return None
        candidates: list[tuple[str, str]] = []
        normalized_names: set[str] = set()
        for contact_id, raw_name in matches.items():
            if (
                not isinstance(contact_id, str)
                or re.fullmatch(r"con_[^\W_][\w]*", contact_id, re.UNICODE) is None
                or not isinstance(raw_name, str)
                or not cls._voice_result_field(raw_name, 120)
            ):
                return None
            parts = raw_name.strip().split()
            if len(parts) < 2 or _argument_identifier(parts[0]) != _argument_identifier(
                first_name
            ):
                return None
            display_name = " ".join(part[:1].upper() + part[1:] for part in parts)
            normalized = _argument_identifier(display_name)
            if normalized in normalized_names:
                return None
            normalized_names.add(normalized)
            candidates.append((contact_id, display_name))
        return tuple(candidates)

    def _validated_trip_contact_candidates(
        self, session: SessionState, *, goal_id: str, first_name: str
    ) -> tuple[Evidence, tuple[tuple[str, str], ...]] | None:
        summaries = session.evidence.latest_for_proposition(
            f"trip_contact_candidates:{goal_id}", current_state_only=True
        )
        if not summaries:
            return None
        summary = summaries[-1]
        if (
            summary.status is not EvidenceStatus.KNOWN
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.derivation != "strict_trip_contact_candidates_v1"
            or len(summary.derived_from) != 1
        ):
            return None
        raw = session.evidence.evidence.get(summary.derived_from[0])
        if (
            raw is None
            or raw.proposition != "trip_contact_matches"
            or raw.status is not EvidenceStatus.KNOWN
            or raw.source_kind is not EvidenceSourceKind.TOOL
            or raw.state_version != session.evidence.current_state_version
        ):
            return None
        parsed = self._trip_contact_candidates_from_evidence(raw, first_name=first_name)
        expected = [
            {"contact_id": contact_id, "display_name": display_name}
            for contact_id, display_name in parsed or ()
        ]
        if parsed is None or summary.value != expected:
            return None
        return summary, parsed

    def _select_trip_contact_candidate(
        self, session: SessionState, text: str
    ) -> tuple[str, str, Evidence] | None:
        goal = self._trip_email_goal(session)
        match = _TRIP_CONTACT_SELECTION_PATTERN.fullmatch(text)
        if goal is None or match is None:
            return None
        first_name = goal.desired_outcome.get("first_name")
        if not isinstance(first_name, str):
            return None
        validated = self._validated_trip_contact_candidates(
            session, goal_id=goal.goal_id, first_name=first_name
        )
        if validated is None:
            return None
        evidence, candidates = validated
        normalized = _argument_identifier(match.group("name"))
        selected = [
            (display_name, contact_id, evidence)
            for contact_id, display_name in candidates
            if _argument_identifier(display_name) == normalized
        ]
        return selected[0] if len(selected) == 1 else None

    def _bind_trip_contact_selection(
        self,
        session: SessionState,
        *,
        goal: Goal,
        display_name: str,
        contact_id: str,
        candidates_evidence: Evidence,
        source_turn_id: str,
    ) -> bool:
        if session.intent is None:
            return False
        grounded = dict(session.grounded_desired_values_by_goal.get(goal.goal_id, {}))
        grounded["selected_contact_name"] = display_name
        session.grounded_desired_values_by_goal[goal.goal_id] = grounded
        sources = dict(session.grounded_value_sources_by_goal.get(goal.goal_id, {}))
        sources["selected_contact_name"] = source_turn_id
        session.grounded_value_sources_by_goal[goal.goal_id] = sources
        goals = [
            candidate.model_copy(
                update={
                    "desired_outcome": {
                        **candidate.desired_outcome,
                        "selected_contact_name": display_name,
                    }
                },
                deep=True,
            )
            if candidate.goal_id == goal.goal_id
            else candidate.model_copy(deep=True)
            for candidate in session.intent.goals
        ]
        session.intent = session.intent.model_copy(update={"goals": goals}, deep=True)
        refreshed_goal = next(
            candidate
            for candidate in session.intent.goals
            if candidate.goal_id == goal.goal_id
        )
        self._apply_navigation_derived_parameters(
            session,
            goal=refreshed_goal,
            parameters={
                "contact_ids": (
                    [contact_id],
                    (candidates_evidence,),
                    "exact_selected_trip_contact_id_v1",
                )
            },
        )
        return True

    @classmethod
    def _trip_contact_information(
        cls,
        evidence: Evidence,
        *,
        contact_id: str,
        selected_name: str,
    ) -> tuple[str, str] | None:
        value = evidence.value
        if not isinstance(value, Mapping) or set(value) != {contact_id}:
            return None
        record = value.get(contact_id)
        if not isinstance(record, Mapping) or record.get("id") != contact_id:
            return None
        name = record.get("name")
        email = record.get("email")
        phone = record.get("phone_number")
        if (
            not isinstance(name, Mapping)
            or set(name) != {"first_name", "last_name"}
            or not isinstance(name.get("first_name"), str)
            or not isinstance(name.get("last_name"), str)
            or _argument_identifier(f"{name['first_name']} {name['last_name']}")
            != _argument_identifier(selected_name)
            or not isinstance(email, str)
            or email != email.strip()
            or len(email) > 254
            or re.fullmatch(
                r"[A-Za-z0-9.!#$%&'*+/=?^_`{|}~-]+@"
                r"[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?"
                r"(?:\.[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?)+",
                email,
            )
            is None
            or not isinstance(phone, str)
            or _POI_PHONE_PATTERN.fullmatch(phone) is None
        ):
            return None
        return email, name["first_name"].strip()

    def _trip_email_body(
        self,
        session: SessionState,
        *,
        trip: Mapping[str, Any],
        charger: Mapping[str, Any],
        recipient_first_name: str,
    ) -> str | None:
        current_location = getattr(session.compiled_policy, "current_location", None)
        start_name = (
            current_location.get("name")
            if isinstance(current_location, Mapping)
            and current_location.get("id") == trip.get("start_id")
            else None
        )
        if not isinstance(start_name, str) or not self._voice_result_field(
            start_name, 120
        ):
            return None
        try:
            distance = Decimal(trip["route_distance_km"])
            route_kilometer = Decimal(charger["route_kilometer"])
            detour_km = Decimal(charger["detour_km"])
            power_kw = Decimal(charger["available_power_kw"])
        except (InvalidOperation, KeyError, TypeError):
            return None
        duration = trip.get("route_duration_minutes")
        detour_minutes = charger.get("detour_minutes")
        if type(duration) is not int or type(detour_minutes) is not int:
            return None
        hours, minutes = divmod(duration, 60)
        distance_rounded = int(distance.quantize(Decimal("1"), rounding=ROUND_HALF_UP))
        kilometer_rounded = int(
            route_kilometer.quantize(Decimal("1"), rounding=ROUND_HALF_UP)
        )
        opening = self._poi_opening_hours_minutes(charger.get("opening_hours"))
        if opening != (0, 24 * 60):
            return None
        if charger.get("dc_occupied") is True:
            dc_clause = "Its DC plugs are currently occupied"
        elif charger.get("dc_available") is True:
            dc_clause = "A DC plug is currently available"
        else:
            dc_clause = "Its DC plugs are currently unavailable"
        article = "an" if charger.get("available_power_type") == "AC" else "a"
        return (
            f"Hi {recipient_first_name},\n\n"
            f"I wanted to update you on my travel time for our meeting in "
            f"{trip['destination_name']}. I'll be driving from {start_name} and the "
            f"route is approximately {distance_rounded} kilometers, which should "
            f"take about {hours} hours and {minutes} minutes.\n\n"
            "Since I'm driving an electric vehicle, I'll need a charging stop. "
            f"{charger['station_name']} is around kilometer {kilometer_rounded}, "
            f"with a {format(detour_km.normalize(), 'f')} kilometer detour that "
            f"adds about {detour_minutes} minutes. It is open 24 hours. "
            f"{dc_clause}, and {article} {format(power_kw.normalize(), 'f')} "
            f"kilowatt {charger['available_power_type']} plug is available.\n\n"
            "I'll keep you posted if there are any changes to my arrival time.\n\n"
            "Best regards"
        )

    def _next_local_trip_email_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            desired = item.goal.desired_outcome
            if desired.get(_LOCAL_TRIP_EMAIL_MARKER) is not True:
                continue
            phase = desired.get(_LOCAL_TRIP_EMAIL_PHASE)

            if phase == _LOCAL_TRIP_EMAIL_INITIAL:
                destination_name = desired.get("destination_name")
                first_name = desired.get("first_name")
                last_name = desired.get("last_name")
                if (
                    not isinstance(destination_name, str)
                    or not isinstance(first_name, str)
                    or not isinstance(last_name, str)
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                    )
                initial_specs: tuple[tuple[str, Mapping[str, Any], str, str], ...] = (
                    (
                        "get_location_id_by_location_name",
                        {"location": destination_name},
                        "resolve_trip_destination",
                        "trip_destination_location_id",
                    ),
                    (
                        "get_contact_id_by_contact_name",
                        {
                            "contact_first_name": first_name,
                            "contact_last_name": last_name,
                        },
                        "find_contact_ids",
                        "trip_contact_matches",
                    ),
                )
                for _, _, _, proposition in initial_specs:
                    self._register_single_read_need(
                        session,
                        goal_id=item.goal.goal_id,
                        proposition=proposition,
                    )
                initial_values = {
                    proposition: self._derived_navigation_read_value(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name=tool_name,
                        arguments=arguments,
                        proposition=proposition,
                    )
                    for tool_name, arguments, _, proposition in initial_specs
                }
                missing_initial = [
                    spec for spec in initial_specs if initial_values[spec[3]] is None
                ]
                if missing_initial:
                    if any(
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name=tool_name,
                            arguments=arguments,
                        )
                        is not None
                        for tool_name, arguments, _, _ in missing_initial
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._parallel_navigation_read_plan(
                        session, item=item, specifications=missing_initial
                    )
                location_value = initial_values["trip_destination_location_id"]
                matches_value = initial_values["trip_contact_matches"]
                assert location_value is not None and matches_value is not None
                destination_id, location_evidence = location_value
                _, matches_evidence = matches_value
                contact_candidates = self._trip_contact_candidates_from_evidence(
                    matches_evidence, first_name=first_name
                )
                selected = [
                    (contact_id, display_name)
                    for contact_id, display_name in contact_candidates or ()
                    if _argument_identifier(display_name)
                    == _argument_identifier(f"{first_name} {last_name}")
                ]
                identity = self._current_location_identity(session)
                if (
                    identity is None
                    or not isinstance(destination_id, str)
                    or _LOCATION_OR_POI_ID_PATTERN.fullmatch(destination_id) is None
                    or len(selected) != 1
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                contact_id = selected[0][0]
                detail_specs: tuple[tuple[str, Mapping[str, Any], str, str], ...] = (
                    (
                        "get_routes_from_start_to_destination",
                        {"start_id": identity[0], "destination_id": destination_id},
                        "find_trip_route",
                        "trip_route_options",
                    ),
                    (
                        "get_contact_information",
                        {"contact_ids": [contact_id]},
                        "read_contact_information",
                        "contact_information",
                    ),
                )
                for _, _, _, proposition in detail_specs:
                    self._register_single_read_need(
                        session,
                        goal_id=item.goal.goal_id,
                        proposition=proposition,
                    )
                detail_values = {
                    proposition: self._derived_navigation_read_value(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name=tool_name,
                        arguments=arguments,
                        proposition=proposition,
                    )
                    for tool_name, arguments, _, proposition in detail_specs
                }
                missing_details = [
                    spec for spec in detail_specs if detail_values[spec[3]] is None
                ]
                if missing_details:
                    if any(
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name=tool_name,
                            arguments=arguments,
                        )
                        is not None
                        for tool_name, arguments, _, _ in missing_details
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._parallel_navigation_read_plan(
                        session, item=item, specifications=missing_details
                    )
                route_value = detail_values["trip_route_options"]
                information_value = detail_values["contact_information"]
                assert route_value is not None and information_value is not None
                _, route_evidence = route_value
                _, information_evidence = information_value
                route = self._detailed_trip_route(
                    route_evidence,
                    start_id=identity[0],
                    destination_id=destination_id,
                )
                if route is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                trip_summary = self._store_trip_route_summary(
                    session,
                    goal=item.goal,
                    destination_name=destination_name,
                    start_id=identity[0],
                    destination_id=destination_id,
                    route=route,
                    location_evidence=location_evidence,
                    route_evidence=route_evidence,
                    charging_evidence=None,
                    state_of_charge=None,
                    available_range=None,
                )
                context = self._store_local_trip_email_context(
                    session,
                    goal=item.goal,
                    destination_name=destination_name,
                    first_name=first_name,
                    last_name=last_name,
                    location=location_evidence,
                    routes=route_evidence,
                    matches=matches_evidence,
                    information=information_evidence,
                )
                if trip_summary is None or context is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                values = context[1]
                hours, minutes = divmod(int(values["route_duration_minutes"]), 60)
                toll = (
                    "with toll roads"
                    if values["includes_toll"] is True
                    else "with no toll roads"
                )
                label = (
                    "fastest and shortest"
                    if values["fastest_is_shortest"] is True
                    else "fastest"
                )
                alternatives = int(values["alternative_count"])
                noun = "route" if alternatives == 1 else "routes"
                session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
                return self._text_plan(
                    session,
                    f"The {label} route to {destination_name} is via "
                    f"{values['route_via']}. It is {values['route_distance_km']} "
                    f"kilometers and takes about {hours} hours and {minutes} "
                    f"minutes, {toll}. There are {alternatives} alternative "
                    f"{noun}. I verified {values['recipient_email']} as the "
                    "recipient. I did not start navigation.",
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )

            if phase == _LOCAL_TRIP_EMAIL_RANGE:
                context = self._validated_local_trip_email_context(session)
                if context is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                arguments: dict[str, Any] = {}
                self._register_single_read_need(
                    session,
                    goal_id=item.goal.goal_id,
                    proposition="trip_charging_status",
                )
                observed = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_charging_specs_and_status",
                    arguments=arguments,
                    proposition="trip_charging_status",
                )
                if observed is None:
                    if (
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name="get_charging_specs_and_status",
                            arguments=arguments,
                        )
                        is not None
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._navigation_read_plan(
                        session,
                        item=item,
                        tool_name="get_charging_specs_and_status",
                        arguments=arguments,
                        semantic_operation=_TRIP_RANGE_OPERATION,
                        proposition="trip_charging_status",
                    )
                _, charging_evidence = observed
                charging = self._trip_charging_values(charging_evidence)
                context_parents = [
                    session.evidence.evidence.get(evidence_id)
                    for evidence_id in context[0].derived_from
                ]
                by_proposition = {
                    parent.proposition: parent
                    for parent in context_parents
                    if parent is not None
                }
                range_location_evidence = by_proposition.get(
                    "trip_destination_location_id"
                )
                range_route_evidence = by_proposition.get("trip_route_options")
                range_route = (
                    self._detailed_trip_route(
                        range_route_evidence,
                        start_id=str(context[1]["start_id"]),
                        destination_id=str(context[1]["destination_id"]),
                    )
                    if range_route_evidence is not None
                    else None
                )
                if (
                    charging is None
                    or range_location_evidence is None
                    or range_route_evidence is None
                    or range_route is None
                ):
                    session.goal_dag.set_status(
                        item.goal.goal_id,
                        GoalStatus.FAILED,
                        block_reason="the current vehicle range was not verifiable",
                    )
                    return self._text_plan(
                        session,
                        "I couldn't verify the current range, so I did not continue the trip calculation.",
                        goal_ids=[item.goal.goal_id],
                    )
                state_of_charge, available_range = charging
                summary = self._store_trip_route_summary(
                    session,
                    goal=item.goal,
                    destination_name=str(context[1]["destination_name"]),
                    start_id=str(context[1]["start_id"]),
                    destination_id=str(context[1]["destination_id"]),
                    route=range_route,
                    location_evidence=range_location_evidence,
                    route_evidence=range_route_evidence,
                    charging_evidence=charging_evidence,
                    state_of_charge=state_of_charge,
                    available_range=available_range,
                )
                if summary is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                enough = available_range >= range_route.distance_km
                session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
                return self._text_plan(
                    session,
                    "I checked the current vehicle status. Your current range is "
                    f"{format(available_range.normalize(), 'f')} kilometers. The "
                    "fastest route is "
                    f"{format(range_route.distance_km.normalize(), 'f')} kilometers, so "
                    f"the current range is {'enough' if enough else 'not enough'} "
                    "for this trip.",
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )

            if phase == _LOCAL_TRIP_EMAIL_CHARGE:
                context = self._validated_local_trip_email_context(session)
                trip = self._validated_trip_route_summary(
                    session, require_range_shortfall=True
                )
                displayed = self._validated_displayed_local_charging_options(session)
                station_name = desired.get("charging_station_name")
                station_id = desired.get("charging_station_id")
                plug_id = desired.get("charging_station_plug_id")
                start_soc = desired.get("start_state_of_charge")
                target_soc = desired.get("target_state_of_charge")
                if (
                    context is None
                    or trip is None
                    or displayed is None
                    or not isinstance(station_name, str)
                    or not isinstance(station_id, str)
                    or not isinstance(plug_id, str)
                    or type(start_soc) is not int
                    or type(target_soc) is not int
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                stations = [
                    option
                    for option in displayed[1]
                    if option.station_id == station_id
                    and _argument_identifier(option.name)
                    == _argument_identifier(station_name)
                ]
                if len(stations) != 1:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                station = stations[0]
                plug = self._highest_available_dc_plug(station)
                if plug is None or plug.plug_id != plug_id:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                specs: tuple[tuple[str, Mapping[str, Any], str, str], ...] = (
                    (
                        "calculate_charging_time_by_soc",
                        {
                            "charging_station_id": station_id,
                            "charging_station_plug_id": plug_id,
                            "start_state_of_charge": start_soc,
                            "target_state_of_charge": target_soc,
                        },
                        "calculate_local_charging_time",
                        "local_charging_time_result",
                    ),
                    (
                        "get_distance_by_soc",
                        {
                            "initial_state_of_charge": target_soc,
                            "final_state_of_charge": 0,
                        },
                        "get_distance_by_soc",
                        "local_trip_email_full_range",
                    ),
                )
                for _, _, _, proposition in specs:
                    self._register_single_read_need(
                        session,
                        goal_id=item.goal.goal_id,
                        proposition=proposition,
                    )
                charge_observed: dict[str, tuple[Any, Evidence] | None] = {
                    proposition: self._derived_navigation_read_value(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name=tool_name,
                        arguments=arguments,
                        proposition=proposition,
                    )
                    for tool_name, arguments, _, proposition in specs
                }
                missing = [spec for spec in specs if charge_observed[spec[3]] is None]
                if missing:
                    if any(
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name=tool_name,
                            arguments=arguments,
                        )
                        is not None
                        for tool_name, arguments, _, _ in missing
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._parallel_navigation_read_plan(
                        session, item=item, specifications=missing
                    )
                charge_calculation = charge_observed["local_charging_time_result"]
                charge_full_range = charge_observed["local_trip_email_full_range"]
                assert charge_calculation is not None and charge_full_range is not None
                duration = self._charging_duration_minutes(
                    charge_calculation[0],
                    start_soc=start_soc,
                    target_soc=target_soc,
                )
                distance = self._active_route_buffer_distance_km(
                    charge_full_range[1], initial_soc=target_soc, final_soc=0
                )
                charge_values = (
                    self._local_trip_email_charge_value(
                        trip=trip[1],
                        station=station,
                        plug=plug,
                        start_soc=start_soc,
                        target_soc=target_soc,
                        duration_minutes=duration,
                        full_range_km=distance,
                    )
                    if duration is not None and distance is not None
                    else None
                )
                stored = (
                    self._store_local_trip_email_charge_summary(
                        session,
                        goal=item.goal,
                        context=context[0],
                        trip=trip[0],
                        displayed=displayed[0],
                        calculation=charge_calculation[1],
                        full_range=charge_full_range[1],
                        values=charge_values,
                    )
                    if charge_values is not None
                    else None
                )
                if stored is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                result = stored[1]
                session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
                stop_text = (
                    "You will need at least one additional charging stop along the way."
                    if result["additional_stop_needed"] is True
                    else "You will not need another charging stop for this route."
                )
                return self._text_plan(
                    session,
                    "I calculated the verified charging update. Charging from "
                    f"{start_soc} to {target_soc} percent at {station.name} should "
                    "take about "
                    f"{result['charging_duration_minutes']} minutes. The estimated "
                    f"range after charging is {result['full_range_km']} kilometers. "
                    f"{stop_text}",
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )

            if phase == _LOCAL_TRIP_EMAIL_SEND:
                context = self._validated_local_trip_email_context(session)
                trip = self._validated_trip_route_summary(
                    session, require_range_shortfall=True
                )
                charge = self._validated_local_trip_email_charge_summary(session)
                if context is None or trip is None or charge is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                if _argument_identifier(
                    str(desired.get("first_name", ""))
                ) != _argument_identifier(
                    str(context[1]["recipient_first_name"])
                ) or _argument_identifier(
                    str(desired.get("last_name", ""))
                ) != _argument_identifier(str(context[1]["recipient_last_name"])):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                body = self._local_trip_email_body(
                    context=context[1], trip=trip[1], charge=charge[1]
                )
                if body is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                recipient = str(context[1]["recipient_email"])
                self._apply_navigation_derived_parameters(
                    session,
                    goal=item.goal,
                    parameters={
                        "email_addresses": (
                            [recipient],
                            (context[0],),
                            "exact_local_trip_email_recipient_v1",
                        ),
                        "message": (
                            body,
                            (context[0], trip[0], charge[0]),
                            "verified_local_trip_email_body_v1",
                        ),
                    },
                )
                refreshed = self._prepare_turn(session)
                refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
                target = (
                    self._unique_bound_target(refreshed_item)
                    if refreshed_item is not None
                    else None
                )
                expected = {
                    "email_addresses": [recipient],
                    "content_message": body,
                }
                if (
                    target is None
                    or target[1].tool_name != "send_email"
                    or not _argument_value_matches_binding(
                        target[1].arguments, expected
                    )
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                deterministic = self._deterministic_bound_action(session, refreshed)
                return deterministic or self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
        return None

    def _local_trip_email_bundle_is_current(
        self, session: SessionState, bundle: ExecutionBundle
    ) -> bool:
        goal = self._local_trip_email_goal(session)
        context = self._validated_local_trip_email_context(session)
        trip = self._validated_trip_route_summary(session, require_range_shortfall=True)
        charge = self._validated_local_trip_email_charge_summary(session)
        if (
            goal is None
            or goal.desired_outcome.get(_LOCAL_TRIP_EMAIL_PHASE)
            != _LOCAL_TRIP_EMAIL_SEND
            or context is None
            or trip is None
            or charge is None
            or len(bundle.calls) != 1
            or bundle.goal_ids != (goal.goal_id,)
            or bundle.calls[0].tool_name != "send_email"
        ):
            return False
        body = self._local_trip_email_body(
            context=context[1], trip=trip[1], charge=charge[1]
        )
        recipient = context[1].get("recipient_email")
        derived = session.derived_value_evidence_by_goal.get(goal.goal_id, {})
        recipient_evidence = session.evidence.evidence.get(
            derived.get("email_addresses", "")
        )
        body_evidence = session.evidence.evidence.get(derived.get("message", ""))
        if (
            body is None
            or not isinstance(recipient, str)
            or recipient_evidence is None
            or body_evidence is None
            or recipient_evidence.source_kind is not EvidenceSourceKind.DERIVED
            or body_evidence.source_kind is not EvidenceSourceKind.DERIVED
            or recipient_evidence.status is not EvidenceStatus.KNOWN
            or body_evidence.status is not EvidenceStatus.KNOWN
            or recipient_evidence.state_version
            != session.evidence.current_state_version
            or body_evidence.state_version != session.evidence.current_state_version
            or recipient_evidence.derivation != "exact_local_trip_email_recipient_v1"
            or body_evidence.derivation != "verified_local_trip_email_body_v1"
            or recipient_evidence.derived_from != [context[0].evidence_id]
            or body_evidence.derived_from
            != [context[0].evidence_id, trip[0].evidence_id, charge[0].evidence_id]
            or recipient_evidence.value != [recipient]
            or body_evidence.value != body
        ):
            return False
        return _argument_value_matches_binding(
            bundle.calls[0].arguments,
            {"email_addresses": [recipient], "content_message": body},
        )

    def _trip_email_bundle_is_current(
        self, session: SessionState, bundle: ExecutionBundle
    ) -> bool:
        if len(bundle.calls) != 1 or len(bundle.goal_ids) != 1:
            return False
        call = bundle.calls[0]
        goal = self._trip_email_goal(session)
        if (
            goal is not None
            and goal.desired_outcome.get(_LOCAL_TRIP_EMAIL_MARKER) is True
        ):
            return self._local_trip_email_bundle_is_current(session, bundle)
        if (
            goal is None
            or goal.goal_id != bundle.goal_ids[0]
            or call.tool_name != "send_email"
        ):
            return False
        trip = self._validated_trip_route_summary(session, require_range_shortfall=True)
        charger = self._validated_trip_charger_summary(session)
        contact_ids = goal.desired_outcome.get("contact_ids")
        selected_name = goal.desired_outcome.get("selected_contact_name")
        first_name = goal.desired_outcome.get("first_name")
        if (
            trip is None
            or charger is None
            or not isinstance(contact_ids, list)
            or len(contact_ids) != 1
            or not isinstance(contact_ids[0], str)
            or not isinstance(selected_name, str)
            or not isinstance(first_name, str)
        ):
            return False
        candidates = self._validated_trip_contact_candidates(
            session, goal_id=goal.goal_id, first_name=first_name
        )
        if candidates is None or (contact_ids[0], selected_name) not in candidates[1]:
            return False
        derived_ids = session.derived_value_evidence_by_goal.get(goal.goal_id, {})
        recipient_evidence = session.evidence.evidence.get(
            derived_ids.get("email_addresses", "")
        )
        message_evidence = session.evidence.evidence.get(derived_ids.get("message", ""))
        if (
            recipient_evidence is None
            or message_evidence is None
            or recipient_evidence.status is not EvidenceStatus.KNOWN
            or message_evidence.status is not EvidenceStatus.KNOWN
            or recipient_evidence.source_kind is not EvidenceSourceKind.DERIVED
            or message_evidence.source_kind is not EvidenceSourceKind.DERIVED
            or recipient_evidence.state_version
            != session.evidence.current_state_version
            or message_evidence.state_version != session.evidence.current_state_version
            or recipient_evidence.derivation != "exact_trip_email_recipient_v1"
            or message_evidence.derivation != "minimal_verified_trip_email_body_v1"
            or len(recipient_evidence.derived_from) != 1
        ):
            return False
        info = session.evidence.evidence.get(recipient_evidence.derived_from[0])
        if (
            info is None
            or info.status is not EvidenceStatus.KNOWN
            or info.source_kind is not EvidenceSourceKind.TOOL
            or info.state_version != session.evidence.current_state_version
            or message_evidence.derived_from
            != [trip[0].evidence_id, charger[0].evidence_id, info.evidence_id]
        ):
            return False
        contact = self._trip_contact_information(
            info, contact_id=contact_ids[0], selected_name=selected_name
        )
        if contact is None:
            return False
        email_address, recipient_first_name = contact
        body = self._trip_email_body(
            session,
            trip=trip[1],
            charger=charger[1],
            recipient_first_name=recipient_first_name,
        )
        expected = {
            "email_addresses": [email_address],
            "content_message": body,
        }
        return (
            body is not None
            and recipient_evidence.value == [email_address]
            and message_evidence.value == body
            and _argument_value_matches_binding(call.arguments, expected)
        )

    def _next_trip_email_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if (
                item.goal.semantic_operation != "send_email"
                or item.goal.desired_outcome.get(_TRIP_EMAIL_MARKER) is not True
                or item.goal.desired_outcome.get(_LOCAL_TRIP_EMAIL_MARKER) is True
            ):
                continue
            first_name = item.goal.desired_outcome.get("first_name")
            if not isinstance(first_name, str) or not self._trip_email_schema_available(
                session, first_name=first_name, full=True
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_CAPABILITY
                )
            trip = self._validated_trip_route_summary(
                session, require_range_shortfall=True
            )
            charger = self._validated_trip_charger_summary(session)
            if trip is None or charger is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            contact_ids = item.goal.desired_outcome.get("contact_ids")
            if contact_ids is None:
                arguments = {"contact_first_name": first_name}
                self._register_single_read_need(
                    session,
                    goal_id=item.goal.goal_id,
                    proposition="trip_contact_matches",
                )
                observed = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_contact_id_by_contact_name",
                    arguments=arguments,
                    proposition="trip_contact_matches",
                )
                if observed is None:
                    if (
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name="get_contact_id_by_contact_name",
                            arguments=arguments,
                        )
                        is not None
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._navigation_read_plan(
                        session,
                        item=item,
                        tool_name="get_contact_id_by_contact_name",
                        arguments=arguments,
                        semantic_operation="find_contact_ids",
                        proposition="trip_contact_matches",
                    )
                _, raw_evidence = observed
                candidates = self._trip_contact_candidates_from_evidence(
                    raw_evidence, first_name=first_name
                )
                if candidates is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                displayed_value = [
                    {"contact_id": contact_id, "display_name": display_name}
                    for contact_id, display_name in candidates
                ]
                existing = self._validated_trip_contact_candidates(
                    session, goal_id=item.goal.goal_id, first_name=first_name
                )
                if existing is None:
                    assert raw_evidence.evidence_id is not None
                    session.evidence.add(
                        Evidence(
                            proposition=f"trip_contact_candidates:{item.goal.goal_id}",
                            value=displayed_value,
                            status=EvidenceStatus.KNOWN,
                            source_kind=EvidenceSourceKind.DERIVED,
                            source_turn_id=f"trip-contacts-{item.goal.goal_id}",
                            confidence=raw_evidence.confidence,
                            derived_from=[raw_evidence.evidence_id],
                            derivation="strict_trip_contact_candidates_v1",
                        )
                    )
                requested_name = item.goal.desired_outcome.get("requested_contact_name")
                if isinstance(requested_name, str):
                    selected = [
                        (contact_id, display_name)
                        for contact_id, display_name in candidates
                        if _argument_identifier(display_name)
                        == _argument_identifier(requested_name)
                    ]
                    current_candidates = self._validated_trip_contact_candidates(
                        session,
                        goal_id=item.goal.goal_id,
                        first_name=first_name,
                    )
                    source_turn_id = session.grounded_value_sources_by_goal.get(
                        item.goal.goal_id, {}
                    ).get("requested_contact_name")
                    if (
                        len(selected) == 1
                        and current_candidates is not None
                        and isinstance(source_turn_id, str)
                        and self._bind_trip_contact_selection(
                            session,
                            goal=item.goal,
                            display_name=selected[0][1],
                            contact_id=selected[0][0],
                            candidates_evidence=current_candidates[0],
                            source_turn_id=source_turn_id,
                        )
                    ):
                        return self._plan_next(session)
                return self._text_plan(
                    session,
                    "I found these current contacts: "
                    + ", ".join(display_name for _, display_name in candidates)
                    + ". Which one should receive the email?",
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.ASK_USER,
                )

            selected_name = item.goal.desired_outcome.get("selected_contact_name")
            if (
                not isinstance(contact_ids, list)
                or len(contact_ids) != 1
                or not isinstance(contact_ids[0], str)
                or not isinstance(selected_name, str)
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            validated_candidates = self._validated_trip_contact_candidates(
                session, goal_id=item.goal.goal_id, first_name=first_name
            )
            if (
                validated_candidates is None
                or (contact_ids[0], selected_name) not in validated_candidates[1]
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            info_arguments = {"contact_ids": contact_ids}
            observed_info = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_contact_information",
                arguments=info_arguments,
                proposition="contact_information",
            )
            if observed_info is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_contact_information",
                        arguments=info_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_contact_information",
                    arguments=info_arguments,
                    semantic_operation="read_contact_information",
                    proposition="contact_information",
                )
            _, info_evidence = observed_info
            contact = self._trip_contact_information(
                info_evidence,
                contact_id=contact_ids[0],
                selected_name=selected_name,
            )
            if contact is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            email_address, recipient_first_name = contact
            body = self._trip_email_body(
                session,
                trip=trip[1],
                charger=charger[1],
                recipient_first_name=recipient_first_name,
            )
            if body is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "email_addresses": (
                        [email_address],
                        (info_evidence,),
                        "exact_trip_email_recipient_v1",
                    ),
                    "message": (
                        body,
                        (trip[0], charger[0], info_evidence),
                        "minimal_verified_trip_email_body_v1",
                    ),
                },
            )
            refreshed = self._prepare_turn(session)
            refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
            target = (
                self._unique_bound_target(refreshed_item)
                if refreshed_item is not None
                else None
            )
            expected = {
                "email_addresses": [email_address],
                "content_message": body,
            }
            if (
                target is None
                or target[1].tool_name != "send_email"
                or not _argument_value_matches_binding(target[1].arguments, expected)
                or self._validated_trip_route_summary(
                    session, require_range_shortfall=True
                )
                is None
                or self._validated_trip_charger_summary(session) is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            deterministic = self._deterministic_bound_action(session, refreshed)
            return deterministic or self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        return None

    @staticmethod
    def _trip_charging_values(
        evidence: Evidence,
    ) -> tuple[Decimal, Decimal] | None:
        value = evidence.value
        if not isinstance(value, Mapping):
            return None
        state_of_charge = value.get("state_of_charge")
        remaining_range = value.get("remaining_range")
        if (
            isinstance(state_of_charge, bool)
            or not isinstance(state_of_charge, (int, float, Decimal))
            or not isinstance(remaining_range, str)
        ):
            return None
        try:
            charge = Decimal(str(state_of_charge))
        except InvalidOperation:
            return None
        if not charge.is_finite() or not 0 <= charge <= 100:
            return None
        match = re.fullmatch(
            r"\s*(\d+(?:\.\d+)?)\s*km\s*",
            remaining_range,
            flags=re.IGNORECASE,
        )
        if match is None:
            return None
        try:
            distance = Decimal(match.group(1))
        except InvalidOperation:
            return None
        if not distance.is_finite() or distance < 0:
            return None
        return charge, distance

    @staticmethod
    def _fastest_trip_route(
        evidence: Evidence,
        *,
        start_id: str,
        destination_id: str,
    ) -> TripRouteAssessment | None:
        routes = evidence.value
        if not isinstance(routes, list) or not 1 <= len(routes) <= 12:
            return None
        fastest: list[TripRouteAssessment] = []
        seen: set[str] = set()
        for route in routes:
            if not isinstance(route, Mapping):
                return None
            route_id = route.get("route_id")
            aliases = route.get("alias")
            raw_distance = route.get("distance_km")
            includes_toll = route.get("includes_toll")
            if (
                not isinstance(route_id, str)
                or _ROUTE_ID_PATTERN.fullmatch(route_id) is None
                or route_id in seen
                or route.get("start_id") != start_id
                or route.get("destination_id") != destination_id
                or not isinstance(aliases, list)
                or not aliases
                or any(not isinstance(alias, str) for alias in aliases)
                or isinstance(raw_distance, bool)
                or not isinstance(raw_distance, (int, float, Decimal))
                or not isinstance(includes_toll, bool)
            ):
                return None
            try:
                distance = Decimal(str(raw_distance))
            except InvalidOperation:
                return None
            if not distance.is_finite() or distance < 0:
                return None
            seen.add(route_id)
            if any(alias.casefold() == "fastest" for alias in aliases):
                fastest.append(
                    TripRouteAssessment(
                        distance_km=distance,
                        includes_toll=includes_toll,
                    )
                )
        return fastest[0] if len(fastest) == 1 else None

    @classmethod
    def _detailed_trip_route(
        cls,
        evidence: Evidence,
        *,
        start_id: str,
        destination_id: str,
    ) -> TripRouteAssessment | None:
        options = cls._destination_route_options_from_evidence(
            evidence,
            start_id=start_id,
            destination_id=destination_id,
        )
        if options is None:
            return None
        fastest = [option for option in options if "fastest" in option.aliases]
        if len(fastest) != 1:
            return None
        option = fastest[0]
        return TripRouteAssessment(
            distance_km=option.distance_km,
            includes_toll=option.includes_toll,
            route_id=option.route_id,
            via=option.via,
            duration_minutes=option.duration_minutes,
        )

    @classmethod
    def _meeting_charging_next_meeting(
        cls,
        evidence: Evidence,
        *,
        current_datetime: tuple[int, int, int, int, int],
    ) -> dict[str, Any] | None:
        value = evidence.value
        if not isinstance(value, Mapping):
            return None
        date = value.get("date")
        meetings = value.get("meetings")
        year, month, day, hour, minute = current_datetime
        if (
            not isinstance(date, Mapping)
            or date.get("year") != year
            or date.get("month") != month
            or date.get("day") != day
            or not isinstance(meetings, list)
            or not 1 <= len(meetings) <= 32
        ):
            return None
        upcoming: list[tuple[int, str]] = []
        for meeting in meetings:
            if not isinstance(meeting, Mapping):
                return None
            start = meeting.get("start")
            location = meeting.get("location")
            if not isinstance(start, Mapping) or not isinstance(location, str):
                return None
            raw_start_hour = start.get("hour")
            raw_start_minute = start.get("minute")
            if (
                isinstance(raw_start_hour, bool)
                or not isinstance(raw_start_hour, (int, str))
                or isinstance(raw_start_minute, bool)
                or not isinstance(raw_start_minute, (int, str))
            ):
                return None
            try:
                start_hour = int(raw_start_hour)
                start_minute = int(raw_start_minute)
            except ValueError:
                return None
            if (
                not 0 <= start_hour <= 23
                or not 0 <= start_minute <= 59
                or not cls._safe_poi_display_label(location, 120)
            ):
                return None
            start_total = start_hour * 60 + start_minute
            if start_total > hour * 60 + minute:
                upcoming.append((start_total, location.strip()))
        if not upcoming:
            return None
        earliest = min(item[0] for item in upcoming)
        selected = [item for item in upcoming if item[0] == earliest]
        if len(selected) != 1:
            return None
        return {
            "meeting_location_name": selected[0][1],
            "meeting_start_minutes": earliest,
        }

    @classmethod
    def _meeting_charging_fastest_plug(
        cls,
        evidence: Evidence,
        *,
        current_location_id: str,
    ) -> tuple[dict[str, Any], tuple[str, ...]] | None:
        rows = evidence.value
        if not isinstance(rows, list) or not 1 <= len(rows) <= 32:
            return None
        candidates: list[dict[str, Any]] = []
        station_names: list[str] = []
        seen_station_ids: set[str] = set()
        seen_plug_ids: set[str] = set()
        for row in rows:
            if not isinstance(row, Mapping):
                return None
            station_id = row.get("id")
            station_name = row.get("name")
            phone_number = row.get("phone_number")
            plugs = row.get("charging_plugs")
            if (
                not isinstance(station_id, str)
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(station_id) is None
                or not station_id.startswith("poi_")
                or station_id in seen_station_ids
                or not isinstance(station_name, str)
                or not cls._safe_poi_display_label(station_name, 120)
                or not isinstance(phone_number, str)
                or _POI_PHONE_PATTERN.fullmatch(phone_number) is None
                or row.get("category") != "charging_stations"
                or row.get("corresponding_location_id") != current_location_id
                or not isinstance(plugs, list)
                or not 1 <= len(plugs) <= 32
            ):
                return None
            seen_station_ids.add(station_id)
            station_names.append(station_name.strip())
            for plug in plugs:
                if not isinstance(plug, Mapping):
                    return None
                plug_id = plug.get("plug_id")
                power_type = plug.get("power_type")
                power_kw = plug.get("power_kw")
                availability = plug.get("availability")
                if (
                    not isinstance(plug_id, str)
                    or _CHARGING_PLUG_ID_PATTERN.fullmatch(plug_id) is None
                    or plug_id in seen_plug_ids
                    or not isinstance(power_type, str)
                    or power_type.upper() not in {"AC", "DC"}
                    or isinstance(power_kw, bool)
                    or not isinstance(power_kw, (int, float, Decimal))
                    or not isinstance(availability, str)
                ):
                    return None
                try:
                    power = Decimal(str(power_kw))
                except (InvalidOperation, TypeError, ValueError):
                    return None
                normalized_availability = _argument_identifier(availability)
                if (
                    not power.is_finite()
                    or not 0 < power <= 1000
                    or normalized_availability
                    not in _LOCAL_CHARGING_AVAILABILITY_VALUES
                ):
                    return None
                seen_plug_ids.add(plug_id)
                candidates.append(
                    {
                        "charging_station_id": station_id,
                        "charging_station_name": station_name.strip(),
                        "charging_station_phone_number": phone_number,
                        "charging_station_plug_id": plug_id,
                        "charging_station_plug_power_type": power_type.upper(),
                        "charging_station_plug_power_kw": format(
                            power.normalize(), "f"
                        ),
                        "charging_station_plug_availability": (normalized_availability),
                    }
                )
        if not candidates:
            return None
        maximum = max(
            Decimal(item["charging_station_plug_power_kw"]) for item in candidates
        )
        selected = [
            item
            for item in candidates
            if Decimal(item["charging_station_plug_power_kw"]) == maximum
        ]
        return (selected[0], tuple(station_names)) if len(selected) == 1 else None

    def _validated_meeting_charging_discovery(
        self, session: SessionState
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        candidates = session.evidence.latest_for_proposition(
            "meeting_charging_discovery_summary", current_state_only=True
        )
        identity = self._current_location_identity(session)
        current_datetime = self._current_datetime_parts(session)
        if len(candidates) != 1 or identity is None or current_datetime is None:
            return None
        summary = candidates[0]
        values = summary.value
        if (
            summary.status is not EvidenceStatus.KNOWN
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.derivation != "validated_meeting_charging_discovery_v1"
            or summary.state_version != session.evidence.current_state_version
            or not isinstance(values, Mapping)
            or len(summary.derived_from) != 3
        ):
            return None
        parents = [
            session.evidence.evidence.get(evidence_id)
            for evidence_id in summary.derived_from
        ]
        if any(parent is None for parent in parents):
            return None
        by_proposition = {
            parent.proposition: parent for parent in parents if parent is not None
        }
        calendar = by_proposition.get("meeting_charging_calendar")
        charging = by_proposition.get("meeting_charging_vehicle_status")
        stations = by_proposition.get("meeting_charging_station_candidates")
        if calendar is None or charging is None or stations is None:
            return None
        meeting = self._meeting_charging_next_meeting(
            calendar, current_datetime=current_datetime
        )
        charging_values = self._trip_charging_values(charging)
        fastest = self._meeting_charging_fastest_plug(
            stations, current_location_id=identity[0]
        )
        arrival_buffer = values.get("arrival_buffer_minutes")
        range_buffer = values.get("range_buffer_km")
        if (
            meeting is None
            or charging_values is None
            or fastest is None
            or type(arrival_buffer) is not int
            or not 0 < arrival_buffer <= 180
            or type(range_buffer) is not int
            or not 0 < range_buffer <= 2000
        ):
            return None
        plug, station_names = fastest
        state_of_charge, remaining_range = charging_values
        expected = {
            **meeting,
            **plug,
            "current_location_id": identity[0],
            "current_datetime": list(current_datetime),
            "arrival_buffer_minutes": arrival_buffer,
            "range_buffer_km": range_buffer,
            "state_of_charge": format(state_of_charge.normalize(), "f"),
            "remaining_range_km": format(remaining_range.normalize(), "f"),
            "station_names": list(station_names),
        }
        return (summary, values) if dict(values) == expected else None

    def _next_meeting_charging_analysis(
        self,
        session: SessionState,
        item: PreparedGoal,
    ) -> PlannedOutbound:
        discovery = self._validated_meeting_charging_discovery(session)
        desired = item.goal.desired_outcome
        if discovery is None:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        discovery_evidence, values = discovery
        station_id = values.get("charging_station_id")
        station_name = values.get("charging_station_name")
        plug_id = values.get("charging_station_plug_id")
        plug_power = values.get("charging_station_plug_power_kw")
        current_location_id = values.get("current_location_id")
        meeting_name = values.get("meeting_location_name")
        if (
            desired.get("selected_charging_station_name") != station_name
            or desired.get("selected_charging_plug_power_kw") != plug_power
            or desired.get("accepted_plug_availability") != "occupied"
            or desired.get("route_selection") != "fastest"
            or not isinstance(station_id, str)
            or not isinstance(station_name, str)
            or not isinstance(plug_id, str)
            or not isinstance(current_location_id, str)
            or not isinstance(meeting_name, str)
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )

        location_arguments = {"location": meeting_name}
        self._register_single_read_need(
            session,
            goal_id=item.goal.goal_id,
            proposition="meeting_charging_location_id",
        )
        location = self._derived_navigation_read_value(
            session,
            goal_id=item.goal.goal_id,
            tool_name="get_location_id_by_location_name",
            arguments=location_arguments,
            proposition="meeting_charging_location_id",
        )
        if location is None:
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="get_location_id_by_location_name",
                arguments=location_arguments,
                semantic_operation="resolve_meeting_location_for_charging",
                proposition="meeting_charging_location_id",
            )
        meeting_location_id, location_evidence = location
        if (
            not isinstance(meeting_location_id, str)
            or not meeting_location_id.startswith("loc_")
            or _LOCATION_OR_POI_ID_PATTERN.fullmatch(meeting_location_id) is None
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )

        route_specs = (
            (
                "meeting_charging_direct_routes",
                {
                    "start_id": current_location_id,
                    "destination_id": meeting_location_id,
                },
                "find_direct_route_to_meeting",
            ),
            (
                "meeting_charging_first_segment_routes",
                {
                    "start_id": current_location_id,
                    "destination_id": station_id,
                },
                "find_route_to_selected_charger",
            ),
            (
                "meeting_charging_second_segment_routes",
                {
                    "start_id": station_id,
                    "destination_id": meeting_location_id,
                },
                "find_route_from_charger_to_meeting",
            ),
        )
        route_results: dict[str, tuple[Any, Evidence]] = {}
        for proposition, arguments, operation in route_specs:
            self._register_single_read_need(
                session,
                goal_id=item.goal.goal_id,
                proposition=proposition,
            )
            observed = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=arguments,
                proposition=proposition,
            )
            if observed is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=arguments,
                    semantic_operation=operation,
                    proposition=proposition,
                )
            route_results[proposition] = observed

        direct = self._detailed_trip_route(
            route_results["meeting_charging_direct_routes"][1],
            start_id=current_location_id,
            destination_id=meeting_location_id,
        )
        first = self._detailed_trip_route(
            route_results["meeting_charging_first_segment_routes"][1],
            start_id=current_location_id,
            destination_id=station_id,
        )
        second = self._detailed_trip_route(
            route_results["meeting_charging_second_segment_routes"][1],
            start_id=station_id,
            destination_id=meeting_location_id,
        )
        try:
            state_of_charge = Decimal(str(values["state_of_charge"]))
            remaining_range = Decimal(str(values["remaining_range_km"]))
            range_buffer = Decimal(str(values["range_buffer_km"]))
            meeting_start = int(values["meeting_start_minutes"])
            arrival_buffer = int(values["arrival_buffer_minutes"])
            current_parts = tuple(values["current_datetime"])
        except (InvalidOperation, KeyError, TypeError, ValueError):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        if (
            direct is None
            or first is None
            or second is None
            or len(current_parts) != 5
            or any(type(part) is not int for part in current_parts)
            or not state_of_charge.is_finite()
            or not remaining_range.is_finite()
            or state_of_charge <= 0
            or remaining_range <= 0
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        kilometers_per_soc = remaining_range / state_of_charge
        consumed_soc = int(
            (first.distance_km / kilometers_per_soc).to_integral_value(
                rounding=ROUND_HALF_UP
            )
        )
        start_soc = int(state_of_charge) - consumed_soc
        target_soc = int(
            (
                (second.distance_km + range_buffer) / kilometers_per_soc
            ).to_integral_value(rounding=ROUND_CEILING)
        )
        current_minutes = current_parts[3] * 60 + current_parts[4]
        maximum_minutes = (
            meeting_start
            - arrival_buffer
            - current_minutes
            - first.duration_minutes
            - second.duration_minutes
        )
        if not 0 <= start_soc < target_soc <= 100 or maximum_minutes <= 0:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )

        calculation_arguments = {
            "charging_station_id": station_id,
            "charging_station_plug_id": plug_id,
            "start_state_of_charge": start_soc,
            "target_state_of_charge": target_soc,
        }
        self._register_single_read_need(
            session,
            goal_id=item.goal.goal_id,
            proposition="meeting_charging_time_result",
        )
        calculation = self._derived_navigation_read_value(
            session,
            goal_id=item.goal.goal_id,
            tool_name="calculate_charging_time_by_soc",
            arguments=calculation_arguments,
            proposition="meeting_charging_time_result",
        )
        if calculation is None:
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="calculate_charging_time_by_soc",
                arguments=calculation_arguments,
                semantic_operation="calculate_selected_charging_window",
                proposition="meeting_charging_time_result",
            )
        minimum_minutes = self._charging_duration_minutes(
            calculation[0], start_soc=start_soc, target_soc=target_soc
        )
        if minimum_minutes is None or minimum_minutes > maximum_minutes:
            session.goal_dag.set_status(
                item.goal.goal_id,
                GoalStatus.FAILED,
                block_reason="the charging duration was missing or exceeded the window",
            )
            return self._text_plan(
                session,
                "I could not verify one unambiguous charging duration, so I did not authorize navigation or a call.",
                goal_ids=[item.goal.goal_id],
            )
        parents = (
            discovery_evidence,
            location_evidence,
            route_results["meeting_charging_direct_routes"][1],
            route_results["meeting_charging_first_segment_routes"][1],
            route_results["meeting_charging_second_segment_routes"][1],
            calculation[1],
        )
        if any(parent.evidence_id is None for parent in parents):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        summary = Evidence(
            proposition="meeting_charging_analysis_summary",
            value={
                **dict(values),
                "meeting_location_id": meeting_location_id,
                "direct_route_id": direct.route_id,
                "first_segment_route_id": first.route_id,
                "second_segment_route_id": second.route_id,
                "first_segment_duration_minutes": first.duration_minutes,
                "second_segment_duration_minutes": second.duration_minutes,
                "start_state_of_charge": start_soc,
                "target_state_of_charge": target_soc,
                "minimum_charging_minutes": minimum_minutes,
                "maximum_charging_minutes": maximum_minutes,
            },
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=f"meeting-charging-analysis-{item.goal.goal_id}",
            confidence=min(parent.confidence for parent in parents),
            derived_from=[
                parent.evidence_id
                for parent in parents
                if parent.evidence_id is not None
            ],
            derivation="validated_meeting_charging_analysis_v1",
        )
        session.evidence.add(summary)
        session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
        if desired.get("navigation_requested_after_calculation") is True:
            threshold = desired.get("minimum_threshold_minutes")
            stored = session.evidence.latest_for_proposition(
                "meeting_charging_analysis_summary", current_state_only=True
            )
            source_turn_ids = (
                tuple(session.intent.intent_source_turn_ids)
                if session.intent is not None
                else ()
            )
            stored_value = stored[0].value if len(stored) == 1 else None
            if (
                type(threshold) is not int
                or len(stored) != 1
                or not isinstance(stored_value, Mapping)
                or len(source_turn_ids) != 1
            ):
                return self._text_plan(
                    session,
                    "I calculated the charging window, but its navigation condition did not pass, so I did not start navigation.",
                    goal_ids=[item.goal.goal_id],
                )
            if (
                self._begin_meeting_charging_navigation_goal(
                    session,
                    turn_id=source_turn_ids[0],
                    analysis=(stored[0], stored_value),
                    threshold=threshold,
                )
                is None
            ):
                return self._text_plan(
                    session,
                    "I calculated the charging window, but its navigation condition did not pass, so I did not start navigation.",
                    goal_ids=[item.goal.goal_id],
                )
            return self._plan_next(session)
        return self._text_plan(
            session,
            f"I calculated a minimum charging time of {minimum_minutes} minutes and a "
            f"maximum charging time of {maximum_minutes} minutes.",
            goal_ids=[item.goal.goal_id],
            kind=ProposalKind.COMPLETE,
        )

    def _validated_meeting_charging_analysis(
        self, session: SessionState
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        candidates = session.evidence.latest_for_proposition(
            "meeting_charging_analysis_summary", current_state_only=True
        )
        discovery = self._validated_meeting_charging_discovery(session)
        if len(candidates) != 1 or discovery is None:
            return None
        summary = candidates[0]
        values = summary.value
        if (
            summary.status is not EvidenceStatus.KNOWN
            or summary.source_kind is not EvidenceSourceKind.DERIVED
            or summary.derivation != "validated_meeting_charging_analysis_v1"
            or summary.state_version != session.evidence.current_state_version
            or not isinstance(values, Mapping)
            or len(summary.derived_from) != 6
        ):
            return None
        parents = [
            session.evidence.evidence.get(evidence_id)
            for evidence_id in summary.derived_from
        ]
        if any(parent is None for parent in parents):
            return None
        by_proposition = {
            parent.proposition: parent for parent in parents if parent is not None
        }
        location = by_proposition.get("meeting_charging_location_id")
        direct_evidence = by_proposition.get("meeting_charging_direct_routes")
        first_evidence = by_proposition.get("meeting_charging_first_segment_routes")
        second_evidence = by_proposition.get("meeting_charging_second_segment_routes")
        calculation = by_proposition.get("meeting_charging_time_result")
        if (
            by_proposition.get("meeting_charging_discovery_summary") is not discovery[0]
            or location is None
            or direct_evidence is None
            or first_evidence is None
            or second_evidence is None
            or calculation is None
        ):
            return None
        current_id = values.get("current_location_id")
        station_id = values.get("charging_station_id")
        meeting_id = values.get("meeting_location_id")
        start_soc = values.get("start_state_of_charge")
        target_soc = values.get("target_state_of_charge")
        if (
            not isinstance(current_id, str)
            or not isinstance(station_id, str)
            or not isinstance(meeting_id, str)
            or location.value != meeting_id
            or type(start_soc) is not int
            or type(target_soc) is not int
        ):
            return None
        direct = self._detailed_trip_route(
            direct_evidence, start_id=current_id, destination_id=meeting_id
        )
        first = self._detailed_trip_route(
            first_evidence, start_id=current_id, destination_id=station_id
        )
        second = self._detailed_trip_route(
            second_evidence, start_id=station_id, destination_id=meeting_id
        )
        minimum = self._charging_duration_minutes(
            calculation.value, start_soc=start_soc, target_soc=target_soc
        )
        try:
            current_parts = tuple(values["current_datetime"])
            maximum = (
                int(values["meeting_start_minutes"])
                - int(values["arrival_buffer_minutes"])
                - (current_parts[3] * 60 + current_parts[4])
                - int(values["first_segment_duration_minutes"])
                - int(values["second_segment_duration_minutes"])
            )
        except (KeyError, TypeError, ValueError):
            return None
        if (
            direct is None
            or first is None
            or second is None
            or minimum is None
            or values.get("direct_route_id") != direct.route_id
            or values.get("first_segment_route_id") != first.route_id
            or values.get("second_segment_route_id") != second.route_id
            or values.get("first_segment_duration_minutes") != first.duration_minutes
            or values.get("second_segment_duration_minutes") != second.duration_minutes
            or values.get("minimum_charging_minutes") != minimum
            or values.get("maximum_charging_minutes") != maximum
            or any(values.get(key) != value for key, value in discovery[1].items())
        ):
            return None
        return summary, values

    def _next_meeting_charging_navigation(
        self,
        session: SessionState,
        item: PreparedGoal,
    ) -> PlannedOutbound:
        analysis = self._validated_meeting_charging_analysis(session)
        desired = item.goal.desired_outcome
        if analysis is None:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        values = analysis[1]
        minimum = values.get("minimum_charging_minutes")
        threshold = desired.get("minimum_threshold_minutes")
        navigation_condition = desired.get("navigation_condition")
        expected_route_ids = [
            values.get("first_segment_route_id"),
            values.get("second_segment_route_id"),
        ]
        condition_matches = (
            navigation_condition == _MEETING_CHARGING_THRESHOLD_CONDITION
            and type(threshold) is int
            and type(minimum) is int
            and minimum < threshold
        ) or (
            navigation_condition == _MEETING_CHARGING_UNCONDITIONAL_NAVIGATION
            and "minimum_threshold_minutes" not in desired
            and type(minimum) is int
        )
        if (
            not condition_matches
            or desired.get("route_selection") != "fastest"
            or desired.get("stop_order") != "charger_then_meeting"
            or desired.get("route_ids") != expected_route_ids
            or any(not isinstance(route_id, str) for route_id in expected_route_ids)
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        navigation_arguments = {"detailed_information": True}
        self._register_single_read_need(
            session,
            goal_id=item.goal.goal_id,
            proposition="current_navigation_state",
        )
        navigation = self._successful_goal_read(
            session,
            goal_id=item.goal.goal_id,
            tool_name="get_current_navigation_state",
            arguments=navigation_arguments,
        )
        if navigation is None:
            return self._navigation_read_plan(
                session,
                item=item,
                tool_name="get_current_navigation_state",
                arguments=navigation_arguments,
                semantic_operation="read_current_navigation_for_meeting_charging",
                proposition="current_navigation_state",
            )
        state = self._navigation_state_view(session, goal_id=item.goal.goal_id)
        if (
            state is None
            or state.active
            or self._navigation_state_signature(navigation.value) != (False, (), ())
            or not self._destination_navigation_snapshot_is_current(
                session, goal_id=item.goal.goal_id
            )
        ):
            session.goal_dag.set_status(item.goal.goal_id, GoalStatus.BLOCKED)
            return self._text_plan(
                session,
                "I verified that navigation is already active or unavailable, so I did not replace it with a new route.",
                goal_ids=[item.goal.goal_id],
            )
        self._record_navigation_policy_facts(
            session, goal_id=item.goal.goal_id, state=state
        )
        self._apply_navigation_derived_parameters(
            session,
            goal=item.goal,
            parameters={
                "route_start_id": (
                    values["current_location_id"],
                    (analysis[0], state.evidence),
                    "meeting_charging_policy_start_v1",
                )
            },
        )
        refreshed = self._prepare_turn(session)
        refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
        target = (
            self._unique_bound_target(refreshed_item)
            if refreshed_item is not None
            else None
        )
        if (
            target is None
            or target[1].tool_name != "set_new_navigation"
            or not _argument_value_matches_binding(
                target[1].arguments, {"route_ids": expected_route_ids}
            )
            or not self._destination_navigation_snapshot_is_current(
                session, goal_id=item.goal.goal_id
            )
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        deterministic = self._deterministic_bound_action(session, refreshed)
        return deterministic or self._limitation_plan(
            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
        )

    def _meeting_charging_navigation_bundle_analysis(
        self,
        session: SessionState,
        bundle: ExecutionBundle,
        *,
        completion_value: Any,
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        if len(bundle.goal_ids) != 1 or len(bundle.calls) != 1:
            return None
        try:
            goal = session.goal_dag.get(bundle.goal_ids[0])
        except KeyError:
            return None
        analysis = self._validated_meeting_charging_analysis(session)
        call = bundle.calls[0]
        if (
            goal.desired_outcome.get(_MEETING_CHARGING_MARKER) is not True
            or goal.desired_outcome.get(_MEETING_CHARGING_PHASE)
            != _MEETING_CHARGING_NAVIGATION
            or analysis is None
            or call.tool_name != "set_new_navigation"
            or not _argument_value_matches_binding(
                call.arguments,
                {
                    "route_ids": [
                        analysis[1].get("first_segment_route_id"),
                        analysis[1].get("second_segment_route_id"),
                    ]
                },
            )
        ):
            return None
        values = analysis[1]
        current_id = values.get("current_location_id")
        station_id = values.get("charging_station_id")
        meeting_id = values.get("meeting_location_id")
        if (
            not isinstance(completion_value, Mapping)
            or not isinstance(current_id, str)
            or not isinstance(station_id, str)
            or not isinstance(meeting_id, str)
        ):
            return None
        expected_waypoints = [current_id, station_id, meeting_id]
        if (
            "start_id" in completion_value
            and completion_value.get("start_id") != current_id
        ) or (
            "destination_id" in completion_value
            and completion_value.get("destination_id") != meeting_id
        ):
            return None
        for result_field in (
            "waypoints",
            "waypoints_id",
            "new_waypoints",
            "new_waypoints_id",
        ):
            if (
                result_field in completion_value
                and completion_value.get(result_field) != expected_waypoints
            ):
                return None
        return analysis

    @staticmethod
    def _record_meeting_charging_navigation_completion(
        session: SessionState,
        *,
        goal_id: str,
        analysis: tuple[Evidence, Mapping[str, Any]],
        source_turn_id: str,
    ) -> None:
        parent, values = analysis
        if parent.evidence_id is None:
            return
        route_ids = [
            values.get("first_segment_route_id"),
            values.get("second_segment_route_id"),
        ]
        completion = Evidence(
            proposition="meeting_charging_navigation_completion",
            value={
                **dict(values),
                "navigation_set": True,
                "navigation_route_ids": route_ids,
                "navigation_goal_id": goal_id,
            },
            status=EvidenceStatus.KNOWN,
            source_kind=EvidenceSourceKind.DERIVED,
            source_turn_id=source_turn_id,
            confidence=parent.confidence,
            derived_from=[parent.evidence_id],
            derivation="successful_meeting_charging_navigation_v1",
        )
        session.evidence.add(completion)

    def _validated_meeting_charging_navigation_completion(
        self, session: SessionState
    ) -> tuple[Evidence, Mapping[str, Any]] | None:
        candidates = session.evidence.latest_for_proposition(
            "meeting_charging_navigation_completion", current_state_only=True
        )
        if len(candidates) != 1:
            return None
        completion = candidates[0]
        values = completion.value
        if (
            completion.status is not EvidenceStatus.KNOWN
            or completion.source_kind is not EvidenceSourceKind.DERIVED
            or completion.derivation != "successful_meeting_charging_navigation_v1"
            or completion.state_version != session.evidence.current_state_version
            or not isinstance(values, Mapping)
            or len(completion.derived_from) != 1
        ):
            return None
        parent = session.evidence.evidence.get(completion.derived_from[0])
        goal_id = values.get("navigation_goal_id")
        route_ids = values.get("navigation_route_ids")
        if (
            parent is None
            or parent.proposition != "meeting_charging_analysis_summary"
            or parent.derivation != "validated_meeting_charging_analysis_v1"
            or parent.state_version + 1 != completion.state_version
            or not isinstance(parent.value, Mapping)
            or not isinstance(goal_id, str)
            or route_ids
            != [
                parent.value.get("first_segment_route_id"),
                parent.value.get("second_segment_route_id"),
            ]
            or values.get("navigation_set") is not True
        ):
            return None
        completed = session.completed_action_calls_by_goal.get(goal_id)
        if (
            completed is None
            or len(completed) != 1
            or completed[0].tool_name != "set_new_navigation"
            or not _argument_value_matches_binding(
                completed[0].arguments, {"route_ids": route_ids}
            )
        ):
            return None
        current_id = parent.value.get("current_location_id")
        station_id = parent.value.get("charging_station_id")
        meeting_id = parent.value.get("meeting_location_id")
        if (
            not isinstance(current_id, str)
            or not isinstance(station_id, str)
            or not isinstance(meeting_id, str)
            or not isinstance(route_ids, list)
            or any(not isinstance(route_id, str) for route_id in route_ids)
        ):
            return None
        current_navigation_reads = [
            observation
            for observation in session.successful_read_results
            if observation.tool_name == "get_current_navigation_state"
            and observation.state_version == session.evidence.current_state_version
            and _argument_value_matches_binding(
                observation.arguments, {"detailed_information": True}
            )
        ]
        if current_navigation_reads and self._navigation_state_signature(
            current_navigation_reads[-1].value
        ) != (
            True,
            (current_id, station_id, meeting_id),
            tuple(route_ids),
        ):
            return None
        expected = {
            **dict(parent.value),
            "navigation_set": True,
            "navigation_route_ids": route_ids,
            "navigation_goal_id": goal_id,
        }
        return (completion, values) if dict(values) == expected else None

    def _next_meeting_charging_call(
        self,
        session: SessionState,
        item: PreparedGoal,
    ) -> PlannedOutbound:
        completion = self._validated_meeting_charging_navigation_completion(session)
        desired = item.goal.desired_outcome
        if completion is None:
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        values = completion[1]
        lower = desired.get("maximum_lower_bound_minutes")
        upper = desired.get("maximum_upper_bound_minutes")
        reported = desired.get("reported_maximum_minutes")
        maximum = values.get("maximum_charging_minutes")
        phone_number = values.get("charging_station_phone_number")
        bounded_condition = (
            desired.get("call_condition") == "maximum_within_open_interval"
            and type(lower) is int
            and type(upper) is int
            and type(maximum) is int
            and lower < maximum < upper
        )
        reported_condition = (
            desired.get("call_condition") == "reported_maximum_matches"
            and type(reported) is int
            and type(maximum) is int
            and reported == maximum
        )
        if (
            not (bounded_condition or reported_condition)
            or desired.get("call_purpose") != "reserve_charging_plug"
            or desired.get("phone_number") != phone_number
            or not isinstance(phone_number, str)
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        refreshed = self._prepare_turn(session)
        refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
        target = (
            self._unique_bound_target(refreshed_item)
            if refreshed_item is not None
            else None
        )
        if (
            target is None
            or target[1].tool_name != "call_phone_by_number"
            or not _argument_value_matches_binding(
                target[1].arguments, {"phone_number": phone_number}
            )
            or self._validated_meeting_charging_navigation_completion(session) is None
        ):
            return self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        deterministic = self._deterministic_bound_action(session, refreshed)
        return deterministic or self._limitation_plan(
            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
        )

    def _next_meeting_charging_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            desired = item.goal.desired_outcome
            if desired.get(_MEETING_CHARGING_MARKER) is not True:
                continue
            phase = desired.get(_MEETING_CHARGING_PHASE)
            if phase == _MEETING_CHARGING_ANALYSIS:
                return self._next_meeting_charging_analysis(session, item)
            if phase == _MEETING_CHARGING_NAVIGATION:
                return self._next_meeting_charging_navigation(session, item)
            if phase == _MEETING_CHARGING_CALL:
                return self._next_meeting_charging_call(session, item)
            if phase != _MEETING_CHARGING_DISCOVERY:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            identity = self._current_location_identity(session)
            current_datetime = self._current_datetime_parts(session)
            arrival_buffer = desired.get("arrival_buffer_minutes")
            range_buffer = desired.get("range_buffer_km")
            if (
                identity is None
                or current_datetime is None
                or type(arrival_buffer) is not int
                or type(range_buffer) is not int
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            location_id, _ = identity
            _, month, day, _, _ = current_datetime
            specifications: tuple[tuple[str, dict[str, Any], str, str], ...] = (
                (
                    "get_entries_from_calendar",
                    {"month": month, "day": day},
                    "read_current_day_meetings_for_charging",
                    "meeting_charging_calendar",
                ),
                (
                    "get_charging_specs_and_status",
                    {},
                    "read_vehicle_charging_status_for_meeting",
                    "meeting_charging_vehicle_status",
                ),
                (
                    "search_poi_at_location",
                    {
                        "location_id": location_id,
                        "category_poi": "charging_stations",
                    },
                    "search_all_local_charging_stations",
                    "meeting_charging_station_candidates",
                ),
            )
            observed: dict[str, tuple[Any, Evidence] | None] = {}
            missing: list[tuple[str, Mapping[str, Any], str, str]] = []
            for tool_name, arguments, operation, proposition in specifications:
                self._register_single_read_need(
                    session,
                    goal_id=item.goal.goal_id,
                    proposition=proposition,
                )
                result = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name=tool_name,
                    arguments=arguments,
                    proposition=proposition,
                )
                observed[proposition] = result
                if result is None:
                    missing.append((tool_name, arguments, operation, proposition))
            if missing:
                return self._parallel_navigation_read_plan(
                    session, item=item, specifications=missing
                )

            calendar = observed["meeting_charging_calendar"]
            charging = observed["meeting_charging_vehicle_status"]
            stations = observed["meeting_charging_station_candidates"]
            assert calendar is not None
            assert charging is not None
            assert stations is not None
            meeting = self._meeting_charging_next_meeting(
                calendar[1], current_datetime=current_datetime
            )
            charging_values = self._trip_charging_values(charging[1])
            fastest = self._meeting_charging_fastest_plug(
                stations[1], current_location_id=location_id
            )
            if meeting is None or charging_values is None or fastest is None:
                session.goal_dag.set_status(
                    item.goal.goal_id,
                    GoalStatus.FAILED,
                    block_reason="the meeting, vehicle status, or fastest plug was ambiguous",
                )
                return self._text_plan(
                    session,
                    "I could not verify a unique upcoming meeting, the current battery status, and one fastest local charging plug, so I did not continue the plan.",
                    goal_ids=[item.goal.goal_id],
                )
            plug, station_names = fastest
            state_of_charge, remaining_range = charging_values
            parents = (calendar[1], charging[1], stations[1])
            if any(parent.evidence_id is None for parent in parents):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            summary = Evidence(
                proposition="meeting_charging_discovery_summary",
                value={
                    **meeting,
                    **plug,
                    "current_location_id": location_id,
                    "current_datetime": list(current_datetime),
                    "arrival_buffer_minutes": arrival_buffer,
                    "range_buffer_km": range_buffer,
                    "state_of_charge": format(state_of_charge.normalize(), "f"),
                    "remaining_range_km": format(remaining_range.normalize(), "f"),
                    "station_names": list(station_names),
                },
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"meeting-charging-discovery-{item.goal.goal_id}",
                confidence=min(parent.confidence for parent in parents),
                derived_from=[
                    parent.evidence_id
                    for parent in parents
                    if parent.evidence_id is not None
                ],
                derivation="validated_meeting_charging_discovery_v1",
            )
            session.evidence.add(summary)
            session.goal_dag.set_status(item.goal.goal_id, GoalStatus.DONE)
            station_list = ", ".join(station_names)
            return self._text_plan(
                session,
                f"I found {station_list}. The fastest plug is the "
                f"{plug['charging_station_plug_power_kw']} kW plug at "
                f"{plug['charging_station_name']}, and it is "
                f"{plug['charging_station_plug_availability']}. Which plug should I "
                "use for the charging calculation?",
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
        return None

    def _next_local_charging_search_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _LOCAL_CHARGING_SEARCH_OPERATION:
                continue
            identity = self._current_location_identity(session)
            trip = self._validated_trip_route_summary(
                session, require_range_shortfall=False
            )
            if identity is None or trip is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            location_id, current_name = identity
            if (
                item.goal.desired_outcome.get("current_location_id") != location_id
                or _argument_identifier(
                    str(item.goal.desired_outcome.get("location_name", ""))
                )
                != _argument_identifier(current_name)
                or item.goal.desired_outcome.get("category") != "charging_stations"
                or item.goal.desired_outcome.get("filters")
                != ["charging_stations::has_available_plug"]
                or item.goal.desired_outcome.get("navigation_deferred") is not True
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            arguments = {
                "location_id": location_id,
                "category_poi": "charging_stations",
                "filters": ["charging_stations::has_available_plug"],
            }
            observed = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="search_poi_at_location",
                arguments=arguments,
                proposition="local_charging_station_candidates",
            )
            if observed is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="search_poi_at_location",
                        arguments=arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="search_poi_at_location",
                    arguments=arguments,
                    semantic_operation=_LOCAL_CHARGING_SEARCH_OPERATION,
                    proposition="local_charging_station_candidates",
                )
            _, raw_evidence = observed
            options = self._local_charging_options_from_evidence(
                raw_evidence, location_id=location_id
            )
            if (
                options is None
                or self._store_displayed_local_charging_options(
                    session,
                    goal=item.goal,
                    raw_evidence=raw_evidence,
                    trip_evidence=trip[0],
                    location_id=location_id,
                    options=options,
                )
                is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            descriptions: list[str] = []
            for option in options:
                plug_text = ", ".join(
                    f"{format(plug.power_kw.normalize(), 'f')} kW "
                    f"{plug.power_type} ({plug.availability})"
                    for plug in option.plugs
                )
                descriptions.append(f"{option.name}: {plug_text}.")
            return self._text_plan(
                session,
                " ".join(descriptions) + " I did not start navigation.",
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
        return None

    def _next_local_charging_estimate_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _LOCAL_CHARGING_ESTIMATE_OPERATION:
                continue
            displayed = self._validated_displayed_local_charging_options(session)
            trip = self._validated_trip_route_summary(
                session, require_range_shortfall=False
            )
            desired = item.goal.desired_outcome
            if displayed is None or trip is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            stations = [
                station
                for station in displayed[1]
                if station.station_id == desired.get("charging_station_id")
                and station.name == desired.get("charging_station_name")
            ]
            if len(stations) != 1:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            station = stations[0]
            plug = self._highest_available_dc_plug(station)
            start_soc = desired.get("start_state_of_charge")
            target_soc = desired.get("target_state_of_charge")
            if (
                plug is None
                or desired.get("charging_station_plug_id") != plug.plug_id
                or desired.get("current_location_id") != station.location_id
                or type(start_soc) is not int
                or type(target_soc) is not int
                or not 0 <= start_soc < target_soc <= 100
                or desired.get("navigation_deferred") is not True
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            route_arguments = {
                "start_id": station.location_id,
                "destination_id": station.station_id,
            }
            calculation_arguments = {
                "charging_station_id": station.station_id,
                "charging_station_plug_id": plug.plug_id,
                "start_state_of_charge": start_soc,
                "target_state_of_charge": target_soc,
            }
            route = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_arguments,
                proposition="local_charging_first_segment_routes",
            )
            calculation = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="calculate_charging_time_by_soc",
                arguments=calculation_arguments,
                proposition="local_charging_time_result",
            )
            missing: list[tuple[str, Mapping[str, Any], str, str]] = []
            if calculation is None:
                missing.append(
                    (
                        "calculate_charging_time_by_soc",
                        calculation_arguments,
                        "calculate_local_charging_time",
                        "local_charging_time_result",
                    )
                )
            if route is None:
                missing.append(
                    (
                        "get_routes_from_start_to_destination",
                        route_arguments,
                        "find_routes_to_local_charging_stop",
                        "local_charging_first_segment_routes",
                    )
                )
            if missing:
                if any(
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name=specification[0],
                        arguments=specification[1],
                    )
                    is not None
                    for specification in missing
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._parallel_navigation_read_plan(
                    session, item=item, specifications=missing
                )
            assert route is not None and calculation is not None
            _, route_evidence = route
            calculation_value, calculation_evidence = calculation
            options = self._conditional_route_options_from_evidence(
                route_evidence,
                start_id=station.location_id,
                destination_id=station.station_id,
            )
            fastest = (
                []
                if options is None
                else [option for option in options if "fastest" in option.aliases]
            )
            duration = self._charging_duration_minutes(
                calculation_value, start_soc=start_soc, target_soc=target_soc
            )
            destination_name = trip[1].get("destination_name")
            destination_id = trip[1].get("destination_id")
            if (
                len(fastest) != 1
                or duration is None
                or not isinstance(destination_name, str)
                or not isinstance(destination_id, str)
                or self._store_selected_local_charging_plan(
                    session,
                    goal=item.goal,
                    station=station,
                    plug=plug,
                    destination_name=destination_name,
                    destination_id=destination_id,
                    first_route_id=fastest[0].route_id,
                    start_soc=start_soc,
                    target_soc=target_soc,
                    duration_minutes=duration,
                    displayed_evidence=displayed[0],
                    trip_evidence=trip[0],
                    route_evidence=route_evidence,
                    calculation_evidence=calculation_evidence,
                )
                is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            return self._text_plan(
                session,
                f"Charging {station.name} from {start_soc} to {target_soc} percent "
                f"with its {format(plug.power_kw.normalize(), 'f')} kW DC plug "
                f"takes about {duration} minutes. I did not start navigation.",
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
        return None

    def _next_charging_stop_navigation_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _CHARGING_STOP_NAVIGATION_OPERATION:
                continue
            plan = self._validated_selected_local_charging_plan(session)
            if plan is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            values = plan[1]
            desired = item.goal.desired_outcome
            current_id = values.get("current_location_id")
            station_id = values.get("charging_station_id")
            destination_id = values.get("destination_id")
            first_route_id = values.get("first_segment_route_id")
            second_selection = desired.get("second_segment_selection")
            requested_via = desired.get("second_segment_via")
            if (
                not isinstance(current_id, str)
                or not isinstance(station_id, str)
                or not isinstance(destination_id, str)
                or not isinstance(first_route_id, str)
                or _ROUTE_ID_PATTERN.fullmatch(first_route_id) is None
                or desired.get("first_segment_selection") != "fastest"
                or second_selection not in _ROUTE_ORDINALS
                or not isinstance(requested_via, str)
                or desired.get("charging_station_name")
                != values.get("charging_station_name")
                or desired.get("destination_name") != values.get("destination_name")
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            navigation = self._successful_goal_read(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_current_navigation_state",
                arguments={"detailed_information": True},
            )
            if navigation is None:
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_current_navigation_state",
                    arguments={"detailed_information": True},
                    semantic_operation="read_current_navigation_for_charging_stop",
                    proposition="current_navigation_state",
                )
            state = self._navigation_state_view(session, goal_id=item.goal.goal_id)
            if (
                state is None
                or state.active
                or self._navigation_state_signature(navigation.value) != (False, (), ())
                or not self._destination_navigation_snapshot_is_current(
                    session, goal_id=item.goal.goal_id
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.POLICY_CONFLICT
                )
            self._record_navigation_policy_facts(
                session, goal_id=item.goal.goal_id, state=state
            )
            route_arguments = {
                "start_id": station_id,
                "destination_id": destination_id,
            }
            second_route = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_arguments,
                proposition="local_charging_second_segment_routes",
            )
            if second_route is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=route_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=route_arguments,
                    semantic_operation="find_routes_after_charging_stop",
                    proposition="local_charging_second_segment_routes",
                )
            _, second_route_evidence = second_route
            options = self._conditional_route_options_from_evidence(
                second_route_evidence,
                start_id=station_id,
                destination_id=destination_id,
            )
            selected = (
                []
                if options is None
                else [
                    option
                    for option in options
                    if second_selection in option.aliases
                    and _argument_identifier(option.via)
                    == _argument_identifier(requested_via)
                ]
            )
            if len(selected) != 1 or selected[0].route_id == first_route_id:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            route_ids = [first_route_id, selected[0].route_id]
            self._apply_navigation_derived_parameters(
                session,
                goal=item.goal,
                parameters={
                    "location": (
                        values["destination_name"],
                        (plan[0],),
                        "multisegment_navigation_destination_name_v1",
                    ),
                    "selected_destination_name": (
                        values["destination_name"],
                        (plan[0],),
                        "multisegment_navigation_confirmation_destination_v1",
                    ),
                    "selected_route_label": (
                        f"fastest first segment and {second_selection} second segment",
                        (plan[0], second_route_evidence),
                        "multisegment_navigation_confirmation_route_v1",
                    ),
                    "start_id": (
                        current_id,
                        (plan[0],),
                        "multisegment_navigation_current_start_v1",
                    ),
                    "route_start_id": (
                        current_id,
                        (plan[0], state.evidence),
                        "multisegment_navigation_policy_start_v1",
                    ),
                    "destination_id": (
                        destination_id,
                        (plan[0], second_route_evidence),
                        "multisegment_navigation_destination_v1",
                    ),
                    "route_ids": (
                        route_ids,
                        (plan[0], state.evidence, second_route_evidence),
                        "ordered_multisegment_routes_v1",
                    ),
                },
            )
            refreshed = self._prepare_turn(session)
            refreshed_item = refreshed.by_goal_id.get(item.goal.goal_id)
            target = (
                self._unique_bound_target(refreshed_item)
                if refreshed_item is not None
                else None
            )
            if (
                target is None
                or target[1].tool_name != "set_new_navigation"
                or not _argument_value_matches_binding(
                    target[1].arguments, {"route_ids": route_ids}
                )
                or not self._destination_navigation_snapshot_is_current(
                    session, goal_id=item.goal.goal_id
                )
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            deterministic = self._deterministic_bound_action(session, refreshed)
            return deterministic or self._limitation_plan(
                session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
            )
        return None

    def _next_trip_range_workflow(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            if item.goal.semantic_operation != _TRIP_RANGE_OPERATION:
                continue

            preview_only = (
                item.goal.desired_outcome.get(_TRIP_ROUTE_PREVIEW_MARKER) is True
            )
            destination_name = item.goal.desired_outcome.get("destination_name")
            if not isinstance(destination_name, str) or not destination_name.strip():
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                )
            if (
                not preview_only
                and item.goal.desired_outcome.get(_TRIP_PARALLEL_RANGE_READ_MARKER)
                is True
            ):
                initial_reads: tuple[tuple[str, Mapping[str, Any], str, str], ...] = (
                    (
                        "get_location_id_by_location_name",
                        {"location": destination_name},
                        "resolve_trip_destination",
                        "trip_destination_location_id",
                    ),
                    (
                        "get_charging_specs_and_status",
                        {},
                        _TRIP_RANGE_OPERATION,
                        "trip_charging_status",
                    ),
                )
                missing_initial_reads = [
                    specification
                    for specification in initial_reads
                    if self._derived_navigation_read_value(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name=specification[0],
                        arguments=specification[1],
                        proposition=specification[3],
                    )
                    is None
                ]
                if len(missing_initial_reads) == len(initial_reads):
                    if any(
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name=specification[0],
                            arguments=specification[1],
                        )
                        is not None
                        for specification in missing_initial_reads
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._parallel_navigation_read_plan(
                        session,
                        item=item,
                        specifications=missing_initial_reads,
                    )
            charging_evidence: Evidence | None = None
            state_of_charge: Decimal | None = None
            available_range: Decimal | None = None
            if not preview_only:
                charging_arguments: dict[str, Any] = {}
                charging = self._derived_navigation_read_value(
                    session,
                    goal_id=item.goal.goal_id,
                    tool_name="get_charging_specs_and_status",
                    arguments=charging_arguments,
                    proposition="trip_charging_status",
                )
                if charging is None:
                    if (
                        self._successful_goal_read(
                            session,
                            goal_id=item.goal.goal_id,
                            tool_name="get_charging_specs_and_status",
                            arguments=charging_arguments,
                        )
                        is not None
                    ):
                        return self._limitation_plan(
                            session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                        )
                    return self._navigation_read_plan(
                        session,
                        item=item,
                        tool_name="get_charging_specs_and_status",
                        arguments=charging_arguments,
                        semantic_operation=_TRIP_RANGE_OPERATION,
                        proposition="trip_charging_status",
                    )
                _, charging_evidence = charging
                charging_values = self._trip_charging_values(charging_evidence)
                if charging_values is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                state_of_charge, available_range = charging_values

            location_arguments = {"location": destination_name}
            location = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_location_id_by_location_name",
                arguments=location_arguments,
                proposition="trip_destination_location_id",
            )
            if location is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_location_id_by_location_name",
                        arguments=location_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_location_id_by_location_name",
                    arguments=location_arguments,
                    semantic_operation="resolve_trip_destination",
                    proposition="trip_destination_location_id",
                )
            destination_id, location_evidence = location
            if (
                not isinstance(destination_id, str)
                or not destination_id.startswith("loc_")
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(destination_id) is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            current_location = getattr(
                session.compiled_policy, "current_location", None
            )
            start_id = (
                current_location.get("id")
                if isinstance(current_location, Mapping)
                else None
            )
            if (
                not isinstance(start_id, str)
                or not start_id.startswith("loc_")
                or _LOCATION_OR_POI_ID_PATTERN.fullmatch(start_id) is None
            ):
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )

            route_arguments = {
                "start_id": start_id,
                "destination_id": destination_id,
            }
            route = self._derived_navigation_read_value(
                session,
                goal_id=item.goal.goal_id,
                tool_name="get_routes_from_start_to_destination",
                arguments=route_arguments,
                proposition="trip_route_options",
            )
            if route is None:
                if (
                    self._successful_goal_read(
                        session,
                        goal_id=item.goal.goal_id,
                        tool_name="get_routes_from_start_to_destination",
                        arguments=route_arguments,
                    )
                    is not None
                ):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                return self._navigation_read_plan(
                    session,
                    item=item,
                    tool_name="get_routes_from_start_to_destination",
                    arguments=route_arguments,
                    semantic_operation="find_trip_route",
                    proposition="trip_route_options",
                )
            _, route_evidence = route
            selection_required = (
                item.goal.desired_outcome.get(
                    _TRIP_RANGE_ROUTE_SELECTION_MARKER
                )
                is True
            )
            fastest: TripRouteAssessment | None
            detailed: TripRouteAssessment | None
            if selection_required:
                options = self._destination_route_options_from_evidence(
                    route_evidence,
                    start_id=start_id,
                    destination_id=destination_id,
                )
                if options is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                self._apply_navigation_derived_parameters(
                    session,
                    goal=item.goal,
                    parameters={
                        "start_id": (
                            start_id,
                            (route_evidence,),
                            "verified_trip_route_start_v1",
                        ),
                        "destination_id": (
                            destination_id,
                            (location_evidence, route_evidence),
                            "verified_trip_route_destination_v1",
                        ),
                    },
                )
                current_goal = next(
                    (
                        goal
                        for goal in session.intent.goals
                        if goal.goal_id == item.goal.goal_id
                    ),
                    None,
                )
                if current_goal is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                route_choice = current_goal.desired_outcome.get("route_choice_alias")
                if route_choice is None:
                    return self._ensure_destination_route_clarification(
                        session,
                        item=item,
                        destination_name=destination_name,
                        options=options,
                    )
                if not isinstance(route_choice, str):
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNSUPPORTED_PARAMETER
                    )
                selected = self._route_options_matching_choice(options, route_choice)
                if len(selected) != 1:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                option = selected[0]
                detailed = TripRouteAssessment(
                    distance_km=option.distance_km,
                    includes_toll=option.includes_toll,
                    route_id=option.route_id,
                    via=option.via,
                    duration_minutes=option.duration_minutes,
                )
                fastest = detailed
            else:
                fastest = self._fastest_trip_route(
                    route_evidence,
                    start_id=start_id,
                    destination_id=destination_id,
                )
                if fastest is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                detailed = self._detailed_trip_route(
                    route_evidence,
                    start_id=start_id,
                    destination_id=destination_id,
                )
            if preview_only and detailed is None:
                return self._limitation_plan(
                    session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                )
            summary = None
            if detailed is not None:
                fastest = detailed
                summary = self._store_trip_route_summary(
                    session,
                    goal=item.goal,
                    destination_name=destination_name,
                    start_id=start_id,
                    destination_id=destination_id,
                    route=fastest,
                    location_evidence=location_evidence,
                    route_evidence=route_evidence,
                    charging_evidence=charging_evidence,
                    state_of_charge=state_of_charge,
                    available_range=available_range,
                )
                if summary is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
            if preview_only:
                options = self._destination_route_options_from_evidence(
                    route_evidence,
                    start_id=start_id,
                    destination_id=destination_id,
                )
                if options is None:
                    return self._limitation_plan(
                        session, item.goal, GateOutcome.UNAVAILABLE_EVIDENCE
                    )
                fastest_option = next(
                    option for option in options if "fastest" in option.aliases
                )
                shortest_option = next(
                    option for option in options if "shortest" in option.aliases
                )
                highlighted = (
                    (("fastest and shortest", fastest_option),)
                    if fastest_option == shortest_option
                    else (
                        ("fastest", fastest_option),
                        ("shortest", shortest_option),
                    )
                )
                descriptions: list[str] = []
                for label, option in highlighted:
                    hours, minutes = divmod(option.duration_minutes, 60)
                    toll = (
                        "with toll roads"
                        if option.includes_toll
                        else "with no toll roads"
                    )
                    descriptions.append(
                        f"The {label} route to {destination_name} is via {option.via}. "
                        f"It is {format(option.distance_km.normalize(), 'f')} kilometers "
                        f"and takes about {hours} hours and {minutes} minutes, {toll}."
                    )
                alternative_count = len(options) - len(highlighted)
                noun = "route" if alternative_count == 1 else "routes"
                return self._text_plan(
                    session,
                    " ".join(descriptions)
                    + f" There are {alternative_count} alternative {noun}. "
                    + "I did not start navigation.",
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )
            assert state_of_charge is not None and available_range is not None
            assert fastest is not None
            return self._text_plan(
                session,
                self.responses.trip_range_assessment(
                    destination=destination_name,
                    state_of_charge=format(state_of_charge.normalize(), "f"),
                    available_range_km=format(available_range.normalize(), "f"),
                    route_distance_km=format(fastest.distance_km.normalize(), "f"),
                    can_reach=available_range >= fastest.distance_km,
                    includes_toll=fastest.includes_toll,
                    language=self._language(session),
                ),
                goal_ids=[item.goal.goal_id],
                kind=ProposalKind.COMPLETE,
            )
        return None

    def _next_current_navigation_read(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            targets = {
                target.semantic_operation: target
                for recipe in item.recipes
                if recipe.primary_operation == "read_current_navigation"
                and (target := recipe.target_operation(item.goal.semantic_operation))
                is not None
                and target.semantic_operation == "read_current_navigation"
            }
            if len(targets) != 1:
                continue
            summary = self._observed_navigation_summary(session, item)
            if summary is not None:
                return self._text_plan(
                    session,
                    self.responses.navigation_summary(
                        active=summary.active,
                        waypoint_names=summary.waypoint_names,
                        vias=summary.vias,
                        road_types=summary.road_types,
                        aliases=summary.aliases,
                        includes_toll=summary.includes_toll,
                        distance_km=summary.distance_km,
                        duration_minutes=summary.duration_minutes,
                        details_available=summary.details_available,
                        language=self._language(session),
                    ),
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )
            if self._read_goal_has_result(session, item):
                continue
            target = next(iter(targets.values()))
            tool_names = [
                name for name in target.tool_names if session.live_tools.has_tool(name)
            ]
            if len(tool_names) != 1:
                continue
            try:
                arguments = session.live_tools.validate_arguments(
                    tool_names[0], {"detailed_information": True}
                )
            except ToolArgumentValidationError:
                continue
            call_id = session.next_call_id()
            proposal = DecisionProposal(
                kind=ProposalKind.TOOL_GET,
                goal_ids=[item.goal.goal_id],
                tool_calls=[
                    ProposedToolCall(
                        tool_name=tool_names[0],
                        arguments=arguments,
                        call_id=call_id,
                        goal_id=item.goal.goal_id,
                    )
                ],
            )
            decision = self.precommit.validate(
                proposal, self._basic_gate_context(session)
            )
            if decision.outcome is not GateOutcome.ALLOW:
                return self._route_gate_failure(session, proposal, decision, item.goal)
            return PlannedOutbound(
                self.adapter.serialize(decision),
                proposal=proposal,
                decision=decision,
                policy_operations={call_id: "read_current_navigation"},
            )
        return None

    def _next_current_day_calendar_read(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        current = (
            session.compiled_policy.current_datetime
            if session.compiled_policy is not None
            else None
        )
        if not isinstance(current, Mapping):
            return None
        month = current.get("month")
        day = current.get("day")
        if (
            isinstance(month, bool)
            or isinstance(day, bool)
            or not isinstance(month, int)
            or not isinstance(day, int)
        ):
            return None

        for item in prepared.goals:
            if (
                item.goal.desired_outcome.get("month") != month
                or item.goal.desired_outcome.get("day") != day
            ):
                continue
            targets = {
                target.semantic_operation: target
                for recipe in item.recipes
                if (target := recipe.target_operation(item.goal.semantic_operation))
                is not None
                and target.semantic_operation == "get_entries_from_calendar"
            }
            if len(targets) != 1:
                continue
            entries = self._observed_calendar_entries(session, item)
            if entries is not None:
                return self._text_plan(
                    session,
                    self.responses.calendar_summary(
                        entries=entries, language=self._language(session)
                    ),
                    goal_ids=[item.goal.goal_id],
                    kind=ProposalKind.COMPLETE,
                )
            if self._read_goal_has_result(session, item):
                continue
            target = next(iter(targets.values()))
            tool_names = [
                name for name in target.tool_names if session.live_tools.has_tool(name)
            ]
            if len(tool_names) != 1:
                continue
            try:
                arguments = session.live_tools.validate_arguments(
                    tool_names[0], {"month": month, "day": day}
                )
            except ToolArgumentValidationError:
                continue
            call_id = session.next_call_id()
            proposal = DecisionProposal(
                kind=ProposalKind.TOOL_GET,
                goal_ids=[item.goal.goal_id],
                tool_calls=[
                    ProposedToolCall(
                        tool_name=tool_names[0],
                        arguments=arguments,
                        call_id=call_id,
                        goal_id=item.goal.goal_id,
                    )
                ],
            )
            decision = self.precommit.validate(
                proposal, self._basic_gate_context(session)
            )
            if decision.outcome is not GateOutcome.ALLOW:
                return self._route_gate_failure(session, proposal, decision, item.goal)
            return PlannedOutbound(
                self.adapter.serialize(decision),
                proposal=proposal,
                decision=decision,
                policy_operations={call_id: "get_entries_from_calendar"},
            )
        return None

    @staticmethod
    def _observed_calendar_entries(
        session: SessionState, item: PreparedGoal
    ) -> tuple[str, ...] | None:
        for observation in reversed(session.successful_read_results):
            if (
                item.goal.goal_id not in observation.goal_ids
                or observation.tool_name != "get_entries_from_calendar"
                or observation.state_version != session.evidence.current_state_version
                or not isinstance(observation.value, Mapping)
            ):
                continue
            meetings = observation.value.get("meetings")
            if not isinstance(meetings, list) or len(meetings) > 20:
                return None
            entries: list[str] = []
            for meeting in meetings:
                if not isinstance(meeting, Mapping):
                    return None
                start = meeting.get("start")
                topic = meeting.get("topic")
                location = meeting.get("location")
                if (
                    not isinstance(start, Mapping)
                    or not isinstance(topic, str)
                    or not topic.strip()
                    or len(topic.strip()) > 120
                    or (location is not None and not isinstance(location, str))
                ):
                    return None
                try:
                    hour = int(start["hour"])
                    minute = int(start["minute"])
                except (KeyError, TypeError, ValueError):
                    return None
                if not 0 <= hour <= 23 or not 0 <= minute <= 59:
                    return None
                detail = f"{topic.strip()} at {hour:02d}:{minute:02d}"
                if isinstance(location, str) and location.strip():
                    if len(location.strip()) > 120:
                        return None
                    detail += f" in {location.strip()}"
                entries.append(detail)
            return tuple(entries)
        return None

    @staticmethod
    def _observed_navigation_summary(
        session: SessionState, item: PreparedGoal
    ) -> NavigationSummary | None:
        for observation in reversed(session.successful_read_results):
            if (
                item.goal.goal_id not in observation.goal_ids
                or observation.tool_name != "get_current_navigation_state"
                or observation.state_version != session.evidence.current_state_version
                or not isinstance(observation.value, Mapping)
            ):
                continue
            active = observation.value.get("navigation_active")
            waypoint_ids = observation.value.get("waypoints_id")
            route_ids = observation.value.get("routes_to_final_destination_id")
            if (
                not isinstance(active, bool)
                or not isinstance(waypoint_ids, list)
                or not isinstance(route_ids, list)
                or len(waypoint_ids) > 16
                or len(route_ids) > 15
                or any(not isinstance(value, str) for value in waypoint_ids)
                or any(not isinstance(value, str) for value in route_ids)
            ):
                return None
            if not active:
                return NavigationSummary(active=False, details_available=True)

            details = observation.value.get("details")
            if not isinstance(details, Mapping):
                return NavigationSummary(active=True)
            waypoint_details = details.get("waypoints")
            route_details = details.get("routes")
            if (
                not isinstance(waypoint_details, list)
                or not isinstance(route_details, list)
                or len(waypoint_details) != len(waypoint_ids)
                or len(route_details) != len(route_ids)
            ):
                return NavigationSummary(active=True)

            names_by_id: dict[str, str] = {}
            waypoint_names: list[str] = []
            for expected_id, waypoint in zip(
                waypoint_ids, waypoint_details, strict=True
            ):
                if not isinstance(waypoint, Mapping):
                    return NavigationSummary(active=True)
                waypoint_id = waypoint.get("id")
                name = waypoint.get("name")
                if (
                    waypoint_id != expected_id
                    or not isinstance(name, str)
                    or not CARGuardOrchestrator._voice_result_field(name, 80)
                ):
                    return NavigationSummary(active=True)
                clean_name = name.strip()
                names_by_id[expected_id] = clean_name
                waypoint_names.append(clean_name)

            total_distance = Decimal(0)
            total_minutes = 0
            vias: list[str] = []
            road_types: list[str] = []
            aliases: list[str] = []
            includes_toll = False
            for expected_id, route in zip(route_ids, route_details, strict=True):
                if (
                    not isinstance(route, Mapping)
                    or route.get("route_id") != expected_id
                ):
                    return NavigationSummary(active=True)
                start_id = route.get("start_id")
                destination_id = route.get("destination_id")
                if start_id not in names_by_id or destination_id not in names_by_id:
                    return NavigationSummary(active=True)
                distance_value = route.get("distance_km")
                hours_value = route.get("duration_hours")
                minutes_value = route.get("duration_minutes")
                if (
                    isinstance(distance_value, bool)
                    or isinstance(hours_value, bool)
                    or isinstance(minutes_value, bool)
                ):
                    return NavigationSummary(active=True)
                try:
                    distance = Decimal(str(distance_value))
                    hours_decimal = Decimal(str(hours_value))
                    minutes_decimal = Decimal(str(minutes_value))
                    hours = int(hours_decimal)
                    minutes = int(minutes_decimal)
                except (InvalidOperation, TypeError, ValueError):
                    return NavigationSummary(active=True)
                if (
                    not distance.is_finite()
                    or distance < 0
                    or hours < 0
                    or hours > 240
                    or minutes < 0
                    or minutes > 59
                    or hours_decimal != hours
                    or minutes_decimal != minutes
                ):
                    return NavigationSummary(active=True)
                total_distance += distance
                total_minutes += hours * 60 + minutes

                via = route.get("name_via")
                if via is not None:
                    if not isinstance(
                        via, str
                    ) or not CARGuardOrchestrator._voice_result_field(via, 120):
                        return NavigationSummary(active=True)
                    clean_via = via.strip()
                    if clean_via and clean_via not in vias:
                        vias.append(clean_via)

                route_road_types = route.get("road_types")
                route_aliases = route.get("alias")
                route_includes_toll = route.get("includes_toll")
                if (
                    not isinstance(route_road_types, list)
                    or len(route_road_types) > 12
                    or not isinstance(route_aliases, list)
                    or len(route_aliases) > 12
                    or not isinstance(route_includes_toll, bool)
                ):
                    return NavigationSummary(active=True)
                for values, destination in (
                    (route_road_types, road_types),
                    (route_aliases, aliases),
                ):
                    for value in values:
                        if not isinstance(
                            value, str
                        ) or not CARGuardOrchestrator._voice_result_field(value, 80):
                            return NavigationSummary(active=True)
                        clean_value = value.strip().replace("_", " ")
                        if clean_value not in destination:
                            destination.append(clean_value)
                includes_toll = includes_toll or route_includes_toll

            return NavigationSummary(
                active=True,
                waypoint_names=tuple(waypoint_names),
                vias=tuple(vias[:4]),
                road_types=tuple(road_types[:8]),
                aliases=tuple(aliases[:8]),
                includes_toll=includes_toll,
                distance_km=format(total_distance.normalize(), "f"),
                duration_minutes=total_minutes,
                details_available=True,
            )
        return None

    @staticmethod
    def _voice_result_field(value: str, limit: int) -> bool:
        cleaned = value.strip()
        return (
            bool(cleaned)
            and len(cleaned) <= limit
            and not any(character in cleaned for character in "\r\n`*_<>_")
        )

    @staticmethod
    def _observed_range_km(session: SessionState, item: PreparedGoal) -> str | None:
        values: set[Decimal] = set()
        for observation in reversed(session.successful_read_results):
            if (
                item.goal.goal_id not in observation.goal_ids
                or observation.tool_name != "get_distance_by_soc"
                or observation.state_version != session.evidence.current_state_version
                or not isinstance(observation.value, Mapping)
            ):
                continue
            for key, value in observation.value.items():
                if not str(key).startswith("distance_km_for_") or not isinstance(
                    value, str
                ):
                    continue
                match = re.fullmatch(
                    r"\s*(\d+(?:\.\d+)?)\s*km\s*", value, flags=re.IGNORECASE
                )
                if match is None:
                    continue
                try:
                    distance = Decimal(match.group(1))
                except InvalidOperation:
                    continue
                if distance.is_finite() and distance >= 0:
                    values.add(distance)
        if len(values) != 1:
            return None
        distance = next(iter(values))
        return format(distance.normalize(), "f")

    @staticmethod
    def _contextual_slot_source(
        session: SessionState, goal: Goal
    ) -> tuple[str, str, str] | None:
        """Return the state proposition, read tool, and missing parameter."""

        if (
            session.intent is None
            or len(session.intent.goals) != 1
            or goal.goal_id not in session.authorized_action_goal_ids
        ):
            return None
        latest = next(
            (
                message
                for message in reversed(session.conversation)
                if message.get("role") == "user"
                and isinstance(message.get("content"), str)
                and isinstance(message.get("turn_id"), str)
            ),
            None,
        )
        if latest is None or latest["turn_id"] not in session.intent.intent_source_turn_ids:
            return None
        text = latest["content"]
        turn_id = latest["turn_id"]
        if goal.desired_outcome == {"percentage": 0}:
            recovered = _fully_open_window_close_intent(text, turn_id=turn_id)
            if (
                recovered is not None
                and recovered.goals[0].semantic_operation == goal.semantic_operation
                and goal.semantic_operation == "set_window_position"
            ):
                return (
                    "contextual_window_position_snapshot",
                    "get_vehicle_window_positions",
                    "window",
                )
        if set(goal.desired_outcome) == {"temperature"}:
            recovered = _absolute_climate_temperature_intent(text, turn_id=turn_id)
            if (
                recovered is not None
                and recovered.goals[0].semantic_operation == goal.semantic_operation
                and recovered.goals[0].desired_outcome == goal.desired_outcome
                and goal.semantic_operation == "set_climate_temperature"
            ):
                return (
                    "contextual_climate_temperature_snapshot",
                    "get_temperature_inside_car",
                    "seat_zone",
                )
        return None

    @classmethod
    def _ensure_contextual_slot_needs(cls, session: SessionState) -> None:
        if session.intent is None:
            return
        for goal in session.intent.goals:
            source = cls._contextual_slot_source(session, goal)
            if source is None:
                continue
            proposition, _, _ = source
            session.evidence.register_need(
                EvidenceNeed(
                    proposition=proposition,
                    required_for_goal_id=goal.goal_id,
                    acceptable_sources={"tool_result"},
                    freshness="current_state",
                    required_before_set=False,
                )
            )

    @staticmethod
    def _contextual_slot_value(
        goal: Goal, *, proposition: str, snapshot: Any
    ) -> tuple[str, str] | None:
        if not isinstance(snapshot, Mapping):
            return None
        if proposition == "contextual_window_position_snapshot":
            position_names = {
                "window_driver_position": "DRIVER",
                "window_passenger_position": "PASSENGER",
                "window_driver_rear_position": "DRIVER_REAR",
                "window_passenger_rear_position": "PASSENGER_REAR",
            }
            if set(snapshot) != set(position_names):
                return None
            fully_open = [
                position_names[name]
                for name, value in snapshot.items()
                if not isinstance(value, bool)
                and isinstance(value, (int, float))
                and Decimal(str(value)) == Decimal(100)
            ]
            return ("window", fully_open[0]) if len(fully_open) == 1 else None

        if proposition != "contextual_climate_temperature_snapshot":
            return None
        target = goal.desired_outcome.get("temperature")
        if isinstance(target, bool) or not isinstance(target, (int, float)):
            return None
        try:
            target_temperature = Decimal(str(target))
        except InvalidOperation:
            return None
        if not target_temperature.is_finite() or snapshot.get("temperature_unit") != "Celsius":
            return None
        zone_names = {
            "climate_temperature_driver": "DRIVER",
            "climate_temperature_passenger": "PASSENGER",
        }
        if set(snapshot) != {*zone_names, "temperature_unit"}:
            return None
        mismatches: list[str] = []
        for name, zone in zone_names.items():
            value = snapshot.get(name)
            if isinstance(value, bool) or not isinstance(value, (int, float)):
                return None
            try:
                current = Decimal(str(value))
            except InvalidOperation:
                return None
            if not current.is_finite():
                return None
            if current != target_temperature:
                mismatches.append(zone)
        return ("seat_zone", mismatches[0]) if len(mismatches) == 1 else None

    def _materialize_contextual_slot_parameters(self, session: SessionState) -> None:
        if session.intent is None or session.live_tools is None:
            return
        for goal in tuple(session.intent.goals):
            source = self._contextual_slot_source(session, goal)
            if source is None:
                continue
            proposition, _, parameter = source
            needs = [
                need
                for need in session.evidence.needs.values()
                if need.required_for_goal_id == goal.goal_id
                and need.proposition == proposition
            ]
            parents = [
                evidence
                for need in needs
                for evidence in session.evidence.satisfying_evidence(need)
            ]
            if len(parents) != 1:
                continue
            derived_value = self._contextual_slot_value(
                goal, proposition=proposition, snapshot=parents[0].value
            )
            if derived_value is None or derived_value[0] != parameter:
                continue
            value = derived_value[1]
            values = {**goal.desired_outcome, parameter: value}
            tool_name = (
                "open_close_window"
                if parameter == "window"
                else "set_climate_temperature"
            )
            if not session.live_tools.has_tool(tool_name):
                continue
            try:
                arguments = session.live_tools.validate_arguments(tool_name, values)
            except ToolArgumentValidationError:
                continue
            if arguments.get(parameter) != value:
                continue

            parent = parents[0]
            if parent.evidence_id is None:
                continue
            derivation = (
                "unique_fully_open_window_v1"
                if parameter == "window"
                else "unique_climate_target_mismatch_zone_v1"
            )
            self._apply_navigation_derived_parameters(
                session,
                goal=goal,
                parameters={parameter: (value, (parent,), derivation)},
            )
            if parameter not in session.derived_value_evidence_by_goal.get(
                goal.goal_id, {}
            ):
                continue
            unresolved = [
                slot
                for slot in session.intent.unresolved_slots
                if not (slot.goal_id == goal.goal_id and slot.name == parameter)
            ]
            if len(unresolved) != len(session.intent.unresolved_slots):
                session.intent = session.intent.model_copy(
                    update={"unresolved_slots": unresolved}, deep=True
                )
                session.goal_dag = self.goal_planner.update(
                    session.goal_dag, session.intent
                )

    def _next_contextual_slot_read(
        self, session: SessionState, prepared: PreparedTurn
    ) -> PlannedOutbound | None:
        for item in prepared.goals:
            source = self._contextual_slot_source(session, item.goal)
            if source is None:
                continue
            proposition, tool_name, _ = source
            needs = [
                need
                for need in session.evidence.needs.values()
                if need.required_for_goal_id == item.goal.goal_id
                and need.proposition == proposition
            ]
            if any(
                session.evidence.satisfying_evidence(need) for need in needs
            ) or session.evidence.latest_for_proposition(
                proposition, current_state_only=True
            ):
                continue
            binding = next(
                (
                    candidate
                    for candidate in item.bindings
                    if candidate.is_read
                    and candidate.tool_name == tool_name
                    and candidate.is_complete
                ),
                None,
            )
            if binding is None:
                continue
            need = next(iter(needs), None)
            if need is None:
                continue
            assert need.need_id is not None
            call_id = session.next_call_id()
            proposal = DecisionProposal(
                kind=ProposalKind.TOOL_GET,
                goal_ids=[item.goal.goal_id],
                tool_calls=[
                    ProposedToolCall(
                        tool_name=binding.tool_name,
                        arguments=binding.arguments,
                        call_id=call_id,
                        goal_id=item.goal.goal_id,
                    )
                ],
            )
            gate = self.precommit.validate(proposal, self._basic_gate_context(session))
            if gate.outcome is not GateOutcome.ALLOW:
                return self._route_gate_failure(session, proposal, gate, item.goal)
            return PlannedOutbound(
                self.adapter.serialize(gate),
                proposal=proposal,
                decision=gate,
                pending_need_ids={call_id: (need.need_id,)},
                policy_operations={call_id: binding.semantic_operation},
            )
        return None

    @staticmethod
    def _ensure_relative_fan_speed_needs(session: SessionState) -> None:
        if session.intent is None:
            return
        for goal in session.intent.goals:
            if (
                goal.goal_id not in session.relative_fan_speed_deltas_by_goal
                or "level" in goal.desired_outcome
            ):
                continue
            session.evidence.register_need(
                EvidenceNeed(
                    proposition="fan_speed",
                    required_for_goal_id=goal.goal_id,
                    acceptable_sources={"tool_result"},
                    freshness="current_state",
                )
            )

    def _materialize_relative_fan_speed_goal_parameter(
        self, session: SessionState
    ) -> None:
        if session.intent is None or not session.relative_fan_speed_deltas_by_goal:
            return
        changed = False
        goals: list[Goal] = []
        for goal in session.intent.goals:
            delta = session.relative_fan_speed_deltas_by_goal.get(goal.goal_id)
            if delta is None or "level" in goal.desired_outcome:
                goals.append(goal.model_copy(deep=True))
                continue
            parents = [
                observation
                for need in session.evidence.needs.values()
                if need.required_for_goal_id == goal.goal_id
                and need.proposition == "fan_speed"
                for observation in session.evidence.satisfying_evidence(need)
            ]
            if not parents:
                goals.append(goal.model_copy(deep=True))
                continue
            if any(type(observation.value) is not int for observation in parents):
                goals.append(goal.model_copy(deep=True))
                continue
            current = parents[0].value
            assert type(current) is int
            if any(observation.value != current for observation in parents[1:]):
                goals.append(goal.model_copy(deep=True))
                continue
            target = current + delta
            if not session.live_tools.has_tool("set_fan_speed"):
                goals.append(goal.model_copy(deep=True))
                continue
            try:
                arguments = session.live_tools.validate_arguments(
                    "set_fan_speed", {"level": target}
                )
            except ToolArgumentValidationError:
                goals.append(goal.model_copy(deep=True))
                continue
            level = arguments.get("level")
            if type(level) is not int:
                goals.append(goal.model_copy(deep=True))
                continue

            parent = max(parents, key=lambda item: item.observation_index)
            assert parent.evidence_id is not None
            derived = Evidence(
                proposition=f"derived_argument:{goal.goal_id}:level",
                value=level,
                status=EvidenceStatus.KNOWN,
                source_kind=EvidenceSourceKind.DERIVED,
                source_turn_id=f"derived-step-{session.budget.steps}",
                confidence=parent.confidence,
                derived_from=[parent.evidence_id],
                derivation="relative_fan_speed_delta_v1",
            )
            session.evidence.add(derived)
            stored = session.evidence.latest_for_proposition(
                derived.proposition, current_state_only=True
            )[-1]
            assert stored.evidence_id is not None
            derived_by_parameter = dict(
                session.derived_value_evidence_by_goal.get(goal.goal_id, {})
            )
            derived_by_parameter["level"] = stored.evidence_id
            session.derived_value_evidence_by_goal[goal.goal_id] = derived_by_parameter
            desired = dict(
                session.grounded_desired_values_by_goal.get(goal.goal_id, {})
            )
            desired["level"] = level
            session.grounded_desired_values_by_goal[goal.goal_id] = desired
            sources = dict(session.grounded_value_sources_by_goal.get(goal.goal_id, {}))
            sources.pop("level", None)
            session.grounded_value_sources_by_goal[goal.goal_id] = sources
            goals.append(
                goal.model_copy(
                    update={
                        "desired_outcome": {**goal.desired_outcome, "level": level}
                    },
                    deep=True,
                )
            )
            changed = True
        if not changed:
            return
        session.intent = session.intent.model_copy(update={"goals": goals}, deep=True)
        session.goal_dag = self.goal_planner.update(session.goal_dag, session.intent)

